def _material_preview_image(path: Path, *, max_edge: int = 640) -> Path:
    if path.suffix.lower() not in {".jpg", ".jpeg", ".png", ".webp"}:
        return path
    cache_dir = path.parent / ".previews"
    try:
        source_stat = path.stat()
        fingerprint = f"{source_stat.st_mtime_ns}.{source_stat.st_size}"
        target = cache_dir / f"{path.stem}.w{max_edge}.{fingerprint}.jpg"
        if target.exists() and target.stat().st_size > 0:
            return target
        raw = np.fromfile(str(path), dtype=np.uint8)
        image = cv2.imdecode(raw, cv2.IMREAD_COLOR)
        if image is None:
            return path
        height, width = image.shape[:2]
        longest = max(height, width)
        if longest <= max_edge:
            return path
        scale = max_edge / float(longest)
        resized = cv2.resize(image, (max(1, int(width * scale)), max(1, int(height * scale))), interpolation=cv2.INTER_AREA)
        ok, encoded = cv2.imencode(".jpg", resized, [int(cv2.IMWRITE_JPEG_QUALITY), 76])
        if not ok:
            return path
        cache_dir.mkdir(parents=True, exist_ok=True)
        tmp = target.with_suffix(".tmp.jpg")
        encoded.tofile(str(tmp))
        os.replace(tmp, target)
        return target
    except Exception:
        logger.debug("Failed to create material preview image for %s", path, exc_info=True)
        return path


_BROWSER_SAFE_MP4_FOURCCS = {"avc1", "h264"}


def _find_ffmpeg_exe() -> Optional[str]:
    exe = shutil.which("ffmpeg")
    if exe:
        return exe
    try:
        import imageio_ffmpeg

        return imageio_ffmpeg.get_ffmpeg_exe()
    except Exception:
        return None


_FFMPEG_ENCODER_SUPPORT_CACHE: Dict[tuple[str, str], bool] = {}


def _ffmpeg_encoder_supported(ffmpeg_exe: str, encoder: str) -> bool:
    key = (str(ffmpeg_exe), str(encoder))
    if key in _FFMPEG_ENCODER_SUPPORT_CACHE:
        return _FFMPEG_ENCODER_SUPPORT_CACHE[key]
    try:
        result = subprocess.run(
            [ffmpeg_exe, "-hide_banner", "-encoders"],
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            encoding="utf-8",
            errors="replace",
            timeout=15,
            check=False,
        )
        supported = result.returncode == 0 and str(encoder) in f"{result.stdout}\n{result.stderr}"
    except Exception:
        supported = False
    _FFMPEG_ENCODER_SUPPORT_CACHE[key] = supported
    return supported


def _preferred_segment_preview_encoder(ffmpeg_exe: str) -> str:
    requested = str(os.environ.get("KEY_ACTION_SEGMENT_PREVIEW_ENCODER") or "auto").strip().lower()
    if requested in {"", "auto"}:
        return "h264_nvenc" if _ffmpeg_encoder_supported(ffmpeg_exe, "h264_nvenc") else "libx264"
    if requested in {"nvenc", "h264_nvenc"}:
        return "h264_nvenc" if _ffmpeg_encoder_supported(ffmpeg_exe, "h264_nvenc") else "libx264"
    return requested


def _video_fourcc_tag(path: Path) -> str:
    cap = cv2.VideoCapture(str(path))
    try:
        if not cap.isOpened():
            return ""
        fourcc = int(cap.get(cv2.CAP_PROP_FOURCC) or 0)
        return "".join(chr((fourcc >> (8 * idx)) & 0xFF) for idx in range(4)).strip().lower()
    except Exception:
        return ""
    finally:
        cap.release()


def _is_material_clip_path(path: Path) -> bool:
    parts = {part.lower() for part in path.parts}
    return (
        path.name.lower() == "clip.mp4"
        and ("published_materials" in parts or ("materials" in parts and "events" in parts))
    )


def _is_window_preview_clip_path(path: Path) -> bool:
    parts = {part.lower() for part in path.parts}
    return path.name.lower() == "window_preview.mp4" and "windows" in parts


def _transcode_material_clip_for_browser(source: Path, target: Path) -> Optional[Path]:
    target.parent.mkdir(parents=True, exist_ok=True)
    ffmpeg_exe = _find_ffmpeg_exe()
    if ffmpeg_exe:
        tmp = target.with_name(f"{target.stem}.tmp_{os.getpid()}_{int(time.time() * 1000)}{target.suffix}")
        cmd = [
            ffmpeg_exe,
            "-y",
            "-i",
            str(source),
            "-c:v",
            "libx264",
            "-preset",
            "veryfast",
            "-crf",
            "23",
            "-pix_fmt",
            "yuv420p",
            "-movflags",
            "+faststart",
            "-an",
            str(tmp),
        ]
        try:
            result = subprocess.run(cmd, stdout=subprocess.PIPE, stderr=subprocess.PIPE, text=True, timeout=180)
            if result.returncode == 0 and tmp.exists() and tmp.stat().st_size > 0:
                shutil.move(str(tmp), str(target))
                return target
            logger.warning("ffmpeg material clip transcode failed: %s", result.stderr[-800:] if result.stderr else result.returncode)
        except Exception as exc:
            logger.warning("ffmpeg material clip transcode error: %s", exc)
        finally:
            tmp.unlink(missing_ok=True)

    tmp = target.with_name(f"{target.stem}.tmp_{os.getpid()}_{int(time.time() * 1000)}{target.suffix}")
    cap = cv2.VideoCapture(str(source))
    writer = None
    try:
        if not cap.isOpened():
            return None
        fps = float(cap.get(cv2.CAP_PROP_FPS) or 30.0)
        if fps <= 0:
            fps = 30.0
        width = int(cap.get(cv2.CAP_PROP_FRAME_WIDTH) or 0)
        height = int(cap.get(cv2.CAP_PROP_FRAME_HEIGHT) or 0)
        if width <= 0 or height <= 0:
            return None
        out_width = width - (width % 2)
        out_height = height - (height % 2)
        if out_width <= 0 or out_height <= 0:
            return None
        writer = cv2.VideoWriter(str(tmp), cv2.VideoWriter_fourcc(*"avc1"), fps, (out_width, out_height))
        if not writer.isOpened():
            return None
        written = 0
        while True:
            ok, frame = cap.read()
            if not ok:
                break
            if frame.shape[1] != out_width or frame.shape[0] != out_height:
                frame = cv2.resize(frame, (out_width, out_height), interpolation=cv2.INTER_AREA)
            writer.write(frame)
            written += 1
        writer.release()
        writer = None
        cap.release()
        if written <= 0 or not tmp.exists() or tmp.stat().st_size <= 0:
            tmp.unlink(missing_ok=True)
            return None
        if _video_fourcc_tag(tmp) not in _BROWSER_SAFE_MP4_FOURCCS:
            tmp.unlink(missing_ok=True)
            return None
        shutil.move(str(tmp), str(target))
        return target
    except Exception as exc:
        logger.warning("Failed to transcode material clip for browser playback: %s -> %s (%s)", source, target, exc)
        tmp.unlink(missing_ok=True)
        return None
    finally:
        if writer is not None:
            writer.release()
        cap.release()


def _browser_playable_material_clip(path: Path) -> Path:
    if path.suffix.lower() != ".mp4" or not (_is_material_clip_path(path) or _is_window_preview_clip_path(path)):
        return path
    if _video_fourcc_tag(path) in _BROWSER_SAFE_MP4_FOURCCS:
        return path
    cache = path.with_name(f"{path.stem}.browser{path.suffix}")
    try:
        source_mtime = path.stat().st_mtime
        if (
            cache.exists()
            and cache.is_file()
            and cache.stat().st_size > 0
            and cache.stat().st_mtime >= source_mtime
            and _video_fourcc_tag(cache) in _BROWSER_SAFE_MP4_FOURCCS
        ):
            return cache
    except OSError:
        return path
    transcoded = _transcode_material_clip_for_browser(path, cache)
    return transcoded or path


def _env_int(name: str, default: int, minimum: int = 1) -> int:
    value = os.environ.get(name)
    if value is None:
        return default
    try:
        parsed = int(value)
    except Exception:
        return default
    return parsed if parsed >= minimum else default


