def _validate_experiment_id(experiment_id: str) -> str:
    value = str(experiment_id or "")
    if not value or not _EXPERIMENT_ID_RE.fullmatch(value):
        raise HTTPException(
            status_code=400,
            detail="Invalid experiment_id format; allowed: letters, numbers, dot, underscore, hyphen",
        )
    return value


def _sanitize_upload_filename(filename: Optional[str], *, default_name: str) -> str:
    raw_name = Path(str(filename or "")).name.strip()
    if not raw_name:
        raw_name = default_name
    cleaned = re.sub(r"[^A-Za-z0-9._-]+", "_", raw_name).strip("._")
    if not cleaned:
        cleaned = default_name
    return cleaned[:128]


async def _save_upload_file(upload: UploadFile, target_path: Path, *, max_bytes: int) -> int:
    total = 0
    try:
        with target_path.open("wb") as handle:
            while True:
                chunk = await upload.read(_UPLOAD_CHUNK_SIZE)
                if not chunk:
                    break
                total += len(chunk)
                if total > max_bytes:
                    raise HTTPException(status_code=413, detail=f"File too large; max {max_bytes} bytes")
                handle.write(chunk)
    except HTTPException:
        try:
            target_path.unlink(missing_ok=True)
        except Exception:
            pass
        raise
    finally:
        try:
            await upload.close()
        except Exception:
            pass
    return total


_KEY_ACTION_RAW_UPLOAD_LOCKS: Dict[str, asyncio.Lock] = {}


def _key_action_raw_upload_lock(experiment_id: str) -> asyncio.Lock:
    lock = _KEY_ACTION_RAW_UPLOAD_LOCKS.get(experiment_id)
    if lock is None:
        lock = asyncio.Lock()
        _KEY_ACTION_RAW_UPLOAD_LOCKS[experiment_id] = lock
    return lock


def _normalize_key_action_raw_upload_view(view: str) -> str:
    aliases = {
        "first": "first_person",
        "first_person": "first_person",
        "operator": "first_person",
        "operator_view": "first_person",
        "ego": "first_person",
        "fpv": "first_person",
        "third": "third_person",
        "third_person": "third_person",
        "overview": "third_person",
        "table": "third_person",
        "top": "third_person",
        "top_view": "third_person",
    }
    normalized = aliases.get(str(view or "").strip().lower())
    if normalized not in {"first_person", "third_person"}:
        raise HTTPException(status_code=400, detail="view must be first_person or third_person")
    return normalized


def _decode_upload_filename(value: Optional[str], *, default_name: str) -> str:
    if not value:
        return default_name
    try:
        decoded = unquote(str(value))
    except Exception:
        decoded = str(value)
    return decoded or default_name


async def _save_request_stream_to_file(request: Request, target_path: Path, *, max_bytes: int) -> int:
    content_length = request.headers.get("content-length")
    if content_length:
        try:
            if int(content_length) > max_bytes:
                raise HTTPException(status_code=413, detail=f"File too large; max {max_bytes} bytes")
        except ValueError:
            pass
    total = 0
    try:
        with target_path.open("wb") as handle:
            async for chunk in request.stream():
                if not chunk:
                    continue
                total += len(chunk)
                if total > max_bytes:
                    raise HTTPException(status_code=413, detail=f"File too large; max {max_bytes} bytes")
                await asyncio.to_thread(handle.write, chunk)
    except HTTPException:
        try:
            target_path.unlink(missing_ok=True)
        except Exception:
            pass
        raise
    except Exception as exc:
        try:
            target_path.unlink(missing_ok=True)
        except Exception:
            pass
        raise HTTPException(status_code=500, detail=f"Failed to save upload: {exc}") from exc
    return total


def _video_store_root() -> Path:
    root = VIDEO_STORE_ROOT.expanduser().resolve()
    root.mkdir(parents=True, exist_ok=True)
    return root


def _video_store_compatible_roots() -> List[Path]:
    roots = [_video_store_root()]
    configured = os.environ.get("LAB_VIDEO_STORE_COMPAT_ROOTS", "")
    for item in [part.strip() for part in configured.split(os.pathsep) if part.strip()]:
        try:
            roots.append(Path(item).expanduser().resolve())
        except Exception:
            continue
    if os.environ.get("LAB_VIDEO_STORE_ENABLE_BUILTIN_LEGACY_ROOT", "1").strip().lower() not in {"0", "false", "no", "off"}:
        for builtin in (r"D:\LabVideo\raw_uploads", r"D:\LabVideoStore\raw_uploads", r"D:\LabVideoStore"):
            try:
                candidate = Path(builtin).resolve()
                if candidate.exists():
                    roots.append(candidate)
            except Exception:
                pass
    unique: List[Path] = []
    seen: set[str] = set()
    for root in roots:
        try:
            key = os.path.normcase(str(root.resolve()))
        except Exception:
            key = os.path.normcase(str(root))
        if key not in seen:
            seen.add(key)
            unique.append(root)
    return unique


def _is_path_under(path: Path, root: Path) -> bool:
    resolved = path.resolve()
    root_resolved = root.resolve()
    try:
        resolved.relative_to(root_resolved)
        return True
    except ValueError:
        return resolved == root_resolved


def _is_path_under_any_video_store(path: Path) -> bool:
    return any(_is_path_under(path, root) for root in _video_store_compatible_roots())


def _video_store_staging_path(safe_name: str) -> Path:
    staging_dir = _video_store_root() / "_staging"
    staging_dir.mkdir(parents=True, exist_ok=True)
    return staging_dir / f"{uuid.uuid4().hex}_{safe_name}"


def _video_store_hash_root() -> Path:
    root = _video_store_root() / "by_hash"
    root.mkdir(parents=True, exist_ok=True)
    return root


def _video_store_hash_index_path() -> Path:
    index_dir = _video_store_root() / "indexes"
    index_dir.mkdir(parents=True, exist_ok=True)
    return index_dir / "video_store_hash_index.jsonl"


def _video_store_hash_index_paths() -> List[Path]:
    paths = [_video_store_hash_index_path()]
    for root in _video_store_compatible_roots():
        candidate = root / "indexes" / "video_store_hash_index.jsonl"
        if candidate.exists():
            paths.append(candidate)
    unique: List[Path] = []
    seen: set[str] = set()
    for path in paths:
        try:
            key = os.path.normcase(str(path.resolve()))
        except Exception:
            key = os.path.normcase(str(path))
        if key not in seen:
            seen.add(key)
            unique.append(path)
    return unique


_VIDEO_STORE_DIGEST_RE = re.compile(r"^[0-9a-fA-F]{64}$")


def _video_store_index_candidate_paths(raw_path: str) -> List[Path]:
    """Return current-root candidates for a path recorded in the hash index."""
    text = str(raw_path or "").strip()
    if not text:
        return []
    root = _video_store_root()
    candidates: List[Path] = []
    try:
        candidates.append(Path(text).expanduser())
    except (TypeError, ValueError):
        return []

    parts = list(Path(text).parts)
    lower_parts = [part.lower() for part in parts]
    if "raw_uploads" in lower_parts:
        raw_index = lower_parts.index("raw_uploads")
        tail = parts[raw_index + 1 :]
        if tail:
            for compatible_root in _video_store_compatible_roots():
                candidates.append(compatible_root.joinpath(*tail))

    unique: List[Path] = []
    seen: set[str] = set()
    for candidate in candidates:
        try:
            key = os.path.normcase(str(candidate.resolve()))
        except Exception:
            key = os.path.normcase(str(candidate))
        if key in seen:
            continue
        seen.add(key)
        unique.append(candidate)
    return unique


def _video_store_path_has_alignment_sidecars(path: Path) -> bool:
    parent = path.parent
    return (
        (parent / "frames.csv").exists()
        or (parent / "meta.json").exists()
        or path.with_name(path.name + ".json").exists()
    )


def _video_store_path_preference(path: Path) -> tuple[int, int, int, str]:
    parts = {part.lower() for part in path.parts}
    has_sidecars = _video_store_path_has_alignment_sidecars(path)
    return (
        0 if has_sidecars else 1,
        0 if "by_import" in parts else 1,
        0 if "by_hash" not in parts else 1,
        os.path.normcase(str(path)),
    )


def _lookup_video_store_hash(digest: str) -> Optional[Path]:
    matches: List[Path] = []
    for index_path in _video_store_hash_index_paths():
        if not index_path.exists():
            continue
        try:
            for line in index_path.read_text(encoding="utf-8").splitlines():
                line = line.strip()
                if not line:
                    continue
                try:
                    row = json.loads(line)
                except json.JSONDecodeError:
                    continue
                if row.get("sha256") != digest:
                    continue
                raw_path = row.get("absolute_path") or row.get("path")
                if raw_path:
                    for candidate in _video_store_index_candidate_paths(str(raw_path)):
                        try:
                            path = candidate.resolve()
                        except Exception:
                            path = candidate
                        if path.exists() and path.is_file() and _is_path_under_any_video_store(path):
                            matches.append(path)
        except Exception as exc:
            logger.warning("Failed to read video-store hash index %s: %s", index_path, exc)
    if not matches:
        for compatible_root in _video_store_compatible_roots():
            final_dir = compatible_root / "by_hash" / digest[:2] / digest[2:4] / digest
            if not final_dir.exists():
                continue
            for candidate in sorted(final_dir.glob(f"{digest}.*")):
                if candidate.suffix.lower() == ".json":
                    continue
                try:
                    path = candidate.resolve()
                except Exception:
                    path = candidate
                if path.exists() and path.is_file() and _is_path_under_any_video_store(path):
                    matches.append(path)
    if not matches:
        return None
    matches.sort(key=_video_store_path_preference)
    return matches[0]


def _video_store_digest_from_path(path_value: Optional[str]) -> Optional[str]:
    text = str(path_value or "").strip()
    if not text:
        return None
    try:
        path = Path(text).expanduser()
    except (TypeError, ValueError):
        return None
    for value in (path.stem, path.parent.name, *reversed(path.parts)):
        if _VIDEO_STORE_DIGEST_RE.match(str(value or "")):
            return str(value).lower()
    return None


def _video_store_sidecar_source_path(path_value: Optional[str]) -> Optional[Path]:
    """Resolve a deduplicated by_hash video back to its sidecar-rich library path."""
    text = str(path_value or "").strip()
    if not text:
        return None
    try:
        direct = Path(text).expanduser()
        if direct.exists() and direct.is_file() and _video_store_path_has_alignment_sidecars(direct):
            return direct
    except Exception:
        direct = None
    digest = _video_store_digest_from_path(path_value)
    if not digest:
        return None
    matched = _lookup_video_store_hash(digest)
    if matched is not None and _video_store_path_has_alignment_sidecars(matched):
        return matched
    return None


def _append_video_store_hash_index(row: Dict[str, Any]) -> None:
    index_path = _video_store_hash_index_path()
    index_path.parent.mkdir(parents=True, exist_ok=True)
    payload = {
        "schema_version": "lab_video_store.hash_index.v1",
        "sha256": row.get("sha256"),
        "path": row.get("path"),
        "absolute_path": row.get("absolute_path") or row.get("path"),
        "size_bytes": row.get("size_bytes") or row.get("size"),
        "original_filename": row.get("original_filename"),
        "view_type": row.get("view_type"),
        "experiment_id": row.get("experiment_id"),
        "index_source": row.get("index_source"),
        "registered_via": row.get("registered_via"),
        "indexed_at": _now_iso(),
    }
    try:
        with index_path.open("a", encoding="utf-8") as handle:
            handle.write(json.dumps(payload, ensure_ascii=False, separators=(",", ":")) + "\n")
    except Exception as exc:
        logger.warning("Failed to append video-store hash index %s: %s", index_path, exc)


def _finalize_video_store_upload(
    staging_path: Path,
    *,
    digest: str,
    size: int,
    safe_name: str,
    original_filename: str,
    experiment_id: str,
    view_type: str,
    content_type: Optional[str] = None,
) -> Dict[str, Any]:
    suffix = Path(safe_name).suffix.lower() or ".mp4"
    final_dir = _video_store_hash_root() / digest[:2] / digest[2:4] / digest
    final_dir.mkdir(parents=True, exist_ok=True)
    final_path = final_dir / f"{digest}{suffix}"
    indexed_path = _lookup_video_store_hash(digest)
    if indexed_path is not None:
        final_path = indexed_path
    deduplicated = final_path.exists()
    if deduplicated:
        try:
            staging_path.unlink(missing_ok=True)
        except Exception:
            pass
    else:
        staging_path.replace(final_path)

    payload = {
        "schema_version": VIDEO_STORE_REF_SCHEMA_VERSION,
        "storage_mode": "external_video_store",
        "video_store_root": str(_video_store_root()),
        "path": str(final_path),
        "absolute_path": str(final_path),
        "sha256": digest,
        "size": int(size),
        "size_bytes": int(size),
        "deduplicated": bool(deduplicated),
        "copied": not bool(deduplicated),
        "registered_via": "upload_stream",
        "original_filename": original_filename,
        "safe_filename": safe_name,
        "content_type": content_type,
        "experiment_id": experiment_id,
        "view_type": view_type,
        "stored_at": _now_iso(),
    }
    sidecar_path = final_path.with_name(f"{final_path.name}.json")
    if not sidecar_path.exists():
        try:
            sidecar_path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
        except Exception as exc:
            logger.warning("Failed to write video-store sidecar %s: %s", sidecar_path, exc)
    payload["metadata_path"] = str(sidecar_path)
    _append_video_store_hash_index(payload)
    return payload


async def _save_upload_to_video_store(
    upload: UploadFile,
    *,
    experiment_id: str,
    view_type: str,
    default_name: str,
    max_bytes: int,
) -> Dict[str, Any]:
    original_filename = str(upload.filename or default_name)
    safe_name = _sanitize_upload_filename(original_filename, default_name=default_name)
    staging_path = _video_store_staging_path(safe_name)
    digest = hashlib.sha256()
    total = 0
    try:
        with staging_path.open("wb") as handle:
            while True:
                chunk = await upload.read(_UPLOAD_CHUNK_SIZE)
                if not chunk:
                    break
                total += len(chunk)
                if total > max_bytes:
                    raise HTTPException(status_code=413, detail=f"File too large; max {max_bytes} bytes")
                digest.update(chunk)
                handle.write(chunk)
    except HTTPException:
        try:
            staging_path.unlink(missing_ok=True)
        except Exception:
            pass
        raise
    except Exception as exc:
        try:
            staging_path.unlink(missing_ok=True)
        except Exception:
            pass
        raise HTTPException(status_code=500, detail=f"Failed to save upload to video store: {exc}") from exc
    finally:
        try:
            await upload.close()
        except Exception:
            pass
    return _finalize_video_store_upload(
        staging_path,
        digest=digest.hexdigest(),
        size=total,
        safe_name=safe_name,
        original_filename=original_filename,
        experiment_id=experiment_id,
        view_type=view_type,
        content_type=getattr(upload, "content_type", None),
    )


async def _save_request_stream_to_video_store(
    request: Request,
    *,
    experiment_id: str,
    view_type: str,
    original_filename: str,
    default_name: str,
    max_bytes: int,
) -> Dict[str, Any]:
    content_length = request.headers.get("content-length")
    if content_length:
        try:
            if int(content_length) > max_bytes:
                raise HTTPException(status_code=413, detail=f"File too large; max {max_bytes} bytes")
        except ValueError:
            pass
    safe_name = _sanitize_upload_filename(original_filename, default_name=default_name)
    staging_path = _video_store_staging_path(safe_name)
    digest = hashlib.sha256()
    total = 0
    try:
        with staging_path.open("wb") as handle:
            async for chunk in request.stream():
                if not chunk:
                    continue
                total += len(chunk)
                if total > max_bytes:
                    raise HTTPException(status_code=413, detail=f"File too large; max {max_bytes} bytes")
                digest.update(chunk)
                await asyncio.to_thread(handle.write, chunk)
    except HTTPException:
        try:
            staging_path.unlink(missing_ok=True)
        except Exception:
            pass
        raise
    except Exception as exc:
        try:
            staging_path.unlink(missing_ok=True)
        except Exception:
            pass
        raise HTTPException(status_code=500, detail=f"Failed to save upload to video store: {exc}") from exc
    return _finalize_video_store_upload(
        staging_path,
        digest=digest.hexdigest(),
        size=total,
        safe_name=safe_name,
        original_filename=original_filename,
        experiment_id=experiment_id,
        view_type=view_type,
        content_type=request.headers.get("content-type"),
    )


def _write_video_store_pointer(
    experiment_id: str,
    *,
    view_type: str,
    stored: Dict[str, Any],
    prefix: str,
) -> Path:
    raw_dir = _experiment_output_dir(experiment_id) / "raw"
    raw_dir.mkdir(parents=True, exist_ok=True)
    safe_stem = Path(str(stored.get("safe_filename") or view_type)).stem[:48] or view_type
    pointer_path = raw_dir / f"{prefix}_{str(stored.get('sha256') or '')[:12]}_{safe_stem}.video_ref.json"
    payload = {
        "schema_version": VIDEO_STORE_REF_SCHEMA_VERSION,
        "experiment_id": experiment_id,
        "view_type": view_type,
        "storage_mode": "external_video_store",
        "video_path": stored.get("path"),
        "absolute_path": stored.get("absolute_path") or stored.get("path"),
        "sha256": stored.get("sha256"),
        "size_bytes": stored.get("size_bytes") or stored.get("size"),
        "original_filename": stored.get("original_filename"),
        "safe_filename": stored.get("safe_filename"),
        "deduplicated": stored.get("deduplicated"),
        "copied": stored.get("copied"),
        "registered_via": stored.get("registered_via"),
        "video_store_root": stored.get("video_store_root"),
        "metadata_path": stored.get("metadata_path"),
        "created_at": _now_iso(),
    }
    pointer_path.write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    return pointer_path


def _record_video_store_ref(
    exp: Dict[str, Any],
    *,
    view_type: str,
    stored: Dict[str, Any],
    pointer_path: Optional[Path] = None,
) -> None:
    refs = exp.setdefault("video_store_refs", [])
    row = {
        "view_type": view_type,
        "storage_mode": "external_video_store",
        "video_path": stored.get("path"),
        "absolute_path": stored.get("absolute_path") or stored.get("path"),
        "sha256": stored.get("sha256"),
        "size_bytes": stored.get("size_bytes") or stored.get("size"),
        "original_filename": stored.get("original_filename"),
        "safe_filename": stored.get("safe_filename"),
        "deduplicated": stored.get("deduplicated"),
        "copied": stored.get("copied"),
        "registered_via": stored.get("registered_via"),
        "video_ref_path": str(pointer_path) if pointer_path else None,
        "metadata_path": stored.get("metadata_path"),
        "recorded_at": _now_iso(),
    }
    refs.append(row)


def _safe_video_store_manifest_file(path_value: Optional[str]) -> Optional[Path]:
    text = str(path_value or "").strip()
    if not text:
        return None
    try:
        path = Path(text).expanduser().resolve()
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"Invalid manifest path: {path_value}") from exc
    if not path.exists() or not path.is_file():
        raise HTTPException(status_code=404, detail=f"Video-store manifest not found: {path}")
    if not (_is_path_under(path, PROJECT_ROOT) or _is_path_under_any_video_store(path)):
        raise HTTPException(status_code=400, detail="Manifest path must stay under the project or configured video store")
    return path


def _video_store_register_request_data(request_model: Any) -> Dict[str, Any]:
    if hasattr(request_model, "model_dump"):
        return request_model.model_dump(exclude_none=True)
    if hasattr(request_model, "dict"):
        return request_model.dict(exclude_none=True)
    return dict(request_model or {})


def _extract_video_store_manifest_ref(path_value: Optional[str], *, view_type: str) -> Dict[str, Any]:
    manifest_path = _safe_video_store_manifest_file(path_value)
    if manifest_path is None:
        return {}
    try:
        manifest = json.loads(manifest_path.read_text(encoding="utf-8-sig"))
    except json.JSONDecodeError as exc:
        raise HTTPException(status_code=400, detail=f"Invalid video-store manifest JSON: {manifest_path}") from exc
    if not isinstance(manifest, dict):
        raise HTTPException(status_code=400, detail="Video-store manifest must be a JSON object")
    ref = extract_video_store_ref(manifest, view_type=view_type)
    ref["manifest_path"] = str(manifest_path)
    return ref


def _existing_video_store_ref_from_request(request_model: Any, *, view_type: str) -> Dict[str, Any]:
    data = _video_store_register_request_data(request_model)
    ref: Dict[str, Any] = {}
    inline_manifest = data.get("manifest")
    if isinstance(inline_manifest, dict):
        ref.update({k: v for k, v in extract_video_store_ref(inline_manifest, view_type=view_type).items() if v is not None})
    for manifest_key in ("manifest_path", "video_ref_path"):
        manifest_ref = _extract_video_store_manifest_ref(data.get(manifest_key), view_type=view_type)
        ref.update({k: v for k, v in manifest_ref.items() if v is not None})
    for key in (
        "sha256",
        "path",
        "absolute_path",
        "video_path",
        "size_bytes",
        "size",
        "original_filename",
        "safe_filename",
        "content_type",
        "metadata_path",
        "video_store_root",
    ):
        value = data.get(key)
        if value is not None:
            ref[key] = value
    return ref


def _resolve_existing_video_store_ref(
    request_model: Any,
    *,
    experiment_id: str,
    view_type: str,
) -> Dict[str, Any]:
    ref = _existing_video_store_ref_from_request(request_model, view_type=view_type)
    digest = normalize_sha256(ref.get("sha256")) or _video_store_digest_from_path(
        str(ref.get("absolute_path") or ref.get("video_path") or ref.get("path") or "")
    )
    if not digest:
        raise HTTPException(status_code=400, detail="sha256 or a manifest/path containing a sha256 digest is required")

    indexed_path = _lookup_video_store_hash(digest)
    candidate_path = indexed_path
    raw_path = ref.get("absolute_path") or ref.get("video_path") or ref.get("path")
    if candidate_path is None and raw_path:
        for candidate in _video_store_index_candidate_paths(str(raw_path)):
            try:
                resolved = candidate.resolve()
            except Exception:
                resolved = candidate
            if resolved.exists() and resolved.is_file() and _is_path_under_any_video_store(resolved):
                candidate_path = resolved
                break
    if candidate_path is None:
        raise HTTPException(status_code=404, detail=f"Video with sha256 {digest} is not present in the video store")
    try:
        final_path = candidate_path.resolve()
    except Exception:
        final_path = candidate_path
    if not final_path.exists() or not final_path.is_file() or not _is_path_under_any_video_store(final_path):
        raise HTTPException(status_code=404, detail=f"Video-store file is not available: {candidate_path}")

    actual_size = int(final_path.stat().st_size)
    expected_size = ref.get("size_bytes") or ref.get("size")
    if expected_size is not None:
        try:
            if int(expected_size) != actual_size:
                raise HTTPException(status_code=409, detail="Video-store manifest size does not match the registered file")
        except ValueError:
            pass
    safe_name = _sanitize_upload_filename(
        ref.get("safe_filename") or ref.get("original_filename") or final_path.name,
        default_name=final_path.name,
    )
    payload = {
        "schema_version": VIDEO_STORE_REF_SCHEMA_VERSION,
        "storage_mode": "external_video_store",
        "video_store_root": str(_video_store_root()),
        "path": str(final_path),
        "absolute_path": str(final_path),
        "sha256": digest,
        "size": actual_size,
        "size_bytes": actual_size,
        "deduplicated": True,
        "copied": False,
        "registered_via": "hash_manifest",
        "index_source": "hash_manifest_register",
        "original_filename": ref.get("original_filename") or final_path.name,
        "safe_filename": safe_name,
        "content_type": ref.get("content_type"),
        "experiment_id": experiment_id,
        "view_type": view_type,
        "metadata_path": ref.get("metadata_path") or str(final_path.with_name(f"{final_path.name}.json")),
        "manifest_path": ref.get("manifest_path"),
        "stored_at": _now_iso(),
    }
    _append_video_store_hash_index(payload)
    return payload


def _key_action_upload_context(existing: Any) -> Dict[str, Any]:
    """Carry upload timing and storage references through later analysis state updates."""
    if not isinstance(existing, dict):
        return {}
    keep_keys = (
        "request_received_at",
        "upload_completed_at",
        "upload_mode",
        "upload_save_sec",
        "video_store_ingest_sec",
        "register_elapsed_sec",
        "third_person_upload_save_sec",
        "first_person_upload_save_sec",
        "third_person_video_store_ingest_sec",
        "first_person_video_store_ingest_sec",
        "storage_mode",
        "third_person_video_ref_path",
        "first_person_video_ref_path",
        "third_person_sha256",
        "first_person_sha256",
        "third_person_deduplicated",
        "first_person_deduplicated",
        "timeline_alignment_path",
        "timeline_alignment_status",
    )
    return {key: existing.get(key) for key in keep_keys if existing.get(key) is not None}


_CAPTURE_DATE_PART_RE = re.compile(r"^(20\d{2})[-_]?([01]\d)[-_]?([0-3]\d)$")
_CAPTURE_TIME_PART_RE = re.compile(r"^([0-2]\d)([0-5]\d)([0-5]\d)$")
_CAPTURE_DATETIME_PART_RE = re.compile(
    r"(?<!\d)(20\d{2})[-_]?([01]\d)[-_]?([0-3]\d)[T_\-]?([0-2]\d)([0-5]\d)([0-5]\d)(?!\d)"
)
_IMPORT_TIMESTAMP_DIR_TOKENS = {"latest_continuous_stream", "by_import"}


def _split_capture_path_parts(path_value: Optional[str]) -> List[str]:
    text = str(path_value or "").strip()
    if not text:
        return []
    return [part for part in re.split(r"[\\/]+", text) if part not in {"", ".", ".."}]


def _datetime_from_capture_parts(
    year: str,
    month: str,
    day: str,
    hour: str,
    minute: str,
    second: str,
) -> Optional[datetime]:
    try:
        local_naive = datetime(
            int(year),
            int(month),
            int(day),
            int(hour),
            int(minute),
            int(second),
        )
        return local_naive.astimezone()
    except Exception:
        return None


def _datetime_from_epoch_us(value: Any) -> Optional[datetime]:
    try:
        timestamp_us = int(float(value))
    except (TypeError, ValueError, OverflowError):
        return None
    if timestamp_us <= 0:
        return None
    try:
        return datetime.fromtimestamp(timestamp_us / 1_000_000.0).astimezone()
    except Exception:
        return None


def _infer_key_action_capture_start_from_sidecars(path_value: Optional[str]) -> tuple[Optional[datetime], Optional[str]]:
    """Infer exact RGB capture start from camera export sidecars.

    Camera folders written by the recorder contain frames.csv and meta.json beside
    rgb.mp4.  frames.csv gives the first RGB frame at microsecond precision, which
    is the safest clock anchor before long-stream experiment segmentation.
    """
    text = str(path_value or "").strip()
    if not text:
        return None, None
    video_path = Path(text).expanduser()
    parent = video_path.parent

    frames_path = parent / "frames.csv"
    if frames_path.exists():
        try:
            with frames_path.open("r", encoding="utf-8-sig", errors="replace") as handle:
                header = [part.strip() for part in handle.readline().strip().split(",")]
                columns = {name: index for index, name in enumerate(header) if name}
                stream_idx = columns.get("stream_type")
                for raw_line in handle:
                    values = raw_line.rstrip("\n").split(",")
                    stream_type = values[stream_idx].strip().lower() if stream_idx is not None and stream_idx < len(values) else ""
                    if stream_type and stream_type != "rgb":
                        continue
                    for column in ("local_time_us", "packet_system_timestamp_us", "frame_system_timestamp_us"):
                        idx = columns.get(column)
                        if idx is None or idx >= len(values):
                            continue
                        parsed = _datetime_from_epoch_us(values[idx])
                        if parsed is not None:
                            return parsed, f"frames_csv_first_rgb_{column}"
                    break
        except Exception:
            logger.debug("Failed to infer capture start from frames.csv for %s", path_value, exc_info=True)

    meta_path = parent / "meta.json"
    if meta_path.exists():
        try:
            meta = json.loads(meta_path.read_text(encoding="utf-8-sig"))
            for key in ("rgb_start_us", "segment_start_us"):
                parsed = _datetime_from_epoch_us(meta.get(key))
                if parsed is not None:
                    return parsed, f"meta_json_{key}"
        except Exception:
            logger.debug("Failed to infer capture start from meta.json for %s", path_value, exc_info=True)

    return None, None


def _key_action_frames_csv_path(path_value: Optional[str]) -> Optional[str]:
    text = str(path_value or "").strip()
    if not text:
        return None
    candidate_paths: List[Path] = []
    try:
        candidate_paths.append(Path(text).expanduser())
    except (TypeError, ValueError):
        return None
    sidecar_source = _video_store_sidecar_source_path(path_value)
    if sidecar_source is not None:
        candidate_paths.append(sidecar_source)
    seen: set[str] = set()
    for candidate in candidate_paths:
        try:
            key = os.path.normcase(str(candidate.resolve()))
        except Exception:
            key = os.path.normcase(str(candidate))
        if key in seen:
            continue
        seen.add(key)
        frames_path = candidate.parent / "frames.csv"
        if frames_path.exists():
            return str(frames_path)
    return None


def _parse_capture_date_part(part: str) -> Optional[tuple[str, str, str]]:
    match = _CAPTURE_DATE_PART_RE.match(str(part or "").strip())
    return match.groups() if match else None


def _parse_capture_time_part(part: str) -> Optional[tuple[str, str, str]]:
    match = _CAPTURE_TIME_PART_RE.match(str(part or "").strip())
    if not match:
        return None
    hour, minute, second = match.groups()
    if int(hour) > 23:
        return None
    return hour, minute, second


def _path_datetime_part_is_import_marker(parts: List[str], index: int) -> bool:
    part = parts[index].lower()
    if any(token in part for token in _IMPORT_TIMESTAMP_DIR_TOKENS):
        return True
    parent = parts[index - 1].lower() if index > 0 else ""
    return parent == "by_import"


def _infer_key_action_capture_start_from_path(path_value: Optional[str]) -> tuple[Optional[datetime], Optional[str]]:
    """Infer camera capture start from the path closest to the video file.

    Camera export paths commonly look like:
    windows-dev-01_cam01/2026-05-20/095224/rgb.mp4.  Import folders such as
    by_import/latest_continuous_stream_20260521_115103 are deliberately ignored.
    """
    parts = _split_capture_path_parts(path_value)
    if not parts:
        return None, None

    # Prefer the closest date-directory/time-directory pair immediately above the media file.
    for index in range(max(0, len(parts) - 2), 0, -1):
        time_part = _parse_capture_time_part(parts[index])
        date_part = _parse_capture_date_part(parts[index - 1])
        if not time_part or not date_part:
            continue
        parsed = _datetime_from_capture_parts(*date_part, *time_part)
        if parsed is not None:
            return parsed, "path_date_time_parent_dirs"

    # Fall back to legacy compact timestamp forms, still searching from leaf to root.
    for index in range(len(parts) - 1, -1, -1):
        if _path_datetime_part_is_import_marker(parts, index):
            continue
        match = _CAPTURE_DATETIME_PART_RE.search(parts[index])
        if not match:
            continue
        parsed = _datetime_from_capture_parts(*match.groups())
        if parsed is not None:
            return parsed, "path_compact_datetime"
    return None, None


def _key_action_capture_start_iso(path_value: Optional[str]) -> tuple[Optional[str], Optional[str]]:
    capture_start, source = _infer_key_action_capture_start_from_sidecars(path_value)
    if capture_start is None:
        capture_start, source = _infer_key_action_capture_start_from_path(path_value)
    if capture_start is None:
        sidecar_source = _video_store_sidecar_source_path(path_value)
        if sidecar_source is not None:
            capture_start, source = _infer_key_action_capture_start_from_sidecars(str(sidecar_source))
            if capture_start is None:
                capture_start, source = _infer_key_action_capture_start_from_path(str(sidecar_source))
            if capture_start is not None and source:
                source = f"video_store_{source}"
    return (capture_start.isoformat(), source) if capture_start is not None else (None, None)


def _safe_datetime_delta_sec(start: Optional[datetime], end: Optional[datetime]) -> Optional[float]:
    if start is None or end is None:
        return None
    try:
        seconds = (end - start).total_seconds()
    except TypeError:
        if start.tzinfo is not None:
            start = start.astimezone(timezone.utc).replace(tzinfo=None)
        if end.tzinfo is not None:
            end = end.astimezone(timezone.utc).replace(tzinfo=None)
        seconds = (end - start).total_seconds()
    return round(seconds, 6)


def _key_action_descriptor_for_view(
    exp: Optional[Dict[str, Any]],
    *,
    role: str,
    path_value: Optional[str],
) -> Dict[str, Any]:
    if not isinstance(exp, dict):
        return {}
    descriptors = list(exp.get("video_inputs") or []) + list(exp.get("video_metadata") or [])
    requested_role = str(role or "").strip().lower()
    path_text = str(path_value or "").strip()
    for descriptor in descriptors:
        if not isinstance(descriptor, dict):
            continue
        descriptor_path = str(descriptor.get("video_path") or descriptor.get("source") or "").strip()
        descriptor_role = str(descriptor.get("view_type") or descriptor.get("role") or "").strip().lower()
        if descriptor_role == requested_role:
            return descriptor
        if path_text and descriptor_path:
            try:
                if os.path.normcase(os.path.abspath(path_text)) == os.path.normcase(os.path.abspath(descriptor_path)):
                    return descriptor
            except Exception:
                if path_text == descriptor_path:
                    return descriptor
    return {}


def _key_action_descriptor_duration_sec(descriptor: Dict[str, Any], fallback: Optional[float] = None) -> Optional[float]:
    for value in (descriptor.get("duration_sec"), descriptor.get("capture_duration_sec"), fallback):
        if value is None or value == "":
            continue
        try:
            return round(max(0.0, float(value)), 6)
        except (TypeError, ValueError):
            continue
    return None


def _key_action_capture_anchor_is_metadata(source: Optional[str]) -> bool:
    text = str(source or "").strip().lower()
    if not text:
        return False
    return text.startswith(
        (
            "frames_csv_",
            "meta_json_",
            "video_store_frames_csv_",
            "video_store_meta_json_",
        )
    )


def _parse_key_action_datetime(value: Any) -> Optional[datetime]:
    text = str(value or "").strip()
    if not text:
        return None
    if text.endswith("Z"):
        text = f"{text[:-1]}+00:00"
    try:
        return datetime.fromisoformat(text)
    except Exception:
        return None


def _key_action_common_timeline(
    *,
    third_person_path: Optional[str],
    first_person_path: Optional[str],
    fallback_session_start_time: Optional[str],
    exp: Optional[Dict[str, Any]] = None,
    duration_fallbacks: Optional[Dict[str, Optional[float]]] = None,
) -> Dict[str, Any]:
    duration_fallbacks = duration_fallbacks or {}
    fallback_start = str(
        fallback_session_start_time
        or ((exp.get("key_action_index") or {}).get("session_start_time") if isinstance(exp, dict) and isinstance(exp.get("key_action_index"), dict) else None)
        or (exp.get("created_at") if isinstance(exp, dict) else None)
        or _now_iso()
    )
    fallback_dt = _parse_key_action_datetime(fallback_start)
    views: Dict[str, Dict[str, Any]] = {}
    capture_datetimes: List[datetime] = []
    resolved_datetimes: List[datetime] = []
    metadata_anchor_roles: List[str] = []
    path_anchor_roles: List[str] = []

    for role, path_value in (("first_person", first_person_path), ("third_person", third_person_path)):
        if not path_value:
            continue
        descriptor = _key_action_descriptor_for_view(exp, role=role, path_value=path_value)
        capture_dt, capture_source = _infer_key_action_capture_start_from_sidecars(path_value)
        if capture_dt is None:
            capture_dt, capture_source = _infer_key_action_capture_start_from_path(path_value)
        sidecar_source_path = _video_store_sidecar_source_path(path_value)
        if capture_dt is None and sidecar_source_path is not None:
            capture_dt, capture_source = _infer_key_action_capture_start_from_sidecars(str(sidecar_source_path))
            if capture_dt is None:
                capture_dt, capture_source = _infer_key_action_capture_start_from_path(str(sidecar_source_path))
            if capture_dt is not None and capture_source:
                capture_source = f"video_store_{capture_source}"
        if capture_dt is None:
            stored_capture = descriptor.get("capture_start_time") or descriptor.get("start_time")
            stored_dt = _parse_key_action_datetime(stored_capture)
            if stored_dt is not None and str(descriptor.get("capture_start_status") or "").startswith("inferred_from_"):
                capture_dt = stored_dt
                capture_source = descriptor.get("capture_start_source") or "stored_capture_start_time"
        if capture_dt is not None:
            start_dt = capture_dt
            start_time = capture_dt.isoformat()
            capture_source_text = str(capture_source or "")
            capture_anchor_reliable = _key_action_capture_anchor_is_metadata(capture_source)
            capture_status = (
                "inferred_from_capture_metadata"
                if capture_anchor_reliable
                else "inferred_from_path"
            )
            offset_source = str(capture_source or "capture_start_path")
            capture_datetimes.append(capture_dt)
            if capture_anchor_reliable:
                metadata_anchor_roles.append(role)
            else:
                path_anchor_roles.append(role)
        else:
            start_dt = fallback_dt
            start_time = fallback_start
            capture_status = "missing_fallback_session_start_time"
            offset_source = "fallback_session_start_time"
            capture_anchor_reliable = False
        if start_dt is not None:
            resolved_datetimes.append(start_dt)
        duration_sec = _key_action_descriptor_duration_sec(descriptor, duration_fallbacks.get(role))
        views[role] = {
            "role": role,
            "view_type": role,
            "video_path": str(path_value),
            "start_time": start_time,
            "frames_csv_path": _key_action_frames_csv_path(path_value),
            "capture_start_time": capture_dt.isoformat() if capture_dt is not None else None,
            "capture_start_source": capture_source,
            "capture_start_status": capture_status,
            "capture_anchor_reliable": bool(capture_anchor_reliable),
            "offset_sec": 0.0,
            "offset_source": offset_source,
            "duration_sec": duration_sec,
            "time_basis": "video_pts_sec maps through rgb frames.csv capture timestamp when frames_csv_path is present",
            "alignment_sidecar_video_path": str(sidecar_source_path) if sidecar_source_path is not None else None,
            "_start_dt": start_dt,
            "_capture_dt": capture_dt,
        }

    origin_dt = min(capture_datetimes) if capture_datetimes else (min(resolved_datetimes) if resolved_datetimes else fallback_dt)
    origin_time = origin_dt.isoformat() if origin_dt is not None else fallback_start
    for view in views.values():
        start_delta = _safe_datetime_delta_sec(origin_dt, view.get("_start_dt"))
        view["global_start_sec"] = max(0.0, float(start_delta or 0.0))
        duration_sec = view.get("duration_sec")
        view["global_end_sec"] = (
            round(float(view["global_start_sec"]) + float(duration_sec), 6)
            if duration_sec is not None
            else None
        )

    overlap_start: Optional[float] = None
    overlap_end: Optional[float] = None
    if views and all(view.get("global_end_sec") is not None for view in views.values()):
        overlap_start = max(float(view.get("global_start_sec") or 0.0) for view in views.values())
        overlap_end = min(float(view.get("global_end_sec") or 0.0) for view in views.values())
    overlap_duration = (
        round(max(0.0, float(overlap_end) - float(overlap_start)), 6)
        if overlap_start is not None and overlap_end is not None
        else None
    )

    has_first = "first_person" in views
    has_third = "third_person" in views
    inferred_capture_count = sum(1 for view in views.values() if view.get("_capture_dt") is not None)
    durations = [
        float(view["duration_sec"])
        for view in views.values()
        if view.get("duration_sec") is not None
    ]
    duration_delta = round((max(durations) - min(durations)) if len(durations) >= 2 else 0.0, 6)
    try:
        max_duration_delta = max(
            0.0,
            float(os.environ.get("KEY_ACTION_SHARED_RECORDING_MAX_DURATION_DELTA_SEC", "5.0")),
        )
    except (TypeError, ValueError):
        max_duration_delta = 5.0
    alignment_method = "unknown"
    reliability_reasons: List[str] = []
    if has_first and has_third and inferred_capture_count == 2:
        if len(metadata_anchor_roles) == 2:
            status = "capture_start_common_timeline"
            alignment_method = "capture_metadata_common_timeline"
            reliable = overlap_duration is None or overlap_duration > 0.05
        elif duration_delta > max_duration_delta:
            status = "capture_start_duration_mismatch_unreliable"
            alignment_method = "path_inferred_capture_start_duration_mismatch"
            reliable = False
            reliability_reasons.append(
                f"only_path_or_fallback_capture_start_with_duration_delta_{duration_delta:.3f}s"
            )
        else:
            status = "capture_start_common_timeline"
            alignment_method = "path_inferred_common_timeline"
            reliable = overlap_duration is None or overlap_duration > 0.05
    elif has_first and has_third and inferred_capture_count == 0:
        if duration_delta > max_duration_delta:
            status = "shared_recording_duration_mismatch"
            alignment_method = "fallback_shared_start_duration_mismatch"
            reliable = False
            reliability_reasons.append(
                f"missing_capture_metadata_and_duration_delta_{duration_delta:.3f}s"
            )
        else:
            status = "shared_recording_fallback"
            alignment_method = "fallback_shared_start"
            reliable = True
    else:
        status = "partial_capture_start_fallback"
        alignment_method = "partial_capture_start_fallback"
        reliable = False
        reliability_reasons.append("missing_one_or_more_capture_start_anchors")
    if has_first and has_third and not (overlap_duration is None or overlap_duration > 0.05):
        reliable = False
        reliability_reasons.append("dual_view_common_overlap_empty")

    serializable_views = {
        role: {key: value for key, value in view.items() if not key.startswith("_")}
        for role, view in views.items()
    }
    return {
        "session_start_time": origin_time,
        "session_origin_time": origin_time,
        "session_origin_source": "capture_start_earliest" if capture_datetimes else "fallback_session_start_time",
        "status": status,
        "alignment_status": "shared_recording" if status == "shared_recording_fallback" else status,
        "alignment_method": alignment_method,
        "timeline_alignment_status": status,
        "alignment_reliable_for_dual_view_pairing": bool(reliable),
        "reliability_reasons": reliability_reasons,
        "duration_delta_sec": duration_delta,
        "max_unreliable_duration_delta_sec": max_duration_delta,
        "capture_metadata_anchor_count": len(metadata_anchor_roles),
        "capture_path_anchor_count": len(path_anchor_roles),
        "views": serializable_views,
        "common_overlap_sec": overlap_duration,
        "common_overlap_start_sec": round(overlap_start, 6) if overlap_start is not None else None,
        "common_overlap_end_sec": round(overlap_end, 6) if overlap_end is not None else None,
    }


def _register_key_action_video_source(
    exp: Dict[str, Any],
    path: Path,
    *,
    view_type: str,
    storage_ref: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    exp.setdefault("video_paths", [])
    exp.setdefault("video_metadata", [])
    exp.setdefault("video_inputs", [])
    exp["video_paths"].append(str(path))
    video_index = len(exp["video_inputs"])
    metadata = _probe_video_metadata(path, video_index)
    metadata["view_type"] = view_type
    metadata["role"] = view_type
    metadata["camera_id"] = view_type
    frames_csv_path = _key_action_frames_csv_path(str(path))
    if frames_csv_path:
        metadata["frames_csv_path"] = frames_csv_path
        metadata["time_basis"] = "video_pts_sec maps through rgb frames.csv capture timestamp for dual-view alignment"
    capture_start_time, capture_start_source = _key_action_capture_start_iso(str(path))
    if capture_start_time:
        capture_start_status = (
            "inferred_from_capture_metadata"
            if str(capture_start_source or "").startswith(("frames_csv", "meta_json"))
            else "inferred_from_path"
        )
        metadata.update(
            {
                "start_time": capture_start_time,
                "capture_start_time": capture_start_time,
                "capture_start_source": capture_start_source,
                "capture_start_status": capture_start_status,
                "offset_source": capture_start_source,
                "sync_method": capture_start_source or "capture_start",
                "alignment_status": "explicit",
            }
        )
    else:
        metadata["capture_start_status"] = "missing_fallback_session_start_time"
    if storage_ref:
        metadata.update(
            {
                "storage_mode": "external_video_store",
                "video_store_root": storage_ref.get("video_store_root"),
                "video_ref_path": storage_ref.get("video_ref_path"),
                "sha256": storage_ref.get("sha256"),
                "size_bytes": storage_ref.get("size_bytes") or storage_ref.get("size"),
                "original_filename": storage_ref.get("original_filename"),
                "deduplicated": storage_ref.get("deduplicated"),
            }
        )
    from labsopguard.video_input_schema import VideoInputValidationError, normalize_video_input

    try:
        normalized, _ = normalize_video_input(metadata, index=video_index, strict=True)
    except VideoInputValidationError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    exp["video_metadata"].append(normalized)
    exp["video_inputs"].append(normalized)
    return normalized


def _write_dual_view_upload_alignment(experiment_id: str, exp: Dict[str, Any], *, session_start_time: Optional[str] = None) -> Optional[Dict[str, Any]]:
    third_person_path, first_person_path = _registered_key_action_video_paths(exp)
    if not third_person_path or not first_person_path:
        return None
    timeline = _key_action_common_timeline(
        third_person_path=third_person_path,
        first_person_path=first_person_path,
        fallback_session_start_time=session_start_time,
        exp=exp,
    )
    streams: List[Dict[str, Any]] = []
    source_start_offsets_sec: Dict[str, float] = {}
    for role in ("first_person", "third_person"):
        view = dict((timeline.get("views") or {}).get(role) or {})
        if not view:
            continue
        try:
            source_start_offsets_sec[role] = round(float(view.get("global_start_sec") or 0.0), 6)
        except (TypeError, ValueError):
            source_start_offsets_sec[role] = 0.0
        streams.append(
            {
                **view,
                "alignment_status": timeline["alignment_status"],
                "alignment_method": timeline.get("alignment_method"),
                "alignment_reliable_for_dual_view_pairing": timeline["alignment_reliable_for_dual_view_pairing"],
                "status": timeline["status"],
                "time_basis": "global_sec = global_start_sec + rgb_capture_rel_sec; rgb_capture_rel_sec is derived from frames.csv when available",
                "video_time_mapping": "local_time_sec is video PTS; key-action pipeline converts it through RGB frames.csv before cross-view alignment when frames_csv_path is present",
            }
        )
    payload = {
        "schema_version": "timeline_alignment.v1",
        "experiment_id": experiment_id,
        "method": "dual_view_capture_start_common_timeline"
        if timeline["status"] == "capture_start_common_timeline"
        else "dual_view_upload_shared_start",
        "status": timeline["status"],
        "alignment_status": timeline["alignment_status"],
        "alignment_method": timeline.get("alignment_method"),
        "alignment_reliable_for_dual_view_pairing": timeline["alignment_reliable_for_dual_view_pairing"],
        "reliability_reasons": timeline.get("reliability_reasons") or [],
        "duration_delta_sec": timeline.get("duration_delta_sec"),
        "capture_metadata_anchor_count": timeline.get("capture_metadata_anchor_count"),
        "capture_path_anchor_count": timeline.get("capture_path_anchor_count"),
        "timeline_alignment_status": timeline["timeline_alignment_status"],
        "shared_start_time": timeline["session_origin_time"],
        "session_origin_time": timeline["session_origin_time"],
        "session_origin_source": timeline["session_origin_source"],
        "offsets_sec": {"first_person": 0.0, "third_person": 0.0},
        "source_start_offsets_sec": source_start_offsets_sec,
        "global_start_sec_by_view": source_start_offsets_sec,
        "mapping": {
            "time_axis": "session_sec",
            "session_zero_time": timeline["session_origin_time"],
            "formula": "session_sec = source_start_offsets_sec[view] + capture_rel_sec; capture_rel_sec is mapped from video PTS using frames.csv when available",
        },
        "common_overlap_sec": timeline["common_overlap_sec"],
        "common_overlap_start_sec": timeline["common_overlap_start_sec"],
        "common_overlap_end_sec": timeline["common_overlap_end_sec"],
        "common_overlap": {
            "global_start_sec": timeline["common_overlap_start_sec"],
            "global_end_sec": timeline["common_overlap_end_sec"],
            "duration_sec": timeline["common_overlap_sec"],
        },
        "streams": streams,
        "generated_at": _now_iso(),
    }
    exp_dir = _experiment_output_dir(experiment_id)
    exp_dir.mkdir(parents=True, exist_ok=True)
    (exp_dir / "timeline_alignment.json").write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    metadata_dir = _key_action_output_dir(experiment_id) / "metadata"
    metadata_dir.mkdir(parents=True, exist_ok=True)
    (metadata_dir / "timeline_alignment.json").write_text(json.dumps(payload, ensure_ascii=False, indent=2), encoding="utf-8")
    return payload


def _key_action_analysis_proxy_prewarm_enabled() -> bool:
    return _key_action_truthy(os.environ.get("KEY_ACTION_ANALYSIS_PROXY_PREWARM"), True)


def _key_action_proxy_source(
    *,
    view: str,
    video_path: str,
    session_start_time: Optional[str],
) -> Any:
    from key_action_indexer.schemas import VideoSource  # type: ignore

    path = str(video_path)
    capture_start_time, capture_start_source = _key_action_capture_start_iso(path)
    start_time = capture_start_time or session_start_time or _now_iso()
    frames_csv_path = _key_action_frames_csv_path(path)
    return VideoSource(
        name=view,
        path=path,
        start_time=str(start_time),
        role=view,
        camera_id=_infer_key_action_camera_id(path, view=view),
        frames_csv_path=frames_csv_path,
        capture_start_time=capture_start_time,
        capture_start_source=capture_start_source,
        capture_start_status="inferred_from_capture_metadata" if capture_start_time else "missing_fallback_session_start_time",
        offset_sec=0.0,
    )


def _prewarm_key_action_analysis_proxies(
    experiment_id: str,
    *,
    sources_by_view: Dict[str, str],
    session_start_time: Optional[str] = None,
) -> None:
    """Build low-fps coarse-scan proxies before the heavy YOLO run consumes them."""

    if not sources_by_view or not _key_action_analysis_proxy_prewarm_enabled():
        return
    try:
        from key_action_indexer.analysis_proxy import build_analysis_proxy_for_source  # type: ignore
    except Exception as exc:
        logger.warning("Analysis proxy prewarm unavailable for %s: %s", experiment_id, exc)
        return

    proxy_root = _experiment_output_dir(experiment_id) / "analysis_proxy"
    requested = {
        view: path
        for view, path in sources_by_view.items()
        if view in {"first_person", "third_person"} and path and Path(path).exists()
    }
    if not requested:
        return

    def build(view: str, path: str) -> tuple[str, Dict[str, Any]]:
        source = _key_action_proxy_source(view=view, video_path=path, session_start_time=session_start_time)
        _proxy_source, meta = build_analysis_proxy_for_source(
            source,
            view=view,
            proxy_root=proxy_root,
            enabled=True,
            dry_run=False,
            existing_only=False,
        )
        return view, meta

    started = time.perf_counter()
    results: Dict[str, Dict[str, Any]] = {}
    worker_count = max(1, min(len(requested), _env_int("KEY_ACTION_ANALYSIS_PROXY_PREWARM_WORKERS", len(requested))))
    try:
        if worker_count <= 1:
            for view, path in requested.items():
                view_id, meta = build(view, path)
                results[view_id] = meta
        else:
            with ThreadPoolExecutor(max_workers=worker_count, thread_name_prefix="analysis_proxy_prewarm") as executor:
                futures = [executor.submit(build, view, path) for view, path in requested.items()]
                for future in as_completed(futures):
                    view_id, meta = future.result()
                    results[view_id] = meta
    except Exception as exc:
        logger.warning("Analysis proxy prewarm failed for %s: %s", experiment_id, exc)

    elapsed = round(time.perf_counter() - started, 3)
    if not results:
        return
    exp = _load_json_if_exists(_experiment_output_dir(experiment_id) / "experiment.json") or _EXPERIMENTS.get(experiment_id) or {}
    if not isinstance(exp, dict):
        exp = {"experiment_id": experiment_id}
    key_action_index = dict(exp.get("key_action_index") or {})
    key_action_index.setdefault("analysis_proxy", {})
    for view, meta in results.items():
        key_action_index["analysis_proxy"][view] = {
            "status": meta.get("status"),
            "proxy_used": bool(meta.get("proxy_used")),
            "proxy_path": meta.get("proxy_path"),
            "metadata_path": meta.get("metadata_path"),
            "cache_key": meta.get("cache_key"),
            "settings": meta.get("settings"),
            "size_bytes": meta.get("size_bytes"),
            "prewarm_elapsed_sec": meta.get("wall_sec"),
            "prewarmed_at": _now_iso(),
        }
    key_action_index["analysis_proxy_prewarm_sec"] = elapsed
    key_action_index["analysis_proxy_prewarm_workers"] = worker_count
    exp["experiment_id"] = experiment_id
    exp["key_action_index"] = key_action_index
    _save_experiment(exp)


def _start_key_action_analysis_proxy_prewarm(
    experiment_id: str,
    *,
    sources_by_view: Dict[str, str],
    session_start_time: Optional[str] = None,
) -> bool:
    """Start proxy prewarm without blocking upload/register or formal analysis."""

    if not sources_by_view or not _key_action_analysis_proxy_prewarm_enabled():
        return False
    import threading

    def runner() -> None:
        try:
            _prewarm_key_action_analysis_proxies(
                experiment_id,
                sources_by_view=sources_by_view,
                session_start_time=session_start_time,
            )
        except Exception as exc:
            logger.warning("Analysis proxy prewarm thread failed for %s: %s", experiment_id, exc)

    thread = threading.Thread(
        target=runner,
        name=f"key-action-proxy-prewarm-{experiment_id[:8]}",
        daemon=True,
    )
    thread.start()
    return True


def _is_blocked_callback_ip(addr: ipaddress._BaseAddress) -> bool:
    return any(
        [
            addr.is_private,
            addr.is_loopback,
            addr.is_link_local,
            addr.is_multicast,
            addr.is_reserved,
            addr.is_unspecified,
        ]
    )


def _parse_callback_allowed_hosts() -> List[str]:
    raw = os.environ.get("REALITYLOOP_CALLBACK_ALLOWED_HOSTS", "")
    return [item.strip().lower() for item in raw.split(",") if item.strip()]


def _host_matches_allowed_patterns(host: str, patterns: List[str]) -> bool:
    if not patterns:
        return True
    normalized = host.strip().lower()
    for pattern in patterns:
        if pattern.startswith("*."):
            suffix = pattern[1:]
            if normalized.endswith(suffix) and normalized != pattern[2:]:
                return True
        elif normalized == pattern:
            return True
    return False


def _parse_callback_allowed_cidrs() -> List[ipaddress._BaseNetwork]:
    raw = os.environ.get("REALITYLOOP_CALLBACK_ALLOWED_CIDRS", "")
    cidrs: List[ipaddress._BaseNetwork] = []
    for item in [token.strip() for token in raw.split(",") if token.strip()]:
        try:
            cidrs.append(ipaddress.ip_network(item, strict=False))
        except ValueError as exc:
            raise ValueError(f"invalid callback CIDR: {item}") from exc
    return cidrs


def _ip_in_allowed_cidrs(addr: ipaddress._BaseAddress, cidrs: List[ipaddress._BaseNetwork]) -> bool:
    if not cidrs:
        return False
    return any(addr in network for network in cidrs)


def _validate_callback_url(callback_url: str) -> str:
    value = str(callback_url or "").strip()
    if not value:
        raise ValueError("callback_url is empty")
    if len(value) > 2048:
        raise ValueError("callback_url is too long")
    parsed = urlsplit(value)
    scheme = (parsed.scheme or "").lower()
    allow_http = os.environ.get("REALITYLOOP_CALLBACK_ALLOW_HTTP", "false").lower() in {"1", "true", "yes"}
    allowed_schemes = {"https", "http"} if allow_http else {"https"}
    if scheme not in allowed_schemes:
        raise ValueError(f"callback_url scheme must be one of: {', '.join(sorted(allowed_schemes))}")
    if not parsed.hostname:
        raise ValueError("callback_url hostname is required")
    host = parsed.hostname.strip().lower()
    allowed_hosts = _parse_callback_allowed_hosts()
    if allowed_hosts and not _host_matches_allowed_patterns(host, allowed_hosts):
        raise ValueError("callback_url host is not in allowed host whitelist")
    if host in {"localhost", "localhost.localdomain"}:
        raise ValueError("callback_url host is not allowed")
    allow_private = os.environ.get("REALITYLOOP_CALLBACK_ALLOW_PRIVATE", "false").lower() in {"1", "true", "yes"}
    allowed_cidrs = _parse_callback_allowed_cidrs()
    try:
        direct_ip = ipaddress.ip_address(host)
    except ValueError:
        direct_ip = None
    if direct_ip is not None:
        allowed_by_cidr = _ip_in_allowed_cidrs(direct_ip, allowed_cidrs)
        if allowed_cidrs and not allowed_by_cidr:
            raise ValueError("callback_url IP is not in allowed CIDR whitelist")
        if _is_blocked_callback_ip(direct_ip) and not allow_private and not allowed_by_cidr:
            raise ValueError("callback_url points to a private or local IP")
        return value
    port = parsed.port or (443 if scheme == "https" else 80)
    try:
        resolved = socket.getaddrinfo(host, port, proto=socket.IPPROTO_TCP)
    except Exception as exc:
        raise ValueError(f"callback_url host resolve failed: {exc}") from exc
    if not resolved:
        raise ValueError("callback_url host resolve returned no addresses")
    resolved_addrs: List[ipaddress._BaseAddress] = []
    for item in resolved:
        sockaddr = item[4]
        if not sockaddr:
            continue
        ip_value = sockaddr[0]
        try:
            addr = ipaddress.ip_address(ip_value)
        except ValueError:
            continue
        resolved_addrs.append(addr)
    if not resolved_addrs:
        raise ValueError("callback_url resolve yielded no valid IP addresses")
    if allowed_cidrs and not any(_ip_in_allowed_cidrs(addr, allowed_cidrs) for addr in resolved_addrs):
        raise ValueError("callback_url resolved IPs are not in allowed CIDR whitelist")
    for addr in resolved_addrs:
        allowed_by_cidr = _ip_in_allowed_cidrs(addr, allowed_cidrs)
        if _is_blocked_callback_ip(addr) and not allow_private and not allowed_by_cidr:
            raise ValueError("callback_url resolves to private/local address")
    return value


def _require_operator_context_from_request(request: Request) -> Dict[str, Any]:
    return _require_operator_context(
        authorization=request.headers.get("Authorization"),
        x_operator=request.headers.get("X-Operator"),
        x_operator_role=request.headers.get("X-Operator-Role"),
        x_allowed_experiments=request.headers.get("X-Allowed-Experiments"),
        x_actor_scope=request.headers.get("X-Actor-Scope"),
    )


@asynccontextmanager
async def app_lifespan(_: FastAPI):
    outputs_dir = PROJECT_ROOT / "outputs"
    outputs_dir.mkdir(parents=True, exist_ok=True)
    auth_refresh_task = None
    if os.environ.get("REALITYLOOP_AUTH_CACHE_REFRESH_ENABLED", "true").lower() not in {"0", "false", "no"}:
        auth_refresh_task = asyncio.create_task(_auth_cache_refresh_loop())
    rules_path = CONFIG_PATH / "sop" / "rules.yaml"
    if not rules_path.exists():
        logger.warning(f"SOP? {rules_path}")
    model_cfg = CONFIG_PATH / "model" / "detection_runtime.yaml"
    if not model_cfg.exists():
        logger.warning(f"? {model_cfg}")
    _recover_orphaned_tasks()
    try:
        yield
    finally:
        if auth_refresh_task is not None:
            auth_refresh_task.cancel()


def _recover_orphaned_tasks() -> None:
    """On startup, mark any tasks that are still 'running' or 'queued' as failed.

    These are tasks that were in-flight when the server last stopped.  Without
    this, the frontend shows a permanent spinner and the experiment can never be
    re-processed.
    """
    task_dir = PROJECT_ROOT / "outputs" / "experiments" / "tasks"
    exp_dir = PROJECT_ROOT / "outputs" / "experiments"
    recovered = 0
    if task_dir.exists():
        for task_file in task_dir.glob("*.json"):
            try:
                task = json.loads(task_file.read_text(encoding="utf-8-sig"))
                if task.get("status") in {"running", "queued"}:
                    task["status"] = "failed"
                    task["error_type"] = "server_restart"
                    task["error_message"] = "Task was interrupted by server restart. Re-run analysis to continue."
                    task_file.write_text(json.dumps(task, ensure_ascii=False, indent=2), encoding="utf-8")
                    # Also patch the experiment.json so the UI reflects the failure immediately
                    eid = task.get("experiment_id")
                    if eid:
                        exp_file = exp_dir / eid / "experiment.json"
                        if exp_file.exists():
                            exp = json.loads(exp_file.read_text(encoding="utf-8"))
                            if exp.get("status") in {"running", "analyzing", "queued"}:
                                exp["status"] = "failed"
                                exp["processing_stage"] = "failed"
                                exp["processing_error"] = "Task interrupted by server restart. Click 'Run analysis' to retry."
                                exp_file.write_text(json.dumps(exp, ensure_ascii=False, indent=2), encoding="utf-8")
                    recovered += 1
            except Exception as exc:
                logger.warning("Failed to recover orphaned task file %s: %s", task_file, exc)
    if recovered:
        logger.info("Recovered %d orphaned task(s) to failed state on startup", recovered)

