def _split_csv_filter(value: Optional[str]) -> Optional[List[str]]:
    if not value:
        return None
    parts = [part.strip() for part in str(value).split(",") if part.strip()]
    return parts or None


def _b64url_decode(value: str) -> bytes:
    return base64.urlsafe_b64decode((value + "=" * (-len(value) % 4)).encode("ascii"))


_OIDC_DISCOVERY_CACHE: Dict[str, Dict[str, Any]] = {}
_JWKS_CACHE: Dict[str, Dict[str, Any]] = {}


def _auth_cache_dir() -> Path:
    raw = os.environ.get("REALITYLOOP_AUTH_CACHE_DIR")
    path = Path(raw) if raw else PROJECT_ROOT / "outputs" / "auth_cache"
    path.mkdir(parents=True, exist_ok=True)
    return path


def _auth_cache_path(prefix: str, key: str) -> Path:
    digest = hashlib.sha1(key.encode("utf-8")).hexdigest()[:24]
    return _auth_cache_dir() / f"{prefix}_{digest}.json"


def _read_auth_disk_cache(prefix: str, key: str) -> Optional[Dict[str, Any]]:
    path = _auth_cache_path(prefix, key)
    if not path.exists():
        return None
    try:
        cached = json.loads(path.read_text(encoding="utf-8"))
    except Exception:
        return None
    if float(cached.get("expires_at") or 0) <= time.time():
        return None
    payload = cached.get("payload")
    return payload if isinstance(payload, dict) else None


def _auth_redis_key(prefix: str, key: str) -> str:
    digest = hashlib.sha1(key.encode("utf-8")).hexdigest()[:24]
    return f"realityloop:auth_cache:{prefix}:{digest}"


def _read_auth_shared_cache(prefix: str, key: str) -> Optional[Dict[str, Any]]:
    if not globals().get("_USE_REDIS") or globals().get("redis_client") is None:
        return None
    try:
        raw = redis_client.get(_auth_redis_key(prefix, key))
        if not raw:
            return None
        cached = json.loads(raw)
        payload = cached.get("payload")
        return payload if isinstance(payload, dict) else None
    except Exception:
        return None


def _write_auth_shared_cache(prefix: str, key: str, payload: Dict[str, Any], ttl_sec: int = 3600) -> None:
    if not globals().get("_USE_REDIS") or globals().get("redis_client") is None:
        return
    try:
        redis_client.setex(
            _auth_redis_key(prefix, key),
            ttl_sec,
            json.dumps(
                {
                    "schema_version": "auth_distributed_cache.v1",
                    "cache_key": key,
                    "payload": payload,
                },
                ensure_ascii=False,
            ),
        )
    except Exception:
        return


def _write_auth_disk_cache(prefix: str, key: str, payload: Dict[str, Any], ttl_sec: int = 3600) -> None:
    path = _auth_cache_path(prefix, key)
    cache_payload = {
        "schema_version": "auth_discovery_cache.v1",
        "cache_key": key,
        "cache_prefix": prefix,
        "key_hash": hashlib.sha1(key.encode("utf-8")).hexdigest()[:24],
        "expires_at": time.time() + ttl_sec,
        "payload": payload,
    }
    path.write_text(json.dumps(cache_payload, ensure_ascii=False, indent=2), encoding="utf-8")


def _b64url_uint(value: str) -> int:
    return int.from_bytes(_b64url_decode(value), "big")


def _oidc_discovery(issuer_url: str) -> Dict[str, Any]:
    issuer = issuer_url.rstrip("/")
    cached = _OIDC_DISCOVERY_CACHE.get(issuer)
    if cached and cached.get("expires_at", 0) > time.time():
        return cached["payload"]
    shared_cached = _read_auth_shared_cache("oidc", issuer)
    if shared_cached:
        _OIDC_DISCOVERY_CACHE[issuer] = {"payload": shared_cached, "expires_at": time.time() + 3600}
        _write_auth_disk_cache("oidc", issuer, shared_cached)
        return shared_cached
    disk_cached = _read_auth_disk_cache("oidc", issuer)
    if disk_cached:
        _OIDC_DISCOVERY_CACHE[issuer] = {"payload": disk_cached, "expires_at": time.time() + 3600}
        _write_auth_shared_cache("oidc", issuer, disk_cached)
        return disk_cached
    url = f"{issuer}/.well-known/openid-configuration"
    try:
        response = requests.get(url, timeout=5)
        response.raise_for_status()
        payload = response.json()
    except Exception as exc:
        raise HTTPException(status_code=401, detail=f"OIDC discovery failed: {exc}") from exc
    _OIDC_DISCOVERY_CACHE[issuer] = {"payload": payload, "expires_at": time.time() + 3600}
    _write_auth_shared_cache("oidc", issuer, payload)
    _write_auth_disk_cache("oidc", issuer, payload)
    return payload


def _jwks_payload() -> Dict[str, Any]:
    jwks_url = os.environ.get("REALITYLOOP_JWKS_URL")
    issuer = os.environ.get("REALITYLOOP_OAUTH_ISSUER_URL") or os.environ.get("REALITYLOOP_JWT_ISSUER")
    if not jwks_url and issuer:
        jwks_url = _oidc_discovery(issuer).get("jwks_uri")
    if not jwks_url:
        raise HTTPException(status_code=401, detail="JWKS URL or OAuth issuer is not configured")
    cached = _JWKS_CACHE.get(jwks_url)
    if cached and cached.get("expires_at", 0) > time.time():
        return cached["payload"]
    shared_cached = _read_auth_shared_cache("jwks", jwks_url)
    if shared_cached:
        _JWKS_CACHE[jwks_url] = {"payload": shared_cached, "expires_at": time.time() + 3600}
        _write_auth_disk_cache("jwks", jwks_url, shared_cached)
        return shared_cached
    disk_cached = _read_auth_disk_cache("jwks", jwks_url)
    if disk_cached:
        _JWKS_CACHE[jwks_url] = {"payload": disk_cached, "expires_at": time.time() + 3600}
        _write_auth_shared_cache("jwks", jwks_url, disk_cached)
        return disk_cached
    try:
        response = requests.get(jwks_url, timeout=5)
        response.raise_for_status()
        payload = response.json()
    except Exception as exc:
        raise HTTPException(status_code=401, detail=f"JWKS fetch failed: {exc}") from exc
    _JWKS_CACHE[jwks_url] = {"payload": payload, "expires_at": time.time() + 3600}
    _write_auth_shared_cache("jwks", jwks_url, payload)
    _write_auth_disk_cache("jwks", jwks_url, payload)
    return payload


def _public_key_from_x5c(jwk: Dict[str, Any]):
    try:
        from cryptography import x509
        from cryptography.hazmat.primitives.asymmetric import padding, rsa
        from cryptography.hazmat.primitives import hashes
    except Exception as exc:
        raise HTTPException(status_code=401, detail="cryptography is required for x5c JWT verification") from exc
    chain_values = jwk.get("x5c") or []
    if not chain_values:
        return None
    try:
        certs = [x509.load_der_x509_certificate(base64.b64decode(value)) for value in chain_values]
    except Exception as exc:
        raise HTTPException(status_code=401, detail="Invalid x5c certificate chain") from exc
    now = datetime.now(timezone.utc)
    for cert in certs:
        not_before = getattr(cert, "not_valid_before_utc", None) or cert.not_valid_before.replace(tzinfo=timezone.utc)
        not_after = getattr(cert, "not_valid_after_utc", None) or cert.not_valid_after.replace(tzinfo=timezone.utc)
        if now < not_before or now > not_after:
            raise HTTPException(status_code=401, detail="x5c certificate is not currently valid")
    for idx in range(len(certs) - 1):
        child = certs[idx]
        issuer = certs[idx + 1]
        issuer_public_key = issuer.public_key()
        if not isinstance(issuer_public_key, rsa.RSAPublicKey):
            raise HTTPException(status_code=401, detail="x5c issuer key is not RSA")
        try:
            issuer_public_key.verify(
                child.signature,
                child.tbs_certificate_bytes,
                padding.PKCS1v15(),
                child.signature_hash_algorithm,
            )
        except Exception as exc:
            raise HTTPException(status_code=401, detail="Invalid x5c certificate chain signature") from exc
    trusted_fingerprints = [
        item.replace(":", "").lower()
        for item in (os.environ.get("REALITYLOOP_JWKS_X5C_TRUSTED_FINGERPRINTS") or "").split(",")
        if item.strip()
    ]
    if trusted_fingerprints:
        root_fp = certs[-1].fingerprint(hashes.SHA256()).hex().lower()
        if root_fp not in trusted_fingerprints:
            raise HTTPException(status_code=401, detail="x5c root fingerprint is not trusted")
    elif os.environ.get("REALITYLOOP_JWKS_X5C_SYSTEM_TRUST", "true").lower() not in {"0", "false", "no"}:
        _verify_x5c_against_system_trust(certs)
    public_key = certs[0].public_key()
    if not isinstance(public_key, rsa.RSAPublicKey):
        raise HTTPException(status_code=401, detail="x5c leaf key is not RSA")
    return public_key


def _load_system_ca_certificates() -> List[Any]:
    try:
        from cryptography import x509
    except Exception as exc:
        raise HTTPException(status_code=401, detail="cryptography is required for system CA verification") from exc
    candidates: List[Path] = []
    verify_paths = ssl.get_default_verify_paths()
    for value in (verify_paths.cafile, os.environ.get("REQUESTS_CA_BUNDLE"), os.environ.get("SSL_CERT_FILE")):
        if value:
            candidates.append(Path(value))
    try:
        import certifi

        candidates.append(Path(certifi.where()))
    except Exception:
        pass
    certs = []
    seen: set[str] = set()
    for path in candidates:
        if not path.exists() or str(path) in seen:
            continue
        seen.add(str(path))
        try:
            pem_data = path.read_bytes()
        except Exception:
            continue
        for block in pem_data.split(b"-----END CERTIFICATE-----"):
            if b"-----BEGIN CERTIFICATE-----" not in block:
                continue
            try:
                certs.append(x509.load_pem_x509_certificate(block + b"-----END CERTIFICATE-----\n"))
            except Exception:
                continue
    return certs


def _verify_x5c_against_system_trust(certs: List[Any]) -> None:
    try:
        from cryptography.hazmat.primitives.asymmetric import padding, rsa
    except Exception as exc:
        raise HTTPException(status_code=401, detail="cryptography is required for system CA verification") from exc
    if not certs:
        raise HTTPException(status_code=401, detail="x5c certificate chain is empty")
    candidate = certs[-1]
    trust_anchors = _load_system_ca_certificates()
    for anchor in trust_anchors:
        if anchor.subject != candidate.issuer:
            continue
        public_key = anchor.public_key()
        if not isinstance(public_key, rsa.RSAPublicKey):
            continue
        try:
            public_key.verify(
                candidate.signature,
                candidate.tbs_certificate_bytes,
                padding.PKCS1v15(),
                candidate.signature_hash_algorithm,
            )
            return
        except Exception:
            continue
    raise HTTPException(status_code=401, detail="x5c chain is not anchored in system CA trust store")


def _refresh_auth_cache_entry(path: Path) -> None:
    try:
        cached = json.loads(path.read_text(encoding="utf-8"))
        prefix = cached.get("cache_prefix")
        key = cached.get("cache_key")
    except Exception:
        return
    if prefix not in {"oidc", "jwks"} or not key:
        return
    try:
        if prefix == "oidc":
            response = requests.get(f"{str(key).rstrip('/')}/.well-known/openid-configuration", timeout=5)
        else:
            response = requests.get(str(key), timeout=5)
        response.raise_for_status()
        payload = response.json()
    except Exception:
        return
    if prefix == "oidc":
        _OIDC_DISCOVERY_CACHE[str(key).rstrip("/")] = {"payload": payload, "expires_at": time.time() + 3600}
    else:
        _JWKS_CACHE[str(key)] = {"payload": payload, "expires_at": time.time() + 3600}
    _write_auth_shared_cache(prefix, str(key), payload)
    _write_auth_disk_cache(prefix, str(key), payload)


async def _auth_cache_refresh_loop() -> None:
    interval = max(60, int(os.environ.get("REALITYLOOP_AUTH_CACHE_REFRESH_INTERVAL_SEC", "900")))
    while True:
        try:
            for path in _auth_cache_dir().glob("*.json"):
                try:
                    cached = json.loads(path.read_text(encoding="utf-8"))
                    expires_at = float(cached.get("expires_at") or 0)
                except Exception:
                    continue
                if expires_at - time.time() <= interval:
                    await asyncio.to_thread(_refresh_auth_cache_entry, path)
        except asyncio.CancelledError:
            raise
        except Exception:
            logger.exception("Auth cache background refresh failed")
        await asyncio.sleep(interval)


def _verify_rs256_jwt(header: Dict[str, Any], parts: List[str]) -> None:
    try:
        from cryptography.hazmat.primitives import hashes
        from cryptography.hazmat.primitives.asymmetric import padding, rsa
    except Exception as exc:
        raise HTTPException(status_code=401, detail="cryptography is required for RS256 JWT verification") from exc
    kid = header.get("kid")
    keys = _jwks_payload().get("keys") or []
    jwk = next((key for key in keys if (not kid or key.get("kid") == kid) and key.get("kty") == "RSA"), None)
    if not jwk:
        raise HTTPException(status_code=401, detail="JWT signing key not found in JWKS")
    try:
        if jwk.get("x5c"):
            public_key = _public_key_from_x5c(jwk)
        else:
            public_key = rsa.RSAPublicNumbers(_b64url_uint(jwk["e"]), _b64url_uint(jwk["n"])).public_key()
        public_key.verify(
            _b64url_decode(parts[2]),
            f"{parts[0]}.{parts[1]}".encode("ascii"),
            padding.PKCS1v15(),
            hashes.SHA256(),
        )
    except Exception as exc:
        raise HTTPException(status_code=401, detail="Invalid RS256 JWT signature") from exc


def _jwt_claims_from_authorization(authorization: Optional[str]) -> Optional[Dict[str, Any]]:
    if not authorization:
        return None
    scheme, _, token = authorization.partition(" ")
    if scheme.lower() != "bearer" or not token:
        raise HTTPException(status_code=401, detail="Authorization must be a Bearer token")
    parts = token.split(".")
    if len(parts) != 3:
        raise HTTPException(status_code=401, detail="Malformed JWT")
    try:
        header = json.loads(_b64url_decode(parts[0]).decode("utf-8"))
        claims = json.loads(_b64url_decode(parts[1]).decode("utf-8"))
    except Exception as exc:
        raise HTTPException(status_code=401, detail="Malformed JWT payload") from exc
    alg = str(header.get("alg") or "")
    if alg not in {"HS256", "RS256"}:
        raise HTTPException(status_code=401, detail="Unsupported JWT algorithm")
    if alg == "HS256":
        secret = os.environ.get("REALITYLOOP_JWT_SECRET") or os.environ.get("JWT_SECRET")
        if not secret:
            raise HTTPException(status_code=401, detail="JWT secret is not configured")
        signing_input = f"{parts[0]}.{parts[1]}".encode("ascii")
        expected = hmac.new(secret.encode("utf-8"), signing_input, hashlib.sha256).digest()
        try:
            signature = _b64url_decode(parts[2])
        except Exception as exc:
            raise HTTPException(status_code=401, detail="Malformed JWT signature") from exc
        if not hmac.compare_digest(signature, expected):
            raise HTTPException(status_code=401, detail="Invalid JWT signature")
    else:
        _verify_rs256_jwt(header, parts)
    now = int(time.time())
    if claims.get("exp") is not None and int(claims["exp"]) < now:
        raise HTTPException(status_code=401, detail="JWT expired")
    expected_issuer = os.environ.get("REALITYLOOP_JWT_ISSUER")
    if expected_issuer and claims.get("iss") != expected_issuer:
        raise HTTPException(status_code=401, detail="Invalid JWT issuer")
    expected_audience = os.environ.get("REALITYLOOP_JWT_AUDIENCE")
    if expected_audience:
        aud = claims.get("aud")
        audiences = aud if isinstance(aud, list) else [aud]
        if expected_audience not in audiences:
            raise HTTPException(status_code=401, detail="Invalid JWT audience")
    return claims


def _claims_list(value: Any) -> List[str]:
    if isinstance(value, list):
        return [str(item) for item in value if str(item)]
    if isinstance(value, str):
        return _split_csv_filter(value) or []
    return []


def _oauth_scope_context(scope: Any) -> Dict[str, Any]:
    result: Dict[str, Any] = {}
    tokens = str(scope or "").split()
    experiments: List[str] = []
    for token in tokens:
        if token.startswith("role:"):
            result["operator_role"] = token.split(":", 1)[1]
        elif token.startswith("experiment:"):
            experiments.append(token.split(":", 1)[1])
        elif token.startswith("actor:"):
            result["actor_scope"] = token.split(":", 1)[1]
    if experiments:
        result["allowed_experiment_ids"] = experiments
    return result


def _auth_context_from_headers(
    *,
    authorization: Optional[str] = None,
    x_operator: Optional[str],
    x_operator_role: Optional[str],
    x_allowed_experiments: Optional[str],
    x_actor_scope: Optional[str],
) -> Dict[str, Any]:
    claims = _jwt_claims_from_authorization(authorization)
    if claims is not None:
        scoped = _oauth_scope_context(claims.get("scope") or claims.get("scp"))
        role = str(
            claims.get("operator_role")
            or claims.get("role")
            or scoped.get("operator_role")
            or "reviewer"
        ).strip().lower()
        if role not in {"reviewer", "approver", "admin", "system"}:
            role = "reviewer"
        allowed = (
            _claims_list(claims.get("allowed_experiment_ids"))
            or _claims_list(claims.get("allowed_experiments"))
            or scoped.get("allowed_experiment_ids")
            or []
        )
        return {
            "operator": claims.get("operator") or claims.get("preferred_username") or claims.get("sub") or "jwt_user",
            "operator_role": role,
            "allowed_experiment_ids": allowed,
            "actor_scope": claims.get("actor_scope") or scoped.get("actor_scope"),
            "auth_source": "jwt",
            "jwt_subject": claims.get("sub"),
        }
    role = (x_operator_role or "reviewer").strip().lower()
    if role not in {"reviewer", "approver", "admin", "system"}:
        role = "reviewer"
    return {
        "operator": x_operator or "anonymous",
        "operator_role": role,
        "allowed_experiment_ids": _split_csv_filter(x_allowed_experiments) or [],
        "actor_scope": x_actor_scope or None,
        "auth_source": "headers" if any([x_operator, x_operator_role, x_allowed_experiments, x_actor_scope]) else "anonymous_default",
    }


def _auth_required_enabled() -> bool:
    return str(os.environ.get("REALITYLOOP_AUTH_REQUIRED", "false")).strip().lower() in {"1", "true", "yes", "on"}


def _require_operator_context(
    x_operator: Optional[str] = Header(None, alias="X-Operator"),
    x_operator_role: Optional[str] = Header(None, alias="X-Operator-Role"),
    x_allowed_experiments: Optional[str] = Header(None, alias="X-Allowed-Experiments"),
    x_actor_scope: Optional[str] = Header(None, alias="X-Actor-Scope"),
    authorization: Optional[str] = Header(None, alias="Authorization"),
) -> Dict[str, Any]:
    auth_ctx = _auth_context_from_headers(
        authorization=authorization,
        x_operator=x_operator,
        x_operator_role=x_operator_role,
        x_allowed_experiments=x_allowed_experiments,
        x_actor_scope=x_actor_scope,
    )
    if _auth_required_enabled() and auth_ctx.get("auth_source") == "anonymous_default":
        raise HTTPException(status_code=401, detail="Authentication required")
    return auth_ctx


def _enforce_experiment_scope(auth_ctx: Dict[str, Any], experiment_id: str) -> str:
    safe_experiment_id = _validate_experiment_id(experiment_id)
    operator_role = str(auth_ctx.get("operator_role") or "").strip().lower()
    if operator_role in {"admin", "system"}:
        return safe_experiment_id
    allowed = {str(item).strip() for item in (auth_ctx.get("allowed_experiment_ids") or []) if str(item).strip()}
    if "*" in allowed:
        return safe_experiment_id
    if allowed and safe_experiment_id not in allowed:
        raise HTTPException(status_code=403, detail="Operator is not allowed to access this experiment")
    return safe_experiment_id


def _scope_filter_experiments(auth_ctx: Dict[str, Any], experiments: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    operator_role = str(auth_ctx.get("operator_role") or "").strip().lower()
    if operator_role in {"admin", "system"}:
        return experiments
    allowed = {str(item).strip() for item in (auth_ctx.get("allowed_experiment_ids") or []) if str(item).strip()}
    if not allowed or "*" in allowed:
        return experiments
    return [item for item in experiments if str(item.get("experiment_id") or "") in allowed]


def _ensure_material_index(experiment_id: str, artifacts: Dict[str, Optional[Path]]) -> Path:
    index_path = artifacts["material_index"]
    material_stream_path = artifacts["material_stream_json"]
    preprocessing_path = artifacts["preprocessing_json"]
    if index_path is None:
        raise HTTPException(status_code=404, detail="Material index path is unavailable")

    # Rebuild when: index file is missing; index is stale vs. material_stream.json /
    # preprocessing.json / materials/events; or index is empty. This guarantees the
    # search endpoint reflects the latest EventPreprocessingEngine run.
    def _needs_rebuild() -> bool:
        if not index_path.exists():
            return True
        try:
            index_mtime = index_path.stat().st_mtime
        except OSError:
            return True
        for candidate in (material_stream_path, preprocessing_path):
            if candidate is not None and candidate.exists():
                try:
                    if candidate.stat().st_mtime > index_mtime + 0.5:
                        return True
                except OSError:
                    pass
        events_dir = index_path.parent / "materials" / "events"
        if events_dir.exists():
            try:
                latest = max((child.stat().st_mtime for child in events_dir.iterdir()), default=0.0)
                if latest > index_mtime + 0.5:
                    return True
            except OSError:
                pass
        try:
            import sqlite3
            conn = sqlite3.connect(str(index_path))
            try:
                cur = conn.execute("SELECT COUNT(*) FROM material_items")
                if int(cur.fetchone()[0] or 0) == 0:
                    return True
            finally:
                conn.close()
        except Exception:
            return True
        return False

    if not _needs_rebuild():
        return index_path
    if material_stream_path is None or not material_stream_path.exists():
        if index_path.exists():
            return index_path
        raise HTTPException(status_code=404, detail="Material stream is not ready")

    from labsopguard.retrieval import MaterialRetrievalIndex

    material_stream = _load_json_if_exists(material_stream_path) or []
    preprocessing = _load_json_if_exists(preprocessing_path) if preprocessing_path is not None else None
    index = MaterialRetrievalIndex(index_path)
    try:
        index.reset()
        index.index_payloads(material_stream, preprocessing=preprocessing or {}, experiment_id=experiment_id)
    finally:
        index.close()
    return index_path


def _ensure_key_material_references(experiment_id: str, exp: Dict[str, Any], artifacts: Dict[str, Optional[Path]]) -> Path:
    output_dir = _experiment_output_dir(experiment_id)
    refs_path = artifacts.get("key_material_references_jsonl") or (_experiment_output_dir(experiment_id) / "artifacts" / "key_material_references.jsonl")
    published_refs_path = output_dir / "material_references" / "key_material_references.jsonl"
    if published_refs_path.exists() and published_refs_path.stat().st_size > 0:
        published_rows = _read_jsonl_rows(published_refs_path)
        if any(
            row.get("formal_material_reference")
            or row.get("dual_event_id")
            or row.get("dual_view_action_event_id")
            or (
                isinstance(row.get("evidence_chain"), dict)
                and (row["evidence_chain"].get("dual_event_id") or row["evidence_chain"].get("dual_view_action_event_id"))
            )
            for row in published_rows
        ):
            refs_path.parent.mkdir(parents=True, exist_ok=True)
            shutil.copyfile(published_refs_path, refs_path)
            published_sqlite = published_refs_path.with_suffix(".sqlite")
            sqlite_path = artifacts.get("key_material_references_sqlite") or (output_dir / "artifacts" / "key_material_references.sqlite")
            if published_sqlite.exists() and published_sqlite.stat().st_size > 0:
                sqlite_path.parent.mkdir(parents=True, exist_ok=True)
                shutil.copyfile(published_sqlite, sqlite_path)
            manifest_path = artifacts.get("key_material_reference_manifest_json") or (output_dir / "artifacts" / "key_material_reference_manifest.json")
            _write_json(
                manifest_path,
                {
                    "schema_version": "key_material_reference_manifest.v1",
                    "experiment_id": experiment_id,
                    "created_at": _now_iso(),
                    "reference_count": len(published_rows),
                    "source": "published_formal_material_references",
                    "paths": {
                        "key_material_references": str(refs_path),
                        "key_material_references_sqlite": str(sqlite_path),
                        "published_key_material_references": str(published_refs_path),
                    },
                },
            )
            return refs_path
    if refs_path.exists() and refs_path.stat().st_size > 0:
        return refs_path
    material_stream = _load_json_if_exists(artifacts.get("material_stream_json")) if artifacts.get("material_stream_json") else []
    preprocessing = _load_json_if_exists(artifacts.get("preprocessing_json")) if artifacts.get("preprocessing_json") else {}
    steps = _load_json_if_exists(artifacts.get("steps_json")) if artifacts.get("steps_json") else []
    segmentation = _load_json_if_exists(output_dir / "artifacts" / "experiment_segmentation.json") or {}
    if material_stream is None:
        material_stream = []
    if preprocessing is None:
        preprocessing = {}
    from labsopguard.key_material_reference import write_experiment_reference_outputs

    write_experiment_reference_outputs(
        experiment_dir=output_dir,
        experiment_record=exp,
        material_stream=material_stream,
        preprocessing=preprocessing,
        steps=steps or [],
        segmentation=segmentation,
        formal_library_root=_formal_material_library_root(),
    )
    return refs_path


def _workspace_material_index_path() -> Path:
    path = PROJECT_ROOT / "outputs" / "materials" / "material_index.sqlite"
    path.parent.mkdir(parents=True, exist_ok=True)
    return path


def _workspace_published_materials_index_path() -> Path:
    path = PROJECT_ROOT / "outputs" / "materials" / "published_materials_index.sqlite"
    path.parent.mkdir(parents=True, exist_ok=True)
    return path


def _safe_project_path(path_value: Optional[str], default_path: Path) -> Path:
    if not path_value:
        return default_path
    candidate = Path(path_value)
    if not candidate.is_absolute():
        candidate = PROJECT_ROOT / candidate
    resolved = candidate.resolve()
    if PROJECT_ROOT.resolve() not in resolved.parents and resolved != PROJECT_ROOT.resolve():
        raise HTTPException(status_code=400, detail="Path must stay inside project root")
    return resolved


_MATERIAL_LONG_CLIP_THRESHOLD_SEC = 30.0
_PLAYABLE_CLIP_SUFFIXES = {".mp4", ".webm", ".mov", ".m4v"}


def _read_jsonl_rows(path: Path) -> List[Dict[str, Any]]:
    if not path.exists():
        return []
    rows: List[Dict[str, Any]] = []
    for line in path.read_text(encoding="utf-8").splitlines():
        line = line.strip()
        if not line:
            continue
        try:
            row = json.loads(line)
        except json.JSONDecodeError:
            continue
        if isinstance(row, dict):
            rows.append(row)
    return rows


def _key_action_row_time_sec(row: Dict[str, Any]) -> Optional[float]:
    for key in ("alignment_time_sec", "session_time_sec", "local_time_sec", "time_sec"):
        try:
            value = row.get(key)
            if value is not None:
                return float(value)
        except (TypeError, ValueError):
            continue
    return None


def _key_action_row_view(row: Dict[str, Any]) -> str:
    return str(row.get("source_view") or row.get("view") or "").strip()


def _key_action_row_interaction_count(row: Dict[str, Any]) -> int:
    interactions = row.get("hand_object_interactions")
    if isinstance(interactions, list):
        return len([item for item in interactions if isinstance(item, dict)])
    try:
        return 1 if float(row.get("interaction_score") or 0.0) > 0.0 else 0
    except (TypeError, ValueError):
        return 0


def _key_action_view_support(
    yolo_rows: List[Dict[str, Any]],
    *,
    view: str,
    start_sec: float,
    end_sec: float,
) -> Dict[str, Any]:
    row_count = 0
    active_row_count = 0
    interaction_count = 0
    labels: Dict[str, int] = {}
    for row in yolo_rows:
        if _key_action_row_view(row) != view:
            continue
        row_time = _key_action_row_time_sec(row)
        if row_time is None or row_time < start_sec - 0.001 or row_time > end_sec + 0.001:
            continue
        row_count += 1
        row_interactions = _key_action_row_interaction_count(row)
        interaction_count += row_interactions
        try:
            active_score = float(row.get("active_score") or row.get("interaction_score") or 0.0)
        except (TypeError, ValueError):
            active_score = 0.0
        if row_interactions > 0 or active_score > 0.2 or row.get("is_active") or row.get("is_experiment_active"):
            active_row_count += 1
        counts = row.get("label_counts")
        if isinstance(counts, dict):
            for label, count in counts.items():
                try:
                    labels[str(label)] = labels.get(str(label), 0) + int(count or 0)
                except (TypeError, ValueError):
                    continue
        detections = row.get("detections")
        if isinstance(detections, list):
            for detection in detections:
                if not isinstance(detection, dict):
                    continue
                label = str(detection.get("label") or detection.get("class_name") or detection.get("raw_label") or "").strip()
                if label:
                    labels[label] = labels.get(label, 0) + 1
    return {
        "row_count": row_count,
        "active_row_count": active_row_count,
        "interaction_count": interaction_count,
        "labels": dict(sorted(labels.items(), key=lambda item: item[1], reverse=True)[:12]),
        "has_physical_action": bool(active_row_count > 0 and interaction_count > 0),
    }


def _key_action_text_list(value: Any) -> List[str]:
    if value is None:
        return []
    if isinstance(value, str):
        return [item.strip() for item in re.split(r"[,;\s]+", value) if item.strip()]
    if isinstance(value, (list, tuple, set)):
        return [str(item).strip() for item in value if str(item).strip()]
    return [str(value).strip()] if str(value).strip() else []


def _key_action_formal_dual_view_context(metadata_dir: Path) -> Dict[str, Any]:
    events = _read_jsonl_rows(metadata_dir / "dual_view_action_events.jsonl")
    episodes = _read_jsonl_rows(metadata_dir / "dual_view_aligned_experiment_episodes.jsonl")
    summary = _load_json_if_exists(metadata_dir / "dual_view_action_alignment_summary.json") or {}
    event_ids = {
        str(row.get("dual_event_id") or row.get("event_id") or "").strip()
        for row in events
        if str(row.get("dual_event_id") or row.get("event_id") or "").strip()
    }
    event_micro_ids: Dict[str, List[str]] = {}
    events_by_id: Dict[str, Dict[str, Any]] = {}
    for row in events:
        event_id = str(row.get("dual_event_id") or row.get("event_id") or "").strip()
        if not event_id:
            continue
        events_by_id[event_id] = row
        event_micro_ids[event_id] = _key_action_text_list(row.get("micro_segment_ids"))
    episodes_by_segment_id = {
        str(row.get("segment_id") or "").strip(): row
        for row in episodes
        if str(row.get("segment_id") or "").strip()
    }
    return {
        "events": events,
        "episodes": episodes,
        "summary": summary if isinstance(summary, dict) else {},
        "event_ids": event_ids,
        "events_by_id": events_by_id,
        "event_micro_ids": event_micro_ids,
        "episodes_by_segment_id": episodes_by_segment_id,
    }


def _key_action_segment_event_ids(segment: Mapping[str, Any]) -> List[str]:
    values: List[str] = []
    for key in ("dual_event_ids", "dual_view_action_event_ids", "event_ids", "source_event_ids"):
        values.extend(_key_action_text_list(segment.get(key)))
    values.extend(_key_action_text_list(segment.get("evidence_link")))
    return list(dict.fromkeys(values))


def _key_action_segment_is_formal_dual_view(
    segment: Mapping[str, Any],
    segment_id: str,
    formal_context: Mapping[str, Any],
) -> Dict[str, Any]:
    formal_event_ids = formal_context.get("event_ids") if isinstance(formal_context.get("event_ids"), set) else set()
    episodes_by_segment_id = (
        formal_context.get("episodes_by_segment_id")
        if isinstance(formal_context.get("episodes_by_segment_id"), dict)
        else {}
    )
    formal_events = (
        formal_context.get("events")
        if isinstance(formal_context.get("events"), list)
        else []
    )

    def _float_value(value: Any) -> Optional[float]:
        try:
            if value is None:
                return None
            parsed = float(value)
        except (TypeError, ValueError):
            return None
        return parsed if math.isfinite(parsed) else None

    def _time_range(row: Mapping[str, Any]) -> tuple[Optional[float], Optional[float]]:
        start = None
        end = None
        for key in ("session_start_sec", "start_sec", "start_time_sec", "global_start_sec"):
            start = _float_value(row.get(key))
            if start is not None:
                break
        for key in ("session_end_sec", "end_sec", "end_time_sec", "global_end_sec"):
            end = _float_value(row.get(key))
            if end is not None:
                break
        if (start is None or end is None) and isinstance(row.get("cv_detection"), Mapping):
            cv_start, cv_end = _time_range(row.get("cv_detection") or {})
            if start is None:
                start = cv_start
            if end is None:
                end = cv_end
        duration = _float_value(row.get("duration_sec"))
        if start is not None and end is None and duration is not None:
            end = start + duration
        if end is not None and start is None and duration is not None:
            start = end - duration
        if start is not None and end is not None and end < start:
            start, end = end, start
        return start, end

    def _ranges_overlap(left: Mapping[str, Any], right: Mapping[str, Any]) -> bool:
        left_start, left_end = _time_range(left)
        right_start, right_end = _time_range(right)
        if left_start is None or left_end is None or right_start is None or right_end is None:
            return False
        overlap = min(left_end, right_end) - max(left_start, right_start)
        if overlap > 0.0:
            return True
        left_center = (left_start + left_end) * 0.5
        right_center = (right_start + right_end) * 0.5
        return abs(left_center - right_center) <= 2.0

    event_ids = _key_action_segment_event_ids(segment)
    row_is_formal_episode = bool(segment.get("_formal_dual_view_action_episode"))
    episode_for_segment = episodes_by_segment_id.get(segment_id) if segment_id else None
    in_formal_episode_file = bool(
        episode_for_segment
        and isinstance(episode_for_segment, dict)
        and _ranges_overlap(segment, episode_for_segment)
    )
    overlapping_event_ids: List[str] = []
    for event in formal_events:
        if not isinstance(event, dict) or not _ranges_overlap(segment, event):
            continue
        event_id = str(event.get("dual_event_id") or event.get("event_id") or "").strip()
        if event_id:
            overlapping_event_ids.append(event_id)
    if overlapping_event_ids:
        event_ids = list(dict.fromkeys([*event_ids, *overlapping_event_ids]))
    token_text = " ".join(
        str(segment.get(key) or "").lower()
        for key in ("decision_path", "reason_code", "boundary_source", "detector_backend", "source", "detector_version")
    )
    has_alignment_marker = (
        "dual_view_action_alignment" in token_text
        or "dual_view_action_aligned" in token_text
        or "dual_view_action_events" in token_text
    )
    event_ids_match = bool(event_ids and formal_event_ids and any(event_id in formal_event_ids for event_id in event_ids))
    confirmed = bool(row_is_formal_episode or in_formal_episode_file or event_ids_match or (has_alignment_marker and event_ids_match))
    reason = "dual_view_action_aligned" if confirmed else "missing_formal_dual_view_action_alignment"
    source = "dual_view_action_alignment" if confirmed else "candidate_window_support"
    return {
        "confirmed": confirmed,
        "status": "confirmed" if confirmed else "candidate",
        "event_ids": event_ids,
        "reason": reason,
        "source": source,
    }


def _material_delivery_safe_name(value: str) -> str:
    return re.sub(r'[<>:"/\\|?*\s]+', "_", value).strip("._") or "material"


def _material_delivery_title_label(value: str) -> str:
    title = re.sub(r"\s+", " ", str(value or "").strip())
    title = re.sub(
        r"(?:[_\-\s]+(?:20\d{6}|20\d{2}[-/.年](?:0?[1-9]|1[0-2])[-/.月](?:0?[1-9]|[12]\d|3[01])日?))"
        r"(?:[_\-\s]+\d{3,6})?$",
        "",
        title,
    ).strip(" _-.")
    return title or "experiment"


def _material_delivery_date_label(value: str) -> str:
    if value:
        try:
            return datetime.fromisoformat(value.replace("Z", "+00:00")).strftime("%Y%m%d")
        except ValueError:
            pass
        match = re.search(r"(?<!\d)(20\d{2})[-_]?([01]\d)[-_]?([0-3]\d)(?!\d)", value)
        if match:
            return "".join(match.groups())
    return datetime.now().strftime("%Y%m%d")


def _formal_material_reference_root_for_exp(exp_dir: Path) -> Path:
    local_root = exp_dir / "material_references"
    for meta_path in (local_root / "manifest.json", local_root / "素材索引.json"):
        payload = _load_json_if_exists(meta_path)
        if not isinstance(payload, dict):
            continue
        candidate = payload.get("formal_material_references") or payload.get("simplified_material_references")
        if candidate:
            return Path(str(candidate))

    exp = _load_json_if_exists(exp_dir / "experiment.json") or {}
    title = _material_delivery_title_label(str(
        exp.get("title")
        or exp.get("experiment_title")
        or exp.get("experiment_name")
        or exp.get("name")
        or exp_dir.name
    ))
    date = _material_delivery_date_label(str(exp.get("created_at") or exp.get("experiment_date") or exp.get("date") or exp_dir.name))
    label = _material_delivery_safe_name(f"{title}_{date}")
    outputs_dir = exp_dir.parent.parent if exp_dir.parent.name == "experiments" else exp_dir.parent
    return outputs_dir / "material_references" / label


def _material_reference_root_candidates(exp_dir: Path) -> List[Path]:
    formal_root = _formal_material_reference_root_for_exp(exp_dir)
    local_root = exp_dir / "material_references"
    roots: List[Path] = []
    for root in (formal_root, local_root):
        if root not in roots:
            roots.append(root)
    return roots


def _material_reference_index_exists(exp_dir: Path) -> bool:
    for ref_root in _material_reference_root_candidates(exp_dir):
        if (ref_root / "素材索引.jsonl").exists() or (ref_root / "素材索引.json").exists():
            return True
    return False


def _material_reference_root_and_rows(exp_dir: Path) -> tuple[Path, List[Dict[str, Any]]]:
    fallback_root = exp_dir / "material_references"
    local_root = exp_dir / "material_references"
    for ref_root in _material_reference_root_candidates(exp_dir):
        rows = _material_reference_rows_from_root(ref_root)
        if not rows:
            continue
        if ref_root.resolve() == local_root.resolve():
            approved_rows = []
            for row in rows:
                candidate_status = str(row.get("candidate_status") or "").lower()
                review_status = str(row.get("review_status") or "").lower()
                has_approval_trace = bool(row.get("approved_at") or row.get("approved_by"))
                if (
                    row.get("formal_material_reference")
                    or candidate_status == "approved"
                    or (review_status == "accepted" and has_approval_trace)
                ):
                    approved_rows.append(row)
            if approved_rows:
                return ref_root, approved_rows
            continue
        return ref_root, rows
    return fallback_root, []


def _material_reference_rows_from_root(ref_root: Path) -> List[Dict[str, Any]]:
    index_jsonl = ref_root / "素材索引.jsonl"
    rows = _read_jsonl_rows(index_jsonl)
    if rows:
        return rows
    payload = _load_json_if_exists(ref_root / "素材索引.json")
    records = payload.get("records") if isinstance(payload, dict) else None
    records = [row for row in (records or []) if isinstance(row, dict)]
    if records:
        return records
    # Fallback: the package builder can rewrite 素材索引.jsonl/.json to empty when
    # micro_segments.jsonl is empty, and on Windows a publish run may fail to
    # replace the index while the backend holds a read handle. key_material_
    # references.jsonl is written from the real asset catalog and is the stable
    # copy, so read it when the canonical index is empty.
    return _read_jsonl_rows(ref_root / "key_material_references.jsonl")


def _material_reference_rows(exp_dir: Path) -> List[Dict[str, Any]]:
    return _material_reference_root_and_rows(exp_dir)[1]


def _material_row_path(row: Dict[str, Any], root: Path) -> Optional[Path]:
    raw_path = row.get("stored_file") or row.get("stored_path") or row.get("file_path")
    if raw_path:
        path = Path(str(raw_path))
        return path if path.is_absolute() else root / path
    filename = row.get("stored_filename") or row.get("file_name")
    asset_kind = row.get("asset_kind") or row.get("material_type")
    if filename and asset_kind:
        return root / str(asset_kind) / str(filename)
    return None


def _object_labels_from_material_row(row: Dict[str, Any]) -> List[str]:
    labels: List[str] = []
    action = row.get("action") if isinstance(row.get("action"), dict) else {}
    values: List[Any] = [row.get("primary_object"), row.get("object_label")]
    if isinstance(row.get("object_labels"), list):
        values.extend(row.get("object_labels") or [])
    if isinstance(row.get("secondary_objects"), list):
        values.extend(row.get("secondary_objects") or [])
    if isinstance(action.get("objects"), list):
        values.extend(action.get("objects") or [])
    for value in values:
        text = str(value or "").strip()
        if text and text not in labels:
            labels.append(text)
    return labels


_MATERIAL_API_HEAVY_KEYS = {
    "source_yolo_evidence",
    "yolo_evidence",
    "detections",
    "ignored_detections",
    "hand_object_interactions",
    "physical_evidence_diagnostics",
    "window_audit",
    "tracklet_summary",
    "evidence_packet",
    "qwen_audit",
}


def _compact_material_api_row(row: Dict[str, Any]) -> Dict[str, Any]:
    compact: Dict[str, Any] = {}
    for key, value in row.items():
        if key in _MATERIAL_API_HEAVY_KEYS:
            if isinstance(value, list):
                compact[f"{key}_count"] = len(value)
            continue
        if key == "evidence_chain" and isinstance(value, dict):
            compact[key] = {
                item_key: value.get(item_key)
                for item_key in (
                    "schema_version",
                    "camera_view",
                    "time_start",
                    "time_end",
                    "micro_segment_id",
                    "segment_id",
                    "source_clip",
                    "source_clip_path",
                    "candidate_source",
                    "candidate_disposition",
                    "physical_action_type",
                    "action_display_name",
                )
                if value.get(item_key) not in (None, "", [], {})
            }
            continue
        if key == "vlm_semantics" and isinstance(value, dict):
            compact[key] = {
                item_key: value.get(item_key)
                for item_key in (
                    "status",
                    "model",
                    "decision",
                    "description",
                    "confirmed_objects",
                    "missing_evidence",
                )
                if value.get(item_key) not in (None, "", [], {})
            }
            continue
        compact[key] = value
    return compact


def _material_reference_items(exp_dir: Path, experiment_id: str) -> Dict[str, Any]:
    ref_root, rows = _material_reference_root_and_rows(exp_dir)
    items: List[Dict[str, Any]] = []
    for index, row in enumerate(rows, start=1):
        row = enrich_material_taxonomy(row)
        api_row = _compact_material_api_row(row)
        asset_kind = str(row.get("asset_kind") or row.get("material_type") or "")
        if asset_kind == "专业报告":
            continue
        path = _material_row_path(row, ref_root)
        action = row.get("action") if isinstance(row.get("action"), dict) else {}
        start_sec = _float_value(row.get("time_start") or row.get("start_sec") or action.get("start_sec") or row.get("source_offset_sec"), 0.0)
        end_sec = _float_value(row.get("time_end") or row.get("end_sec") or action.get("end_sec"), start_sec)
        item_id = str(row.get("item_id") or row.get("candidate_id") or row.get("micro_segment_id") or f"material_reference_{index:04d}")
        url = _experiment_file_api_path(path, experiment_id) if path else None
        preview_url = url if asset_kind == "关键帧" else None
        clip_url = url if asset_kind == "关键片段" else None
        action_labels = [row.get("display_title") or row.get("action_name") or action.get("title") or asset_kind, row.get("canonical_action_type")]
        if isinstance(row.get("secondary_actions"), list):
            action_labels.extend(row.get("secondary_actions") or [])
        action_labels = [str(item) for item in action_labels if str(item or "").strip()]
        items.append(
            {
                **api_row,
                "item_id": item_id,
                "experiment_id": experiment_id,
                "event_id": row.get("event_id") or row.get("micro_segment_id") or item_id,
                "display_name": row.get("display_name") or row.get("display_title") or action.get("title") or row.get("action_name") or asset_kind or item_id,
                "event_type": row.get("display_title") or row.get("action_name") or action.get("title") or asset_kind,
                "timestamp_sec": start_sec,
                "time_start": start_sec,
                "time_end": end_sec,
                "duration_sec": max(0.0, end_sec - start_sec),
                "object_labels": _object_labels_from_material_row(row),
                "actions": list(dict.fromkeys(action_labels)),
                "canonical_action_type": row.get("canonical_action_type"),
                "canonical_object": row.get("canonical_object"),
                "sop_phase": row.get("sop_phase"),
                "interaction_family": row.get("interaction_family"),
                "review_status": row.get("review_status") or "accepted",
                "evidence_level": row.get("evidence_level") or "recovered_reference",
                "preview_url": preview_url,
                "clip_url": clip_url,
                "report_url": url if asset_kind == "专业报告" else None,
                "material_url": url,
                "frame_path": str(path) if path and asset_kind == "关键帧" else row.get("frame_path"),
                "clip_file_path": str(path) if path and asset_kind == "关键片段" else row.get("clip_file_path"),
                "published_paths": {
                    "keyframe": str(path) if path and asset_kind == "关键帧" else "",
                    "clip": str(path) if path and asset_kind == "关键片段" else "",
                    "report": str(path) if path and asset_kind == "专业报告" else "",
                },
                "payload": api_row,
            }
        )
    items = _backfill_missing_material_key_clips(exp_dir, experiment_id, items)
    items = enrich_material_best_scores(items)
    return {
        "schema_version": "published_materials.material_references_fallback.v1",
        "experiment_id": experiment_id,
        "total": len(items),
        "items": items,
        "grouped_items": _group_material_reference_assets(items),
        "source": str(ref_root),
    }


def _material_item_field(item: Dict[str, Any], key: str) -> Any:
    value = item.get(key)
    if value is not None and value != "":
        return value
    payload = item.get("payload") if isinstance(item.get("payload"), dict) else {}
    return payload.get(key)


def _source_micro_clip_candidates(exp_dir: Path, micro_segment_id: str, view: str) -> List[Path]:
    micro_id = str(micro_segment_id or "").strip()
    view_name = str(view or "").strip()
    if not micro_id or not view_name:
        return []
    base_ids = [micro_id]
    if micro_id.endswith("_merged"):
        base_ids.append(micro_id[: -len("_merged")])
    clip_root = exp_dir / "key_action_index" / "clips" / "micro"
    candidates: List[Path] = []
    for base_id in dict.fromkeys(base_ids):
        candidates.append(clip_root / f"{base_id}_{view_name}.mp4")
        candidates.extend(clip_root.glob(f"{base_id}*_{view_name}.mp4") if clip_root.exists() else [])
    seen: set[str] = set()
    unique: List[Path] = []
    for candidate in candidates:
        key = str(candidate)
        if key in seen:
            continue
        seen.add(key)
        if candidate.exists() and candidate.is_file() and candidate.stat().st_size > 0:
            unique.append(candidate)
    return unique


def _backfill_missing_material_key_clips(exp_dir: Path, experiment_id: str, items: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    if os.environ.get("KEY_ACTION_BACKFILL_SOURCE_MICRO_CLIPS", "1").strip().lower() in {"0", "false", "no", "off"}:
        return items
    if not (exp_dir / "key_action_index" / "clips" / "micro").exists():
        return items

    grouped: Dict[str, List[Dict[str, Any]]] = {}
    for item in items:
        if not isinstance(item, dict):
            continue
        group_id = _material_item_group_id(item)
        action = str(_material_item_field(item, "canonical_action_type") or _material_item_field(item, "event_type") or "").strip()
        key = f"{group_id}::{action}" if group_id and action else group_id
        if key:
            grouped.setdefault(key, []).append(item)

    backfilled: List[Dict[str, Any]] = []
    for group_items in grouped.values():
        for view in ("third_person", "first_person"):
            view_items = [item for item in group_items if _material_item_view(item) == view]
            if not view_items:
                continue
            has_keyframe = any(_material_item_asset_kind(item) == "keyframe" for item in view_items)
            has_clip = any(_material_item_asset_kind(item) == "clip" for item in view_items)
            if not has_keyframe or has_clip:
                continue
            keyframe = max(view_items, key=_material_item_score)
            micro_id = str(_material_item_field(keyframe, "micro_segment_id") or "").strip()
            clip_candidates = _source_micro_clip_candidates(exp_dir, micro_id, view)
            if not clip_candidates:
                continue
            clip_path = clip_candidates[0]
            clip_url = _experiment_file_api_path(clip_path, experiment_id)
            item_id = f"{keyframe.get('item_id') or keyframe.get('candidate_id') or micro_id}_{view}_source_clip"
            clip_item = {
                **keyframe,
                "item_id": item_id,
                "candidate_id": item_id,
                "asset_kind": "关键片段",
                "asset_kind_normalized": "clip",
                "material_type": "关键片段",
                "preview_url": keyframe.get("preview_url"),
                "clip_url": clip_url,
                "material_url": clip_url,
                "frame_path": keyframe.get("frame_path"),
                "clip_file_path": str(clip_path),
                "source_file": str(clip_path),
                "source_clip": str(clip_path),
                "source_clip_path": str(clip_path),
                "source_micro_clip_backfilled": True,
                "library_sync_status": "source_micro_clip_reference",
                "published_paths": {
                    **(keyframe.get("published_paths") if isinstance(keyframe.get("published_paths"), dict) else {}),
                    "clip": str(clip_path),
                },
            }
            payload = dict(clip_item.get("payload") if isinstance(clip_item.get("payload"), dict) else {})
            payload.update(
                {
                    "asset_kind": "关键片段",
                    "material_type": "关键片段",
                    "source_file": str(clip_path),
                    "source_clip": str(clip_path),
                    "source_clip_path": str(clip_path),
                    "stored_file": str(clip_path),
                    "clip_file_path": str(clip_path),
                    "source_micro_clip_backfilled": True,
                    "library_sync_status": "source_micro_clip_reference",
                }
            )
            clip_item["payload"] = payload
            backfilled.append(clip_item)

    if not backfilled:
        return items
    return [*items, *backfilled]


def _material_item_view(item: Dict[str, Any]) -> str:
    payload = item.get("payload") if isinstance(item.get("payload"), dict) else {}
    for key in ("view", "camera_view", "camera_id", "stream_id"):
        value = item.get(key)
        if isinstance(value, str) and value.strip():
            return value.strip()
    for key in ("view", "camera_view", "camera_id", "stream_id"):
        value = payload.get(key)
        if isinstance(value, str) and value.strip():
            return value.strip()
    text = " ".join(
        str(value or "")
        for value in (
            item.get("clip_file_path"),
            item.get("frame_path"),
            item.get("preview_url"),
            item.get("clip_url"),
            payload.get("source_clip_path"),
            payload.get("source_clip"),
        )
    ).lower()
    if "first_person" in text or "operator" in text:
        return "first_person"
    if "third_person" in text or "top" in text:
        return "third_person"
    return "other"


def _material_item_asset_kind(item: Dict[str, Any]) -> str:
    asset_kind = str(_material_item_field(item, "asset_kind") or _material_item_field(item, "material_type") or "").strip()
    if asset_kind == "关键片段" or _material_item_field(item, "clip_url") or _material_item_field(item, "clip_file_path"):
        return "clip"
    if asset_kind == "关键帧" or _material_item_field(item, "preview_url") or _material_item_field(item, "frame_path"):
        return "keyframe"
    return "asset"


def _material_item_group_id(item: Dict[str, Any]) -> str:
    for key in ("material_group_id", "physical_action_material_id", "micro_segment_id", "evidence_window_id", "time_window_id", "window_id"):
        value = _material_item_field(item, key)
        if isinstance(value, str) and value.strip():
            return value.strip()
    time_start = _float_value(_material_item_field(item, "time_start") or _material_item_field(item, "start_sec") or _material_item_field(item, "timestamp_sec"), 0.0)
    time_end = _float_value(_material_item_field(item, "time_end") or _material_item_field(item, "end_sec"), time_start)
    action = str(_material_item_field(item, "canonical_action_type") or _material_item_field(item, "event_type") or _material_item_field(item, "display_name") or "material").strip()
    return f"{action}::{time_start:.2f}-{time_end:.2f}"


def _material_item_score(item: Dict[str, Any]) -> float:
    return max(
        _float_value(_material_item_field(item, "best_score"), 0.0),
        _float_value(_material_item_field(item, "quality_score"), 0.0),
        _float_value(_material_item_field(item, "score"), 0.0),
        _float_value(_material_item_field(item, "valid_yolo_evidence_count"), 0.0) / 10.0,
    )


def _material_item_dual_view_group_key(item: Dict[str, Any]) -> str:
    group_id = _material_item_group_id(item)
    action = str(_material_item_field(item, "canonical_action_type") or _material_item_field(item, "event_type") or "").strip()
    return f"{group_id}::{action}" if group_id and action else group_id


def _is_dual_view_key_material_row(item: Dict[str, Any]) -> bool:
    view = _material_item_view(item)
    if view in {"first_person", "third_person"}:
        return True
    return bool(_material_item_field(item, "micro_segment_id") or _material_item_field(item, "physical_action_material_id"))


def _filter_complete_dual_view_key_material_items(items: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    scoped_items = [item for item in items if isinstance(item, dict) and _is_dual_view_key_material_row(item)]
    if not scoped_items:
        return items
    required = {
        ("third_person", "keyframe"),
        ("third_person", "clip"),
        ("first_person", "keyframe"),
        ("first_person", "clip"),
    }
    by_group: Dict[str, set[tuple[str, str]]] = {}
    for item in scoped_items:
        group_key = _material_item_dual_view_group_key(item)
        if not group_key:
            continue
        view = _material_item_view(item)
        kind = _material_item_asset_kind(item)
        if view in {"first_person", "third_person"} and kind in {"keyframe", "clip"}:
            by_group.setdefault(group_key, set()).add((view, kind))
    complete = {group_key for group_key, assets in by_group.items() if required.issubset(assets)}
    filtered: List[Dict[str, Any]] = []
    for item in items:
        if not isinstance(item, dict):
            continue
        if not _is_dual_view_key_material_row(item):
            filtered.append(item)
            continue
        group_key = _material_item_dual_view_group_key(item)
        if group_key not in complete:
            continue
        filtered.append(
            {
                **item,
                "material_group_id": group_key,
                "physical_action_material_id": group_key,
            }
        )
    return filtered


def _merge_material_texts(left: Iterable[Any], right: Iterable[Any]) -> List[str]:
    values: List[str] = []
    seen: set[str] = set()
    for value in [*left, *right]:
        text = str(value or "").strip()
        if not text or text in seen:
            continue
        seen.add(text)
        values.append(text)
    return values


def _group_material_reference_assets(items: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    grouped: Dict[str, Dict[str, Any]] = {}
    for raw_item in items:
        if not isinstance(raw_item, dict):
            continue
        contract_item = _material_window_contract_item(raw_item)
        group_id = _material_item_group_id(raw_item)
        view = _material_item_view(raw_item)
        kind = _material_item_asset_kind(raw_item)
        start_sec = _float_value(raw_item.get("time_start") or raw_item.get("start_sec") or raw_item.get("timestamp_sec"), 0.0)
        end_sec = _float_value(raw_item.get("time_end") or raw_item.get("end_sec"), start_sec)
        asset_item = {
            **raw_item,
            **contract_item,
            "material_group_id": group_id,
            "physical_action_material_id": group_id,
            "view": view,
            "camera_view": view,
            "asset_kind_normalized": kind,
        }
        group = grouped.get(group_id)
        if group is None:
            group = {
                "schema_version": "published_materials.physical_action_group.v1",
                **contract_item,
                "item_id": group_id,
                "material_group_id": group_id,
                "physical_action_material_id": group_id,
                "experiment_id": raw_item.get("experiment_id"),
                "event_id": raw_item.get("event_id") or raw_item.get("micro_segment_id") or group_id,
                "micro_segment_id": raw_item.get("micro_segment_id"),
                "parent_segment_id": raw_item.get("parent_segment_id") or raw_item.get("segment_id"),
                "display_name": raw_item.get("display_name") or raw_item.get("display_title") or raw_item.get("event_type") or "关键素材",
                "display_title": raw_item.get("display_title") or raw_item.get("display_name") or raw_item.get("event_type") or "关键素材",
                "event_type": raw_item.get("event_type") or raw_item.get("display_title") or raw_item.get("display_name"),
                "canonical_action_type": raw_item.get("canonical_action_type"),
                "canonical_object": raw_item.get("canonical_object"),
                "sop_phase": raw_item.get("sop_phase"),
                "interaction_family": raw_item.get("interaction_family"),
                "timestamp_sec": start_sec,
                "time_start": start_sec,
                "time_end": end_sec,
                "duration_sec": max(0.0, end_sec - start_sec),
                "segment_id": contract_item.get("segment_id") or raw_item.get("segment_id") or raw_item.get("parent_segment_id"),
                "object_labels": list(raw_item.get("object_labels") or []),
                "actions": list(raw_item.get("actions") or []),
                "asset_items": [],
                "assets": {"first_person": {}, "third_person": {}, "other": {}},
                "views": [],
                "clip_count": 0,
                "keyframe_count": 0,
                "review_status": contract_item.get("review_status") or raw_item.get("review_status") or "accepted",
                "evidence_level": raw_item.get("evidence_level") or "recovered_reference",
            }
            grouped[group_id] = group
        group["time_start"] = min(_float_value(group.get("time_start"), start_sec), start_sec)
        group["time_end"] = max(_float_value(group.get("time_end"), end_sec), end_sec)
        group["timestamp_sec"] = group["time_start"]
        group["duration_sec"] = max(0.0, _float_value(group.get("time_end"), 0.0) - _float_value(group.get("time_start"), 0.0))
        group["object_labels"] = _merge_material_texts(group.get("object_labels") or [], raw_item.get("object_labels") or [])
        group["actions"] = _merge_material_texts(group.get("actions") or [], raw_item.get("actions") or [])
        if view not in group["views"]:
            group["views"].append(view)
        if kind == "clip":
            group["clip_count"] = int(group.get("clip_count") or 0) + 1
        elif kind == "keyframe":
            group["keyframe_count"] = int(group.get("keyframe_count") or 0) + 1
        group["asset_items"].append(asset_item)
        view_bucket = view if view in {"first_person", "third_person"} else "other"
        current = group["assets"].setdefault(view_bucket, {}).get(kind)
        if current is None or _material_item_score(asset_item) >= _material_item_score(current):
            group["assets"].setdefault(view_bucket, {})[kind] = asset_item

    for group in grouped.values():
        assets = group.get("assets") if isinstance(group.get("assets"), dict) else {}
        third = assets.get("third_person") if isinstance(assets.get("third_person"), dict) else {}
        first = assets.get("first_person") if isinstance(assets.get("first_person"), dict) else {}
        representative_keyframe = third.get("keyframe") or first.get("keyframe")
        representative_clip = third.get("clip") or first.get("clip")
        if isinstance(representative_keyframe, dict):
            group["preview_url"] = representative_keyframe.get("preview_url")
            group["frame_path"] = representative_keyframe.get("frame_path")
        if isinstance(representative_clip, dict):
            group["clip_url"] = representative_clip.get("clip_url")
            group["clip_file_path"] = representative_clip.get("clip_file_path")
        group["view"] = "dual_view" if {"first_person", "third_person"}.issubset(set(group.get("views") or [])) else ",".join(group.get("views") or ["other"])
        group["first_person_available"] = "first_person" in set(group.get("views") or [])
        group["third_person_available"] = "third_person" in set(group.get("views") or [])
    return sorted(grouped.values(), key=lambda item: (_float_value(item.get("time_start"), 0.0), str(item.get("display_name") or "")))


def _workspace_published_payload_with_media_urls(payload: Dict[str, Any]) -> Dict[str, Any]:
    items = payload.get("items") if isinstance(payload, dict) else []
    if not isinstance(items, list):
        return payload
    updated_items: List[Dict[str, Any]] = []
    for item in items:
        if not isinstance(item, dict):
            updated_items.append(item)
            continue
        updated = dict(item)
        experiment_id = str(updated.get("experiment_id") or "").strip()
        if experiment_id:
            published_paths = updated.get("published_paths") if isinstance(updated.get("published_paths"), dict) else {}
            preview_source = updated.get("preview_path") or published_paths.get("preview") or published_paths.get("keyframe")
            clip_source = updated.get("clip_path") or published_paths.get("clip")
            report_source = updated.get("report_path") or published_paths.get("report")
            if not updated.get("preview_url") and preview_source:
                updated["preview_url"] = _experiment_file_api_path(Path(str(preview_source)), experiment_id)
            if not updated.get("clip_url") and clip_source:
                updated["clip_url"] = _experiment_file_api_path(Path(str(clip_source)), experiment_id)
            if not updated.get("report_url") and report_source:
                updated["report_url"] = _experiment_file_api_path(Path(str(report_source)), experiment_id)
        updated_items.append(updated)
    return {**payload, "items": updated_items}


def _rebuild_workspace_published_materials_index_quietly() -> Dict[str, Any]:
    try:
        from labsopguard.material_maintenance import rebuild_workspace_published_materials_index

        return rebuild_workspace_published_materials_index(
            PROJECT_ROOT / "outputs" / "experiments",
            _workspace_published_materials_index_path(),
        )
    except Exception as exc:
        logger.exception("Workspace published material reindex failed")
        return {"status": "failed", "error": str(exc)}


_MATERIAL_REVIEW_QUEUE_DIR_NAME = "_material_review_queue"
_LEGACY_MATERIAL_CANDIDATES_DIR_NAME = "material_candidates"
_MATERIAL_CANDIDATE_INDEX_FILENAME = "\u7d20\u6750\u5019\u9009\u7d22\u5f15.jsonl"


def _material_candidate_roots(experiment_id: str) -> List[Path]:
    exp_dir = _experiment_output_dir(experiment_id)
    return [
        exp_dir / _MATERIAL_REVIEW_QUEUE_DIR_NAME,
        exp_dir / _LEGACY_MATERIAL_CANDIDATES_DIR_NAME,
        exp_dir / "key_action_index" / _MATERIAL_REVIEW_QUEUE_DIR_NAME,
        exp_dir / "key_action_index" / _LEGACY_MATERIAL_CANDIDATES_DIR_NAME,
    ]


def _material_candidate_root(experiment_id: str) -> Path:
    roots = _material_candidate_roots(experiment_id)
    for root in roots:
        if (root / _MATERIAL_CANDIDATE_INDEX_FILENAME).exists():
            return root
    for root in roots:
        if root.exists():
            return root
    return roots[0]


def _material_candidate_index_path(experiment_id: str) -> Path:
    return _material_candidate_root(experiment_id) / _MATERIAL_CANDIDATE_INDEX_FILENAME


def _material_candidate_rows(experiment_id: str) -> List[Dict[str, Any]]:
    rows = _read_jsonl_rows(_material_candidate_index_path(experiment_id))
    if rows:
        return rows
    exp_dir = _experiment_output_dir(experiment_id)
    fallback_paths = [
        exp_dir / "key_action_index" / "metadata" / "review_candidate_materials.jsonl",
        exp_dir / "metadata" / "review_candidate_materials.jsonl",
    ]
    for fallback_path in fallback_paths:
        rows = _read_jsonl_rows(fallback_path)
        if rows:
            return rows
    return []


def _write_material_candidate_rows(experiment_id: str, rows: List[Dict[str, Any]]) -> None:
    _write_jsonl(_material_candidate_index_path(experiment_id), rows)


def _material_candidate_status(row: Dict[str, Any]) -> str:
    raw_status = row.get("candidate_status") or row.get("review_status") or "pending"
    status = str(raw_status).strip().lower()
    if not status or status in {"none", "null", "unknown"}:
        return "pending"
    if status == "accepted":
        return "approved"
    return status


def _material_candidate_group_status(rows: List[Dict[str, Any]]) -> str:
    statuses = [_material_candidate_status(row) for row in rows]
    if any(status in {"approved", "accepted"} for status in statuses):
        return "approved"
    if any(status == "confirmed" for status in statuses):
        return "confirmed"
    if any(status in {"pending", "review", "needs_review", "candidate"} for status in statuses):
        return "pending"
    if statuses and all(status == "not_selected" for status in statuses):
        return "not_selected"
    if statuses and all(status == "deferred" for status in statuses):
        return "deferred"
    if any(status in {"rejected", "failed", "blocked"} for status in statuses):
        return next(status for status in statuses if status in {"rejected", "failed", "blocked"})
    if any(status == "deferred" for status in statuses):
        return "deferred"
    return statuses[0] if statuses else "pending"


def _first_material_candidate_value(rows: List[Dict[str, Any]], key: str, default: Any = None) -> Any:
    for row in rows:
        value = row.get(key)
        if value not in (None, "", [], {}):
            return value
    return default


def _material_candidate_file_payload(experiment_id: str, row: Dict[str, Any]) -> Dict[str, Any]:
    row = enrich_material_taxonomy(row)
    api_row = _compact_material_api_row(row)
    candidate_root = _material_candidate_root(experiment_id)
    path = _material_row_path(row, candidate_root)
    url = _experiment_file_api_path(path, experiment_id) if path else None
    asset_kind = str(row.get("asset_kind") or row.get("material_type") or "")
    candidate_status = _material_candidate_status(row)
    review_status = str(row.get("review_status") or candidate_status)
    return {
        **api_row,
        "candidate_status": candidate_status,
        "review_status": review_status,
        "url": url,
        "preview_url": url if (url and asset_kind == "关键帧") else row.get("preview_url"),
        "clip_url": url if (url and asset_kind == "关键片段") else row.get("clip_url"),
        "exists": bool(path and path.exists() and path.is_file()) or bool(row.get("exists")),
    }


def _float_value(value: Any, default: float = 0.0) -> float:
    try:
        return float(value)
    except (TypeError, ValueError):
        return default


def _material_candidates_payload(experiment_id: str) -> Dict[str, Any]:
    rows = _material_candidate_rows(experiment_id)
    groups: Dict[str, List[Dict[str, Any]]] = {}
    for row in rows:
        group_id = str(row.get("candidate_group_id") or row.get("candidate_id") or "ungrouped")
        groups.setdefault(group_id, []).append(_material_candidate_file_payload(experiment_id, row))

    items: List[Dict[str, Any]] = []
    for group_id, group_rows in sorted(groups.items()):
        keyframes = [row for row in group_rows if row.get("asset_kind") == "关键帧"]
        clips = [row for row in group_rows if row.get("asset_kind") == "关键片段"]
        first = group_rows[0] if group_rows else {}
        recommended = [row for row in group_rows if row.get("recommended") is True]
        group_status = _material_candidate_group_status(group_rows)
        items.append(
            {
                "candidate_group_id": group_id,
                "status": group_status,
                "review_status": "approved" if group_status == "approved" else str(_first_material_candidate_value(group_rows, "review_status", group_status)),
                "recommended": bool(recommended),
                "recommended_count": len(recommended),
                "quality_score": max((_float_value(row.get("quality_score"), 0.0) for row in group_rows), default=0.0),
                "quality_bucket": _first_material_candidate_value(group_rows, "quality_bucket"),
                "quality_tier": _first_material_candidate_value(group_rows, "quality_tier"),
                "quality_grade": _first_material_candidate_value(group_rows, "quality_grade"),
                "quality_label": _first_material_candidate_value(group_rows, "quality_label"),
                "pipeline_status": _first_material_candidate_value(group_rows, "pipeline_status"),
                "pipeline_stage": _first_material_candidate_value(group_rows, "pipeline_stage"),
                "pipeline_flow": _first_material_candidate_value(group_rows, "pipeline_flow", []),
                "candidate_source": _first_material_candidate_value(group_rows, "candidate_source"),
                "source_event_id": _first_material_candidate_value(group_rows, "source_event_id"),
                "event_type": _first_material_candidate_value(group_rows, "event_type"),
                "physical_action_type": _first_material_candidate_value(group_rows, "physical_action_type"),
                "review_route": _first_material_candidate_value(group_rows, "review_route"),
                "review_reason_codes": _first_material_candidate_value(group_rows, "review_reason_codes", []),
                "physical_evidence_mode": _first_material_candidate_value(group_rows, "physical_evidence_mode"),
                "review_gate_policy": _first_material_candidate_value(group_rows, "review_gate_policy"),
                "yolo_recheck": _first_material_candidate_value(group_rows, "yolo_recheck"),
                "vlm_semantics": _first_material_candidate_value(group_rows, "vlm_semantics"),
                "view": _first_material_candidate_value(group_rows, "view") or first.get("view"),
                "camera_view": _first_material_candidate_value(group_rows, "camera_view") or first.get("camera_view"),
                "primary_object": _first_material_candidate_value(group_rows, "primary_object") or first.get("primary_object"),
                "raw_primary_object": _first_material_candidate_value(group_rows, "raw_primary_object") or first.get("raw_primary_object"),
                "manipulated_object": _first_material_candidate_value(group_rows, "manipulated_object") or first.get("manipulated_object"),
                "instrument_context": _first_material_candidate_value(group_rows, "instrument_context") or first.get("instrument_context"),
                "semantic_action": _first_material_candidate_value(group_rows, "semantic_action") or first.get("semantic_action"),
                "corrected_primary_object": _first_material_candidate_value(group_rows, "corrected_primary_object") or first.get("corrected_primary_object"),
                "display_title": _first_material_candidate_value(group_rows, "display_title") or first.get("display_title"),
                "semantic_evidence_refs": _first_material_candidate_value(group_rows, "semantic_evidence_refs", []),
                "action_name": _first_material_candidate_value(group_rows, "action_name") or first.get("action_name"),
                "canonical_action_type": _first_material_candidate_value(group_rows, "canonical_action_type") or first.get("canonical_action_type"),
                "canonical_object": _first_material_candidate_value(group_rows, "canonical_object") or first.get("canonical_object"),
                "sop_phase": _first_material_candidate_value(group_rows, "sop_phase") or first.get("sop_phase"),
                "interaction_family": _first_material_candidate_value(group_rows, "interaction_family") or first.get("interaction_family"),
                "approval_reason_code": _first_material_candidate_value(group_rows, "approval_reason_code"),
                "approval_reason": _first_material_candidate_value(group_rows, "approval_reason"),
                "rejection_reason_code": _first_material_candidate_value(group_rows, "rejection_reason_code"),
                "rejection_reason": _first_material_candidate_value(group_rows, "rejection_reason"),
                "review_notes": _first_material_candidate_value(group_rows, "review_notes"),
                "micro_segment_id": _first_material_candidate_value(group_rows, "micro_segment_id") or first.get("micro_segment_id"),
                "parent_segment_id": _first_material_candidate_value(group_rows, "parent_segment_id") or first.get("parent_segment_id"),
                "keyframes": keyframes,
                "clips": clips,
                "files": group_rows,
            }
        )

    def _candidate_group_sort_key(item: Dict[str, Any]) -> tuple:
        bucket = str(item.get("quality_bucket") or "")
        route = str(item.get("review_route") or "")
        action = str(item.get("physical_action_type") or "")
        status = str(item.get("status") or "")
        bucket_rank = {
            "auto_ready": 0,
            "review_candidate": 1,
            "low_quality": 9,
        }.get(bucket, 5)
        route_rank = {
            "human_review": 0,
            "vlm_review": 1,
            "auto_ready": 2,
        }.get(route, 3)
        status_rank = {
            "pending": 0,
            "deferred": 1,
            "approved": 2,
            "accepted": 2,
            "not_selected": 3,
            "rejected": 4,
        }.get(status, 5)
        action_rank = 0 if action else 1
        return (
            0 if item.get("recommended") else 1,
            status_rank,
            bucket_rank,
            route_rank,
            action_rank,
            -_float_value(item.get("quality_score"), 0.0),
            str(item.get("display_title") or item.get("candidate_group_id") or ""),
        )

    items.sort(key=_candidate_group_sort_key)

    candidate_root = _material_candidate_root(experiment_id)
    manifest = _load_json_if_exists(candidate_root / "manifest.json") or {}
    return {
        "schema_version": "material_candidates.api.v1",
        "experiment_id": experiment_id,
        "total": len(items),
        "file_total": len(rows),
        "pending_total": sum(1 for row in rows if _material_candidate_status(row) == "pending"),
        "approved_total": sum(1 for row in rows if _material_candidate_status(row) in {"approved", "accepted"}),
        "rejected_total": sum(1 for row in rows if _material_candidate_status(row) == "rejected"),
        "deferred_total": sum(1 for row in rows if _material_candidate_status(row) == "deferred"),
        "not_selected_total": sum(1 for row in rows if _material_candidate_status(row) == "not_selected"),
        "items": items,
        "manifest": manifest,
        "candidate_index": str(candidate_root / _MATERIAL_CANDIDATE_INDEX_FILENAME),
    }


def _material_review_batch_log_path(experiment_id: str) -> Path:
    return _experiment_output_dir(experiment_id) / "material_review_batches.jsonl"


def _read_material_review_batches(experiment_id: str) -> List[Dict[str, Any]]:
    return _read_jsonl_rows(_material_review_batch_log_path(experiment_id))


def _write_material_review_batches(experiment_id: str, rows: List[Dict[str, Any]]) -> None:
    _write_jsonl(_material_review_batch_log_path(experiment_id), rows)


def _append_material_review_batch(experiment_id: str, row: Dict[str, Any]) -> None:
    path = _material_review_batch_log_path(experiment_id)
    path.parent.mkdir(parents=True, exist_ok=True)
    with path.open("a", encoding="utf-8", newline="\n") as handle:
        handle.write(json.dumps(row, ensure_ascii=False, separators=(",", ":")) + "\n")


def _material_candidate_asset_is_formal(row: Dict[str, Any]) -> bool:
    kind = str(row.get("asset_kind") or row.get("material_type") or row.get("role") or "").lower()
    if "report" in kind or "报告" in kind:
        return False
    return bool(row.get("clip_file_path") or row.get("frame_path") or row.get("stored_file") or kind)


def _candidate_status_counts_for_rows(rows: List[Dict[str, Any]]) -> Dict[str, int]:
    counts: Dict[str, int] = {}
    for row in rows:
        status = _material_candidate_status(row)
        counts[status] = counts.get(status, 0) + 1
    return counts


def _material_batch_group_ids(groups: List[MaterialCandidateBatchItem]) -> List[str]:
    return [str(group.candidate_group_id).strip() for group in groups if str(group.candidate_group_id).strip()]


def _material_batch_candidate_ids(groups: List[MaterialCandidateBatchItem]) -> List[str]:
    ids: List[str] = []
    for group in groups:
        ids.extend([str(item).strip() for item in (group.candidate_ids or []) if str(item).strip()])
    return sorted(set(ids))


def _material_batch_affected_rows(
    rows: List[Dict[str, Any]],
    *,
    group_ids: List[str],
    candidate_ids: List[str],
) -> List[Dict[str, Any]]:
    group_set = set(group_ids)
    id_set = set(candidate_ids)
    affected = []
    for row in rows:
        row_id = str(row.get("candidate_id") or "")
        row_group = str(row.get("candidate_group_id") or "")
        if row_group in group_set or (id_set and row_id in id_set):
            affected.append(row)
    return affected


def _material_batch_addition_summary(before_rows: List[Dict[str, Any]], after_rows: List[Dict[str, Any]], group_ids: List[str]) -> Dict[str, Any]:
    before_approved = {str(row.get("candidate_id") or "") for row in before_rows if _material_candidate_status(row) == "approved"}
    group_set = set(group_ids)
    by_action: Dict[str, int] = {}
    total = 0
    for row in after_rows:
        candidate_id = str(row.get("candidate_id") or "")
        if not candidate_id or candidate_id in before_approved:
            continue
        if str(row.get("candidate_group_id") or "") not in group_set:
            continue
        if _material_candidate_status(row) != "approved" or not _material_candidate_asset_is_formal(row):
            continue
        total += 1
        action = str(row.get("canonical_action_type") or enrich_material_taxonomy(row).get("canonical_action_type") or "unknown")
        by_action[action] = by_action.get(action, 0) + 1
    return {"expected_formal_additions": total, "expected_formal_additions_by_action": by_action}


def _refresh_candidate_metadata_after_direct_write(experiment_id: str, rows: List[Dict[str, Any]]) -> None:
    try:
        from key_action_indexer.material_references import existing_material_candidates_root, _refresh_candidate_review_metadata  # type: ignore

        candidate_root = existing_material_candidates_root(_key_action_output_dir(experiment_id))
        _refresh_candidate_review_metadata(candidate_root, rows)
    except Exception:
        logger.debug("Candidate metadata refresh after direct write failed for %s", experiment_id, exc_info=True)


def _reset_formal_materials_from_candidate_rows(experiment_id: str, rows: List[Dict[str, Any]]) -> Dict[str, Any]:
    try:
        from key_action_indexer.material_references import reset_material_references_to_approved_candidates  # type: ignore

        approved_for_sync = [
            row
            for row in rows
            if str(row.get("candidate_status") or "").lower() == "approved"
            or str(row.get("review_status") or "").lower() == "accepted"
        ]
        return reset_material_references_to_approved_candidates(
            _key_action_output_dir(experiment_id),
            approved_rows=approved_for_sync,
            merge_existing=True,
        )
    except Exception as exc:
        logger.exception("Formal material reset from candidate rows failed for %s", experiment_id)
        return {"status": "failed", "error": str(exc)}


def _auto_publish_key_action_material_candidates(
    experiment_id: str,
    candidate_summary: Optional[Dict[str, Any]],
) -> Dict[str, Any]:
    enabled = os.environ.get("KEY_ACTION_AUTO_PUBLISH_MATERIAL_CANDIDATES", "1").strip().lower() not in {"0", "false", "no", "off"}
    result: Dict[str, Any] = {
        "schema_version": "key_action_material_auto_publish.v1",
        "enabled": enabled,
        "status": "skipped",
        "eligible_count": 0,
        "approved_count": 0,
    }
    if not enabled:
        result["reason"] = "disabled_by_env"
        return result
    if not isinstance(candidate_summary, dict) or candidate_summary.get("status") == "failed":
        result["reason"] = "candidate_generation_unavailable"
        return result
    formal_health = _experiment_formal_publish_health(experiment_id)
    if formal_health.get("status") == "blocked":
        result.update(
            {
                "status": "skipped",
                "reason": formal_health.get("reason") or "formal_publish_blocked",
                "formal_publish_health": formal_health,
                "policy": "正式素材发布要求 first/third 同一时间窗内存在确认动作事件；单视角或错位动作只保留为调试证据。",
            }
        )
        return result

    def is_paired_view_context(row: Dict[str, Any]) -> bool:
        return (
            str(row.get("physical_evidence_mode") or "") == "paired_view_time_alignment"
            or str(row.get("candidate_source") or "")
            in {"paired_view_micro_segment_key_asset_reference", "paired_view_time_alignment"}
            or str(row.get("box_filter") or "") == "paired_view_time_alignment_asset_reference"
        )

    def is_strict_yolo_evidence(row: Dict[str, Any]) -> bool:
        return str(row.get("physical_evidence_mode") or "") == "strict_yolo_physical_evidence"

    def is_explicit_dual_event_sparse_evidence(row: Dict[str, Any]) -> bool:
        if str(row.get("physical_evidence_mode") or "") != "sparse_yolo_interaction_review_required":
            return False
        return bool(str(row.get("dual_event_id") or row.get("dual_view_action_event_id") or "").strip())

    allow_paired_context_companions = os.environ.get(
        "KEY_ACTION_AUTO_PUBLISH_PAIRED_VIEW_CONTEXT_MATERIAL",
        "1",
    ).strip().lower() not in {"0", "false", "no", "off"}
    rows = _material_candidate_rows(experiment_id)
    eligible_ids: List[str] = []
    eligible_group_ids: set[str] = set()
    for row in rows:
        if row.get("recommended") is not True:
            continue
        if row.get("exists") is False:
            continue
        candidate_id = str(row.get("candidate_id") or "").strip()
        if not candidate_id:
            continue
        candidate_status = str(row.get("candidate_status") or "pending").lower()
        review_status = str(row.get("review_status") or "pending").lower()
        if candidate_status in {"rejected", "not_selected"} or review_status in {"rejected", "not_selected"}:
            continue
        if not is_strict_yolo_evidence(row):
            continue
        yolo_recheck = row.get("yolo_recheck") if isinstance(row.get("yolo_recheck"), dict) else {}
        if str(yolo_recheck.get("status") or "").lower() != "passed":
            continue
        pipeline_status = str(row.get("pipeline_status") or "").lower()
        if pipeline_status not in {"vlm_assisted_yolo_recheck_passed", "yolo_recheck_passed_frontend_review_required"}:
            continue
        vlm_semantics = row.get("vlm_semantics") if isinstance(row.get("vlm_semantics"), dict) else {}
        if str(vlm_semantics.get("status") or "").lower() in {"error", "uncertain_vlm_review", "weak_but_yolo_preserved"}:
            continue
        eligible_ids.append(candidate_id)
        group_id = str(row.get("candidate_group_id") or "").strip()
        if group_id:
            eligible_group_ids.add(group_id)

    companion_count = 0
    if eligible_group_ids:
        for row in rows:
            if str(row.get("candidate_group_id") or "").strip() not in eligible_group_ids:
                continue
            if row.get("exists") is False:
                continue
            paired_context = is_paired_view_context(row)
            if paired_context:
                if not allow_paired_context_companions:
                    continue
                try:
                    from key_action_indexer.material_references import paired_view_context_scene_gate_passed  # type: ignore
                except Exception:
                    paired_view_context_scene_gate_passed = None  # type: ignore
                if paired_view_context_scene_gate_passed is None or not paired_view_context_scene_gate_passed(row):  # type: ignore[misc]
                    continue
            elif not (is_strict_yolo_evidence(row) or is_explicit_dual_event_sparse_evidence(row)):
                continue
            candidate_id = str(row.get("candidate_id") or "").strip()
            if candidate_id and candidate_id not in eligible_ids:
                eligible_ids.append(candidate_id)
                companion_count += 1

    result["eligible_count"] = len(eligible_ids)
    result["eligible_group_count"] = len(eligible_group_ids)
    result["paired_companion_count"] = companion_count
    try:
        from key_action_indexer.material_references import (  # type: ignore
            apply_formal_dual_view_material_publish_gate,
            filter_aligned_dual_view_material_rows,
            filter_complete_dual_view_material_rows,
        )

        os.environ.setdefault("KEY_ACTION_REQUIRE_DUAL_VIEW_COMPLETE_MATERIAL_GROUPS", "1")
        eligible_rows = [
            dict(row)
            for row in rows
            if str(row.get("candidate_id") or "").strip() in set(eligible_ids)
        ]
        complete_rows = filter_aligned_dual_view_material_rows(
            _key_action_output_dir(experiment_id),
            filter_complete_dual_view_material_rows(eligible_rows),
        )
        complete_rows, formal_gate_suppressed = apply_formal_dual_view_material_publish_gate(
            _key_action_output_dir(experiment_id),
            complete_rows,
        )
        if formal_gate_suppressed:
            result["formal_dual_view_gate_filtered_count"] = len(formal_gate_suppressed)
        complete_ids = [
            str(row.get("candidate_id") or "").strip()
            for row in complete_rows
            if str(row.get("candidate_id") or "").strip()
        ]
        if set(complete_ids) != set(eligible_ids):
            result["dual_view_incomplete_filtered_count"] = len(set(eligible_ids)) - len(set(complete_ids))
        if eligible_ids and not complete_ids:
            result["dual_view_alignment_filtered_count"] = len(set(eligible_ids))
        eligible_ids = sorted(set(complete_ids))
        result["eligible_count"] = len(eligible_ids)
        result["dual_view_complete_group_count"] = len({
            str(row.get("candidate_group_id") or "").strip()
            for row in complete_rows
            if str(row.get("candidate_group_id") or "").strip()
        })
    except Exception as exc:
        logger.warning("Dual-view complete material filter skipped for %s: %s", experiment_id, exc)
    if not eligible_ids:
        result["reason"] = "no_complete_dual_view_material_groups"
        return result

    try:
        from key_action_indexer.material_references import approve_material_candidates  # type: ignore

        approval = approve_material_candidates(
            _key_action_output_dir(experiment_id),
            candidate_ids=eligible_ids,
            reviewer="key_action_pipeline",
            notes="Auto-published recommended YOLO/VLM-passed material candidates after upload analysis.",
        )
    except Exception as exc:
        logger.exception("Key-action material auto-publish failed for experiment %s", experiment_id)
        result.update({"status": "failed", "error": str(exc)})
        return result

    exp_dir = _experiment_output_dir(experiment_id)
    published_materials = _sync_published_materials_from_references(exp_dir, experiment_id)
    approved_count = int(approval.get("approved_count") or 0) if isinstance(approval, dict) else 0
    workspace_reindex = _rebuild_workspace_published_materials_index_quietly() if approved_count else {"status": "skipped", "reason": "no_approved_candidates"}
    result.update(
        {
            "status": "completed",
            "approved_count": approved_count,
            "approval": approval,
            "published_materials": published_materials,
            "workspace_published_materials_reindex": workspace_reindex,
        }
    )
    return result


def _first_non_empty(*values: Any) -> str:
    for value in values:
        if isinstance(value, str):
            value = value.strip()
        if value is None or value == "":
            continue
        text = str(value).strip()
        if text:
            return text
    return ""


def _material_window_id_for_item(item: Dict[str, Any]) -> str:
    return _first_non_empty(item.get("window_id"), item.get("experiment_window_id"), item.get("segment_id"))


def _material_window_artifact_path(exp_dir: Path, value: Any) -> str:
    if value is None:
        return ""
    text = str(value).strip()
    if not text:
        return ""
    if text.startswith(("http://", "https://", "/api/")):
        return ""
    path = Path(text)
    return str(path if path.is_absolute() else exp_dir / path)


def _material_window_artifact_exists(exp_dir: Path, value: Any) -> bool:
    path = _material_window_artifact_path(exp_dir, value)
    if not path:
        return False
    try:
        return Path(path).exists()
    except OSError:
        return False


def _material_window_contract_item(item: Dict[str, Any]) -> Dict[str, Any]:
    window_id = _material_window_id_for_item(item)
    segment_id = _first_non_empty(item.get("segment_id"), window_id)
    experiment_window_id = _first_non_empty(item.get("experiment_window_id"), window_id)
    source_window_sync_index = _first_non_empty(
        item.get("source_window_sync_index"),
        item.get("window_sync_index"),
    )
    window_preview = _first_non_empty(
        item.get("window_preview"),
        item.get("preview"),
        item.get("window_preview_path"),
    )
    sample_grid = _first_non_empty(
        item.get("sample_grid"),
        item.get("sample_grid_path"),
        item.get("preview_poster"),
        item.get("poster"),
    )
    review_status = _first_non_empty(item.get("review_status"), item.get("material_status"), item.get("status"), "candidate_review")
    official_status = _first_non_empty(item.get("official_status"), item.get("status"))
    keyframe_quality_score = item.get("keyframe_quality_score")
    if keyframe_quality_score is None:
        keyframe_quality_score = item.get("selected_keyframe_score")
    if keyframe_quality_score is None:
        keyframe_quality_score = item.get("best_keyframe_score")
    if keyframe_quality_score is None:
        keyframe_quality_score = item.get("best_score")
    if keyframe_quality_score is None:
        keyframe_quality_score = item.get("quality_score")
    cli_ready_folder = _first_non_empty(item.get("cli_ready_folder"), item.get("cli_ready"), item.get("cli_folder"))
    evidence_bundle_id = _first_non_empty(item.get("evidence_bundle_id"), item.get("evidence_id"))
    orphan_material = not window_id or not source_window_sync_index
    return {
        **item,
        "window_id": window_id or item.get("window_id"),
        "segment_id": segment_id or item.get("segment_id"),
        "experiment_window_id": experiment_window_id or item.get("experiment_window_id"),
        "source_window_sync_index": source_window_sync_index or item.get("source_window_sync_index"),
        "window_preview": window_preview or item.get("window_preview"),
        "sample_grid": sample_grid or item.get("sample_grid"),
        "review_status": review_status or item.get("review_status"),
        "official_status": official_status or item.get("official_status"),
        "keyframe_quality_score": keyframe_quality_score if keyframe_quality_score is not None else item.get("keyframe_quality_score"),
        "cli_ready_folder": cli_ready_folder or item.get("cli_ready_folder"),
        "evidence_bundle_id": evidence_bundle_id or item.get("evidence_bundle_id"),
        "orphan_material": orphan_material,
    }


def _canonicalize_published_material_payload(payload: Dict[str, Any]) -> Dict[str, Any]:
    items = payload.get("items") if isinstance(payload, dict) else []
    if not isinstance(items, list):
        return payload
    canonical_items = [enrich_material_taxonomy(item) if isinstance(item, dict) else item for item in items]
    scored_items = enrich_material_best_scores([item for item in canonical_items if isinstance(item, dict)])
    scored_iter = iter(scored_items)
    canonical_items = [next(scored_iter) if isinstance(item, dict) else item for item in canonical_items]
    return {**payload, "items": canonical_items, "taxonomy": list(STANDARD_MATERIAL_ACTION_TYPES)}


def _normalize_published_window_fields(payload: Dict[str, Any], exp_dir: Path) -> Dict[str, Any]:
    if not isinstance(payload, dict):
        return payload
    items = payload.get("items") if isinstance(payload, dict) else []
    if not isinstance(items, list):
        return payload
    normalized_items = [_material_window_contract_item(item) if isinstance(item, dict) else item for item in items]
    grouped_items = payload.get("grouped_items")
    normalized_grouped_items = (
        [
            _material_window_contract_item(item) if isinstance(item, dict) else item
            for item in grouped_items
        ]
        if isinstance(grouped_items, list)
        else grouped_items
    )
    return {**payload, "items": normalized_items, "grouped_items": normalized_grouped_items}


def _write_material_window_dependency_report(exp_dir: Path, payload: Dict[str, Any]) -> Dict[str, Any]:
    items = payload.get("items") if isinstance(payload, dict) else []
    material_items = [item for item in (items if isinstance(items, list) else []) if isinstance(item, dict)]
    missing_refs: List[Dict[str, Any]] = []
    missing_artifacts: List[Dict[str, Any]] = []
    for item in material_items:
        material_id = _first_non_empty(item.get("material_id"), item.get("item_id"), item.get("event_id"), str(len(missing_refs) + 1))
        window_id = str(item.get("window_id") or "").strip()
        sync_index = str(item.get("source_window_sync_index") or "").strip()
        has_preview = _material_window_artifact_exists(exp_dir, item.get("window_preview"))
        has_sample_grid = _material_window_artifact_exists(exp_dir, item.get("sample_grid"))
        if not window_id or not sync_index:
            missing_refs.append({"material_id": material_id, "window_id": window_id, "source_window_sync_index": sync_index})
        if window_id and not has_preview and not has_sample_grid:
            missing_artifacts.append({"material_id": material_id, "window_id": window_id})
    report = {
        "material_count": len(material_items),
        "material_with_window_id_count": sum(1 for item in material_items if str(item.get("window_id") or "").strip()),
        "material_with_source_window_sync_index_count": sum(1 for item in material_items if str(item.get("source_window_sync_index") or "").strip()),
        "material_with_window_preview_count": sum(1 for item in material_items if _material_window_artifact_exists(exp_dir, item.get("window_preview"))),
        "material_with_sample_grid_count": sum(1 for item in material_items if _material_window_artifact_exists(exp_dir, item.get("sample_grid"))),
        "orphan_material_count": sum(1 for item in material_items if bool(item.get("orphan_material"))),
        "materials_missing_window_refs": missing_refs,
        "materials_missing_window_artifacts": missing_artifacts,
        "status": "ok" if not missing_refs and not missing_artifacts else "needs_attention",
    }
    _write_json(exp_dir / "material_window_dependency_report.json", report)
    return {**payload, "material_window_dependency_report": report}


STANDARD_MATERIAL_ACTION_TYPES = (
    "hand-bottle",
    "hand-balance",
    "hand-spatula",
    "hand-paper",
    "hand-container",
)


MATERIAL_VISUAL_REVIEW_STATUSES = {
    "unreviewed",
    "confirmed_best",
    "needs_replacement",
    "unusable",
}


def _material_quality_review_path(experiment_id: str) -> Path:
    return _experiment_output_dir(experiment_id) / "material_quality_review.json"


def _video_playback_calibration_path(experiment_id: str) -> Path:
    return _experiment_output_dir(experiment_id) / "video_playback_calibration.json"


def _empty_video_playback_calibration(experiment_id: str) -> Dict[str, Any]:
    return {
        "schema_version": "video_playback_calibration.v1",
        "experiment_id": experiment_id,
        "offset_adjust_sec": 0.0,
        "updated_at": None,
        "updated_by": None,
        "note": None,
        "history": [],
    }


def _read_video_playback_calibration(experiment_id: str) -> Dict[str, Any]:
    payload = _load_json_if_exists(_video_playback_calibration_path(experiment_id))
    base = _empty_video_playback_calibration(experiment_id)
    if not isinstance(payload, dict):
        return base
    try:
        offset_adjust_sec = float(payload.get("offset_adjust_sec") or 0.0)
    except (TypeError, ValueError):
        offset_adjust_sec = 0.0
    history = payload.get("history") if isinstance(payload.get("history"), list) else []
    return {
        **base,
        **{key: value for key, value in payload.items() if key not in {"offset_adjust_sec", "history"}},
        "schema_version": "video_playback_calibration.v1",
        "experiment_id": experiment_id,
        "offset_adjust_sec": round(offset_adjust_sec, 3),
        "history": history[-50:],
    }


def _write_video_playback_calibration(
    experiment_id: str,
    *,
    offset_adjust_sec: float,
    reviewer: Optional[str],
    note: Optional[str],
    reset: bool = False,
) -> Dict[str, Any]:
    previous = _read_video_playback_calibration(experiment_id)
    timestamp = datetime.now(timezone.utc).isoformat()
    history = list(previous.get("history") or [])
    history.append(
        {
            "changed_at": timestamp,
            "changed_by": reviewer or "operator",
            "previous_offset_adjust_sec": previous.get("offset_adjust_sec", 0.0),
            "next_offset_adjust_sec": round(float(offset_adjust_sec), 3),
            "reset": bool(reset),
            "note": note,
        }
    )
    payload = {
        **previous,
        "schema_version": "video_playback_calibration.v1",
        "experiment_id": experiment_id,
        "offset_adjust_sec": round(float(offset_adjust_sec), 3),
        "updated_at": timestamp,
        "updated_by": reviewer or "operator",
        "note": note,
        "history": history[-50:],
    }
    _write_json(_video_playback_calibration_path(experiment_id), payload)
    return payload


def _empty_material_quality_review(experiment_id: str) -> Dict[str, Any]:
    return {
        "schema_version": "material_quality_review.v1",
        "experiment_id": experiment_id,
        "updated_at": None,
        "reviews": {
            action: {
                "status": "unreviewed",
                "preferred_item_id": None,
                "reviewed_at": None,
                "reviewed_by": None,
                "note": None,
                "reason": None,
            }
            for action in STANDARD_MATERIAL_ACTION_TYPES
        },
    }


def _read_material_quality_review(experiment_id: str) -> Dict[str, Any]:
    payload = _load_json_if_exists(_material_quality_review_path(experiment_id))
    base = _empty_material_quality_review(experiment_id)
    if not isinstance(payload, dict):
        return base
    raw_reviews = payload.get("reviews") if isinstance(payload.get("reviews"), dict) else {}
    reviews = dict(base["reviews"])
    for action in STANDARD_MATERIAL_ACTION_TYPES:
        raw = raw_reviews.get(action) if isinstance(raw_reviews.get(action), dict) else {}
        status = str(raw.get("status") or "unreviewed").strip()
        if status not in MATERIAL_VISUAL_REVIEW_STATUSES:
            status = "unreviewed"
        reviews[action] = {
            "status": status,
            "preferred_item_id": raw.get("preferred_item_id"),
            "reviewed_at": raw.get("reviewed_at"),
            "reviewed_by": raw.get("reviewed_by"),
            "note": raw.get("note"),
            "reason": raw.get("reason"),
        }
    return {
        **base,
        **{key: value for key, value in payload.items() if key != "reviews"},
        "schema_version": "material_quality_review.v1",
        "experiment_id": experiment_id,
        "reviews": reviews,
    }


def _material_identity_values(item: Dict[str, Any]) -> set[str]:
    paths = item.get("published_paths") if isinstance(item.get("published_paths"), dict) else {}
    values: set[str] = set()
    for value in (
        item.get("public_item_id"),
        item.get("item_id"),
        item.get("candidate_id"),
        item.get("material_id"),
        item.get("event_id"),
        item.get("display_name"),
        item.get("stored_file"),
        item.get("source_candidate_file"),
        item.get("source_reference_file"),
        paths.get("clip"),
        paths.get("preview"),
        paths.get("keyframe"),
    ):
        if value is not None and str(value).strip():
            values.add(str(value))
            values.add(Path(str(value)).name)
    return values


def _material_public_item_id(item: Dict[str, Any]) -> str:
    for value in (item.get("item_id"), item.get("candidate_id"), item.get("material_id"), item.get("event_id")):
        if value is not None and str(value).strip():
            return str(value)
    paths = item.get("published_paths") if isinstance(item.get("published_paths"), dict) else {}
    for value in (paths.get("preview"), paths.get("keyframe"), paths.get("clip"), item.get("display_name")):
        if value is not None and str(value).strip():
            return str(value)
    return hashlib.sha1(json.dumps(item, ensure_ascii=False, sort_keys=True, default=str).encode("utf-8")).hexdigest()[:16]


def _apply_material_quality_reviews(experiment_id: str, payload: Dict[str, Any]) -> Dict[str, Any]:
    if not isinstance(payload, dict):
        return payload
    items = payload.get("items") if isinstance(payload.get("items"), list) else []
    review = _read_material_quality_review(experiment_id)
    reviews = review.get("reviews") if isinstance(review.get("reviews"), dict) else {}
    next_items: List[Dict[str, Any]] = []
    for item in items:
        if not isinstance(item, dict):
            next_items.append(item)
            continue
        enriched = dict(item)
        action = str(enriched.get("canonical_action_type") or "")
        record = reviews.get(action) if isinstance(reviews.get(action), dict) else {}
        preferred_id = record.get("preferred_item_id")
        enriched["public_item_id"] = _material_public_item_id(enriched)
        enriched["visual_review_status"] = record.get("status") or "unreviewed"
        enriched["visual_review_note"] = record.get("note")
        enriched["visual_review_reason"] = record.get("reason")
        enriched["visual_reviewed_at"] = record.get("reviewed_at")
        enriched["visual_reviewed_by"] = record.get("reviewed_by")
        enriched["preferred_best"] = bool(preferred_id and str(preferred_id) in _material_identity_values(enriched))
        next_items.append(enriched)
    return {**payload, "items": next_items, "quality_review": review}


def _experiment_time_axis_health(experiment_id: str) -> Dict[str, Any]:
    output_dir = _experiment_output_dir(experiment_id)
    metadata_dir = _key_action_output_dir(experiment_id) / "metadata"
    candidates = [
        metadata_dir / "time_axis_health.json",
        metadata_dir / "pre_coarse_timeline_alignment.json",
        output_dir / "timeline_alignment.json",
    ]
    for candidate in candidates:
        payload = _load_json_if_exists(candidate)
        if not isinstance(payload, dict) or not payload:
            continue
        health = payload.get("time_axis_health") if isinstance(payload.get("time_axis_health"), dict) else payload
        status = str(
            health.get("status")
            or health.get("time_axis_health_status")
            or payload.get("status")
            or payload.get("alignment_status")
            or ""
        ).strip()
        unreliable = bool(
            health.get("time_axis_unreliable")
            or payload.get("time_axis_unreliable")
            or status == "time_axis_unreliable"
            or payload.get("gate_failure_reason") == "time_axis_unreliable"
        )
        reasons = health.get("reasons")
        if not isinstance(reasons, list):
            reasons = payload.get("reliability_reasons") if isinstance(payload.get("reliability_reasons"), list) else []
        return {
            "schema_version": "time_axis_health_gate.v1",
            "status": status or ("time_axis_unreliable" if unreliable else "unknown"),
            "time_axis_unreliable": unreliable,
            "can_publish_formal_materials": bool(health.get("can_publish_formal_materials", not unreliable)) and not unreliable,
            "can_write_video_memory": bool(health.get("can_write_video_memory", not unreliable)) and not unreliable,
            "source_path": str(candidate),
            "reasons": reasons,
            "raw": health,
        }
    return {
        "schema_version": "time_axis_health_gate.v1",
        "status": "not_checked",
        "time_axis_unreliable": False,
        "can_publish_formal_materials": True,
        "can_write_video_memory": True,
        "source_path": None,
        "reasons": [],
        "raw": {},
    }


def _experiment_formal_publish_health(experiment_id: str) -> Dict[str, Any]:
    output_dir = _key_action_output_dir(experiment_id)
    metadata_dir = output_dir / "metadata"
    time_axis_health = _experiment_time_axis_health(experiment_id)
    dual_summary_path = metadata_dir / "dual_view_action_alignment_summary.json"
    dual_summary = _load_json_if_exists(dual_summary_path) or {}
    dual_event_count = _jsonl_row_count(metadata_dir / "dual_view_action_events.jsonl")
    if isinstance(dual_summary, dict) and dual_summary.get("dual_view_action_event_count") is not None:
        try:
            dual_event_count = int(float(dual_summary.get("dual_view_action_event_count") or 0))
        except (TypeError, ValueError):
            dual_event_count = 0
    unmatched_count = _jsonl_row_count(metadata_dir / "unmatched_view_evidence.jsonl")
    if isinstance(dual_summary, dict) and dual_summary.get("unmatched_view_evidence_count") is not None:
        try:
            unmatched_count = int(float(dual_summary.get("unmatched_view_evidence_count") or 0))
        except (TypeError, ValueError):
            pass
    aligned_episode_count = _jsonl_row_count(metadata_dir / "dual_view_aligned_experiment_episodes.jsonl")
    activity_aligned_episode_count = _jsonl_row_count(metadata_dir / "dual_view_activity_aligned_experiment_episodes.jsonl")
    official_segment_count = _jsonl_row_count(metadata_dir / "key_action_segments.jsonl")
    candidate_segment_count = _jsonl_row_count(metadata_dir / "candidate_action_windows.jsonl")
    reasons: List[str] = []
    status = "passed"
    reason = "formal_publish_allowed"
    if time_axis_health.get("time_axis_unreliable") or not bool(time_axis_health.get("can_publish_formal_materials", True)):
        status = "blocked"
        reason = "time_axis_unreliable"
        reasons.extend(str(item) for item in (time_axis_health.get("reasons") or []) if str(item).strip())
    elif dual_summary_path.exists():
        formal_allowed = bool(dual_summary.get("formal_results_allowed")) if isinstance(dual_summary, dict) else False
        if dual_event_count <= 0 or not formal_allowed:
            if activity_aligned_episode_count > 0 and official_segment_count > 0:
                status = "segments_only"
                reason = "dual_view_activity_segments_without_action_specific_materials"
                reasons.append("已形成 first/third 同一时间窗内的实验活动片段，但尚未形成可发布的动作级关键素材。")
            else:
                status = "blocked"
                reason = "no_confirmed_dual_view_action_events"
                reasons.append("未形成 first/third 同一时间窗内的确认动作事件。")
        elif aligned_episode_count <= 0 or official_segment_count <= 0:
            status = "blocked"
            reason = "no_formal_dual_view_action_episodes"
            reasons.append("已检测到动作证据，但尚未形成可展示的正式双视角实验片段。")
    else:
        status = "not_checked"
        reason = "dual_view_action_alignment_not_checked"
        reasons.append("尚未生成双视角动作对齐结果。")

    can_publish = status == "passed"
    can_publish_segments = status in {"passed", "segments_only"}
    return {
        "schema_version": "formal_publish_health.v1",
        "status": status,
        "reason": reason,
        "reasons": reasons,
        "can_publish_formal_segments": can_publish_segments,
        "can_publish_formal_materials": can_publish,
        "can_write_video_memory": can_publish,
        "time_axis": time_axis_health,
        "action_alignment": {
            "status": "passed" if dual_event_count > 0 and status == "passed" else ("blocked" if status == "blocked" else status),
            "dual_view_action_event_count": dual_event_count,
            "unmatched_view_evidence_count": unmatched_count,
            "aligned_episode_count": aligned_episode_count,
            "activity_aligned_episode_count": activity_aligned_episode_count,
            "formal_results_allowed": bool(dual_summary.get("formal_results_allowed")) if isinstance(dual_summary, dict) else False,
            "decision": dual_summary.get("decision") if isinstance(dual_summary, dict) else None,
            "source_path": str(dual_summary_path) if dual_summary_path.exists() else None,
        },
        "official_segment_count": official_segment_count if can_publish_segments else 0,
        "raw_official_segment_count": official_segment_count,
        "activity_aligned_episode_count": activity_aligned_episode_count,
        "candidate_segment_count": candidate_segment_count,
        "dual_view_action_event_count": dual_event_count,
        "unmatched_view_evidence_count": unmatched_count,
        "user_message_zh": (
            "双视角动作证据未对齐：只有 first/third 同一时间窗内都出现确认动作，才允许生成正式实验片段、正式关键素材和 30 天态势记忆。"
            if status == "blocked" and reason != "time_axis_unreliable"
            else "已形成双视角实验活动片段；动作级关键素材和 30 天态势记忆仍等待更强的双视角动作证据。"
            if status == "segments_only"
            else "时间轴健康检查未通过：采集时间轴与视频播放 PTS 不一致，结果已从正式展示和 30 天态势记忆中隔离。"
            if reason == "time_axis_unreliable"
            else ""
        ),
    }


def _apply_published_material_alignment_gate(experiment_id: str, payload: Dict[str, Any]) -> Dict[str, Any]:
    items = payload.get("items") if isinstance(payload.get("items"), list) else []
    all_items = items[:] if isinstance(items, list) else []
    # Demo presentation bypass: surface already-confirmed key materials without
    # the strict dual-view completeness filtering (which requires both first &
    # third person keyframe+clip per group). Off by default; the imported
    # catalog assets are single-view but individually confirmed/visual_confirmed,
    # so for the demo they should be shown. Disable by unsetting the env.
    if os.environ.get("KEY_ACTION_DEMO_SHOW_ALL_PUBLISHED", "0").strip().lower() in {"1", "true", "yes", "on"}:
        dict_items = [item for item in items if isinstance(item, dict)]
        return {
            **payload,
            "items": dict_items,
            "grouped_items": _group_material_reference_assets(dict_items),
            "total": len(dict_items),
            "returned": len(dict_items),
            "all_items": all_items,
            "alignment_gate": {
                "schema_version": "published_material_alignment_gate.v1",
                "status": "demo_show_all",
                "reason": "demo_presentation_bypass",
                "visible_item_count": len(dict_items),
            },
        }
    time_axis_health = _experiment_time_axis_health(experiment_id)
    formal_health = _experiment_formal_publish_health(experiment_id)
    if formal_health.get("status") == "blocked" or not bool(formal_health.get("can_publish_formal_materials", False)):
        return {
            **payload,
            "items": [],
            "grouped_items": [],
            "total": 0,
            "returned": 0,
            "all_items": all_items,
            "time_axis_health": time_axis_health,
            "formal_publish_health": formal_health,
            "alignment_gate": {
                "schema_version": "published_material_alignment_gate.v1",
                "status": "blocked",
                "reason": formal_health.get("reason") or "formal_publish_blocked",
                "hidden_item_count": len(items),
                "hidden_incomplete_dual_view_item_count": 0,
                "complete_dual_view_item_count": 0,
            },
        }
    if not items:
        return {
            **payload,
            "time_axis_health": time_axis_health,
            "formal_publish_health": formal_health,
            "all_items": all_items,
            "alignment_gate": {
                "schema_version": "published_material_alignment_gate.v1",
                "status": "empty",
                "reason": "no_published_materials",
                "hidden_item_count": 0,
                "hidden_incomplete_dual_view_item_count": 0,
                "complete_dual_view_item_count": 0,
            },
        }
    if time_axis_health.get("time_axis_unreliable"):
        return {
            **payload,
            "items": [],
            "grouped_items": [],
            "total": 0,
            "returned": 0,
            "all_items": all_items,
            "time_axis_health": time_axis_health,
            "alignment_gate": {
                "schema_version": "published_material_alignment_gate.v1",
                "status": "blocked",
                "reason": "time_axis_unreliable",
                "hidden_item_count": len(items),
                "hidden_incomplete_dual_view_item_count": 0,
                "complete_dual_view_item_count": 0,
            },
        }
    filtered_items = items
    hidden_incomplete_count = 0
    formal_rejected_count = 0
    def _has_passed_formal_publish_gate(item: Dict[str, Any]) -> bool:
        payload_item = item.get("payload") if isinstance(item.get("payload"), dict) else {}
        gate = item.get("formal_publish_gate")
        if not isinstance(gate, dict):
            gate = payload_item.get("formal_publish_gate") if isinstance(payload_item.get("formal_publish_gate"), dict) else {}
        dual_event_id = (
            item.get("dual_event_id")
            or item.get("dual_view_action_event_id")
            or payload_item.get("dual_event_id")
            or payload_item.get("dual_view_action_event_id")
        )
        return str(gate.get("status") or "").strip().lower() == "passed" and bool(str(dual_event_id or "").strip())

    dict_items = [item for item in items if isinstance(item, dict)]
    if dict_items and all(_has_passed_formal_publish_gate(item) for item in dict_items):
        filtered_items = dict_items
    else:
        try:
            from key_action_indexer.material_references import apply_formal_dual_view_material_publish_gate  # type: ignore

            filtered_items, formal_rejected = apply_formal_dual_view_material_publish_gate(
                _key_action_output_dir(experiment_id),
                dict_items,
            )
            formal_rejected_count = len(formal_rejected)
        except Exception:
            logger.debug("Published material formal dual-view action gate unavailable", exc_info=True)
            filtered_items = dict_items
    strict_filtered_items = _filter_complete_dual_view_key_material_items(filtered_items)
    hidden_incomplete_count = max(0, len(items) - len(strict_filtered_items))
    filtered_items = strict_filtered_items
    try:
        from key_action_indexer.material_references import session_has_reliable_dual_view_alignment  # type: ignore

        reliable = session_has_reliable_dual_view_alignment(_key_action_output_dir(experiment_id))
    except Exception:
        reliable = False
    if os.environ.get("KEY_ACTION_REQUIRE_RELIABLE_DUAL_VIEW_ALIGNMENT", "1").strip().lower() in {"0", "false", "no", "off"}:
        reliable = True
    if reliable:
        result = {
            **payload,
            "items": filtered_items,
            "grouped_items": _group_material_reference_assets(filtered_items),
            "total": len(filtered_items),
            "returned": len(filtered_items),
            "all_items": all_items,
        }
        if hidden_incomplete_count:
            result["dual_view_quality_gate"] = {
                "schema_version": "published_material_dual_view_quality_gate.v1",
                "status": "filtered",
                "reason": "formal_dual_view_action_or_complete_asset_gate_failed",
                "hidden_item_count": hidden_incomplete_count,
                "hidden_formal_gate_item_count": formal_rejected_count,
                "visible_item_count": len(filtered_items),
            }
        return result
        return {
            **payload,
            "items": [],
            "grouped_items": [],
            "total": 0,
            "returned": 0,
            "all_items": all_items,
            "alignment_gate": {
                "schema_version": "published_material_alignment_gate.v1",
                "status": "blocked",
                "reason": "timeline_alignment_not_reliable_for_dual_view_materials",
                "hidden_item_count": len(items),
            "hidden_incomplete_dual_view_item_count": hidden_incomplete_count,
            "complete_dual_view_item_count": len(filtered_items),
        },
    }


def _published_material_items(exp_dir: Path, experiment_id: str) -> Dict[str, Any]:
    payload = _load_json_if_exists(exp_dir / "published_materials.json")
    if isinstance(payload, dict) and payload.get("items"):
        normalized_payload = _normalize_published_window_fields(
            _apply_material_quality_reviews(experiment_id, _canonicalize_published_material_payload(payload)),
            exp_dir,
        )
        normalized_payload = _write_material_window_dependency_report(exp_dir, normalized_payload)
        return _apply_published_material_alignment_gate(
            experiment_id,
            normalized_payload,
        )
    fallback = _material_reference_items(exp_dir, experiment_id)
    try:
        from labsopguard.material_publishing import SemanticMaterialPublisher

        listed = SemanticMaterialPublisher(exp_dir, experiment_id=experiment_id).list_published()
        if isinstance(listed, dict) and listed.get("items"):
            normalized_payload = _normalize_published_window_fields(
                _apply_material_quality_reviews(experiment_id, _canonicalize_published_material_payload(listed)),
                exp_dir,
            )
            normalized_payload = _write_material_window_dependency_report(exp_dir, normalized_payload)
            return _apply_published_material_alignment_gate(
                experiment_id,
                normalized_payload,
            )
    except Exception:
        logger.debug("Published material listing unavailable; falling back to material_references", exc_info=True)
    if fallback.get("items"):
        normalized_fallback = _normalize_published_window_fields(
            _apply_material_quality_reviews(experiment_id, fallback),
            exp_dir,
        )
        normalized_fallback = _write_material_window_dependency_report(exp_dir, normalized_fallback)
        return _apply_published_material_alignment_gate(experiment_id, normalized_fallback)
    return (
        _apply_published_material_alignment_gate(
            experiment_id,
            _write_material_window_dependency_report(
                exp_dir,
                _normalize_published_window_fields(
                    _apply_material_quality_reviews(experiment_id, _canonicalize_published_material_payload(payload)),
                    exp_dir,
                ),
            ),
        )
        if isinstance(payload, dict)
        else fallback
    )


def _sync_published_materials_from_references(exp_dir: Path, experiment_id: str) -> Dict[str, Any]:
    payload = _material_reference_items(exp_dir, experiment_id)
    payload = {
        **payload,
        "schema_version": "published_materials.approved_material_references.v1",
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "total": len(payload.get("items") or []),
        "taxonomy": list(STANDARD_MATERIAL_ACTION_TYPES),
        "policy": "Only frontend-approved keyframes and key clips are synchronized into the key material library. Professional PDF reports are approved into the professional report folder only.",
    }
    _write_json(exp_dir / "published_materials.json", payload)
    _write_material_taxonomy_calibration_report(experiment_id, payload)
    return payload


def _professional_report_basename() -> str:
    raw = os.environ.get("PROFESSIONAL_REPORT_BASENAME", "professional_report_qwen36max").strip()
    cleaned = re.sub(r"[^A-Za-z0-9_.-]+", "_", raw).strip("._")
    return cleaned or "professional_report_qwen36max"


def _professional_report_output_paths(experiment_id: str) -> Dict[str, Path]:
    reports_dir = _experiment_output_dir(experiment_id) / "reports"
    base = _professional_report_basename()
    return {
        "pdf": reports_dir / f"{base}.pdf",
        "html": reports_dir / f"{base}.html",
        "json": reports_dir / f"{base}.json",
        "manifest": reports_dir / "professional_report_manifest.json",
    }


def _professional_report_materials_payload(experiment_id: str) -> Dict[str, Any]:
    exp_dir = _experiment_output_dir(experiment_id)
    seen: Dict[str, Dict[str, Any]] = {}

    def add_report(path: Path, *, source: str, role: str) -> None:
        if not path.exists() or not path.is_file():
            return
        key = str(path.resolve())
        seen[key] = {
            "report_id": hashlib.sha1(key.encode("utf-8", errors="ignore")).hexdigest()[:12],
            "experiment_id": experiment_id,
            "role": role,
            "source": source,
            "file_name": path.name,
            "path": str(path),
            "size_bytes": path.stat().st_size,
            "updated_at": datetime.fromtimestamp(path.stat().st_mtime, timezone.utc).isoformat(),
            "url": _experiment_file_api_path(path, experiment_id),
            "grid_policy": "professional_report_only",
        }

    for role, path in _professional_report_output_paths(experiment_id).items():
        add_report(path, source="experiment_reports", role=f"professional_report_{role}")

    for root in _material_reference_root_candidates(exp_dir):
        report_dir = root / "专业报告"
        if not report_dir.exists():
            continue
        for path in sorted(report_dir.iterdir()):
            add_report(path, source="formal_material_reference_report_folder", role="professional_report_material_reference")

    candidate_report_dir = _material_candidate_root(experiment_id) / "专业报告"
    if candidate_report_dir.exists():
        for path in sorted(candidate_report_dir.iterdir()):
            add_report(path, source="candidate_report_folder", role="professional_report_candidate")

    items = sorted(seen.values(), key=lambda item: (str(item["source"]), str(item["file_name"])))
    return {
        "schema_version": "professional_report_materials.v1",
        "experiment_id": experiment_id,
        "total": len(items),
        "items": items,
        "policy": "Professional reports are listed through this endpoint and are excluded from the formal key material grid.",
    }


def _professional_report_enabled() -> bool:
    return os.environ.get("EXPERIMENT_PROFESSIONAL_REPORT_ENABLED", "1").strip().lower() not in {"0", "false", "no", "off"}


def _experiment_file_api_path(path: Path, experiment_id: str) -> Optional[str]:
    resolved_path = path.resolve()
    exp_dir = _experiment_output_dir(experiment_id)
    try:
        rel = resolved_path.relative_to(exp_dir.resolve())
    except ValueError:
        pass
    else:
        return f"/api/v1/experiments/{experiment_id}/files/{quote(rel.as_posix(), safe='/')}"

    for ref_root in _material_reference_root_candidates(exp_dir):
        try:
            rel = resolved_path.relative_to(ref_root.resolve())
        except ValueError:
            continue
        return f"/api/v1/experiments/{experiment_id}/material-references/files/{quote(rel.as_posix(), safe='/')}"
    return None


def _write_professional_report_html_snapshot(*, sidecar_path: Path, html_path: Path, summary: Dict[str, Any]) -> None:
    if html_path.exists():
        return
    import html as html_lib

    sidecar = _load_json_if_exists(sidecar_path) or {}
    report = sidecar.get("report") if isinstance(sidecar, dict) else {}
    context = sidecar.get("context") if isinstance(sidecar, dict) else {}
    overview = context.get("overview") if isinstance(context, dict) else {}
    experiment = overview.get("experiment") if isinstance(overview, dict) else {}
    executive = report.get("executive_summary") if isinstance(report, dict) else {}
    findings = report.get("key_findings") if isinstance(report, dict) else []
    alerts = (report.get("risk_alerts") or {}).get("alerts", []) if isinstance(report, dict) else []

    def esc(value: Any) -> str:
        if isinstance(value, (dict, list)):
            value = json.dumps(value, ensure_ascii=False)
        return html_lib.escape(str(value or "-"))

    finding_items = "".join(
        f"<li><strong>{esc(item.get('finding') if isinstance(item, dict) else item)}</strong><br>{esc(item.get('evidence') if isinstance(item, dict) else '')}</li>"
        for item in (findings if isinstance(findings, list) else [])
    )
    alert_items = "".join(
        f"<li><strong>{esc(item.get('severity') if isinstance(item, dict) else '')}</strong> {esc(item.get('rule') if isinstance(item, dict) else item)}</li>"
        for item in (alerts if isinstance(alerts, list) else [])
    )
    html_text = f"""<!doctype html>
<html lang="zh-CN">
<head>
  <meta charset="utf-8">
  <title>{esc(experiment.get('experiment_name') if isinstance(experiment, dict) else summary.get('experiment_id'))} - Professional Report</title>
  <style>
    body {{ font-family: "Microsoft YaHei", Arial, sans-serif; margin: 40px; color: #172033; line-height: 1.65; }}
    h1, h2 {{ color: #0f172a; }}
    .meta {{ background: #f5f7fb; border: 1px solid #dbe3ef; padding: 16px; border-radius: 8px; }}
    li {{ margin-bottom: 10px; }}
    code {{ background: #eef2f7; padding: 2px 6px; border-radius: 4px; }}
  </style>
</head>
<body>
  <h1>RealityLoop Professional Experiment Analysis Report</h1>
  <div class="meta">
    <div>Experiment: {esc(experiment.get('experiment_name') if isinstance(experiment, dict) else "")}</div>
    <div>Experiment ID: <code>{esc(summary.get('experiment_id'))}</code></div>
    <div>Generated At: {esc(summary.get('generated_at'))}</div>
    <div>PDF: {esc(summary.get('pdf_path'))}</div>
  </div>
  <h2>Executive Summary</h2>
  <p>{esc(executive.get('summary') if isinstance(executive, dict) else "")}</p>
  <p><strong>Conclusion:</strong> {esc(executive.get('overall_conclusion') if isinstance(executive, dict) else "")}</p>
  <h2>Key Findings</h2>
  <ul>{finding_items or "<li>-</li>"}</ul>
  <h2>Risk Alerts</h2>
  <ul>{alert_items or "<li>-</li>"}</ul>
</body>
</html>
"""
    html_path.parent.mkdir(parents=True, exist_ok=True)
    html_path.write_text(html_text, encoding="utf-8")


def _sync_professional_report_material_delivery(
    experiment_id: str,
    exp: Dict[str, Any],
    report_summary: Dict[str, Any],
) -> Dict[str, Any]:
    try:
        from key_action_indexer.material_references import sync_professional_report_material_references

        report_payload = {
            **report_summary,
            "experiment_title": exp.get("title") or exp.get("experiment_name") or experiment_id,
            "experiment_name": exp.get("title") or exp.get("experiment_name") or experiment_id,
            "experiment_date": exp.get("created_at") or exp.get("started_at") or _now_iso(),
        }
        session_dir = _experiment_output_dir(experiment_id) / "key_action_index"
        if not session_dir.exists():
            session_dir = _experiment_output_dir(experiment_id)
        return sync_professional_report_material_references(
            session_dir,
            report_summary=report_payload,
            archive_existing=False,
        )
    except Exception as exc:
        logger.exception("Professional report material delivery sync failed for %s", experiment_id)
        return {"available": False, "error": str(exc)}


def _generate_professional_report_for_experiment(
    experiment_id: str,
    *,
    output_paths: Optional[Dict[str, Any]] = None,
    fail_pipeline: Optional[bool] = None,
) -> Dict[str, Any]:
    report_paths = _professional_report_output_paths(experiment_id)
    summary: Dict[str, Any] = {
        "schema_version": "professional_report.pipeline.v1",
        "experiment_id": experiment_id,
        "enabled": _professional_report_enabled(),
        "available": False,
        "pdf_path": str(report_paths["pdf"]),
        "html_path": str(report_paths["html"]),
        "sidecar_path": str(report_paths["json"]),
        "manifest_path": str(report_paths["manifest"]),
    }
    report_paths["manifest"].parent.mkdir(parents=True, exist_ok=True)
    if not summary["enabled"]:
        summary["status"] = "disabled"
        _write_json(report_paths["manifest"], summary)
        return summary

    should_fail_pipeline = (
        os.environ.get("EXPERIMENT_PROFESSIONAL_REPORT_FAIL_PIPELINE", "0").strip().lower() in {"1", "true", "yes", "on"}
        if fail_pipeline is None
        else bool(fail_pipeline)
    )
    try:
        from labsopguard.professional_report import generate_professional_report_pdf

        exp_dir = _experiment_output_dir(experiment_id)
        exp = _normalize_experiment_dict(_load_json_if_exists(exp_dir / "experiment.json") or {})
        exp["output_paths"] = {
            **(exp.get("output_paths") or {}),
            **({key: str(value) for key, value in (output_paths or {}).items()}),
        }
        overview = _build_analysis_overview(exp)
        try:
            key_actions = _key_action_results_payload(experiment_id)  # type: ignore[name-defined]
        except Exception as exc:
            logger.info("Professional report key-action payload unavailable for %s: %s", experiment_id, exc)
            key_actions = None
        try:
            materials = _published_material_items(exp_dir, experiment_id)
        except Exception as exc:
            logger.info("Professional report material payload unavailable for %s: %s", experiment_id, exc)
            materials = {"schema_version": "published_materials.empty", "total": 0, "items": []}

        logo_path = PROJECT_ROOT / "docs" / "images" / "realityloop-logo-report.png"
        generated = generate_professional_report_pdf(
            overview=overview,
            key_actions=key_actions,
            materials=materials,
            output_pdf_path=report_paths["pdf"],
            logo_path=logo_path if logo_path.exists() else None,
        )
        qwen_meta = generated.get("qwen") if isinstance(generated.get("qwen"), dict) else {}
        report_model = (
            qwen_meta.get("model")
            or os.environ.get("QWEN_REPORT_MODEL")
            or "qwen3.6-max-preview"
        )
        summary.update(
            {
                **generated,
                "status": "completed",
                "available": report_paths["pdf"].exists(),
                "model": report_model,
                "qwen_model": report_model,
                "pdf_path": str(report_paths["pdf"]),
                "html_path": str(report_paths["html"]),
                "sidecar_path": str(report_paths["json"]),
                "manifest_path": str(report_paths["manifest"]),
                "pdf_url": f"/api/v1/experiments/{experiment_id}/artifacts/professional_report_pdf",
                "html_url": f"/api/v1/experiments/{experiment_id}/artifacts/professional_report_html",
                "sidecar_url": f"/api/v1/experiments/{experiment_id}/artifacts/professional_report_json",
                "generated_at": _now_iso(),
            }
        )
        if report_paths["pdf"].exists():
            summary["size_bytes"] = report_paths["pdf"].stat().st_size
        _write_professional_report_html_snapshot(
            sidecar_path=report_paths["json"],
            html_path=report_paths["html"],
            summary=summary,
        )
        _write_json(report_paths["manifest"], summary)
        summary["material_delivery"] = _sync_professional_report_material_delivery(experiment_id, exp, summary)
        _write_json(report_paths["manifest"], summary)
        return summary
    except Exception as exc:
        logger.exception("Professional PDF report generation failed for experiment %s", experiment_id)
        summary.update(
            {
                "status": "failed",
                "available": False,
                "error": str(exc),
                "generated_at": _now_iso(),
            }
        )
        _write_json(report_paths["manifest"], summary)
        if should_fail_pipeline:
            raise
        return summary


def _attach_professional_report_output_paths(
    experiment_id: str,
    output_paths: Dict[str, Any],
    report_summary: Dict[str, Any],
) -> Dict[str, Any]:
    if report_summary.get("pdf_path"):
        output_paths["professional_report_pdf"] = str(report_summary["pdf_path"])
    if report_summary.get("html_path"):
        output_paths["professional_report_html"] = str(report_summary["html_path"])
    if report_summary.get("sidecar_path"):
        output_paths["professional_report_json"] = str(report_summary["sidecar_path"])
    if report_summary.get("manifest_path"):
        output_paths["professional_report_manifest_json"] = str(report_summary["manifest_path"])
    output_paths["professional_report_summary"] = report_summary
    return output_paths


def _key_action_output_dir(experiment_id: str) -> Path:
    return _experiment_output_dir(experiment_id) / "key_action_index"


def _read_key_action_yolo_model_config(view: str) -> Dict[str, str]:
    view_name = str(view or "").strip().lower()
    config_path = PROJECT_ROOT / "models" / "yolo" / view_name / "model_config.yaml"
    if not config_path.exists():
        return {}
    values: Dict[str, str] = {}
    try:
        for raw_line in config_path.read_text(encoding="utf-8").splitlines():
            line = raw_line.strip()
            if not line or line.startswith("#") or line.startswith("- ") or ":" not in line:
                continue
            key, value = line.split(":", 1)
            values[key.strip().lower()] = value.strip().strip("\"'")
    except OSError:
        return {}
    return values


def _key_action_model_config_path(raw_path: Optional[str], *, view: str) -> Optional[Path]:
    if not raw_path:
        return None
    candidate = Path(str(raw_path).strip()).expanduser()
    if candidate.is_absolute():
        return candidate
    view_name = str(view or "").strip().lower()
    return PROJECT_ROOT / "models" / "yolo" / view_name / candidate


def _default_key_action_yolo_model_path(view: str) -> Optional[str]:
    view_name = str(view or "").strip().lower()
    env_name = (
        "KEY_ACTION_YOLO_FIRST_PERSON_MODEL"
        if view_name == "first_person"
        else "KEY_ACTION_YOLO_THIRD_PERSON_MODEL"
    )
    env_path = os.environ.get(env_name)
    model_config = _read_key_action_yolo_model_config(view_name)
    candidates = [
        Path(env_path) if env_path else None,
        _key_action_model_config_path(model_config.get("model_path"), view=view_name),
    ]
    # Central external model store (no weights tracked in the repo). Resolve the
    # per-view "current" pointer first, then any concrete version folders under it.
    models_root = Path(os.environ.get("LAB_MODELS_DIR", r"D:\LabModels"))
    view_root = models_root / "yolo" / view_name
    candidates.append(view_root / "current" / "best.pt")
    if view_root.is_dir():
        for version_dir in sorted(view_root.iterdir(), reverse=True):
            if version_dir.name == "current" or not version_dir.is_dir():
                continue
            candidates.append(version_dir / "best.pt")
    # Backward-compatible legacy in-repo location (now relocated to LAB_MODELS_DIR).
    candidates.append(PROJECT_ROOT / "models" / "yolo" / view_name / "best.pt")
    for candidate in candidates:
        if candidate and candidate.exists():
            return str(candidate)
    return None


def _default_key_action_yolo_imgsz(view: str) -> Optional[int]:
    view_name = str(view or "").strip().lower()
    env_name = (
        "KEY_ACTION_YOLO_FIRST_PERSON_IMGSZ"
        if view_name == "first_person"
        else "KEY_ACTION_YOLO_THIRD_PERSON_IMGSZ"
    )
    raw = os.environ.get(env_name)
    if raw:
        try:
            value = int(float(raw))
            if value > 0:
                return value
        except (TypeError, ValueError):
            pass
    model_config = _read_key_action_yolo_model_config(view_name)
    for key in ("recommended_imgsz", "yolo_imgsz", "imgsz"):
        value = model_config.get(key)
        if value:
            try:
                parsed = int(float(value))
                if parsed > 0:
                    return parsed
            except (TypeError, ValueError):
                pass
    # If a packaged weight for this view resolves (central store or env), the
    # trained models expect imgsz=640. Reuse the canonical resolver instead of
    # hardcoding any machine-specific path.
    resolved = _default_key_action_yolo_model_path(view_name)
    if resolved and Path(resolved).exists():
        return 640
    return None


def _default_key_action_yolo_device() -> str:
    configured = os.environ.get("KEY_ACTION_YOLO_DEVICE")
    if configured is not None and configured.strip():
        return configured.strip()
    return os.environ.get("KEY_ACTION_YOLO_CUDA_DEVICE", "0").strip() or "0"


class KeyActionCudaRequiredError(RuntimeError):
    """Formal key-action runs must fail closed when CUDA is unavailable."""


def _key_action_yolo_runtime_info() -> Dict[str, Any]:
    info: Dict[str, Any] = {
        "python_executable": sys.executable,
        "python_version": sys.version.split()[0],
    }
    try:
        import torch  # type: ignore

        cuda = getattr(torch, "cuda", None)
        cuda_available = bool(cuda is not None and cuda.is_available())
        info.update(
            {
                "torch_version": str(getattr(torch, "__version__", "")),
                "torch_cuda": str(getattr(getattr(torch, "version", None), "cuda", None)),
                "cuda_available": cuda_available,
                "cuda_device_count": int(cuda.device_count()) if cuda is not None else 0,
                "cuda_device_name": cuda.get_device_name(0) if cuda_available else None,
            }
        )
    except Exception as exc:
        info.update({"cuda_available": False, "torch_error": str(exc)})
    return info


def _key_action_requests_cuda_device(device: Any) -> bool:
    value = str(device or "").strip().lower()
    if value in {"", "none", "auto", "cpu"}:
        return False
    if value == "cuda" or value.startswith("cuda:"):
        return True
    return all(part.strip().isdigit() for part in value.split(",") if part.strip())


def _key_action_cuda_required_message(runtime: Dict[str, Any], detection_config: Dict[str, Any]) -> str:
    return (
        "正式 key-action 分析需要 CUDA GPU；当前后端没有可用 CUDA，已拒绝运行。"
        "请切换到 CUDA 版 LabSOPGuard 后端后重试。"
    )


def _key_action_cuda_failure_detail(
    error: Exception,
    detection_config: Dict[str, Any],
    runtime: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    if runtime is None and isinstance(detection_config.get("yolo_runtime"), dict):
        runtime = detection_config.get("yolo_runtime")
    runtime = runtime or {}
    return {
        "code": "KEY_ACTION_CUDA_REQUIRED",
        "message_zh": _key_action_cuda_required_message(runtime, detection_config),
        "message": "Formal key-action analysis requires CUDA GPU; CPU fallback is disabled.",
        "error": str(error),
        "cuda_required": True,
        "cuda_available": bool(runtime.get("cuda_available")),
        "cuda_device_count": runtime.get("cuda_device_count"),
        "requested_yolo_device": detection_config.get("yolo_device"),
        "python_executable": runtime.get("python_executable"),
        "torch_version": runtime.get("torch_version"),
        "torch_cuda": runtime.get("torch_cuda"),
    }


def _raise_key_action_cuda_required(detection_config: Dict[str, Any], runtime: Dict[str, Any]) -> None:
    raise KeyActionCudaRequiredError(_key_action_cuda_required_message(runtime, detection_config))


def _validate_key_action_yolo_runtime(
    detection_config: Dict[str, Any],
    *,
    runtime_info: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    runtime = runtime_info or _key_action_yolo_runtime_info()
    detection_config["yolo_runtime"] = runtime
    backend = str(detection_config.get("detector_backend") or "").strip().lower()
    yolo_backend = backend in {"yolo", "yolo_interaction", "multiview_yolo"}
    cuda_required = _key_action_truthy(detection_config.get("require_cuda"), False)
    if yolo_backend and cuda_required:
        detection_config["cuda_required"] = True
        device_value = str(detection_config.get("yolo_device") or "").strip().lower()
        if device_value in {"", "none", "auto"}:
            detection_config["yolo_device"] = os.environ.get("KEY_ACTION_YOLO_CUDA_DEVICE", "0").strip() or "0"
            device_value = str(detection_config.get("yolo_device") or "").strip().lower()
        if device_value == "cpu" or not _key_action_requests_cuda_device(device_value):
            _raise_key_action_cuda_required(detection_config, runtime)
        if not runtime.get("cuda_available"):
            _raise_key_action_cuda_required(detection_config, runtime)
    elif yolo_backend and _key_action_requests_cuda_device(detection_config.get("yolo_device")):
        if not runtime.get("cuda_available"):
            _raise_key_action_cuda_required(detection_config, runtime)
    return runtime


def _directory_size_bytes(path: Path) -> int:
    if not path.exists():
        return 0
    if path.is_file():
        try:
            return int(path.stat().st_size)
        except OSError:
            return 0
    total = 0
    for item in path.rglob("*"):
        if not item.is_file():
            continue
        try:
            total += int(item.stat().st_size)
        except OSError:
            continue
    return total


def _key_action_output_size_summary(output_dir: Path) -> Dict[str, Any]:
    groups = {
        "metadata": output_dir / "metadata",
        "cv_outputs": output_dir / "cv_outputs",
        "clips": output_dir / "clips",
        "keyframes": output_dir / "keyframes",
        "index": output_dir / "index",
        "reports": output_dir / "reports",
        "evaluation": output_dir / "evaluation",
        "material_candidates": output_dir / "material_candidates",
        "material_references": output_dir / "material_references",
    }
    by_group = {name: _directory_size_bytes(path) for name, path in groups.items() if path.exists()}
    total = _directory_size_bytes(output_dir)
    return {
        "total_bytes": total,
        "total_mb": round(total / 1024 / 1024, 3),
        "by_group_bytes": by_group,
        "by_group_mb": {name: round(size / 1024 / 1024, 3) for name, size in by_group.items()},
    }


def _key_action_truthy(value: Any, default: bool = False) -> bool:
    if value is None:
        return default
    if isinstance(value, bool):
        return value
    if isinstance(value, (int, float)):
        return bool(value)
    return str(value).strip().lower() not in {"", "0", "false", "no", "off"}


