def _with_default_key_action_yolo_config(config: Dict[str, Any]) -> Dict[str, Any]:
    _ensure_key_action_fast_defaults()
    merged = dict(config or {})
    merged.setdefault("fast_locate_only", _key_action_truthy(os.environ.get("KEY_ACTION_FAST_LOCATE_ONLY"), False))
    fast_locate_enabled = _key_action_truthy(os.environ.get("KEY_ACTION_FAST_LOCATE_ONLY"), False) or _key_action_truthy(
        merged.get("fast_locate_only"),
        False,
    )
    merged.setdefault("detector_backend", "yolo")
    merged.setdefault(
        "require_cuda",
        _key_action_truthy(os.environ.get("KEY_ACTION_REQUIRE_CUDA_FOR_FORMAL_ANALYSIS"), True),
    )
    merged.setdefault(
        "yolo_scan_both_views",
        _key_action_truthy(os.environ.get("KEY_ACTION_YOLO_SCAN_BOTH_VIEWS"), True),
    )
    preferred_default = "third_person" if fast_locate_enabled else "first_person"
    merged.setdefault("yolo_preferred_view", os.environ.get("KEY_ACTION_YOLO_PREFERRED_VIEW", preferred_default))
    merged.setdefault("yolo_device", _default_key_action_yolo_device())
    merged.setdefault("yolo_conf", float(os.environ.get("KEY_ACTION_YOLO_CONF", "0.25")))
    merged.setdefault("yolo_iou", float(os.environ.get("KEY_ACTION_YOLO_IOU", "0.45")))
    merged.setdefault("yolo_continuity_frames", int(float(os.environ.get("KEY_ACTION_YOLO_CONTINUITY_FRAMES", "1"))))
    merged.setdefault(
        "enable_micro_refine_rescan",
        _key_action_truthy(os.environ.get("KEY_ACTION_ENABLE_MICRO_REFINE_RESCAN"), True),
    )
    merged.setdefault("micro_refine_sample_fps", float(os.environ.get("KEY_ACTION_MICRO_REFINE_SAMPLE_FPS", "8.0")))
    merged.setdefault(
        "long_video_two_stage_sampling",
        _key_action_truthy(os.environ.get("KEY_ACTION_LONG_VIDEO_TWO_STAGE_SAMPLING"), True),
    )
    merged.setdefault("long_video_chunk_sec", float(os.environ.get("KEY_ACTION_LONG_VIDEO_CHUNK_SEC", "900.0")))
    default_stage1_sample_fps = (
        os.environ.get("KEY_ACTION_FAST_LOCATE_STAGE1_SAMPLE_FPS", "0.2")
        if fast_locate_enabled
        else "0.2"
    )
    merged.setdefault(
        "long_video_stage1_sample_fps",
        float(os.environ.get("KEY_ACTION_LONG_VIDEO_STAGE1_SAMPLE_FPS", default_stage1_sample_fps)),
    )
    default_stage2_sample_fps = os.environ.get(
        "KEY_ACTION_FAST_LOCATE_STAGE2_SAMPLE_FPS",
        "1.5" if fast_locate_enabled else "3.0",
    )
    merged.setdefault(
        "long_video_stage2_sample_fps",
        float(os.environ.get("KEY_ACTION_LONG_VIDEO_STAGE2_SAMPLE_FPS", default_stage2_sample_fps)),
    )
    if fast_locate_enabled and not _key_action_truthy(
        os.environ.get("KEY_ACTION_FAST_LOCATE_PRESERVE_MERGE_GAP"),
        False,
    ):
        max_fast_locate_merge_gap = float(os.environ.get("KEY_ACTION_FAST_LOCATE_MAX_MERGE_GAP_SEC", "300.0"))
        if float(merged.get("merge_gap_sec") or 0.0) > max_fast_locate_merge_gap:
            merged["merge_gap_sec"] = max_fast_locate_merge_gap
    merged.setdefault(
        "render_segment_yolo",
        _key_action_truthy(os.environ.get("KEY_ACTION_RENDER_SEGMENT_YOLO_DEFAULT"), False),
    )
    merged.setdefault(
        "generate_professional_report",
        _key_action_truthy(os.environ.get("KEY_ACTION_PROFESSIONAL_REPORT_ENABLED"), False),
    )
    first_model = _default_key_action_yolo_model_path("first_person")
    third_model = _default_key_action_yolo_model_path("third_person")
    if first_model:
        merged.setdefault("yolo_first_person_model_path", first_model)
    if third_model:
        merged.setdefault("yolo_third_person_model_path", third_model)
    first_imgsz = _default_key_action_yolo_imgsz("first_person")
    third_imgsz = _default_key_action_yolo_imgsz("third_person")
    if first_imgsz:
        merged.setdefault("yolo_first_person_imgsz", first_imgsz)
    if third_imgsz:
        merged.setdefault("yolo_third_person_imgsz", third_imgsz)
    return merged


def _key_action_vlm_assist_config() -> Dict[str, Any]:
    import importlib.util

    enabled = os.environ.get("KEY_ACTION_ENABLE_VLM_ASSIST", "1").strip().lower() not in {
        "0",
        "false",
        "no",
        "off",
    }
    try:
        max_groups = int(os.environ.get("KEY_ACTION_VLM_MAX_GROUPS", "8"))
    except Exception:
        max_groups = 8
    return {
        "enabled": enabled,
        "model": (
            os.environ.get("KEY_ACTION_VLM_MODEL")
            or os.environ.get("QWEN_VL_MODEL")
            or os.environ.get("VLM_MODEL")
            or "qwen3.6-plus"
        ),
        "max_groups": max(0, max_groups),
        "api_key_configured": bool(os.environ.get("DASHSCOPE_API_KEY")),
        "dashscope_installed": importlib.util.find_spec("dashscope") is not None,
    }


def _build_key_action_vlm_assist_client(model_override: Optional[str] = None) -> tuple[Any | None, Dict[str, Any]]:
    config = _key_action_vlm_assist_config()
    if model_override:
        config = {**config, "model": str(model_override)}
    if not config["enabled"]:
        return None, {**config, "configured": False, "reason": "disabled"}
    if not config["dashscope_installed"]:
        return None, {**config, "configured": False, "reason": "dashscope_not_installed"}
    if not config["api_key_configured"]:
        return None, {**config, "configured": False, "reason": "dashscope_api_key_missing"}
    try:
        from experiment.vlm_client import DashScopeVLClient

        client = DashScopeVLClient(
            api_key=os.environ.get("DASHSCOPE_API_KEY"),
            base_url=os.environ.get("DASHSCOPE_BASE_URL"),
            model=str(config["model"]),
            timeout=int(os.environ.get("KEY_ACTION_VLM_TIMEOUT", "60")),
        )
        return client, {**config, "configured": True}
    except Exception as exc:
        logger.warning("Key-action VLM assist unavailable: %s", exc)
        return None, {**config, "configured": False, "error": str(exc)}


