def _compact_material_auto_publish_for_status(auto_publish: Any) -> Any:
    if not isinstance(auto_publish, dict):
        return auto_publish
    compact = {
        key: auto_publish.get(key)
        for key in ("schema_version", "status", "reason", "policy", "approved_count", "eligible_count", "error")
        if key in auto_publish
    }
    formal_reset = auto_publish.get("formal_reset")
    if isinstance(formal_reset, dict):
        compact["formal_reset"] = {
            key: formal_reset.get(key)
            for key in (
                "schema_version",
                "created_at",
                "experiment_id",
                "file_count",
                "planned_file_count",
                "keyframe_count",
                "key_clip_count",
                "report_count",
                "material_references",
                "local_material_references_mirror",
                "index_json",
                "index_jsonl",
                "local_index_json",
                "local_index_jsonl",
                "policy",
                "error",
            )
            if key in formal_reset
        }
        for package_key in ("openclaw_evidence_package", "local_openclaw_evidence_package"):
            package = formal_reset.get(package_key)
            if isinstance(package, dict):
                compact["formal_reset"][package_key] = {
                    key: package.get(key)
                    for key in (
                        "schema_version",
                        "status",
                        "ok",
                        "scope",
                        "package_root",
                        "manifest",
                        "reference_count",
                        "physical_change_count",
                        "portable",
                    )
                    if key in package
                }
    return compact


def _compact_material_candidates_for_status(candidate_summary: Any) -> Any:
    if not isinstance(candidate_summary, dict):
        return candidate_summary
    compact: Dict[str, Any] = {}
    keep_keys = (
        "schema_version",
        "status",
        "generated_at",
        "candidate_count",
        "group_count",
        "file_count",
        "pending_total",
        "approved_total",
        "rejected_total",
        "recommended_total",
        "candidate_folder",
        "candidate_root",
        "index_json",
        "index_jsonl",
        "manifest_path",
        "auto_publish",
        "vlm_assist",
        "policy",
        "error",
    )
    for key in keep_keys:
        if key in candidate_summary:
            compact[key] = (
                _compact_material_auto_publish_for_status(candidate_summary.get(key))
                if key == "auto_publish"
                else candidate_summary.get(key)
            )
    records = candidate_summary.get("records")
    if isinstance(records, list):
        compact["record_count"] = len(records)
        compact["records_omitted"] = True
    groups = candidate_summary.get("groups")
    if isinstance(groups, list):
        compact["group_count"] = compact.get("group_count", len(groups))
        compact["groups_omitted"] = True
    pipeline_summary = candidate_summary.get("pipeline_summary")
    if isinstance(pipeline_summary, dict):
        compact["pipeline_summary"] = {
            key: pipeline_summary.get(key)
            for key in (
                "candidate_count",
                "group_count",
                "file_count",
                "recommended_total",
                "pending_total",
                "status",
            )
            if key in pipeline_summary
        }
    return compact


