def _compact_key_action_summary_for_status(summary: Any) -> Any:
    if not isinstance(summary, dict):
        return summary
    compact: Dict[str, Any] = {}
    keep_keys = (
        "session_id",
        "output_dir",
        "dry_run",
        "run_id",
        "run_manifest_id",
        "mode",
        "fast_locate_only",
        "coarse_segment_count",
        "fine_scan_window_count",
        "fine_scan_window_duration_sec",
        "refined_segment_count",
        "fine_yolo_row_count",
        "segment_count",
        "micro_segment_count",
        "raw_micro_segment_count",
        "total_action_duration_sec",
        "failed_stages",
        "alignment_health",
        "detector_summary",
        "micro_refine_summary",
        "fast_refine_stage_timings",
        "experiment_focus_summary",
        "yolo_annotated_clips",
        "yolo_experiment_focus_clips",
        "reviewed_dataset",
        "elapsed_sec",
    )
    for key in keep_keys:
        if key in summary:
            compact[key] = (
                _compact_reviewed_dataset_for_status(summary.get(key))
                if key == "reviewed_dataset"
                else summary.get(key)
            )
    if "yolo_index_enrichment" in summary:
        compact["yolo_index_enrichment"] = _compact_yolo_index_enrichment_for_status(summary.get("yolo_index_enrichment"))
    if "material_auto_publish" in summary:
        compact["material_auto_publish"] = _compact_material_auto_publish_for_status(summary.get("material_auto_publish"))
    if isinstance(summary.get("stage_stats"), dict):
        stage_stats = summary["stage_stats"]
        compact["stage_stats"] = {
            key: stage_stats.get(key)
            for key in ("run_id", "stage_count", "total_duration_sec")
            if key in stage_stats
        }
    if isinstance(summary.get("artifacts"), dict):
        artifacts = summary["artifacts"]
        compact["artifacts"] = {
            key: artifacts.get(key)
            for key in (
                "key_action_segments",
                "micro_segments",
                "vector_metadata",
                "micro_vector_metadata",
                "yolo_frame_rows",
                "experiment_focus_clips",
                "index_dir",
                "debug_report",
                "formal_report",
            )
            if key in artifacts
        }
    if "material_candidates" in summary:
        compact["material_candidates"] = _compact_material_candidates_for_status(summary.get("material_candidates"))
    if "material_candidate_summary" in summary:
        compact["material_candidate_summary"] = _compact_material_candidates_for_status(summary.get("material_candidate_summary"))
    if "quality_gate" in summary:
        compact["quality_gate"] = _compact_quality_gate_for_status(summary.get("quality_gate"))
    if "reviewed_quality_gate" in summary:
        compact["reviewed_quality_gate"] = _compact_quality_gate_for_status(summary.get("reviewed_quality_gate"))
    return compact


def _compact_key_action_status_payload(payload: Dict[str, Any]) -> Dict[str, Any]:
    compact = dict(payload)
    if "material_candidates" in compact:
        compact["material_candidates"] = _compact_material_candidates_for_status(compact.get("material_candidates"))
    if "summary" in compact:
        compact["summary"] = _compact_key_action_summary_for_status(compact.get("summary"))
    if "quality_gate" in compact:
        compact["quality_gate"] = _compact_quality_gate_for_status(compact.get("quality_gate"))
    return compact


def _write_key_action_status(experiment_id: str, payload: Dict[str, Any]) -> Dict[str, Any]:
    status_path = _key_action_status_path(experiment_id)
    status_path.parent.mkdir(parents=True, exist_ok=True)
    current = _load_json_if_exists(status_path) or {}
    if not isinstance(current, dict):
        current = {}
    payload = _compact_key_action_status_payload(payload)
    incoming_status = str(payload.get("status") or "").strip().lower()
    if incoming_status in {"queued", "running", "completed"}:
        for stale_error_key in ("error_type", "error_message"):
            current.pop(stale_error_key, None)
            payload.pop(stale_error_key, None)
    if incoming_status in {"queued", "running"}:
        for stale_key in (
            "completed_at",
            "output_size_summary",
            "summary",
            "summary_path",
            "quality_gate",
            "reviewed_quality_gate",
            "ready_for_delivery",
            "fast_locate_only",
            "fast_locate_refined",
            "material_candidates",
            "material_auto_publish",
        ):
            current.pop(stale_key, None)
        if incoming_status == "queued":
            for queued_stale_key in ("started_at", "stage", "pipeline_progress"):
                current.pop(queued_stale_key, None)
        elif "stage" not in payload:
            current.pop("stage", None)
            current.pop("pipeline_progress", None)
    elif incoming_status == "completed":
        current.pop("pipeline_progress", None)
    current.update(payload)
    current.setdefault("experiment_id", experiment_id)
    current.setdefault("output_dir", str(_key_action_output_dir(experiment_id)))
    current["updated_at"] = _now_iso()
    _write_json(status_path, current)
    _key_action_status_cache.pop(experiment_id, None)
    return current


def _read_key_action_status(experiment_id: str) -> Dict[str, Any]:
    payload = _load_json_if_exists(_key_action_status_path(experiment_id))
    if isinstance(payload, dict):
        return payload
    return _key_action_status_payload(experiment_id)


def _key_action_ready_for_delivery(state: Dict[str, Any]) -> bool:
    if not isinstance(state, dict):
        return False
    if str(state.get("status") or "").lower() != "completed":
        return False
    if bool(state.get("ready_for_delivery")):
        return True
    quality_gate = state.get("quality_gate") if isinstance(state.get("quality_gate"), dict) else {}
    return bool(quality_gate.get("ready_for_delivery") or quality_gate.get("can_mark_complete"))


def _effective_experiment_task_state(experiment_id: str) -> Dict[str, Any]:
    task_state = _experiment_task_state(experiment_id)
    key_action_state = _read_key_action_status(experiment_id)
    if not _key_action_ready_for_delivery(key_action_state):
        return task_state

    completed_state = dict(task_state)
    completed_state.update(
        {
            "task_id": completed_state.get("task_id") or key_action_state.get("task_id") or key_action_state.get("run_id"),
            "experiment_id": experiment_id,
            "status": "completed",
            "current_stage": key_action_state.get("stage") or completed_state.get("current_stage") or "key_action_index",
            "progress": 1.0,
            "message": key_action_state.get("message") or completed_state.get("message") or "Key-action pipeline completed",
            "error_type": None,
            "error_message": None,
            "completed_at": key_action_state.get("completed_at") or completed_state.get("completed_at"),
            "updated_at": key_action_state.get("updated_at") or completed_state.get("updated_at"),
            "elapsed_sec": key_action_state.get("elapsed_sec") or completed_state.get("elapsed_sec"),
        }
    )
    output_paths = dict(completed_state.get("output_paths") or {})
    output_paths.setdefault("key_action_index", str(_key_action_output_dir(experiment_id)))
    completed_state["output_paths"] = output_paths
    completed_state["key_action_index"] = _compact_key_action_status_payload(key_action_state)
    return completed_state


