def _key_action_file_url(experiment_id: str, path_value: Any) -> Optional[str]:
    if not path_value:
        return None
    path = Path(str(path_value))
    if not path.is_absolute():
        path = _experiment_output_dir(experiment_id) / path
    return _experiment_file_api_path(path, experiment_id)


_key_action_status_cache: Dict[str, Dict[str, Any]] = {}


def _key_action_artifact_fingerprint(experiment_id: str) -> int:
    output_dir = _key_action_output_dir(experiment_id)
    candidates = [
        _key_action_status_path(experiment_id),
        output_dir / "pipeline_summary.json",
        output_dir / "run_manifest.json",
        output_dir / "metadata" / "key_action_segments.jsonl",
        output_dir / "metadata" / "micro_segments.jsonl",
        output_dir / "metadata" / "vector_metadata.jsonl",
        output_dir / "metadata" / "micro_vector_metadata.jsonl",
        output_dir / "metadata" / "experiment_focus_window.json",
        output_dir / "metadata" / "experiment_focus_clips.json",
        output_dir / "metadata" / "time_axis_health.json",
        output_dir / "metadata" / "pre_coarse_timeline_alignment.json",
        output_dir / "metadata" / "dual_view_action_alignment_summary.json",
        output_dir / "metadata" / "dual_view_action_events.jsonl",
        output_dir / "metadata" / "dual_view_aligned_experiment_episodes.jsonl",
        output_dir / "metadata" / "unmatched_view_evidence.jsonl",
        output_dir / "cv_outputs" / "detected_segments.jsonl",
        output_dir / "cv_outputs" / "frame_scores.jsonl",
        output_dir / "cv_outputs" / "yolo_frame_rows.jsonl",
    ]
    fingerprint = 0
    for path in candidates:
        try:
            if path.exists():
                stat = path.stat()
                fingerprint = max(fingerprint, int(stat.st_mtime_ns), int(stat.st_size))
        except Exception:
            continue
    return fingerprint


def _key_action_status_payload(experiment_id: str) -> Dict[str, Any]:
    fingerprint = _key_action_artifact_fingerprint(experiment_id)
    cached = _key_action_status_cache.get(experiment_id)
    if cached and cached.get("fingerprint") == fingerprint and isinstance(cached.get("payload"), dict):
        return cached["payload"]
    result = _key_action_status_payload_uncached(experiment_id)
    _key_action_status_cache[experiment_id] = {
        "fingerprint": _key_action_artifact_fingerprint(experiment_id),
        "payload": result,
    }
    return result


def _key_action_status_payload_uncached(experiment_id: str) -> Dict[str, Any]:
    output_dir = _key_action_output_dir(experiment_id)
    status_payload = _load_json_if_exists(_key_action_status_path(experiment_id))
    if isinstance(status_payload, dict) and status_payload:
        status_payload = _sync_key_action_status_with_task_state(experiment_id, status_payload)
        return _reconcile_key_action_status_summary(experiment_id, status_payload)
    manifest = _load_json_if_exists(output_dir / "manifest.json") or _load_json_if_exists(_experiment_output_dir(experiment_id) / "manifest.json") or {}
    has_outputs = output_dir.exists() or bool(manifest)
    return _reconcile_key_action_status_summary(experiment_id, {
        "experiment_id": experiment_id,
        "status": "completed" if has_outputs else "not_started",
        "progress": 1.0 if has_outputs else 0.0,
        "message": "Key-action recovery artifacts are available." if has_outputs else "Key-action index is not ready.",
        "output_dir": str(output_dir),
        "completed_at": manifest.get("generated_at") or manifest.get("created_at"),
        "summary": {
            "segment_count": len(manifest.get("actions") or []),
            "keyframe_count": manifest.get("keyframe_count", 0),
            "key_clip_count": manifest.get("key_clip_count", 0),
            "report_count": manifest.get("report_count", 0),
            "recovery_status": manifest.get("recovery_status"),
        },
    })


def _sync_key_action_status_with_task_state(experiment_id: str, status_payload: Dict[str, Any]) -> Dict[str, Any]:
    """Prevent stale key-action job files from leaving the UI in a fake running state."""
    status = str(status_payload.get("status") or "").lower()
    if status not in {"queued", "running", "analyzing", "processing", "generating_outputs"}:
        return status_payload
    try:
        task_state = _experiment_task_state(experiment_id)
    except Exception:
        return status_payload
    if not isinstance(task_state, dict) or not task_state:
        return status_payload
    task_status = str(task_state.get("status") or "").lower()
    if task_status in {"completed", "analyzed"}:
        completed = dict(status_payload)
        completed.update(
            {
                "status": "completed",
                "progress": 1.0,
                "message": task_state.get("message") or status_payload.get("message") or "Key-action pipeline completed",
                "completed_at": task_state.get("completed_at") or status_payload.get("completed_at"),
                "elapsed_sec": task_state.get("elapsed_sec") or status_payload.get("elapsed_sec"),
                "output_size_summary": task_state.get("output_size_summary") or status_payload.get("output_size_summary"),
            }
        )
        return completed
    if task_status not in {"failed", "partial_failed", "cancelled", "canceled"}:
        return status_payload
    stage = str(task_state.get("current_stage") or task_state.get("stage") or "").lower()
    output_paths = task_state.get("output_paths") if isinstance(task_state.get("output_paths"), dict) else {}
    if "key_action" not in stage and "key_action_index" not in output_paths:
        return status_payload
    updated = dict(status_payload)
    updated.update(
        {
            "status": "failed",
            "message": task_state.get("error_message") or "Key-action task failed. Re-run analysis to continue.",
            "error_type": task_state.get("error_type") or task_status,
            "error_message": task_state.get("error_message") or task_state.get("message"),
            "completed_at": task_state.get("completed_at") or task_state.get("updated_at"),
        }
    )
    return _write_key_action_status(experiment_id, updated)


def _jsonl_row_count(path: Path) -> int:
    if not path.exists():
        return 0
    count = 0
    for line in path.read_text(encoding="utf-8").splitlines():
        if line.strip():
            count += 1
    return count


def _yolo_interaction_count_from_rows(path: Path) -> int:
    count = 0
    for row in _read_jsonl_rows(path):
        count += len(_key_action_list(row.get("hand_object_interactions")))
    return count


def _reconcile_key_action_status_summary(experiment_id: str, status_payload: Dict[str, Any]) -> Dict[str, Any]:
    payload = copy.deepcopy(status_payload)
    output_dir = _key_action_output_dir(experiment_id)
    metadata_dir = output_dir / "metadata"
    cv_dir = output_dir / "cv_outputs"
    segment_rows = _jsonl_row_count(metadata_dir / "key_action_segments.jsonl")
    micro_rows = _jsonl_row_count(metadata_dir / "micro_segments.jsonl")
    vector_rows = _jsonl_row_count(metadata_dir / "vector_metadata.jsonl")
    micro_vector_rows = _jsonl_row_count(metadata_dir / "micro_vector_metadata.jsonl")
    yolo_frame_rows = _jsonl_row_count(cv_dir / "yolo_frame_rows.jsonl")
    raw_interactions = _yolo_interaction_count_from_rows(cv_dir / "yolo_frame_rows.jsonl") if yolo_frame_rows else 0
    pipeline_summary = _load_json_if_exists(output_dir / "pipeline_summary.json") or {}
    detector_summary = pipeline_summary.get("detector_summary") if isinstance(pipeline_summary, dict) else None
    summary = dict(payload.get("summary") or {})
    if segment_rows:
        summary["segment_count"] = segment_rows
        summary["source"] = "key_action_index_metadata"
    elif isinstance(detector_summary, dict) and detector_summary.get("segment_count") is not None:
        summary["segment_count"] = detector_summary.get("segment_count")
    if micro_rows:
        summary["micro_segment_count"] = micro_rows
        summary["raw_micro_segment_count"] = micro_rows
    elif isinstance(pipeline_summary, dict):
        if pipeline_summary.get("micro_segment_count") is not None:
            summary["micro_segment_count"] = pipeline_summary.get("micro_segment_count")
        if pipeline_summary.get("raw_micro_segment_count") is not None:
            summary["raw_micro_segment_count"] = pipeline_summary.get("raw_micro_segment_count")
    if yolo_frame_rows:
        summary["yolo_frame_row_count"] = yolo_frame_rows
    if vector_rows or micro_vector_rows:
        summary["vector_count"] = vector_rows + micro_vector_rows
        summary["segment_vector_count"] = vector_rows
        summary["micro_vector_count"] = micro_vector_rows
    if raw_interactions:
        summary["interaction_count"] = raw_interactions
        summary["raw_yolo_interaction_count"] = raw_interactions
    if isinstance(detector_summary, dict):
        merged_detector = dict(detector_summary)
        if segment_rows:
            merged_detector["segment_count"] = segment_rows
        if yolo_frame_rows:
            merged_detector["frame_rows"] = yolo_frame_rows
        if raw_interactions:
            merged_detector["interaction_count"] = raw_interactions
        summary["detector_summary"] = merged_detector
    formal_health = _experiment_formal_publish_health(experiment_id)
    summary["formal_publish_health"] = formal_health
    summary["official_segment_count"] = formal_health.get("official_segment_count")
    summary["raw_official_segment_count"] = formal_health.get("raw_official_segment_count")
    summary["candidate_segment_count"] = formal_health.get("candidate_segment_count")
    summary["dual_view_action_event_count"] = formal_health.get("dual_view_action_event_count")
    summary["unmatched_view_evidence_count"] = formal_health.get("unmatched_view_evidence_count")
    payload["formal_publish_health"] = formal_health
    payload["action_alignment_health"] = formal_health.get("action_alignment")
    if formal_health.get("status") == "blocked":
        if str(payload.get("status") or "").lower() == "completed":
            payload["status"] = "partial_failed"
        payload["message"] = formal_health.get("user_message_zh") or payload.get("message")
        payload["ready_for_delivery"] = False
        payload["requires_review"] = True
    payload["summary"] = summary
    return payload


def _key_action_float(value: Any, default: float = 0.0) -> float:
    try:
        return float(value)
    except (TypeError, ValueError):
        return default


def _key_action_list(value: Any) -> List[Any]:
    return value if isinstance(value, list) else []


def _key_action_copy_rows(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
    return [copy.deepcopy(row) for row in rows if isinstance(row, dict)]


def _key_action_put_file_url(experiment_id: str, row: Dict[str, Any], path_key: str, url_key: str) -> None:
    if not isinstance(row, dict):
        return
    url = _key_action_file_url(experiment_id, row.get(path_key))
    if url:
        row[url_key] = url


def _enrich_key_action_keyframes(experiment_id: str, keyframes: Any) -> None:
    if not isinstance(keyframes, dict):
        return
    urls: List[str] = []
    key_pairs = {
        "start": "start_url",
        "middle": "middle_url",
        "end": "end_url",
        "contact": "contact_url",
        "peak": "peak_url",
        "release": "release_url",
        "contact_frame": "contact_frame_url",
        "peak_frame": "peak_frame_url",
        "release_frame": "release_frame_url",
    }
    for path_key, url_key in key_pairs.items():
        url = _key_action_file_url(experiment_id, keyframes.get(path_key))
        if url:
            keyframes[url_key] = url
            urls.append(url)
    if urls:
        keyframes["urls"] = urls


def _enrich_key_action_media_ref(experiment_id: str, ref: Any) -> None:
    if not isinstance(ref, dict):
        return
    _key_action_put_file_url(experiment_id, ref, "clip_path", "clip_url")
    _key_action_put_file_url(experiment_id, ref, "annotated_clip_path", "annotated_clip_url")
    _key_action_put_file_url(experiment_id, ref, "keyframe_path", "keyframe_url")
    if isinstance(ref.get("keyframe_paths"), list):
        urls = [_key_action_file_url(experiment_id, path) for path in ref.get("keyframe_paths") or []]
        ref["keyframe_urls"] = [url for url in urls if url]
    _enrich_key_action_keyframes(experiment_id, ref.get("keyframes"))


def _enrich_key_action_event(experiment_id: str, event: Dict[str, Any]) -> None:
    _key_action_put_file_url(experiment_id, event, "keyframe_path", "keyframe_url")
    _key_action_put_file_url(experiment_id, event, "keyframe_path", "preview_url")
    _key_action_put_file_url(experiment_id, event, "path", "url")
    _key_action_put_file_url(experiment_id, event, "path", "preview_url")


def _enrich_key_action_micro_segment(experiment_id: str, micro: Dict[str, Any]) -> None:
    _enrich_key_action_media_ref(experiment_id, micro.get("first_person"))
    _enrich_key_action_media_ref(experiment_id, micro.get("third_person"))
    for path_key, url_key in (
        ("first_person_clip", "first_person_clip_url"),
        ("third_person_clip", "third_person_clip_url"),
        ("peak_keyframe", "peak_keyframe_url"),
    ):
        _key_action_put_file_url(experiment_id, micro, path_key, url_key)
    _enrich_key_action_keyframes(experiment_id, micro.get("keyframes"))
    for binding in _key_action_list(micro.get("asset_bindings")):
        _enrich_key_action_media_ref(experiment_id, binding)


def _enrich_key_action_segment(experiment_id: str, segment: Dict[str, Any]) -> None:
    _enrich_key_action_media_ref(experiment_id, segment.get("first_person"))
    _enrich_key_action_media_ref(experiment_id, segment.get("third_person"))
    for binding in _key_action_list(segment.get("asset_bindings")):
        _enrich_key_action_media_ref(experiment_id, binding)
    for micro in _key_action_list(segment.get("micro_segments")):
        if isinstance(micro, dict):
            micro.setdefault("parent_segment_id", segment.get("segment_id"))
            _enrich_key_action_micro_segment(experiment_id, micro)
    for event in _key_action_list(segment.get("interaction_events")):
        if isinstance(event, dict):
            event.setdefault("segment_id", segment.get("segment_id"))
            _enrich_key_action_event(experiment_id, event)
    for keyframe in _key_action_list(segment.get("interaction_keyframes")):
        if isinstance(keyframe, dict):
            keyframe.setdefault("segment_id", segment.get("segment_id"))
            _enrich_key_action_event(experiment_id, keyframe)


def _key_action_segment_id_for_row(row: Dict[str, Any], segments: List[Dict[str, Any]]) -> Optional[str]:
    if not segments:
        return None
    local_time = _key_action_float(row.get("local_time_sec") or row.get("time_sec") or row.get("timestamp_sec"), -1.0)
    view = str(row.get("source_view") or row.get("view") or "").strip().lower()
    for segment in segments:
        ref = segment.get(view) if view in {"first_person", "third_person"} else None
        if not isinstance(ref, dict):
            ref = segment.get("first_person") if view.startswith("first") else segment.get("third_person")
        if not isinstance(ref, dict):
            continue
        start_sec = _key_action_float(ref.get("local_start_sec"), -1.0)
        end_sec = _key_action_float(ref.get("local_end_sec"), -1.0)
        if start_sec - 0.25 <= local_time <= end_sec + 0.25:
            return str(segment.get("segment_id") or "")
    if len(segments) == 1:
        return str(segments[0].get("segment_id") or "")
    return None


def _yolo_frame_rows_to_interaction_events(
    experiment_id: str,
    yolo_frame_rows: List[Dict[str, Any]],
    segments: List[Dict[str, Any]],
) -> List[Dict[str, Any]]:
    events: List[Dict[str, Any]] = []
    for frame_row in yolo_frame_rows:
        if not isinstance(frame_row, dict):
            continue
        segment_id = _key_action_segment_id_for_row(frame_row, segments)
        for interaction in _key_action_list(frame_row.get("hand_object_interactions")):
            if not isinstance(interaction, dict):
                continue
            index = len(events) + 1
            hand_label = interaction.get("hand_label")
            object_label = interaction.get("object_label")
            event = {
                "event_id": f"yolo_interaction_{index:04d}",
                "segment_id": segment_id,
                "view": frame_row.get("source_view") or frame_row.get("view"),
                "source_view": frame_row.get("source_view") or frame_row.get("view"),
                "frame_index": frame_row.get("frame_index"),
                "local_time_sec": frame_row.get("local_time_sec") or frame_row.get("time_sec"),
                "global_time": frame_row.get("global_time") or frame_row.get("global_timestamp"),
                "interaction": f"{hand_label or 'hand'}->{object_label or 'object'}",
                "hand_label": hand_label,
                "object_label": object_label,
                "object_name": interaction.get("object_name") or object_label,
                "confidence": interaction.get("score") or interaction.get("confidence"),
                "score": interaction.get("score") or interaction.get("confidence"),
                "distance_px": interaction.get("distance_px"),
                "iou": interaction.get("iou"),
                "hand_bbox": interaction.get("hand_bbox"),
                "object_bbox": interaction.get("object_bbox"),
                "detections": frame_row.get("detections") or [],
                "source": "yolo_frame_rows",
            }
            _enrich_key_action_event(experiment_id, event)
            events.append(event)
    return events


def _legacy_key_action_manifest_segments(
    experiment_id: str,
    output_dir: Path,
    root_manifest: Dict[str, Any],
) -> List[Dict[str, Any]]:
    actions = root_manifest.get("actions") or []
    segments: List[Dict[str, Any]] = []
    for index, action in enumerate(actions if isinstance(actions, list) else []):
        if not isinstance(action, dict):
            continue
        start_sec = _key_action_float(action.get("start_sec"), 0.0)
        end_sec = _key_action_float(action.get("end_sec"), start_sec)
        segment_id = str(action.get("id") or f"seg_{index + 1:06d}")
        objects = [str(item) for item in (action.get("objects") or [])]
        segments.append(
            {
                "session_id": experiment_id,
                "segment_id": segment_id,
                "global_start_time": root_manifest.get("generated_at") or "",
                "global_end_time": root_manifest.get("generated_at") or "",
                "duration_sec": max(0.0, end_sec - start_sec),
                "third_person": {
                    "video_path": "",
                    "clip_path": "",
                    "local_start_sec": start_sec,
                    "local_end_sec": end_sec,
                },
                "first_person": None,
                "cv_detection": {
                    "avg_motion_score": 0.0,
                    "avg_active_score": 0.0,
                    "start_reason": "recovered_manifest",
                    "end_reason": "recovered_manifest",
                },
                "text_description": {
                    "action_type": action.get("title") or segment_id,
                    "summary": action.get("description") or "",
                    "tools": [],
                    "objects": objects,
                    "numbers": [],
                },
                "dialogue_context": [],
                "yolo_labels": objects,
                "visual_keywords": objects,
                "index": {
                    "embedding_id": segment_id,
                    "index_text": " ".join([str(action.get("title") or ""), str(action.get("description") or ""), *objects]),
                    "vector_store": str(output_dir / "index"),
                },
            }
        )
    return segments


_key_action_results_cache: Dict[str, Any] = {}


def _key_action_results_payload(experiment_id: str) -> Dict[str, Any]:
    if experiment_id in _key_action_results_cache:
        return _key_action_results_cache[experiment_id]
    result = _key_action_results_payload_uncached(experiment_id)
    _key_action_results_cache[experiment_id] = result
    return result


def _key_action_results_payload_uncached(experiment_id: str) -> Dict[str, Any]:
    output_dir = _key_action_output_dir(experiment_id)
    metadata_dir = output_dir / "metadata"
    cv_dir = output_dir / "cv_outputs"
    exp_dir = _experiment_output_dir(experiment_id)
    root_manifest = _load_json_if_exists(exp_dir / "manifest.json") or {}
    status = _key_action_status_payload(experiment_id)

    segment_rows = _read_jsonl_rows(metadata_dir / "key_action_segments.jsonl")
    using_index_metadata = bool(segment_rows)
    if using_index_metadata:
        segments = _key_action_copy_rows(segment_rows)
        micro_segments = _key_action_copy_rows(_read_jsonl_rows(metadata_dir / "micro_segments.jsonl"))
        if not micro_segments:
            for segment in segments:
                for micro in _key_action_list(segment.get("micro_segments")):
                    if isinstance(micro, dict):
                        row = copy.deepcopy(micro)
                        row.setdefault("parent_segment_id", segment.get("segment_id"))
                        micro_segments.append(row)
        micro_by_parent: Dict[str, List[Dict[str, Any]]] = {}
        for micro in micro_segments:
            parent_id = str(micro.get("parent_segment_id") or micro.get("segment_id") or "")
            micro_by_parent.setdefault(parent_id, []).append(micro)
            _enrich_key_action_micro_segment(experiment_id, micro)
        for segment in segments:
            segment_id = str(segment.get("segment_id") or "")
            if not segment.get("micro_segments") and segment_id in micro_by_parent:
                segment["micro_segments"] = copy.deepcopy(micro_by_parent[segment_id])
            _enrich_key_action_segment(experiment_id, segment)

        interaction_keyframes: List[Dict[str, Any]] = []
        segment_interaction_events: List[Dict[str, Any]] = []
        yolo_interactions: List[Dict[str, Any]] = []
        for segment in segments:
            segment_id = segment.get("segment_id")
            for event in _key_action_list(segment.get("interaction_events")):
                if isinstance(event, dict):
                    row = copy.deepcopy(event)
                    row.setdefault("segment_id", segment_id)
                    _enrich_key_action_event(experiment_id, row)
                    segment_interaction_events.append(row)
            for keyframe in _key_action_list(segment.get("interaction_keyframes")):
                if isinstance(keyframe, dict):
                    row = copy.deepcopy(keyframe)
                    row.setdefault("segment_id", segment_id)
                    _enrich_key_action_event(experiment_id, row)
                    interaction_keyframes.append(row)
            for interaction in _key_action_list(segment.get("yolo_interactions")):
                if isinstance(interaction, dict):
                    row = copy.deepcopy(interaction)
                    row.setdefault("segment_id", segment_id)
                    yolo_interactions.append(row)

        yolo_frame_rows = _read_jsonl_rows(cv_dir / "yolo_frame_rows.jsonl")
        raw_yolo_events = _yolo_frame_rows_to_interaction_events(experiment_id, yolo_frame_rows, segments)
        interaction_events = raw_yolo_events or segment_interaction_events or yolo_interactions
        vector_metadata = _key_action_copy_rows(_read_jsonl_rows(metadata_dir / "vector_metadata.jsonl"))
        micro_vector_metadata = _key_action_copy_rows(_read_jsonl_rows(metadata_dir / "micro_vector_metadata.jsonl"))
        pipeline_summary = _load_json_if_exists(output_dir / "pipeline_summary.json") or {}
        yolo_frame_scan = _load_json_if_exists(metadata_dir / "yolo_frame_scan.json") or {}
        summary: Dict[str, Any] = {
            **(status.get("summary") if isinstance(status.get("summary"), dict) else {}),
            **(pipeline_summary.get("summary") if isinstance(pipeline_summary.get("summary"), dict) else {}),
            "source": "key_action_index_metadata",
            "segment_count": len(segments),
            "micro_segment_count": len(micro_segments),
            "interaction_event_count": len(interaction_events),
            "segment_interaction_event_count": len(segment_interaction_events),
            "interaction_keyframe_count": len(interaction_keyframes),
            "yolo_frame_row_count": len(yolo_frame_rows),
            "raw_yolo_interaction_count": len(raw_yolo_events),
            "yolo_interaction_count": len(yolo_interactions),
            "vector_metadata_count": len(vector_metadata),
        }
        detector_summary = pipeline_summary.get("detector_summary")
        if isinstance(detector_summary, dict):
            summary["detector_summary"] = detector_summary
        if not yolo_frame_scan:
            yolo_frame_scan = {
                "frame_rows": len(yolo_frame_rows),
                "interaction_count": len(raw_yolo_events),
                "source": "cv_outputs/yolo_frame_rows.jsonl",
            }
    else:
        segments = _legacy_key_action_manifest_segments(experiment_id, output_dir, root_manifest)
        micro_segments = []
        interaction_events = []
        interaction_keyframes = []
        vector_metadata = []
        micro_vector_metadata = []
        yolo_frame_scan = {}
        summary = {
            **(status.get("summary") if isinstance(status.get("summary"), dict) else {}),
            "source": "recovered_manifest" if root_manifest else "key_action_index",
            "segment_count": len(segments),
            "micro_segment_count": 0,
            "interaction_event_count": 0,
            "interaction_keyframe_count": 0,
        }

    formal_report_path = _experiment_output_artifact_paths(experiment_id).get("professional_report_pdf")
    formal_publish_health = _experiment_formal_publish_health(experiment_id)
    return {
        "experiment_id": experiment_id,
        "status": status,
        "output_dir": str(output_dir),
        "summary": summary,
        "time_axis": _experiment_time_axis_health(experiment_id),
        "formal_publish_health": formal_publish_health,
        "action_alignment_health": formal_publish_health.get("action_alignment"),
        "formal_report": {
            "path": str(formal_report_path) if formal_report_path else None,
            "url": f"/api/v1/experiments/{experiment_id}/artifacts/professional_report_pdf" if formal_report_path and formal_report_path.exists() else None,
            "available": bool(formal_report_path and formal_report_path.exists()),
        },
        "formal_report_path": str(formal_report_path) if formal_report_path else None,
        "formal_report_url": f"/api/v1/experiments/{experiment_id}/artifacts/professional_report_pdf" if formal_report_path and formal_report_path.exists() else None,
        "detected_segments": segments,
        "segments": segments,
        "vector_metadata": vector_metadata,
        "micro_vector_metadata": micro_vector_metadata,
        "micro_segments": micro_segments,
        "interaction_events": interaction_events,
        "interaction_keyframes": interaction_keyframes,
        "yolo_frame_scan": yolo_frame_scan,
        "debug": {
            "projection_source": summary.get("source"),
            "report": str(output_dir / "reports" / "mvp_validation_report.md"),
            "formal_report_path": str(formal_report_path) if formal_report_path else None,
            "formal_report_url": f"/api/v1/experiments/{experiment_id}/artifacts/professional_report_pdf" if formal_report_path and formal_report_path.exists() else None,
        },
    }


def _key_action_review_url(experiment_id: str, path_value: Any) -> Optional[str]:
    if not path_value:
        return None
    path = Path(str(path_value))
    if not path.is_absolute():
        output_candidate = _key_action_output_dir(experiment_id) / path
        exp_candidate = _experiment_output_dir(experiment_id) / path
        path = output_candidate if output_candidate.exists() else exp_candidate
    return _experiment_file_api_path(path, experiment_id)


def _enrich_key_action_review_item_urls(experiment_id: str, item: Dict[str, Any]) -> Dict[str, Any]:
    enriched = copy.deepcopy(item)
    enriched["preview_urls"] = [
        url
        for url in (_key_action_review_url(experiment_id, path) for path in enriched.get("preview_paths") or [])
        if url
    ]
    enriched["clip_urls"] = [
        url
        for url in (_key_action_review_url(experiment_id, path) for path in enriched.get("clip_paths") or [])
        if url
    ]
    return enriched


def _key_action_quality_payload(experiment_id: str) -> Dict[str, Any]:
    try:
        from key_action_indexer.review_queue import build_quality_convergence  # type: ignore

        payload = build_quality_convergence(_key_action_output_dir(experiment_id))
    except Exception as exc:
        logger.exception("Key-action quality convergence failed for %s", experiment_id)
        payload = {
            "schema_version": "key_action_quality_convergence.error",
            "experiment_id": experiment_id,
            "status": "failed",
            "error": str(exc),
        }
    payload["experiment_id"] = experiment_id
    return payload


_key_action_review_queue_cache: Dict[str, Any] = {}


def _invalidate_key_action_caches(experiment_id: str) -> None:
    _key_action_status_cache.pop(experiment_id, None)
    _key_action_results_cache.pop(experiment_id, None)
    _key_action_review_queue_cache.pop(experiment_id, None)
    _key_action_results_json_cache.pop(experiment_id, None)


def _key_action_review_queue_payload(experiment_id: str) -> Dict[str, Any]:
    if experiment_id in _key_action_review_queue_cache:
        return _key_action_review_queue_cache[experiment_id]
    result = _key_action_review_queue_payload_uncached(experiment_id)
    _key_action_review_queue_cache[experiment_id] = result
    return result


def _key_action_review_queue_payload_uncached(experiment_id: str) -> Dict[str, Any]:
    try:
        from key_action_indexer.review_queue import build_review_queue  # type: ignore

        payload = build_review_queue(
            _key_action_output_dir(experiment_id),
            material_candidates=_material_candidates_payload(experiment_id),
        )
    except Exception as exc:
        logger.exception("Key-action review queue failed for %s", experiment_id)
        payload = {
            "schema_version": "key_action_review_queue.error",
            "experiment_id": experiment_id,
            "summary": {"total": 0, "pending": 0, "approved": 0, "rejected": 0, "needs_review": 0},
            "items": [],
            "quality": _key_action_quality_payload(experiment_id),
            "error": str(exc),
        }
    payload["experiment_id"] = experiment_id
    payload["items"] = [
        _enrich_key_action_review_item_urls(experiment_id, item)
        for item in (payload.get("items") or [])
        if isinstance(item, dict)
    ]
    return payload


def _key_action_evidence_adapter_payload(experiment_id: str) -> Dict[str, Any]:
    output_dir = _key_action_output_dir(experiment_id)
    metadata = output_dir / "metadata"
    files = {
        "object_tracks": metadata / "object_tracks.jsonl",
        "panel_ocr": metadata / "panel_ocr.jsonl",
        "equipment_panel_states": metadata / "equipment_panel_states.jsonl",
        "liquid_state": metadata / "liquid_state.jsonl",
        "liquid_segmentation": metadata / "liquid_segmentation.jsonl",
        "container_state": metadata / "container_state.jsonl",
        "container_state_events": metadata / "container_state_events.jsonl",
        "model_observation_events": metadata / "model_observation_events.jsonl",
        "advanced_vision_evidence": metadata / "advanced_vision_evidence.jsonl",
    }
    counts = {name: _jsonl_row_count(path) for name, path in files.items()}
    try:
        from key_action_indexer.evidence_adapter_validation import validate_evidence_adapters  # type: ignore

        validation = validate_evidence_adapters(output_dir)
    except Exception as exc:
        logger.exception("Key-action evidence adapter validation failed for %s", experiment_id)
        validation = {
            "schema_version": "key_action_evidence_adapter_validation.error",
            "status": "fail",
            "error": str(exc),
        }
    return {
        "schema_version": "key_action_advanced_evidence_adapters.v1",
        "experiment_id": experiment_id,
        "metadata_dir": str(metadata),
        "protocol_doc": str(PROJECT_ROOT.parent / "docs" / "advanced_evidence_input_protocol.md"),
        "input_contracts": {
            "object_tracks.jsonl": "object trajectory, bbox track points, motion and identity confidence",
            "panel_ocr.jsonl": "equipment OCR, readout, button, knob, switch or control state rows",
            "liquid_state.jsonl": "liquid level, meniscus, flow, mask, volume or stream direction rows",
            "container_state.jsonl": "open/closed, cap/lid, color, liquid-level or container state rows",
        },
        "accepted_aliases": {
            "panel_ocr.jsonl": ["equipment_panel_states.jsonl", "equipment_panel_ocr.jsonl", "equipment_control_states.jsonl"],
            "liquid_state.jsonl": ["liquid_segmentation.jsonl", "liquid_level_events.jsonl", "liquid_flow_events.jsonl"],
            "container_state.jsonl": ["container_state_events.jsonl", "container_open_close_events.jsonl", "container_color_events.jsonl"],
        },
        "counts": counts,
        "validation": validation,
        "adapters": validation.get("adapters") if isinstance(validation, dict) else {},
        "summary": validation.get("summary") if isinstance(validation, dict) else {},
        "ready": bool(counts.get("model_observation_events") or counts.get("advanced_vision_evidence")),
    }


def _infer_key_action_start_time(*names: str) -> str:
    for name in names:
        capture_dt, _capture_source = _infer_key_action_capture_start_from_path(str(name or ""))
        if capture_dt is not None:
            return capture_dt.isoformat()
        match = re.search(r"(20\d{6})[-_]?(\d{6})", str(name or ""))
        if not match:
            continue
        date_text, time_text = match.groups()
        try:
            return datetime.strptime(f"{date_text}{time_text}", "%Y%m%d%H%M%S").astimezone().isoformat()
        except Exception:
            continue
    return _now_iso()


def _infer_key_action_camera_id(path_value: Optional[str], *, view: str) -> str:
    name = Path(str(path_value or "")).name.lower()
    if view == "first_person":
        return "first_person"
    if view == "third_person":
        return "third_person"
    if any(token in name for token in ("bottom_view", "usb", "front_view", "front-view", "front view")):
        return "bottom_view"
    if any(token in name for token in ("top_view", "rgb", "top-view", "top view")):
        return "top_view"
    if "bottom" in name and "top" not in name:
        return "bottom_view"
    if "top" in name:
        return "top_view"
    if view == "third_person":
        if "overview" in name:
            return "overview"
        return "third_person"
    if "first" in name or "fpv" in name or "ego" in name:
        return "first_person"
    return "first_person"


def _registered_key_action_video_paths(exp: Dict[str, Any]) -> tuple[Optional[str], Optional[str]]:
    third_person_path: Optional[str] = None
    first_person_path: Optional[str] = None
    descriptors = list(exp.get("video_inputs") or exp.get("video_metadata") or [])
    for descriptor in descriptors:
        if not isinstance(descriptor, dict):
            continue
        path = descriptor.get("video_path") or descriptor.get("source")
        if not path:
            continue
        view = str(descriptor.get("view_type") or descriptor.get("role") or "").strip().lower()
        camera_id = str(descriptor.get("camera_id") or "").strip().lower()
        if view in {"third_person", "top_view", "overview"}:
            third_person_path = str(path)
            continue
        if view in {"first_person", "operator_view", "bottom_view"}:
            first_person_path = str(path)
            continue
        if any(token in camera_id for token in ("camera_00", "top", "overview")):
            third_person_path = str(path)
        elif any(token in camera_id for token in ("camera_01", "bottom", "operator")):
            first_person_path = str(path)
    if third_person_path is None:
        paths = [str(item) for item in exp.get("video_paths") or [] if item]
        if paths:
            third_person_path = paths[0]
        if len(paths) > 1 and first_person_path is None:
            first_person_path = paths[1]
    return third_person_path, first_person_path


def _run_key_action_video_memory_write_stage(
    experiment_id: str,
    summary: Dict[str, Any],
) -> Dict[str, Any]:
    started = time.perf_counter()
    timing = summary.setdefault("backend_stage_timings", {})
    if not isinstance(timing, dict):
        timing = {}
        summary["backend_stage_timings"] = timing
    health = _experiment_time_axis_health(experiment_id)
    if not bool(health.get("can_write_video_memory", True)):
        duration_sec = round(time.perf_counter() - started, 3)
        timing["video_memory_write_sec"] = duration_sec
        return {
            "schema_version": "key_action_video_memory_write.v1",
            "status": "skipped",
            "reason": "time_axis_unreliable",
            "duration_sec": duration_sec,
            "can_write_video_memory": False,
        }
    formal_health = _experiment_formal_publish_health(experiment_id)
    if not bool(formal_health.get("can_write_video_memory", True)):
        duration_sec = round(time.perf_counter() - started, 3)
        timing["video_memory_write_sec"] = duration_sec
        return {
            "schema_version": "key_action_video_memory_write.v1",
            "status": "skipped",
            "reason": formal_health.get("reason") or "formal_publish_blocked",
            "duration_sec": duration_sec,
            "can_write_video_memory": False,
            "formal_publish_health": formal_health,
        }
    try:
        from key_action_indexer.video_memory import build_video_memory  # type: ignore

        result = build_video_memory(
            library_root=_material_library_root(),
            job_type="incremental",
            force_material_sync=False,
            vlm_mode="offline_metadata",
        )
        duration_sec = round(time.perf_counter() - started, 3)
        timing["video_memory_write_sec"] = duration_sec
        job = result.get("job") if isinstance(result.get("job"), dict) else {}
        snapshot = result.get("snapshot") if isinstance(result.get("snapshot"), dict) else {}
        counts = result.get("counts") if isinstance(result.get("counts"), dict) else {}
        return {
            "schema_version": "key_action_video_memory_write.v1",
            "status": str(job.get("job_status") or "succeeded"),
            "duration_sec": duration_sec,
            "job_id": job.get("job_id"),
            "snapshot_id": snapshot.get("snapshot_id"),
            "material_count": counts.get("materials"),
            "cluster_count": counts.get("clusters"),
            "window_completeness": job.get("window_completeness") or snapshot.get("window_completeness"),
        }
    except Exception as exc:
        duration_sec = round(time.perf_counter() - started, 3)
        timing["video_memory_write_sec"] = duration_sec
        logger.warning("Video Memory write skipped after key-action analysis for %s: %s", experiment_id, exc)
        return {
            "schema_version": "key_action_video_memory_write.v1",
            "status": "failed",
            "duration_sec": duration_sec,
            "error": str(exc),
        }


def _run_key_action_index_task(
    experiment_id: str,
    *,
    third_person_video_path: str,
    first_person_video_path: Optional[str],
    session_start_time: str,
    detection_config: Dict[str, Any],
) -> None:
    output_dir = _key_action_output_dir(experiment_id)
    task_started_perf = time.perf_counter()
    detection_config = _with_default_key_action_yolo_config(detection_config)
    yolo_runtime = _key_action_yolo_runtime_info()
    _write_key_action_status(
        experiment_id,
        {
            "status": "running",
            "progress": 0.1,
            "message": "准备双视角 key-action 输入",
            "started_at": _now_iso(),
            "third_person_video_path": third_person_video_path,
            "first_person_video_path": first_person_video_path,
            "detection_config": detection_config,
            "yolo_runtime": yolo_runtime,
            "elapsed_sec": 0.0,
        },
    )
    try:
        _validate_key_action_yolo_runtime(detection_config, runtime_info=yolo_runtime)
        try:
            from key_action_indexer.pipeline import run_detection_only, run_pipeline  # type: ignore
            from key_action_indexer.validation import validate_video_source  # type: ignore
            from key_action_indexer.yolo_analysis import (  # type: ignore
                enrich_key_action_index_with_yolo,
                render_segment_overlays_from_yolo_rows,
                render_experiment_focus_overlay_from_yolo_rows,
                run_yolo_on_experiment_focus_clips,
                run_yolo_on_segment_clips,
            )
        except Exception as exc:
            raise RuntimeError(
                "Full key-action runner is not present in the recovered workspace. "
                "Uploaded videos were saved, but automatic YOLO segment generation cannot run yet."
            ) from exc

        output_dir.mkdir(parents=True, exist_ok=True)
        third_info = validate_video_source(third_person_video_path)
        first_info = validate_video_source(first_person_video_path) if first_person_video_path else None
        third_fps = third_info.get("fps") or 30
        first_fps = (first_info or {}).get("fps") or third_fps
        timeline = _key_action_common_timeline(
            third_person_path=third_person_video_path,
            first_person_path=first_person_video_path,
            fallback_session_start_time=session_start_time,
            duration_fallbacks={
                "third_person": third_info.get("duration_sec"),
                "first_person": (first_info or {}).get("duration_sec"),
            },
        )
        timeline_views = timeline.get("views") if isinstance(timeline.get("views"), dict) else {}
        third_timeline = dict(timeline_views.get("third_person") or {})
        first_timeline = dict(timeline_views.get("first_person") or {})
        session_start_time = str(timeline.get("session_start_time") or session_start_time)
        manifest = {
            "session_id": experiment_id,
            "session_start_time": session_start_time,
            "videos": {
                "third_person": {
                    "path": third_person_video_path,
                    "start_time": third_timeline.get("start_time") or session_start_time,
                    "fps": third_fps,
                    "offset_sec": float(third_timeline.get("offset_sec") or 0.0),
                    "role": "third_person",
                    "camera_id": _infer_key_action_camera_id(third_person_video_path, view="third_person"),
                    "duration_sec": third_timeline.get("duration_sec") or third_info.get("duration_sec"),
                    "frames_csv_path": third_timeline.get("frames_csv_path") or _key_action_frames_csv_path(third_person_video_path),
                    "capture_start_time": third_timeline.get("capture_start_time"),
                    "capture_start_source": third_timeline.get("capture_start_source"),
                    "capture_start_status": third_timeline.get("capture_start_status"),
                    "global_start_sec": third_timeline.get("global_start_sec"),
                    "global_end_sec": third_timeline.get("global_end_sec"),
                }
            },
            "detection_config": detection_config,
            "config": {
                "timeline_alignment": {
                    "status": timeline.get("status"),
                    "alignment_status": timeline.get("alignment_status"),
                    "alignment_method": timeline.get("alignment_method"),
                    "alignment_reliable_for_dual_view_pairing": timeline.get("alignment_reliable_for_dual_view_pairing"),
                    "reliability_reasons": timeline.get("reliability_reasons") or [],
                    "duration_delta_sec": timeline.get("duration_delta_sec"),
                    "capture_metadata_anchor_count": timeline.get("capture_metadata_anchor_count"),
                    "capture_path_anchor_count": timeline.get("capture_path_anchor_count"),
                    "session_origin_time": timeline.get("session_origin_time"),
                    "session_origin_source": timeline.get("session_origin_source"),
                    "common_overlap_sec": timeline.get("common_overlap_sec"),
                    "common_overlap_start_sec": timeline.get("common_overlap_start_sec"),
                    "common_overlap_end_sec": timeline.get("common_overlap_end_sec"),
                    "source_start_offsets_sec": {
                        "third_person": third_timeline.get("global_start_sec"),
                        "first_person": first_timeline.get("global_start_sec"),
                    },
                }
            },
            "output_dir": str(output_dir),
        }
        if first_person_video_path:
            manifest["videos"]["first_person"] = {
                "path": first_person_video_path,
                "start_time": first_timeline.get("start_time") or session_start_time,
                "fps": first_fps,
                "offset_sec": float(first_timeline.get("offset_sec") or 0.0),
                "role": "first_person",
                "camera_id": _infer_key_action_camera_id(first_person_video_path, view="first_person"),
                "duration_sec": first_timeline.get("duration_sec") or (first_info or {}).get("duration_sec"),
                "frames_csv_path": first_timeline.get("frames_csv_path") or _key_action_frames_csv_path(first_person_video_path),
                "capture_start_time": first_timeline.get("capture_start_time"),
                "capture_start_source": first_timeline.get("capture_start_source"),
                "capture_start_status": first_timeline.get("capture_start_status"),
                "global_start_sec": first_timeline.get("global_start_sec"),
                "global_end_sec": first_timeline.get("global_end_sec"),
            }
        manifest_path = output_dir / "manifest.json"
        _write_json(manifest_path, manifest)

        def _pipeline_progress_callback(event: Dict[str, Any]) -> None:
            progress = float(event.get("progress") or 0.35)
            progress = max(0.12, min(0.935, progress))
            message = str(event.get("message") or "Running key-action pipeline")
            status_payload = {
                "status": "running",
                "progress": progress,
                "message": message,
                "stage": event.get("stage"),
                "pipeline_progress": event,
                "elapsed_sec": round(time.perf_counter() - task_started_perf, 3),
            }
            _write_key_action_status(experiment_id, status_payload)
            try:
                exp_state = _load_json_if_exists(_experiment_output_dir(experiment_id) / "experiment.json") or {}
                task_id = (
                    exp_state.get("analysis_job_id")
                    if isinstance(exp_state, dict)
                    else None
                ) or f"key_action_{experiment_id}"
                _persist_experiment_task_state(
                    experiment_id,
                    {
                        "task_id": task_id,
                        "experiment_id": experiment_id,
                        "status": "running",
                        "current_stage": str(event.get("stage") or ProcessStage.DATA_ANALYSIS.value),
                        "progress": progress,
                        "message": message,
                        "video_path": third_person_video_path,
                        "started_at": _read_key_action_status(experiment_id).get("started_at"),
                        "elapsed_sec": round(time.perf_counter() - task_started_perf, 3),
                    },
                )
            except Exception:
                logger.debug("Key-action progress task-state update failed for %s", experiment_id, exc_info=True)

        fast_locate_only = _key_action_truthy(os.environ.get("KEY_ACTION_FAST_LOCATE_ONLY"), False) or _key_action_truthy(
            detection_config.get("fast_locate_only"),
            False,
        )
        if fast_locate_only:
            _write_key_action_status(
                experiment_id,
                {
                    "progress": 0.30,
                    "message": "运行 YOLO 粗扫与物理交互精扫",
                    "stage": "fast_locate",
                },
            )
            previous_fast_locate_env = os.environ.get("KEY_ACTION_FAST_LOCATE_ONLY")
            os.environ["KEY_ACTION_FAST_LOCATE_ONLY"] = "1"
            try:
                summary = run_detection_only(manifest_path, dry_run=False)
            finally:
                if previous_fast_locate_env is None:
                    os.environ.pop("KEY_ACTION_FAST_LOCATE_ONLY", None)
                else:
                    os.environ["KEY_ACTION_FAST_LOCATE_ONLY"] = previous_fast_locate_env
            refined_mode = summary.get("mode") == "yolo_fast_locate_refined" or summary.get("fast_locate_only") is False
            summary.setdefault("fast_locate_only", not refined_mode)
            summary.setdefault("mode", "yolo_fast_locate_refined" if refined_mode else "yolo_fast_locate_only")
            timing_summary = _load_json_if_exists(output_dir / "metadata" / "yolo_timing_summary.json")
            if isinstance(timing_summary, dict):
                summary["yolo_timing_summary"] = timing_summary
            yolo_scan_summary = _load_json_if_exists(output_dir / "metadata" / "yolo_scan_summary.json")
            if isinstance(yolo_scan_summary, dict):
                summary["yolo_scan_summary"] = yolo_scan_summary
            _write_key_action_status(
                experiment_id,
                {
                    "progress": 0.985,
                    "message": "写入 30 天态势 Memory",
                },
            )
            summary["video_memory_write"] = _run_key_action_video_memory_write_stage(experiment_id, summary)
            _write_json(output_dir / "pipeline_summary.json", summary)
            completed_at = _now_iso()
            elapsed_sec = round(time.perf_counter() - task_started_perf, 3)
            output_size_summary = _key_action_output_size_summary(output_dir)
            exp = _load_json_if_exists(_experiment_output_dir(experiment_id) / "experiment.json") or {}
            if isinstance(exp, dict) and exp:
                output_paths = {
                    **(exp.get("output_paths") or {}),
                    "key_action_index": str(output_dir),
                }
                task_id = exp.get("analysis_job_id") or exp.get("run_id") or f"key_action_{experiment_id}"
                exp["status"] = ExperimentStatus.ANALYZED.value
                exp["processing_stage"] = ProcessStage.OUTPUT_GENERATION.value
                exp["completed_at"] = completed_at
                exp["analyzed_at"] = completed_at
                exp["analysis_job_id"] = task_id
                exp["output_paths"] = output_paths
                upload_context = _key_action_upload_context(exp.get("key_action_index"))
                exp["key_action_index"] = {
                    **upload_context,
                    "status": "completed",
                    "ready_for_delivery": True,
                    "segment_count": int(summary.get("segment_count") or 0),
                    "coarse_segment_count": int(summary.get("coarse_segment_count") or summary.get("segment_count") or 0),
                    "micro_segment_count": int(summary.get("micro_segment_count") or 0),
                    "output_dir": str(output_dir),
                    "fast_locate_only": bool(summary.get("fast_locate_only", not refined_mode)),
                    "fast_locate_refined": bool(refined_mode),
                    "material_candidate_summary": summary.get("material_candidate_summary") or {},
                    "yolo_runtime": _key_action_yolo_runtime_info(),
                }
                _save_experiment(exp)
                _persist_experiment_task_state(
                    experiment_id,
                    {
                        "task_id": task_id,
                        "experiment_id": experiment_id,
                        "status": "completed",
                        "current_stage": "fast_locate_refined" if refined_mode else "fast_locate",
                        "progress": 1.0,
                        "message": "YOLO 粗扫与物理交互精扫完成"
                        if refined_mode
                        else "YOLO 粗扫完成；关键片段与 micro 证据已延后生成",
                        "video_path": third_person_video_path,
                        "started_at": _read_key_action_status(experiment_id).get("started_at"),
                        "completed_at": completed_at,
                        "output_paths": output_paths,
                        "key_action_index": exp.get("key_action_index"),
                        "elapsed_sec": elapsed_sec,
                        "output_size_summary": output_size_summary,
                        "error_type": None,
                        "error_message": None,
                    },
                )
            _write_key_action_status(
                experiment_id,
                {
                    "status": "completed",
                    "progress": 1.0,
                    "message": "YOLO 粗扫与物理交互精扫完成"
                    if refined_mode
                    else "YOLO 粗扫完成；关键片段与 micro 证据已延后生成",
                    "completed_at": completed_at,
                    "elapsed_sec": elapsed_sec,
                    "output_size_summary": output_size_summary,
                    "yolo_runtime": _key_action_yolo_runtime_info(),
                    "summary": summary,
                    "summary_path": str(output_dir / "pipeline_summary.json"),
                    "fast_locate_only": bool(summary.get("fast_locate_only", not refined_mode)),
                    "fast_locate_refined": bool(refined_mode),
                    "ready_for_delivery": True,
                    "stage": "fast_locate_refined" if refined_mode else "fast_locate",
                },
            )
            return

        _write_key_action_status(experiment_id, {"progress": 0.30, "message": "Running key-action detection, clipping and indexing"})
        summary = run_pipeline(manifest_path, dry_run=False, progress_callback=_pipeline_progress_callback)
        views = ["third_person"] + (["first_person"] if first_person_video_path else [])
        model_paths_by_view = {
            "first_person": detection_config.get("yolo_first_person_model_path"),
            "third_person": detection_config.get("yolo_third_person_model_path"),
        }
        try:
            render_segment_overlay_default = _key_action_truthy(
                detection_config.get("render_segment_yolo"),
                _key_action_truthy(os.environ.get("KEY_ACTION_RENDER_SEGMENT_YOLO_DEFAULT"), False),
            )
            if render_segment_overlay_default:
                overlay_source = str(os.environ.get("KEY_ACTION_SEGMENT_OVERLAY_SOURCE") or "rows").strip().lower()
                _write_key_action_status(
                    experiment_id,
                    {
                        "progress": 0.88,
                        "message": "Rendering YOLO annotated dual-view key-action clips from cached rows"
                        if overlay_source != "model"
                        else "Rendering YOLO annotated dual-view key-action clips",
                    },
                )
                if overlay_source == "model":
                    yolo_clip_summary = run_yolo_on_segment_clips(
                        output_dir,
                        model_path=detection_config.get("yolo_model_path"),
                        project_root=PROJECT_ROOT,
                        preferred_view=str(detection_config.get("yolo_preferred_view") or "first_person"),
                        views=views,
                        model_paths_by_view=model_paths_by_view,
                        conf=float(detection_config.get("yolo_conf", 0.25)),
                        iou=float(detection_config.get("yolo_iou", 0.45)),
                        device=str(detection_config.get("yolo_device") or os.environ.get("KEY_ACTION_YOLO_DEVICE", "cpu")),
                        detect_fps=float(os.environ.get("KEY_ACTION_YOLO_ANNOTATION_FPS", "5.0")),
                        class_thresholds=detection_config.get("yolo_class_thresholds")
                        if isinstance(detection_config.get("yolo_class_thresholds"), dict)
                        else None,
                    )
                    yolo_clip_summary["render_source"] = "model"
                else:
                    yolo_clip_summary = render_segment_overlays_from_yolo_rows(
                        output_dir,
                        preferred_view=str(detection_config.get("yolo_preferred_view") or "first_person"),
                        views=views,
                    )
                summary["yolo_annotated_clips"] = yolo_clip_summary
                _write_key_action_segment_overlay_status(
                    experiment_id,
                    {
                        "status": "completed" if yolo_clip_summary.get("available") else "failed",
                        "available": bool(yolo_clip_summary.get("available")),
                        "summary": yolo_clip_summary,
                        "completed_at": _now_iso(),
                    },
                )
            else:
                yolo_clip_summary = {
                    "available": False,
                    "status": "deferred",
                    "reason": "on_demand_render",
                    "render_source": "yolo_frame_rows",
                    "reused_yolo_rows": True,
                    "render_endpoint": f"/api/v1/experiments/{experiment_id}/key-actions/segment-overlays/render",
                    "message": "Segment YOLO overlays are generated on demand; default analysis keeps index, micro evidence and material package generation fast.",
                }
                _write_json(output_dir / "metadata" / "yolo_clip_summary.json", yolo_clip_summary)
                _write_key_action_segment_overlay_status(
                    experiment_id,
                    {
                        "status": "deferred",
                        "available": False,
                        "summary": yolo_clip_summary,
                    },
                )
                summary["yolo_annotated_clips"] = yolo_clip_summary
            summary["yolo_index_enrichment"] = enrich_key_action_index_with_yolo(output_dir)
        except Exception as exc:
            logger.exception("YOLO annotated key-action clip generation failed for experiment %s", experiment_id)
            summary["yolo_annotated_clips"] = {"available": False, "error": str(exc)}
        backend_stage_timings: Dict[str, float] = {}
        candidate_summary: Optional[Dict[str, Any]] = None
        try:
            from key_action_indexer.material_references import build_yolo_material_candidates  # type: ignore

            vlm_assist_client, vlm_assist_config = _build_key_action_vlm_assist_client()
            summary["key_action_vlm_assist"] = vlm_assist_config
            _write_key_action_status(
                experiment_id,
                {
                    "progress": 0.94,
                    "message": "Building YOLO/VLM-assisted review-gated physical-action material candidates",
                    "key_action_vlm_assist": vlm_assist_config,
                },
            )
            material_candidate_started = time.perf_counter()
            candidate_summary = build_yolo_material_candidates(
                output_dir,
                archive_existing=False,
                rebuild_source=True,
                vlm_client=vlm_assist_client,
                enable_vlm=bool(vlm_assist_config.get("enabled")),
                max_vlm_groups=int(vlm_assist_config.get("max_groups") or 0),
                vlm_model_name=str(vlm_assist_config.get("model") or ""),
            )
            backend_stage_timings["material_candidate_generation_sec"] = round(time.perf_counter() - material_candidate_started, 6)
        except Exception as exc:
            logger.exception("Key-action material candidate generation failed for experiment %s", experiment_id)
            candidate_summary = {"status": "failed", "error": str(exc)}
        _write_key_action_status(
            experiment_id,
            {
                "progress": 0.965,
                "message": "Staging review-gated key material candidates",
                "material_candidates": candidate_summary,
            },
        )
        material_publish_started = time.perf_counter()
        material_auto_publish = _auto_publish_key_action_material_candidates(experiment_id, candidate_summary)
        backend_stage_timings["material_auto_publish_sec"] = round(time.perf_counter() - material_publish_started, 6)
        if isinstance(candidate_summary, dict):
            candidate_summary["auto_publish"] = material_auto_publish
        summary["material_candidates"] = candidate_summary
        summary["material_auto_publish"] = material_auto_publish
        summary["backend_stage_timings"] = backend_stage_timings
        _write_key_action_status(
            experiment_id,
            {
                "progress": 0.972,
                "message": "写入 30 天态势 Memory",
            },
        )
        summary["video_memory_write"] = _run_key_action_video_memory_write_stage(experiment_id, summary)
        render_focus_overlay_default = _key_action_truthy(
            detection_config.get("render_experiment_focus_yolo"),
            _key_action_truthy(os.environ.get("KEY_ACTION_RENDER_EXPERIMENT_FOCUS_YOLO_DEFAULT"), False),
        )
        if render_focus_overlay_default:
            try:
                overlay_source = str(os.environ.get("KEY_ACTION_EXPERIMENT_FOCUS_OVERLAY_SOURCE") or "rows").strip().lower()
                _write_key_action_status(
                    experiment_id,
                    {
                        "progress": 0.975,
                        "message": "Rendering experiment-focus YOLO overlay from cached detection rows"
                        if overlay_source != "model"
                        else "Rendering continuous experiment-focus dual-view YOLO clips",
                    },
                )
                if overlay_source == "model":
                    focus_clip_summary = run_yolo_on_experiment_focus_clips(
                        output_dir,
                        model_path=detection_config.get("yolo_model_path"),
                        project_root=PROJECT_ROOT,
                        preferred_view=str(detection_config.get("yolo_preferred_view") or "first_person"),
                        views=["third_person"] + (["first_person"] if first_person_video_path else []),
                        model_paths_by_view={
                            "first_person": detection_config.get("yolo_first_person_model_path"),
                            "third_person": detection_config.get("yolo_third_person_model_path"),
                        },
                        conf=float(detection_config.get("yolo_conf", 0.25)),
                        iou=float(detection_config.get("yolo_iou", 0.45)),
                        device=str(detection_config.get("yolo_device") or os.environ.get("KEY_ACTION_YOLO_DEVICE", "cpu")),
                        detect_fps=float(os.environ.get("KEY_ACTION_YOLO_EXPERIMENT_FOCUS_FPS", os.environ.get("KEY_ACTION_YOLO_ANNOTATION_FPS", "5.0"))),
                        class_thresholds=detection_config.get("yolo_class_thresholds")
                        if isinstance(detection_config.get("yolo_class_thresholds"), dict)
                        else None,
                    )
                else:
                    focus_clip_summary = render_experiment_focus_overlay_from_yolo_rows(
                        output_dir,
                        preferred_view=str(detection_config.get("yolo_preferred_view") or "first_person"),
                        views=["third_person"] + (["first_person"] if first_person_video_path else []),
                    )
                summary["yolo_experiment_focus_clips"] = focus_clip_summary
                _write_key_action_focus_overlay_status(
                    experiment_id,
                    {
                        "status": "completed" if focus_clip_summary.get("available") else "failed",
                        "available": bool(focus_clip_summary.get("available")),
                        "summary": focus_clip_summary,
                        "completed_at": _now_iso(),
                    },
                )
            except Exception as exc:
                logger.exception("YOLO experiment-focus clip generation failed for experiment %s", experiment_id)
                summary["yolo_experiment_focus_clips"] = {"available": False, "error": str(exc)}
                _write_key_action_focus_overlay_status(
                    experiment_id,
                    {"status": "failed", "available": False, "error": str(exc), "completed_at": _now_iso()},
                )
        else:
            existing_focus_summary = _load_json_if_exists(output_dir / "metadata" / "yolo_experiment_focus_summary.json")
            if isinstance(existing_focus_summary, dict) and existing_focus_summary.get("available"):
                focus_clip_summary = {**existing_focus_summary, "status": "completed", "cache_status": "existing"}
            else:
                focus_clip_summary = {
                    "available": False,
                    "status": "deferred",
                    "reason": "on_demand_render",
                    "render_source": "yolo_frame_rows",
                    "reused_yolo_rows": True,
                    "render_endpoint": f"/api/v1/experiments/{experiment_id}/key-actions/focus-overlay/render",
                    "message": "Experiment-focus YOLO overlay is generated on demand; default analysis keeps index, micro evidence and material package generation fast.",
                }
                _write_json(output_dir / "metadata" / "yolo_experiment_focus_summary.json", focus_clip_summary)
            _write_key_action_status(
                experiment_id,
                {
                    "progress": 0.975,
                    "message": "Experiment-focus YOLO overlay deferred; index and material evidence are ready for review",
                    "focus_overlay": focus_clip_summary,
                },
            )
            _write_key_action_focus_overlay_status(
                experiment_id,
                {
                    "status": focus_clip_summary.get("status") or "deferred",
                    "available": bool(focus_clip_summary.get("available")),
                    "summary": focus_clip_summary,
                },
            )
            summary["yolo_experiment_focus_clips"] = focus_clip_summary
        try:
            from key_action_indexer.quality_gate import build_quality_gate  # type: ignore
            from key_action_indexer.reviewed_dataset import freeze_reviewed_dataset  # type: ignore

            freeze_reviewed_default = _key_action_truthy(
                detection_config.get("freeze_reviewed_dataset"),
                _key_action_truthy(os.environ.get("KEY_ACTION_FREEZE_REVIEWED_DATASET_DEFAULT"), False),
            )
            create_reviewed_release = _key_action_truthy(
                detection_config.get("create_reviewed_release"),
                _key_action_truthy(os.environ.get("KEY_ACTION_CREATE_REVIEWED_RELEASE_DEFAULT"), False),
            )
            write_reviewed_export = _key_action_truthy(
                detection_config.get("write_reviewed_export"),
                _key_action_truthy(os.environ.get("KEY_ACTION_WRITE_REVIEWED_EXPORT_DEFAULT"), create_reviewed_release),
            )
            if freeze_reviewed_default or create_reviewed_release or write_reviewed_export:
                reviewed_release = freeze_reviewed_dataset(
                    output_dir,
                    create_release=create_reviewed_release,
                    write_export=write_reviewed_export,
                )
                summary["reviewed_dataset"] = reviewed_release
            else:
                summary["reviewed_dataset"] = {
                    "available": False,
                    "status": "deferred",
                    "reason": "on_demand_review_freeze",
                    "create_release": False,
                    "write_export": False,
                    "freeze_endpoint": f"/api/v1/experiments/{experiment_id}/key-actions/review/freeze",
                    "message": "Reviewed dataset release/export is generated after explicit review freeze; default analysis keeps the fast evidence package lean.",
                }
            summary["reviewed_quality_gate"] = build_quality_gate(
                output_dir,
                output_path=output_dir / "reports" / "quality_gate.json",
            )
        except Exception as exc:
            logger.exception("Reviewed release convergence failed for experiment %s", experiment_id)
            summary["reviewed_dataset"] = {"available": False, "error": str(exc)}
        _write_json(output_dir / "pipeline_summary.json", summary)
        result = _key_action_results_payload(experiment_id)
        quality_gate_started = time.perf_counter()
        quality_payload = _key_action_quality_payload(experiment_id)
        backend_stage_timings["quality_gate_sec"] = round(time.perf_counter() - quality_gate_started, 6)
        summary["backend_stage_timings"] = backend_stage_timings
        quality_gate = quality_payload.get("quality_gate") if isinstance(quality_payload, dict) else None
        if not isinstance(quality_gate, dict):
            quality_gate = {}
        can_mark_complete = bool(quality_gate.get("can_mark_complete"))
        requires_review = bool(quality_gate.get("requires_review"))
        ready_for_delivery = bool(quality_gate.get("ready_for_delivery", can_mark_complete and not requires_review))
        final_key_action_status = "completed" if can_mark_complete else "needs_review"
        final_task_status = "completed" if can_mark_complete else "partial_failed"
        final_message = (
            "key-action 分析完成，交付前需要素材与质量复核"
            if can_mark_complete and requires_review
            else "key-action 分析完成"
            if can_mark_complete
            else "key-action 输出已生成，质量门禁需要复核"
        )
        summary["quality_gate"] = quality_gate
        summary["quality_convergence"] = quality_payload
        generate_professional_report = _key_action_truthy(
            detection_config.get("generate_professional_report"),
            _key_action_truthy(os.environ.get("KEY_ACTION_PROFESSIONAL_REPORT_ENABLED"), False),
        )

        exp = _load_json_if_exists(_experiment_output_dir(experiment_id) / "experiment.json") or {}
        if isinstance(exp, dict) and exp:
            output_paths = {
                **(exp.get("output_paths") or {}),
                "key_action_index": str(output_dir),
            }
            if generate_professional_report:
                professional_report = _generate_professional_report_for_experiment(
                    experiment_id,
                    output_paths=output_paths,
                )
            else:
                professional_report = {
                    "schema_version": "professional_report.pipeline.v1",
                    "experiment_id": experiment_id,
                    "enabled": False,
                    "available": False,
                    "status": "deferred",
                    "reason": "key_action_fast_default",
                    "message": "Professional PDF generation is deferred for the default fast key-action pipeline.",
                    "generated_at": _now_iso(),
                }
            output_paths = _attach_professional_report_output_paths(
                experiment_id,
                output_paths,
                professional_report,
            )
            exp.setdefault("output_paths", {})
            exp["output_paths"] = output_paths
            upload_context = _key_action_upload_context(exp.get("key_action_index"))
            exp["key_action_index"] = {
                **upload_context,
                "status": final_key_action_status,
                "segment_count": len(result.get("segments") or []),
                "output_dir": str(output_dir),
                "report": str(output_dir / "reports" / "mvp_validation_report.md"),
                "material_candidates": _compact_material_candidates_for_status(candidate_summary),
                "quality_gate": _compact_quality_gate_for_status(quality_gate),
                "requires_review": requires_review,
                "ready_for_delivery": ready_for_delivery,
            }
            exp.setdefault("metadata", {})["professional_report"] = professional_report
            completed_at = _now_iso()
            projected_step_groups = _key_action_step_groups_for_overview(experiment_id)
            task_id = exp.get("analysis_job_id") or exp.get("run_id") or f"key_action_{experiment_id}"
            exp["status"] = ExperimentStatus.ANALYZED.value if can_mark_complete else "partial_failed"
            exp["processing_stage"] = ProcessStage.OUTPUT_GENERATION.value
            exp["completed_at"] = completed_at if can_mark_complete else None
            exp["analyzed_at"] = completed_at
            exp["analysis_job_id"] = task_id
            exp["total_steps"] = len(projected_step_groups.get("candidate") or []) + len(projected_step_groups.get("inferred") or [])
            _save_experiment(exp)
            _persist_experiment_task_state(
                experiment_id,
                {
                    "task_id": task_id,
                    "experiment_id": experiment_id,
                    "status": final_task_status,
                    "current_stage": ProcessStage.OUTPUT_GENERATION.value,
                    "progress": 1.0 if can_mark_complete else 0.98,
                    "message": final_message,
                    "video_path": third_person_video_path,
                    "started_at": _read_key_action_status(experiment_id).get("started_at"),
                    "completed_at": completed_at if can_mark_complete else None,
                    "output_paths": output_paths,
                    "professional_report": professional_report,
                    "key_action_index": exp.get("key_action_index"),
                    "quality_gate": _compact_quality_gate_for_status(quality_gate),
                    "requires_review": requires_review,
                    "ready_for_delivery": ready_for_delivery,
                    "elapsed_sec": round(time.perf_counter() - task_started_perf, 3),
                    "output_size_summary": _key_action_output_size_summary(output_dir),
                    "error_type": None,
                    "error_message": None,
                },
            )

        elapsed_sec = round(time.perf_counter() - task_started_perf, 3)
        _write_json(output_dir / "pipeline_summary.json", summary)
        _write_key_action_status(
            experiment_id,
            {
                "status": final_key_action_status,
                "progress": 1.0 if can_mark_complete else 0.98,
                "message": final_message,
                "completed_at": _now_iso() if can_mark_complete else None,
                "elapsed_sec": elapsed_sec,
                "output_size_summary": _key_action_output_size_summary(output_dir),
                "yolo_runtime": _key_action_yolo_runtime_info(),
                "summary": summary,
                "summary_path": str(output_dir / "pipeline_summary.json"),
                "quality_gate": quality_gate,
                "requires_review": requires_review,
                "ready_for_delivery": ready_for_delivery,
                "material_candidates": candidate_summary,
            },
        )
    except Exception as exc:
        logger.exception("Key-action pipeline failed for experiment %s", experiment_id)
        cuda_gate_failed = isinstance(exc, KeyActionCudaRequiredError)
        public_error = (
            _key_action_cuda_required_message(_key_action_yolo_runtime_info(), detection_config)
            if cuda_gate_failed
            else str(exc)
        )
        _write_key_action_status(
            experiment_id,
            {
                "status": "failed",
                "progress": 1.0,
                "message": public_error,
                "error": public_error,
                "error_type": "KEY_ACTION_CUDA_REQUIRED" if cuda_gate_failed else type(exc).__name__,
                "error_message": public_error,
                "completed_at": _now_iso(),
                "detection_config": detection_config,
                "yolo_runtime": _key_action_yolo_runtime_info(),
                "elapsed_sec": round(time.perf_counter() - task_started_perf, 3),
                "output_size_summary": _key_action_output_size_summary(output_dir),
            },
        )


def _run_key_action_focus_overlay_render_task(
    experiment_id: str,
    *,
    source: str = "rows",
    views: Optional[List[str]] = None,
    force: bool = False,
    max_hold_sec: Optional[float] = None,
) -> None:
    output_dir = _key_action_output_dir(experiment_id)
    _write_key_action_focus_overlay_status(
        experiment_id,
        {
            "status": "running",
            "available": False,
            "message": "Rendering experiment-focus YOLO overlay",
            "started_at": _now_iso(),
            "source": source,
            "views": views,
        },
    )
    try:
        if not output_dir.exists():
            raise RuntimeError(f"Key-action output directory does not exist: {output_dir}")
        manifest = _load_json_if_exists(output_dir / "manifest.json") or {}
        videos = manifest.get("videos") if isinstance(manifest.get("videos"), dict) else {}
        requested_views = views or (["third_person"] + (["first_person"] if isinstance(videos, dict) and videos.get("first_person") else []))
        detection_config = _with_default_key_action_yolo_config(
            manifest.get("detection_config") if isinstance(manifest.get("detection_config"), dict) else {}
        )
        source_name = str(source or "rows").strip().lower()
        if source_name == "model":
            from key_action_indexer.yolo_analysis import run_yolo_on_experiment_focus_clips  # type: ignore

            summary = run_yolo_on_experiment_focus_clips(
                output_dir,
                model_path=detection_config.get("yolo_model_path"),
                project_root=PROJECT_ROOT,
                preferred_view=str(detection_config.get("yolo_preferred_view") or "first_person"),
                views=requested_views,
                model_paths_by_view={
                    "first_person": detection_config.get("yolo_first_person_model_path"),
                    "third_person": detection_config.get("yolo_third_person_model_path"),
                },
                conf=float(detection_config.get("yolo_conf", 0.25)),
                iou=float(detection_config.get("yolo_iou", 0.45)),
                device=str(detection_config.get("yolo_device") or os.environ.get("KEY_ACTION_YOLO_DEVICE", "cpu")),
                detect_fps=float(os.environ.get("KEY_ACTION_YOLO_EXPERIMENT_FOCUS_FPS", os.environ.get("KEY_ACTION_YOLO_ANNOTATION_FPS", "5.0"))),
                class_thresholds=detection_config.get("yolo_class_thresholds")
                if isinstance(detection_config.get("yolo_class_thresholds"), dict)
                else None,
            )
            summary["render_source"] = "model"
        else:
            from key_action_indexer.yolo_analysis import render_experiment_focus_overlay_from_yolo_rows  # type: ignore

            summary = render_experiment_focus_overlay_from_yolo_rows(
                output_dir,
                preferred_view=str(detection_config.get("yolo_preferred_view") or "first_person"),
                views=requested_views,
                max_hold_sec=max_hold_sec,
                force=force,
            )
        pipeline_summary = _load_json_if_exists(output_dir / "pipeline_summary.json")
        if isinstance(pipeline_summary, dict):
            pipeline_summary["yolo_experiment_focus_clips"] = summary
            _write_json(output_dir / "pipeline_summary.json", pipeline_summary)
        _invalidate_key_action_caches(experiment_id)
        _write_key_action_focus_overlay_status(
            experiment_id,
            {
                "status": "completed" if summary.get("available") else "failed",
                "available": bool(summary.get("available")),
                "message": "Experiment-focus YOLO overlay ready" if summary.get("available") else "Experiment-focus YOLO overlay failed",
                "summary": summary,
                "completed_at": _now_iso(),
            },
        )
    except Exception as exc:
        logger.exception("Experiment-focus YOLO overlay render failed for %s", experiment_id)
        _write_key_action_focus_overlay_status(
            experiment_id,
            {
                "status": "failed",
                "available": False,
                "message": str(exc),
                "error": str(exc),
                "completed_at": _now_iso(),
            },
        )


