def _resolve_material_diagnostic_path(path_value: Any) -> Optional[Path]:
    if not path_value:
        return None
    raw_path = str(path_value)
    normalized = raw_path.replace("\\", "/")
    normalized_lower = normalized.lower()
    for root_name in ("outputs", "uploads"):
        marker = f"{root_name}/experiments/"
        marker_index = normalized_lower.find(marker)
        if marker_index < 0:
            continue
        tail = normalized[marker_index + len(marker):]
        parts = [part for part in tail.split("/") if part]
        if not parts:
            continue
        experiment_root = (PROJECT_ROOT / root_name / "experiments").resolve()
        candidate = experiment_root.joinpath(*parts).resolve()
        try:
            candidate.relative_to(experiment_root)
        except ValueError:
            continue
        return candidate
    try:
        return _safe_project_path(raw_path, PROJECT_ROOT)
    except HTTPException:
        return None


def _material_path_exists(path_value: Any) -> bool:
    path = _resolve_material_diagnostic_path(path_value)
    return bool(path and path.exists() and path.is_file())


def _material_clip_is_playable(path_value: Any) -> bool:
    path = _resolve_material_diagnostic_path(path_value)
    return bool(path and path.exists() and path.is_file() and path.suffix.lower() in _PLAYABLE_CLIP_SUFFIXES)


def _material_duration_sec(item: Dict[str, Any]) -> float:
    for key in ("duration_sec", "clip_duration_sec"):
        value = item.get(key)
        if value is not None:
            try:
                return max(0.0, float(value))
            except (TypeError, ValueError):
                pass
    try:
        return max(0.0, float(item.get("time_end", 0.0)) - float(item.get("time_start", 0.0)))
    except (TypeError, ValueError):
        return 0.0


def _material_published_paths(item: Dict[str, Any]) -> Dict[str, Any]:
    paths = item.get("published_paths")
    return paths if isinstance(paths, dict) else {}


def _material_item_file_exists(item: Dict[str, Any]) -> bool:
    paths = _material_published_paths(item)
    for value in (
        paths.get("clip"),
        paths.get("preview"),
        paths.get("keyframe"),
        item.get("clip_file_path"),
        item.get("frame_path"),
        item.get("material_path"),
        item.get("stored_file"),
    ):
        if _material_path_exists(value):
            return True
    return False


def _material_best_score_value(item: Dict[str, Any]) -> float:
    try:
        return float(item.get("best_score") or 0.0)
    except (TypeError, ValueError):
        return 0.0


def _material_yolo_evidence_count(item: Dict[str, Any]) -> int:
    yolo = item.get("yolo_recheck") if isinstance(item.get("yolo_recheck"), dict) else {}
    payload = item.get("payload") if isinstance(item.get("payload"), dict) else {}
    diagnostics = yolo.get("diagnostics") if isinstance(yolo.get("diagnostics"), dict) else {}
    for value in (
        item.get("yolo_evidence_count"),
        yolo.get("valid_evidence_count"),
        diagnostics.get("valid_evidence_count"),
        payload.get("yolo_evidence_count"),
    ):
        try:
            return max(0, int(value))
        except (TypeError, ValueError):
            continue
    return 0


def _material_view_set(item: Dict[str, Any]) -> set[str]:
    views: set[str] = set()
    for value in (item.get("view"), item.get("camera_id"), item.get("stream_id")):
        if value:
            views.add(str(value))
    yolo = item.get("yolo_recheck") if isinstance(item.get("yolo_recheck"), dict) else {}
    if yolo.get("view"):
        views.add(str(yolo.get("view")))
    diagnostics = yolo.get("diagnostics") if isinstance(yolo.get("diagnostics"), dict) else {}
    for key in ("evidence_by_view", "valid_evidence_by_view"):
        values = diagnostics.get(key)
        if isinstance(values, dict):
            views.update(str(view) for view, count in values.items() if count)
    return {view for view in views if view}


def _numeric_distribution(values: List[float]) -> Dict[str, Any]:
    clean = sorted(float(value) for value in values if isinstance(value, (int, float)) and np.isfinite(value))
    if not clean:
        return {"count": 0, "min": None, "p50": None, "avg": None, "max": None}
    midpoint = len(clean) // 2
    p50 = clean[midpoint] if len(clean) % 2 else (clean[midpoint - 1] + clean[midpoint]) / 2
    return {
        "count": len(clean),
        "min": round(clean[0], 4),
        "p50": round(p50, 4),
        "avg": round(sum(clean) / len(clean), 4),
        "max": round(clean[-1], 4),
    }


def _candidate_decision_ratio(status_counts: Dict[str, int]) -> Dict[str, Any]:
    total = sum(status_counts.values())
    if total <= 0:
        return {"total": 0}
    return {
        "total": total,
        "approved_ratio": round(status_counts.get("approved", 0) / total, 4),
        "pending_ratio": round(status_counts.get("pending", 0) / total, 4),
        "false_positive_ratio": round(status_counts.get("rejected", 0) / total, 4),
        "not_selected_ratio": round(status_counts.get("not_selected", 0) / total, 4),
        "deferred_ratio": round(status_counts.get("deferred", 0) / total, 4),
    }


def _threshold_recommendation_for_action(
    action: str,
    *,
    candidate_total: int,
    approved_total: int,
    rejected_total: int,
    formal_total: int,
    yolo_distribution: Dict[str, Any],
    score_distribution: Dict[str, Any],
) -> str:
    if candidate_total == 0:
        return "Detection gap: no candidates reached the YOLO/material gate. Lower the object confidence only after checking raw detections for this action."
    if approved_total == 0 and formal_total == 0:
        return "Review gap: candidates exist but none were approved. Prioritize manual review before changing detector thresholds."
    if rejected_total > approved_total and rejected_total >= 3:
        return "False-positive pressure is high. Raise the hand-object interaction requirement or require VLM alignment for this action."
    if float(yolo_distribution.get("p50") or 0) < 2:
        return "YOLO evidence is thin. Keep single-view fallback, but lower only the per-object threshold, not the interaction gate."
    if float(score_distribution.get("p50") or 0) < 0.65:
        return "Best-score distribution is weak. Keep approval manual and prefer clips over frames for this class."
    return f"{action} is stable under the current >=2 YOLO evidence-frame gate; keep threshold and monitor new experiments."


def _material_taxonomy_calibration_report(
    experiment_id: str,
    payload: Dict[str, Any],
    *,
    candidate_rows: Optional[List[Dict[str, Any]]] = None,
) -> Dict[str, Any]:
    raw_items = payload.get("items") if isinstance(payload, dict) else []
    items = [item for item in raw_items if isinstance(item, dict)]
    candidates = candidate_rows if candidate_rows is not None else [enrich_material_taxonomy(row) for row in _material_candidate_rows(experiment_id)]
    rows_by_action: Dict[str, List[Dict[str, Any]]] = {action: [] for action in STANDARD_MATERIAL_ACTION_TYPES}
    items_by_action: Dict[str, List[Dict[str, Any]]] = {action: [] for action in STANDARD_MATERIAL_ACTION_TYPES}
    unmapped_candidates = []
    for row in candidates:
        action = str(row.get("canonical_action_type") or "")
        if action in rows_by_action:
            rows_by_action[action].append(row)
        else:
            unmapped_candidates.append(row)
    for item in items:
        action = str(item.get("canonical_action_type") or "")
        if action in items_by_action:
            items_by_action[action].append(item)

    per_action: Dict[str, Dict[str, Any]] = {}
    for action in STANDARD_MATERIAL_ACTION_TYPES:
        action_candidates = rows_by_action[action]
        action_items = items_by_action[action]
        status_counts: Dict[str, int] = {}
        for row in action_candidates:
            status = _material_candidate_status(row)
            status_counts[status] = status_counts.get(status, 0) + 1
        missing_files = sum(1 for item in action_items if not _material_item_file_exists(item))
        best_scores = [_material_best_score_value(item) for item in action_items]
        yolo_counts = [_material_yolo_evidence_count(item) for item in action_candidates + action_items]
        view_counts = [_material_view_set(item) for item in action_items]
        single_view_total = sum(1 for views in view_counts if len(views) <= 1)
        multiview_total = sum(1 for views in view_counts if len(views) >= 2)
        score_distribution = _numeric_distribution(best_scores)
        yolo_distribution = _numeric_distribution([float(count) for count in yolo_counts])
        if not action_candidates:
            missing_reason = "detection_missing"
            recommendation = "No candidates reached the YOLO physical-evidence gate; inspect detector labels and consider a lower object/interaction threshold for this class."
        elif not action_items and status_counts.get("approved", 0) == 0:
            missing_reason = "approval_gate"
            recommendation = "Review pending candidates and approve at least one representative keyframe/clip for the class."
        elif not action_items:
            missing_reason = "file_unavailable_or_sync_missing"
            recommendation = "Approved candidates exist but are not visible in published materials; re-sync formal references and check copied files."
        elif missing_files:
            missing_reason = "file_unavailable"
            recommendation = "Formal rows exist but one or more files cannot be opened; rebuild the material reference mirror."
        else:
            missing_reason = "covered"
            recommendation = "Class is covered; keep the current >=2 YOLO evidence-frame gate unless new false positives appear."
        threshold_recommendation = _threshold_recommendation_for_action(
            action,
            candidate_total=len(action_candidates),
            approved_total=status_counts.get("approved", 0),
            rejected_total=status_counts.get("rejected", 0),
            formal_total=len(action_items),
            yolo_distribution=yolo_distribution,
            score_distribution=score_distribution,
        )
        per_action[action] = {
            "candidate_total": len(action_candidates),
            "approved_total": status_counts.get("approved", 0),
            "pending_total": status_counts.get("pending", 0),
            "rejected_total": status_counts.get("rejected", 0),
            "deferred_total": status_counts.get("deferred", 0),
            "not_selected_total": status_counts.get("not_selected", 0),
            "formal_material_total": len(action_items),
            "best_material_total": 1 if action_items else 0,
            "missing_file_count": missing_files,
            "missing_reason": missing_reason,
            "missing_reason_detail": recommendation,
            "best_score_distribution": score_distribution,
            "yolo_evidence_distribution": yolo_distribution,
            "view_support": {
                "formal_material_total": len(action_items),
                "single_view_total": single_view_total,
                "multi_view_total": multiview_total,
                "single_view_ratio": round(single_view_total / len(action_items), 4) if action_items else 0.0,
                "multi_view_ratio": round(multiview_total / len(action_items), 4) if action_items else 0.0,
            },
            "candidate_decision_ratio": _candidate_decision_ratio(status_counts),
            "threshold_recommendation": threshold_recommendation,
        }

    return {
        "schema_version": "material_taxonomy_calibration.v1",
        "experiment_id": experiment_id,
        "generated_at": datetime.now(timezone.utc).isoformat(),
        "taxonomy": list(STANDARD_MATERIAL_ACTION_TYPES),
        "candidate_total": len(candidates),
        "formal_material_total": len(items),
        "unmapped_candidate_total": len(unmapped_candidates),
        "per_action": per_action,
        "acceptance_queries": ["天平称量", "取试剂瓶", "药匙加样", "称量纸", "容器承接"],
        "suggested_thresholds": {
            "min_yolo_evidence_frames": 2,
            "prefer_yolo_evidence_frames": 3,
            "min_quality_score_for_best": 0.70,
            "require_hand_object_interaction": True,
            "allow_single_view_when_yolo_vlm_aligned": True,
        },
    }


def _write_material_taxonomy_calibration_report(experiment_id: str, payload: Dict[str, Any]) -> Dict[str, Any]:
    report = _material_taxonomy_calibration_report(experiment_id, payload)
    exp_dir = _experiment_output_dir(experiment_id)
    _write_json(exp_dir / "material_taxonomy_calibration.json", report)
    today = datetime.now().strftime("%Y-%m-%d")
    _write_json(exp_dir / f"material_taxonomy_calibration_{today}.json", report)
    return report


