@app.put("/api/v1/experiments/{experiment_id}/key-actions/upload-raw/{view}", tags=["experiments"])
async def upload_key_action_raw_video(
    experiment_id: str,
    view: str,
    request: Request,
    background_tasks: BackgroundTasks,
    x_filename: Optional[str] = Header(None, alias="X-Filename"),
    x_session_start_time: Optional[str] = Header(None, alias="X-Session-Start-Time"),
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Stream one key-action video directly to disk without multipart temp-file overhead."""
    request_received_at = _now_iso()
    save_started_perf = time.perf_counter()
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    await get_experiment_dict(safe_experiment_id)
    normalized_view = _normalize_key_action_raw_upload_view(view)
    default_name = f"{normalized_view}.mp4"
    raw_name = _decode_upload_filename(x_filename, default_name=default_name)
    prefix = "first" if normalized_view == "first_person" else "third"
    stored = await _save_request_stream_to_video_store(
        request,
        experiment_id=safe_experiment_id,
        view_type=normalized_view,
        original_filename=raw_name,
        default_name=default_name,
        max_bytes=MAX_VIDEO_UPLOAD_BYTES,
    )
    target_path = Path(str(stored["path"]))
    pointer_path = _write_video_store_pointer(
        safe_experiment_id,
        view_type=normalized_view,
        stored=stored,
        prefix=prefix,
    )
    stored["video_ref_path"] = str(pointer_path)
    size = int(stored.get("size_bytes") or stored.get("size") or 0)
    upload_completed_at = _now_iso()
    upload_save_sec = round(time.perf_counter() - save_started_perf, 3)

    async with _key_action_raw_upload_lock(safe_experiment_id):
        exp = await get_experiment_dict(safe_experiment_id)
        metadata = _register_key_action_video_source(
            exp,
            target_path,
            view_type=normalized_view,
            storage_ref=stored,
        )
        _record_video_store_ref(exp, view_type=normalized_view, stored=stored, pointer_path=pointer_path)
        exp["video_asset_id"] = exp.get("video_asset_id") or f"{safe_experiment_id}:key-action-video:0"
        if exp.get("status") in {"created", ExperimentStatus.CREATED.value, ExperimentStatus.DRAFT.value}:
            exp["status"] = ExperimentStatus.VIDEO_UPLOADED.value
        _ensure_experiment_run_metadata(exp)
        exp["output_paths"] = {
            **(exp.get("output_paths") or {}),
            **_write_experiment_run_artifacts(safe_experiment_id, exp),
            "key_action_index": str(_key_action_output_dir(safe_experiment_id)),
        }
        key_action_index = dict(exp.get("key_action_index") or {})
        key_action_index.update(
            {
                "status": "uploaded",
                "output_dir": str(_key_action_output_dir(safe_experiment_id)),
                "request_received_at": key_action_index.get("request_received_at") or request_received_at,
                "upload_completed_at": upload_completed_at,
                "upload_mode": "raw_stream",
                "video_store_ingest_sec": upload_save_sec,
            }
        )
        if x_session_start_time:
            key_action_index["session_start_time"] = x_session_start_time
        if normalized_view == "third_person":
            key_action_index["third_person_video_path"] = str(target_path)
            key_action_index["third_person_video_ref_path"] = str(pointer_path)
            key_action_index["third_person_sha256"] = stored.get("sha256")
            key_action_index["third_person_deduplicated"] = stored.get("deduplicated")
            key_action_index["third_person_upload_save_sec"] = upload_save_sec
            key_action_index["third_person_video_store_ingest_sec"] = upload_save_sec
        else:
            key_action_index["first_person_video_path"] = str(target_path)
            key_action_index["first_person_video_ref_path"] = str(pointer_path)
            key_action_index["first_person_sha256"] = stored.get("sha256")
            key_action_index["first_person_deduplicated"] = stored.get("deduplicated")
            key_action_index["first_person_upload_save_sec"] = upload_save_sec
            key_action_index["first_person_video_store_ingest_sec"] = upload_save_sec
        key_action_index["storage_mode"] = "external_video_store"
        key_action_index["upload_save_sec"] = round(
            max(
                float(key_action_index.get("third_person_upload_save_sec") or 0.0),
                float(key_action_index.get("first_person_upload_save_sec") or 0.0),
            ),
            3,
        )
        exp["key_action_index"] = key_action_index
        alignment = _write_dual_view_upload_alignment(
            safe_experiment_id,
            exp,
            session_start_time=str(key_action_index.get("session_start_time") or x_session_start_time or ""),
        )
        if alignment:
            key_action_index["timeline_alignment_path"] = str(_experiment_output_dir(safe_experiment_id) / "timeline_alignment.json")
            key_action_index["timeline_alignment_status"] = alignment.get("alignment_status")
            exp["key_action_index"] = key_action_index
        _save_experiment(exp)

    return {
        "experiment_id": safe_experiment_id,
        "view": normalized_view,
        "video_path": str(target_path),
        "video_ref_path": str(pointer_path),
        "storage_mode": "external_video_store",
        "sha256": stored.get("sha256"),
        "deduplicated": stored.get("deduplicated"),
        "copied": stored.get("copied"),
        "registered_via": stored.get("registered_via"),
        "size": size,
        "metadata": metadata,
        "request_received_at": request_received_at,
        "upload_completed_at": upload_completed_at,
        "upload_save_sec": upload_save_sec,
        "video_store_ingest_sec": upload_save_sec,
        "ingest_elapsed_sec": upload_save_sec,
        "upload_mode": "raw_stream",
    }


@app.post("/api/v1/experiments/{experiment_id}/key-actions/register-raw/{view}", tags=["experiments"])
async def register_key_action_raw_video(
    experiment_id: str,
    view: str,
    req: VideoStoreRegisterRequest,
    background_tasks: BackgroundTasks,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Register an existing key-action raw video by hash or manifest without copying bytes."""
    request_received_at = _now_iso()
    register_started_perf = time.perf_counter()
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    normalized_view = _normalize_key_action_raw_upload_view(view)
    await get_experiment_dict(safe_experiment_id)
    prefix = "first" if normalized_view == "first_person" else "third"
    stored = _resolve_existing_video_store_ref(
        req,
        experiment_id=safe_experiment_id,
        view_type=normalized_view,
    )
    target_path = Path(str(stored["path"]))
    pointer_path = _write_video_store_pointer(
        safe_experiment_id,
        view_type=normalized_view,
        stored=stored,
        prefix=prefix,
    )
    stored["video_ref_path"] = str(pointer_path)
    size = int(stored.get("size_bytes") or stored.get("size") or 0)
    upload_completed_at = _now_iso()
    register_elapsed_sec = round(time.perf_counter() - register_started_perf, 3)

    async with _key_action_raw_upload_lock(safe_experiment_id):
        exp = await get_experiment_dict(safe_experiment_id)
        metadata = _register_key_action_video_source(
            exp,
            target_path,
            view_type=normalized_view,
            storage_ref=stored,
        )
        metadata["copied"] = False
        metadata["registered_via"] = "hash_manifest"
        _record_video_store_ref(exp, view_type=normalized_view, stored=stored, pointer_path=pointer_path)
        exp["video_asset_id"] = exp.get("video_asset_id") or f"{safe_experiment_id}:key-action-video:0"
        if exp.get("status") in {"created", ExperimentStatus.CREATED.value, ExperimentStatus.DRAFT.value}:
            exp["status"] = ExperimentStatus.VIDEO_UPLOADED.value
        _ensure_experiment_run_metadata(exp)
        exp["output_paths"] = {
            **(exp.get("output_paths") or {}),
            **_write_experiment_run_artifacts(safe_experiment_id, exp),
            "key_action_index": str(_key_action_output_dir(safe_experiment_id)),
        }
        key_action_index = dict(exp.get("key_action_index") or {})
        key_action_index.update(
            {
                "status": "uploaded",
                "output_dir": str(_key_action_output_dir(safe_experiment_id)),
                "request_received_at": key_action_index.get("request_received_at") or request_received_at,
                "upload_completed_at": upload_completed_at,
                "upload_mode": "hash_manifest_register",
                "storage_mode": "external_video_store",
                "register_elapsed_sec": register_elapsed_sec,
                "video_store_ingest_sec": register_elapsed_sec,
            }
        )
        req_session_start = getattr(req, "session_start_time", None)
        if req_session_start:
            key_action_index["session_start_time"] = req_session_start
        if normalized_view == "third_person":
            key_action_index["third_person_video_path"] = str(target_path)
            key_action_index["third_person_video_ref_path"] = str(pointer_path)
            key_action_index["third_person_sha256"] = stored.get("sha256")
            key_action_index["third_person_deduplicated"] = True
            key_action_index["third_person_upload_save_sec"] = register_elapsed_sec
            key_action_index["third_person_video_store_ingest_sec"] = register_elapsed_sec
        else:
            key_action_index["first_person_video_path"] = str(target_path)
            key_action_index["first_person_video_ref_path"] = str(pointer_path)
            key_action_index["first_person_sha256"] = stored.get("sha256")
            key_action_index["first_person_deduplicated"] = True
            key_action_index["first_person_upload_save_sec"] = register_elapsed_sec
            key_action_index["first_person_video_store_ingest_sec"] = register_elapsed_sec
        key_action_index["upload_save_sec"] = round(
            max(
                float(key_action_index.get("third_person_upload_save_sec") or 0.0),
                float(key_action_index.get("first_person_upload_save_sec") or 0.0),
            ),
            3,
        )
        exp["key_action_index"] = key_action_index
        alignment = _write_dual_view_upload_alignment(
            safe_experiment_id,
            exp,
            session_start_time=str(key_action_index.get("session_start_time") or req_session_start or ""),
        )
        if alignment:
            key_action_index["timeline_alignment_path"] = str(_experiment_output_dir(safe_experiment_id) / "timeline_alignment.json")
            key_action_index["timeline_alignment_status"] = alignment.get("alignment_status")
            exp["key_action_index"] = key_action_index
        _save_experiment(exp)

    return {
        "experiment_id": safe_experiment_id,
        "view": normalized_view,
        "video_path": str(target_path),
        "video_ref_path": str(pointer_path),
        "storage_mode": "external_video_store",
        "sha256": stored.get("sha256"),
        "deduplicated": True,
        "copied": False,
        "registered_via": "hash_manifest",
        "size": size,
        "metadata": metadata,
        "request_received_at": request_received_at,
        "upload_completed_at": upload_completed_at,
        "upload_save_sec": register_elapsed_sec,
        "register_elapsed_sec": register_elapsed_sec,
        "video_store_ingest_sec": register_elapsed_sec,
        "ingest_elapsed_sec": register_elapsed_sec,
        "upload_mode": "hash_manifest_register",
    }


@app.put("/api/v1/experiments/{experiment_id}/key-actions/upload-analysis-proxy/{view}", tags=["experiments"])
async def upload_key_action_analysis_proxy(
    experiment_id: str,
    view: str,
    request: Request,
    x_filename: Optional[str] = Header(None, alias="X-Filename"),
    x_session_start_time: Optional[str] = Header(None, alias="X-Session-Start-Time"),
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Register a lightweight analysis proxy for an already-uploaded raw key-action video."""
    request_received_at = _now_iso()
    save_started_perf = time.perf_counter()
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    normalized_view = _normalize_key_action_raw_upload_view(view)
    async with _key_action_raw_upload_lock(safe_experiment_id):
        exp = await get_experiment_dict(safe_experiment_id)
        third_person_path, first_person_path = _registered_key_action_video_paths(exp)
        source_path = first_person_path if normalized_view == "first_person" else third_person_path
        if not source_path:
            raise HTTPException(status_code=409, detail=f"Upload raw {normalized_view} video before its analysis proxy")
        if not Path(source_path).exists():
            raise HTTPException(status_code=404, detail=f"Raw {normalized_view} video not found: {source_path}")

        raw_name = _decode_upload_filename(x_filename, default_name=f"{normalized_view}_analysis_proxy.mp4")
        safe_name = _sanitize_upload_filename(raw_name, default_name=f"{normalized_view}_analysis_proxy.mp4")
        staging_dir = _experiment_output_dir(safe_experiment_id) / "analysis_proxy_uploads"
        staging_dir.mkdir(parents=True, exist_ok=True)
        staging_path = staging_dir / f"{normalized_view}_{uuid.uuid4().hex[:8]}_{safe_name}"
        size = await _save_request_stream_to_file(request, staging_path, max_bytes=MAX_VIDEO_UPLOAD_BYTES)

        try:
            from key_action_indexer.analysis_proxy import register_existing_analysis_proxy_for_source  # type: ignore
            from key_action_indexer.schemas import VideoSource  # type: ignore
        except Exception as exc:
            try:
                staging_path.unlink(missing_ok=True)
            except Exception:
                pass
            raise HTTPException(status_code=500, detail=f"Analysis proxy support is unavailable: {exc}") from exc

        key_action_index = dict(exp.get("key_action_index") or {})
        session_start_time = (
            x_session_start_time
            or key_action_index.get("session_start_time")
            or exp.get("created_at")
            or _now_iso()
        )
        source = VideoSource(
            name=normalized_view,
            path=str(source_path),
            start_time=str(session_start_time),
            role=normalized_view,
            camera_id=_infer_key_action_camera_id(source_path, view=normalized_view),
            offset_sec=0.0,
        )
        try:
            proxy_meta = register_existing_analysis_proxy_for_source(
                source,
                view=normalized_view,
                proxy_root=_experiment_output_dir(safe_experiment_id) / "analysis_proxy",
                proxy_file=staging_path,
                source_label="frontend_uploaded_analysis_proxy",
            )
        except Exception as exc:
            try:
                staging_path.unlink(missing_ok=True)
            except Exception:
                pass
            raise HTTPException(status_code=400, detail=f"Failed to register analysis proxy: {exc}") from exc

        upload_completed_at = _now_iso()
        upload_save_sec = round(time.perf_counter() - save_started_perf, 3)
        key_action_index.setdefault("analysis_proxy", {})
        key_action_index["analysis_proxy"][normalized_view] = {
            "status": proxy_meta.get("status"),
            "proxy_path": proxy_meta.get("proxy_path"),
            "metadata_path": proxy_meta.get("metadata_path"),
            "cache_key": proxy_meta.get("cache_key"),
            "settings": proxy_meta.get("settings"),
            "size_bytes": proxy_meta.get("size_bytes"),
            "upload_save_sec": upload_save_sec,
            "request_received_at": request_received_at,
            "upload_completed_at": upload_completed_at,
        }
        if x_session_start_time:
            key_action_index["session_start_time"] = x_session_start_time
        exp["key_action_index"] = key_action_index
        _save_experiment(exp)

    return {
        "experiment_id": safe_experiment_id,
        "view": normalized_view,
        "proxy_path": proxy_meta.get("proxy_path"),
        "metadata_path": proxy_meta.get("metadata_path"),
        "size": size,
        "cache_key": proxy_meta.get("cache_key"),
        "settings": proxy_meta.get("settings"),
        "request_received_at": request_received_at,
        "upload_completed_at": upload_completed_at,
        "upload_save_sec": upload_save_sec,
        "upload_mode": "analysis_proxy_stream",
    }


@app.post("/api/v1/experiments/{experiment_id}/key-actions/upload-and-run", tags=["experiments"])
async def upload_and_run_key_actions(
    experiment_id: str,
    background_tasks: BackgroundTasks,
    first_person_video: Optional[UploadFile] = File(None),
    third_person_video: Optional[UploadFile] = File(None),
    top_video: Optional[UploadFile] = File(None),
    bottom_video: Optional[UploadFile] = File(None),
    session_start_time: Optional[str] = Form(None),
    fast_locate_only: bool = Form(True),
    sample_fps: float = Form(0.2),
    start_threshold: float = Form(0.18),
    end_threshold: float = Form(0.08),
    start_min_duration_sec: float = Form(1.0),
    end_min_duration_sec: float = Form(2.0),
    merge_gap_sec: float = Form(3.0),
    min_segment_duration_sec: float = Form(2.0),
    buffer_sec: float = Form(1.0),
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Upload dual-view videos and run key-action indexing plus report delivery."""
    request_received_at = _now_iso()
    upload_save_started_perf = time.perf_counter()
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    exp = await get_experiment_dict(safe_experiment_id)

    def has_upload(upload: Optional[UploadFile]) -> bool:
        return bool(upload and upload.filename)

    third_upload = (
        third_person_video
        if has_upload(third_person_video)
        else bottom_video
        if has_upload(bottom_video)
        else None
    )
    first_upload = (
        first_person_video
        if has_upload(first_person_video)
        else top_video
        if has_upload(top_video)
        else None
    )
    if first_upload is third_upload:
        first_upload = None
    if third_upload is None:
        raise HTTPException(status_code=400, detail="A third_person_video/bottom_video file is required")

    third_upload_name = third_upload.filename or "third_person.mp4"
    first_upload_name = first_upload.filename if first_upload else ""
    third_stored = await _save_upload_to_video_store(
        third_upload,
        experiment_id=safe_experiment_id,
        view_type="third_person",
        default_name="third_person.mp4",
        max_bytes=MAX_VIDEO_UPLOAD_BYTES,
    )
    third_path = Path(str(third_stored["path"]))
    third_ref_path = _write_video_store_pointer(
        safe_experiment_id,
        view_type="third_person",
        stored=third_stored,
        prefix="third",
    )
    third_stored["video_ref_path"] = str(third_ref_path)
    third_size = int(third_stored.get("size_bytes") or third_stored.get("size") or 0)

    first_path: Optional[Path] = None
    first_size: Optional[int] = None
    first_stored: Optional[Dict[str, Any]] = None
    first_ref_path: Optional[Path] = None
    if first_upload is not None:
        first_stored = await _save_upload_to_video_store(
            first_upload,
            experiment_id=safe_experiment_id,
            view_type="first_person",
            default_name="first_person.mp4",
            max_bytes=MAX_VIDEO_UPLOAD_BYTES,
        )
        first_path = Path(str(first_stored["path"]))
        first_ref_path = _write_video_store_pointer(
            safe_experiment_id,
            view_type="first_person",
            stored=first_stored,
            prefix="first",
        )
        first_stored["video_ref_path"] = str(first_ref_path)
        first_size = int(first_stored.get("size_bytes") or first_stored.get("size") or 0)
    upload_completed_at = _now_iso()
    upload_save_sec = round(time.perf_counter() - upload_save_started_perf, 3)

    third_metadata = _register_key_action_video_source(
        exp,
        third_path,
        view_type="third_person",
        storage_ref=third_stored,
    )
    _record_video_store_ref(exp, view_type="third_person", stored=third_stored, pointer_path=third_ref_path)
    first_metadata = None
    if first_path and first_stored:
        first_metadata = _register_key_action_video_source(
            exp,
            first_path,
            view_type="first_person",
            storage_ref=first_stored,
        )
        _record_video_store_ref(exp, view_type="first_person", stored=first_stored, pointer_path=first_ref_path)
    inferred_start = session_start_time or _infer_key_action_start_time(
        third_upload_name,
        first_upload_name,
    )
    detection_config = {
        "fast_locate_only": bool(fast_locate_only),
        "sample_fps": float(sample_fps),
        "start_threshold": float(start_threshold),
        "end_threshold": float(end_threshold),
        "start_min_duration_sec": float(start_min_duration_sec),
        "end_min_duration_sec": float(end_min_duration_sec),
        "merge_gap_sec": float(merge_gap_sec),
        "min_segment_duration_sec": float(min_segment_duration_sec),
        "buffer_sec": float(buffer_sec),
        "motion_normalization": "adaptive",
        "roi_mode": "manifest_or_default",
        "require_cuda": True,
    }
    detection_config = _with_default_key_action_yolo_config(detection_config)
    try:
        yolo_runtime = _validate_key_action_yolo_runtime(detection_config)
    except KeyActionCudaRequiredError as exc:
        raise HTTPException(
            status_code=409,
            detail=_key_action_cuda_failure_detail(exc, detection_config),
        ) from exc

    exp["video_asset_id"] = exp.get("video_asset_id") or f"{safe_experiment_id}:key-action-video:0"
    task_id = exp.get("analysis_job_id") or exp.get("run_id") or f"key_action_{safe_experiment_id}"
    exp["analysis_job_id"] = task_id
    if exp.get("status") in {"created", ExperimentStatus.CREATED.value, ExperimentStatus.DRAFT.value}:
        exp["status"] = ExperimentStatus.VIDEO_UPLOADED.value
    _ensure_experiment_run_metadata(exp)
    exp["output_paths"] = {
        **(exp.get("output_paths") or {}),
        **_write_experiment_run_artifacts(safe_experiment_id, exp),
        "key_action_index": str(_key_action_output_dir(safe_experiment_id)),
    }
    exp["key_action_index"] = {
        "status": "queued",
        "third_person_video_path": str(third_path),
        "first_person_video_path": str(first_path) if first_path else None,
        "third_person_video_ref_path": str(third_ref_path),
        "first_person_video_ref_path": str(first_ref_path) if first_ref_path else None,
        "third_person_sha256": third_stored.get("sha256"),
        "first_person_sha256": first_stored.get("sha256") if first_stored else None,
        "third_person_deduplicated": third_stored.get("deduplicated"),
        "first_person_deduplicated": first_stored.get("deduplicated") if first_stored else None,
        "storage_mode": "external_video_store",
        "session_start_time": inferred_start,
        "output_dir": str(_key_action_output_dir(safe_experiment_id)),
        "request_received_at": request_received_at,
        "upload_completed_at": upload_completed_at,
        "upload_save_sec": upload_save_sec,
        "video_store_ingest_sec": upload_save_sec,
        "yolo_runtime": yolo_runtime,
    }
    alignment = _write_dual_view_upload_alignment(safe_experiment_id, exp, session_start_time=inferred_start)
    if alignment:
        exp["key_action_index"]["timeline_alignment_path"] = str(_experiment_output_dir(safe_experiment_id) / "timeline_alignment.json")
        exp["key_action_index"]["timeline_alignment_status"] = alignment.get("alignment_status")
    _save_experiment(exp)

    queued_at = _now_iso()
    status = _write_key_action_status(
        safe_experiment_id,
        {
            "status": "queued",
            "progress": 0.0,
            "message": "视频已上传，正式 key-action 分析正在启动",
            "request_received_at": request_received_at,
            "upload_completed_at": upload_completed_at,
            "upload_save_sec": upload_save_sec,
            "queued_at": queued_at,
            "third_person_video_path": str(third_path),
            "first_person_video_path": str(first_path) if first_path else None,
            "third_person_video_ref_path": str(third_ref_path),
            "first_person_video_ref_path": str(first_ref_path) if first_ref_path else None,
            "third_person_sha256": third_stored.get("sha256"),
            "first_person_sha256": first_stored.get("sha256") if first_stored else None,
            "third_person_deduplicated": third_stored.get("deduplicated"),
            "first_person_deduplicated": first_stored.get("deduplicated") if first_stored else None,
            "storage_mode": "external_video_store",
            "session_start_time": inferred_start,
            "detection_config": detection_config,
            "yolo_runtime": yolo_runtime,
            "output_dir": str(_key_action_output_dir(safe_experiment_id)),
        },
    )
    _persist_experiment_task_state(
        safe_experiment_id,
        {
            "task_id": task_id,
            "experiment_id": safe_experiment_id,
            "status": "queued",
            "current_stage": "key_action_index",
            "progress": 0.0,
            "message": "视频已上传，正式 key-action 分析正在启动",
            "video_path": str(third_path),
            "started_at": None,
            "completed_at": None,
            "request_received_at": request_received_at,
            "upload_completed_at": upload_completed_at,
            "upload_save_sec": upload_save_sec,
            "video_store_ingest_sec": upload_save_sec,
            "queued_at": queued_at,
            "output_paths": exp.get("output_paths", {}),
            "error_type": None,
            "error_message": None,
        },
    )
    background_tasks.add_task(
        _run_key_action_index_task,
        safe_experiment_id,
        third_person_video_path=str(third_path),
        first_person_video_path=str(first_path) if first_path else None,
        session_start_time=inferred_start,
        detection_config=detection_config,
    )
    return {
        "experiment_id": safe_experiment_id,
        "status": status,
        "third_person_video_path": str(third_path),
        "first_person_video_path": str(first_path) if first_path else None,
        "third_person_video_ref_path": str(third_ref_path),
        "first_person_video_ref_path": str(first_ref_path) if first_ref_path else None,
        "storage_mode": "external_video_store",
        "third_person_sha256": third_stored.get("sha256"),
        "first_person_sha256": first_stored.get("sha256") if first_stored else None,
        "third_person_deduplicated": third_stored.get("deduplicated"),
        "first_person_deduplicated": first_stored.get("deduplicated") if first_stored else None,
        "third_person_copied": third_stored.get("copied"),
        "first_person_copied": first_stored.get("copied") if first_stored else None,
        "registered_via": "upload_stream",
        "third_size": third_size,
        "first_size": first_size,
        "third_person_metadata": third_metadata,
        "first_person_metadata": first_metadata,
        "request_received_at": request_received_at,
        "upload_completed_at": upload_completed_at,
        "upload_save_sec": upload_save_sec,
        "video_store_ingest_sec": upload_save_sec,
        "ingest_elapsed_sec": upload_save_sec,
        "queued_at": queued_at,
    }


@app.post("/api/v1/experiments/{experiment_id}/upload/stream", tags=["experiments"])
async def upload_stream(
    experiment_id: str,
    req: UploadStreamRequest,
    background_tasks: BackgroundTasks,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Register a live or network stream source for an experiment."""
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    if req.sync_confidence is not None and not 0.0 <= float(req.sync_confidence) <= 1.0:
        raise HTTPException(status_code=400, detail="sync_confidence must be between 0 and 1")
    exp = await get_experiment_dict(safe_experiment_id)
    exp.setdefault("video_metadata", [])
    exp.setdefault("video_inputs", [])
    stream_index = len(exp["video_inputs"])
    provided_fields = set(getattr(req, "model_fields_set", None) or getattr(req, "__fields_set__", set()) or set())
    raw_descriptor = {
        "video_index": stream_index,
        "video_path": req.source,
        "source": req.source,
        "source_type": req.source_type,
        "ingest_mode": req.source_type,
        "camera_id": req.camera_id,
        "view_type": req.view_type,
        "role": req.role or req.view_type,
        "source_group": req.source_group,
        "sync_group": req.sync_group,
        "start_offset_sec": req.start_offset_sec,
        "offset_source": "explicit" if "start_offset_sec" in provided_fields else None,
        "capture_duration_sec": req.capture_duration_sec,
        "is_live_source": req.source_type in {"rtsp", "usb"},
    }
    for field in (
        "sync_method",
        "sync_anchors",
        "hardware_timecode_start_sec",
        "sync_board_offset_sec",
        "clock_scale",
        "clock_drift_ppm",
        "sync_confidence",
    ):
        value = getattr(req, field, None)
        if value is not None:
            raw_descriptor[field] = value
    from labsopguard.video_input_schema import VideoInputValidationError, normalize_video_input
    try:
        stream_descriptor, validation_warnings = normalize_video_input(raw_descriptor, index=stream_index, strict=True)
    except VideoInputValidationError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    exp["video_inputs"].append(stream_descriptor)
    exp["video_metadata"].append(dict(stream_descriptor))
    exp["video_asset_id"] = exp.get("video_asset_id") or f"{safe_experiment_id}:video:0"
    if exp.get("status") in {"created", ExperimentStatus.CREATED.value, ExperimentStatus.DRAFT.value}:
        exp["status"] = ExperimentStatus.VIDEO_UPLOADED.value
    _ensure_experiment_run_metadata(exp)
    exp["output_paths"] = {
        **(exp.get("output_paths") or {}),
        **_write_experiment_run_artifacts(safe_experiment_id, exp),
    }
    _save_experiment(exp)
    analysis_task = None
    if req.auto_analyze:
        analysis_task = _queue_experiment_auto_analysis(
            experiment_id=safe_experiment_id,
            background_tasks=background_tasks,
            source_ref=req.source,
            source_type=req.source_type,
            trigger="stream_upload",
        )
    return {
        "experiment_id": safe_experiment_id,
        "stream": stream_descriptor,
        "status": exp["status"],
        "validation_warnings": validation_warnings,
        "analysis_task": analysis_task,
    }


