@app.post("/api/v1/experiments/{experiment_id}/timeline-alignment", tags=["experiments"])
async def update_experiment_timeline_alignment(
    experiment_id: str,
    req: TimelineAlignmentUpdateRequest,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Update per-stream time alignment metadata and rebuild alignment artifacts."""
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    exp = await get_experiment_dict(safe_experiment_id)
    exp.setdefault("video_inputs", [])
    allowed_fields = {
        "sync_method",
        "sync_anchors",
        "sync_group",
        "start_offset_sec",
        "hardware_timecode_start_sec",
        "sync_board_offset_sec",
        "clock_scale",
        "clock_drift_ppm",
        "sync_confidence",
        "alignment_status",
        "offset_source",
    }
    allowed_statuses = {"pending", "explicit", "shared_recording", "calibrated"}
    updated_streams: List[Dict[str, Any]] = []
    streams = req.streams or []
    if streams and req.rebuild_only:
        raise HTTPException(status_code=400, detail="rebuild_only cannot include stream updates")
    for update in streams:
        if not isinstance(update, dict):
            raise HTTPException(status_code=400, detail="stream update must be an object")
        unknown_fields = sorted(set(update) - allowed_fields - {"video_index", "media_asset_id", "asset_id", "camera_id"})
        if unknown_fields:
            raise HTTPException(status_code=400, detail=f"Unsupported alignment fields: {unknown_fields}")
        if "alignment_status" in update and str(update["alignment_status"]).lower() not in allowed_statuses:
            raise HTTPException(status_code=400, detail=f"alignment_status must be one of {sorted(allowed_statuses)}")
        if "sync_confidence" in update and _bounded_confidence(update.get("sync_confidence")) is None:
            raise HTTPException(status_code=400, detail="sync_confidence must be numeric")
        if "sync_confidence" in update and not 0.0 <= float(update["sync_confidence"]) <= 1.0:
            raise HTTPException(status_code=400, detail="sync_confidence must be between 0 and 1")
        if "clock_scale" in update:
            clock_scale = _optional_float(update.get("clock_scale"))
            if clock_scale is None or clock_scale <= 0:
                raise HTTPException(status_code=400, detail="clock_scale must be positive")

        target = None
        for descriptor in exp.get("video_inputs") or []:
            if not isinstance(descriptor, dict):
                continue
            if update.get("video_index") is not None:
                try:
                    if int(descriptor.get("video_index", -1)) == int(update["video_index"]):
                        target = descriptor
                        break
                except (TypeError, ValueError) as exc:
                    raise HTTPException(status_code=400, detail="video_index must be an integer") from exc
            for key in ("media_asset_id", "asset_id", "camera_id"):
                if update.get(key) is not None and str(descriptor.get(key) or "") == str(update[key]):
                    target = descriptor
                    break
            if target is not None:
                break
        if target is None:
            raise HTTPException(status_code=404, detail="Stream descriptor not found")
        for field in allowed_fields:
            if field in update:
                target[field] = update[field]
        if "start_offset_sec" in update and "offset_source" not in update:
            target["offset_source"] = "explicit"
        if "sync_confidence" in target:
            target["sync_confidence"] = _bounded_confidence(target["sync_confidence"])
        updated_streams.append(dict(target))

    exp["video_metadata"] = [dict(item) for item in exp.get("video_inputs") or [] if isinstance(item, dict)]
    _ensure_experiment_run_metadata(exp)
    output_paths = {
        **(exp.get("output_paths") or {}),
        **_write_experiment_run_artifacts(safe_experiment_id, exp),
    }
    dual_view_alignment = _write_dual_view_upload_alignment(
        safe_experiment_id,
        exp,
        session_start_time=str((exp.get("key_action_index") or {}).get("session_start_time") or ""),
    )
    if dual_view_alignment:
        output_paths["timeline_alignment_json"] = str(_experiment_output_dir(safe_experiment_id) / "timeline_alignment.json")
        key_action_index = exp.setdefault("key_action_index", {})
        if isinstance(key_action_index, dict):
            key_action_index["timeline_alignment_path"] = output_paths["timeline_alignment_json"]
            key_action_index["timeline_alignment_status"] = dual_view_alignment.get("alignment_status")
            key_action_index["session_start_time"] = dual_view_alignment.get("session_origin_time") or key_action_index.get("session_start_time")
    exp["output_paths"] = output_paths
    _save_experiment(exp)
    alignment_path = _experiment_output_artifact_paths(safe_experiment_id, exp)["timeline_alignment_json"]
    return {
        "experiment_id": safe_experiment_id,
        "updated": len(updated_streams),
        "rebuild_only": req.rebuild_only,
        "timeline_alignment": _load_json_if_exists(alignment_path) if alignment_path else None,
        "output_paths": exp.get("output_paths", {}),
    }


@app.get("/api/v1/experiments/{experiment_id}/video", tags=["experiments"])
async def get_experiment_video(
    experiment_id: str,
    request: Request,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Stream the primary uploaded experiment video."""
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    exp = await get_experiment_dict(safe_experiment_id)
    experiment_dir = _experiment_output_dir(safe_experiment_id)
    _raise_if_source_video_candidates_escape_project(
        _experiment_source_video_candidates(experiment_dir, exp),
        "Video path must stay inside project root or configured video store",
    )
    artifacts = _experiment_output_artifact_paths(safe_experiment_id, exp)
    file_path = artifacts.get("source_video")
    if file_path is None:
        raise HTTPException(status_code=404, detail="Video not found")
    file_path = file_path.resolve()
    if not (_is_path_under(file_path, PROJECT_ROOT) or _is_path_under_any_video_store(file_path)):
        raise HTTPException(status_code=403, detail="Video path must stay inside project root or configured video store")
    if not file_path.exists():
        raise HTTPException(status_code=404, detail="Video file not found")
    return _serve_project_file(file_path, request, media_type="video/mp4")


@app.get("/api/v1/experiments/{experiment_id}/artifacts/{artifact_name}", tags=["experiments"])
async def get_experiment_artifact(
    experiment_id: str,
    artifact_name: str,
    request: Request,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    exp = await get_experiment_dict(safe_experiment_id)
    if artifact_name == "source_video":
        experiment_dir = _experiment_output_dir(safe_experiment_id)
        _raise_if_source_video_candidates_escape_project(
            _experiment_source_video_candidates(experiment_dir, exp),
            "Artifact path must stay inside project root or configured video store",
        )
    artifacts = _experiment_output_artifact_paths(safe_experiment_id, exp)
    if artifact_name not in artifacts:
        raise HTTPException(status_code=404, detail="Artifact not found")
    artifact_path = artifacts[artifact_name]
    if artifact_path is None or not artifact_path.exists():
        raise HTTPException(status_code=404, detail=f"Artifact not ready: {artifact_name}")
    artifact_path = artifact_path.resolve()
    if artifact_name == "source_video":
        if not (_is_path_under(artifact_path, PROJECT_ROOT) or _is_path_under_any_video_store(artifact_path)):
            raise HTTPException(status_code=403, detail="Artifact path must stay inside project root or configured video store")
    else:
        try:
            artifact_path.relative_to(PROJECT_ROOT.resolve())
        except ValueError as exc:
            raise HTTPException(status_code=403, detail="Artifact path must stay inside project root") from exc

    return _serve_project_file(artifact_path, request)


@app.get("/api/v1/experiments/{experiment_id}/files/{file_path:path}", tags=["experiments"])
async def serve_experiment_file(
    experiment_id: str,
    file_path: str,
    request: Request,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Serve any file under an experiment's output directory (clips, keyframes, etc)."""
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    exp_dir = _experiment_output_dir(safe_experiment_id)
    target = (exp_dir / file_path).resolve()
    try:
        target.relative_to(exp_dir.resolve())
    except ValueError:
        raise HTTPException(status_code=403, detail="Path traversal not allowed")
    if not target.exists() or not target.is_file():
        raise HTTPException(status_code=404, detail="File not found")
    return _serve_project_file(_browser_playable_material_clip(target), request)


@app.get("/api/v1/experiments/{experiment_id}/material-references/files/{file_path:path}", tags=["experiments"])
async def serve_experiment_material_reference_file(
    experiment_id: str,
    file_path: str,
    request: Request,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Serve approved material-reference files from the experiment's formal delivery folder."""
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    rel = Path(file_path)
    if rel.is_absolute():
        raise HTTPException(status_code=403, detail="Path traversal not allowed")
    checked_inside_delivery = False
    for root in _material_reference_root_candidates(_experiment_output_dir(safe_experiment_id)):
        root_resolved = root.resolve()
        target = (root / rel).resolve()
        try:
            target.relative_to(root_resolved)
        except ValueError:
            continue
        checked_inside_delivery = True
        if target.exists() and target.is_file():
            served_target = _material_preview_image(target) if _query_flag_enabled(request.query_params.get("preview")) else target
            return _serve_project_file(_browser_playable_material_clip(served_target), request)
    if checked_inside_delivery:
        raise HTTPException(status_code=404, detail="File not found")
    raise HTTPException(status_code=403, detail="Path traversal not allowed")


@app.get("/api/v1/experiments/{experiment_id}/materials/search", tags=["experiments"])
async def search_experiment_materials(
    experiment_id: str,
    objects: Optional[str] = None,
    actions: Optional[str] = None,
    event_type: Optional[str] = None,
    actor_name: Optional[str] = None,
    display_name: Optional[str] = None,
    source_container_class: Optional[str] = None,
    target_container_class: Optional[str] = None,
    start_time_sec: Optional[float] = None,
    end_time_sec: Optional[float] = None,
    camera_id: Optional[str] = None,
    stream_id: Optional[str] = None,
    has_clip: Optional[bool] = None,
    clip_exists: Optional[bool] = None,
    text: Optional[str] = None,
    embedding_text: Optional[str] = None,
    limit: int = 50,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Search time-anchored material stream items by object/action/time/camera/clip/text."""
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    exp = await get_experiment_dict(safe_experiment_id)
    artifacts = _experiment_output_artifact_paths(safe_experiment_id, exp)
    index_path = _ensure_material_index(safe_experiment_id, artifacts)

    from labsopguard.retrieval import MaterialQuery, MaterialRetrievalIndex
    from labsopguard.event_preprocessing.material_index_writer import EventMaterialIndexWriter

    index = MaterialRetrievalIndex(index_path)
    try:
        items = index.query(
            MaterialQuery(
                objects=_split_csv_filter(objects),
                actions=_split_csv_filter(actions),
                start_time_sec=start_time_sec,
                end_time_sec=end_time_sec,
                camera_id=camera_id,
                stream_id=stream_id,
                has_clip=has_clip,
                clip_exists=clip_exists,
                text=text,
                embedding_text=embedding_text,
                limit=min(max(int(limit), 1), 500),
            )
        )
        embedding_mode = index.embedding_provider.mode
    finally:
        index.close()

    event_items = []
    event_filter_active = bool(event_type or actor_name or display_name or source_container_class or target_container_class)
    if event_filter_active:
        event_index = EventMaterialIndexWriter(index_path)
        try:
            event_items = event_index.query_events(
                experiment_id=safe_experiment_id,
                event_type=event_type,
                actor_name=actor_name,
                display_name=display_name,
                source_container_class=source_container_class,
                target_container_class=target_container_class,
                start_time_sec=start_time_sec,
                end_time_sec=end_time_sec,
                text=text,
                limit=min(max(int(limit), 1), 500),
            )
        finally:
            event_index.close()

    for item in items:
        item.pop("embedding_json", None)
    if event_filter_active:
        items = event_items
    return {
        "experiment_id": safe_experiment_id,
        "total": len(items),
        "items": items,
        "index_path": str(index_path),
        "embedding_mode": embedding_mode if embedding_text else None,
    }


@app.get("/api/v1/experiments/{experiment_id}/materials/references", tags=["experiments"])
async def get_experiment_key_material_references(
    experiment_id: str,
    limit: int = 200,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Return the experiment-level key material reference ledger."""
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    exp = await get_experiment_dict(safe_experiment_id)
    artifacts = _experiment_output_artifact_paths(safe_experiment_id, exp)
    refs_path = _ensure_key_material_references(safe_experiment_id, exp, artifacts)
    from labsopguard.key_material_reference import load_key_material_references

    refs = load_key_material_references(_experiment_output_dir(safe_experiment_id))
    formal_gate = None
    try:
        from key_action_indexer.material_references import apply_formal_dual_view_material_publish_gate

        key_action_dir = _experiment_output_dir(safe_experiment_id) / "key_action_index"
        if key_action_dir.exists():
            kept_refs, rejected_refs = apply_formal_dual_view_material_publish_gate(key_action_dir, [dict(item) for item in refs])
            refs = kept_refs
            formal_gate = {
                "status": "applied",
                "kept": len(kept_refs),
                "rejected": len(rejected_refs),
            }
    except Exception as exc:
        formal_gate = {"status": "error", "error": str(exc)}
    refs = refs[: min(max(int(limit), 1), 2000)]
    return {
        "experiment_id": safe_experiment_id,
        "total": len(refs),
        "references": refs,
        "path": str(refs_path),
        "formal_gate": formal_gate,
    }


@app.post("/api/v1/experiments/{experiment_id}/materials/step-query", tags=["experiments"])
async def query_experiment_step_materials(
    experiment_id: str,
    request: StepMaterialQueryRequest,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Find key materials for a step text and optionally judge the step evidence."""
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    exp = await get_experiment_dict(safe_experiment_id)
    artifacts = _experiment_output_artifact_paths(safe_experiment_id, exp)
    _ensure_key_material_references(safe_experiment_id, exp, artifacts)
    from labsopguard.key_material_reference import query_step_materials

    result = query_step_materials(
        experiment_dir=_experiment_output_dir(safe_experiment_id),
        step_text=request.step_text,
        message_sent_at=request.message_sent_at,
        window_before_sec=request.window_before_sec,
        window_after_sec=request.window_after_sec,
        limit=request.limit,
    )
    return result.to_dict()


def _masked_config_value(value: Optional[str], *, keep: int = 4) -> str:
    value = str(value or "").strip()
    if not value:
        return ""
    if len(value) <= keep * 2:
        return "*" * len(value)
    return f"{value[:keep]}...{value[-keep:]}"


@app.get("/api/v1/feishu/status", tags=["feishu"])
async def get_feishu_status(auth_ctx: Dict[str, Any] = Depends(_require_operator_context)):
    """Return Feishu outbound-message configuration status without exposing secrets."""
    _ = auth_ctx
    keys = ["FEISHU_APP_ID", "FEISHU_APP_SECRET", "FEISHU_RECEIVE_ID"]
    missing = [key for key in keys if not os.environ.get(key)]
    receive_id_type = os.environ.get("FEISHU_RECEIVE_ID_TYPE", "chat_id")
    return {
        "configured": not missing,
        "missing": missing,
        "receive_id_type": receive_id_type,
        "receive_id_masked": _masked_config_value(os.environ.get("FEISHU_RECEIVE_ID")),
        "public_base_url": os.environ.get("LABSOPGUARD_PUBLIC_BASE_URL", "http://127.0.0.1:8000"),
        "inbound_event_url": os.environ.get(
            "FEISHU_EVENT_CALLBACK_URL",
            f"{os.environ.get('LABSOPGUARD_PUBLIC_BASE_URL', 'http://127.0.0.1:8000').rstrip('/')}/api/v1/feishu/events",
        ),
        "verification_token_configured": bool(os.environ.get("FEISHU_VERIFICATION_TOKEN")),
        "encrypt_key_configured": bool(os.environ.get("FEISHU_ENCRYPT_KEY")),
        "default_experiment_id": os.environ.get("FEISHU_DEFAULT_EXPERIMENT_ID"),
    }


def _feishu_bindings_path() -> Path:
    return PROJECT_ROOT / "outputs" / "feishu" / "chat_bindings.json"


def _latest_feishu_experiment_id() -> Optional[str]:
    configured = str(os.environ.get("FEISHU_DEFAULT_EXPERIMENT_ID") or "").strip()
    if configured:
        return configured
    experiments = [item for item in _load_experiments() if isinstance(item, dict) and item.get("experiment_id")]
    if not experiments:
        return None
    experiments.sort(
        key=lambda item: str(item.get("updated_at") or item.get("completed_at") or item.get("created_at") or ""),
        reverse=True,
    )
    return str(experiments[0].get("experiment_id") or "")


def _send_feishu_text_to_message_chat(message: Any, text: str) -> Dict[str, Any]:
    from backend.feishu_notifier import FeishuNotifier

    chat_id = str(getattr(message, "chat_id", "") or "").strip()
    sender_open_id = str(getattr(message, "sender_open_id", "") or "").strip()
    receive_id = chat_id or sender_open_id
    receive_id_type = "chat_id" if chat_id else "open_id"
    notifier = FeishuNotifier.from_env_for_receive(receive_id=receive_id, receive_id_type=receive_id_type)
    sent_id = notifier.send_text(text)
    return {"text_sent": True, "message_ids": [sent_id] if sent_id else [], "receive_id_type": receive_id_type}


def _handle_feishu_inbound_message(message: Any) -> Dict[str, Any]:
    from backend.feishu_event_handler import (
        build_feishu_help_text,
        get_bound_experiment_id,
        parse_step_command,
        save_feishu_chat_binding,
    )
    from backend.feishu_notifier import FeishuNotifier
    from backend.feishu_step_material_bot import send_step_query_result_to_feishu
    from labsopguard.key_material_reference import query_step_materials

    if getattr(message, "message_type", "text") != "text":
        send_result = _send_feishu_text_to_message_chat(message, "当前只支持文本步骤核验消息。")
        return {"status": "unsupported_message_type", "send_result": send_result}
    parsed = parse_step_command(getattr(message, "text", ""))
    default_experiment_id = _latest_feishu_experiment_id()
    bindings_path = _feishu_bindings_path()

    if parsed.command == "help":
        send_result = _send_feishu_text_to_message_chat(message, build_feishu_help_text(default_experiment_id))
        return {"status": "help_sent", "send_result": send_result}

    if parsed.command == "bind":
        assert parsed.experiment_id is not None
        safe_experiment_id = _validate_experiment_id(parsed.experiment_id)
        exp_path = _experiment_output_dir(safe_experiment_id) / "experiment.json"
        if not exp_path.exists():
            send_result = _send_feishu_text_to_message_chat(message, f"未找到实验：{safe_experiment_id}")
            return {"status": "experiment_not_found", "experiment_id": safe_experiment_id, "send_result": send_result}
        save_feishu_chat_binding(bindings_path, chat_id=getattr(message, "chat_id", ""), experiment_id=safe_experiment_id)
        send_result = _send_feishu_text_to_message_chat(message, f"已绑定当前飞书会话到实验：{safe_experiment_id}")
        return {"status": "bound", "experiment_id": safe_experiment_id, "send_result": send_result}

    experiment_id = (
        parsed.experiment_id
        or get_bound_experiment_id(bindings_path, chat_id=getattr(message, "chat_id", ""))
        or default_experiment_id
    )
    if not experiment_id:
        send_result = _send_feishu_text_to_message_chat(message, build_feishu_help_text(default_experiment_id))
        return {"status": "missing_experiment_id", "send_result": send_result}
    safe_experiment_id = _validate_experiment_id(experiment_id)
    exp_dir = _experiment_output_dir(safe_experiment_id)
    exp = _load_json_if_exists(exp_dir / "experiment.json")
    if not isinstance(exp, dict):
        send_result = _send_feishu_text_to_message_chat(message, f"未找到实验：{safe_experiment_id}")
        return {"status": "experiment_not_found", "experiment_id": safe_experiment_id, "send_result": send_result}
    if not parsed.step_text:
        send_result = _send_feishu_text_to_message_chat(message, "请发送要核验的实验步骤，例如：检查试剂瓶归位是否正确")
        return {"status": "missing_step_text", "experiment_id": safe_experiment_id, "send_result": send_result}

    artifacts = _experiment_output_artifact_paths(safe_experiment_id, exp)
    _ensure_key_material_references(safe_experiment_id, exp, artifacts)
    query_limit = parsed.limit if parsed.limit is not None else int(os.environ.get("FEISHU_STEP_QUERY_LIMIT", "5"))
    query_result = query_step_materials(
        experiment_dir=exp_dir,
        step_text=parsed.step_text,
        message_sent_at=parsed.message_sent_at or getattr(message, "create_time_iso", None),
        window_before_sec=parsed.window_before_sec,
        window_after_sec=parsed.window_after_sec,
        limit=query_limit,
    ).to_dict()
    receive_id = str(getattr(message, "chat_id", "") or getattr(message, "sender_open_id", "") or "").strip()
    receive_id_type = "chat_id" if getattr(message, "chat_id", "") else "open_id"
    push = send_step_query_result_to_feishu(
        notifier=FeishuNotifier.from_env_for_receive(receive_id=receive_id, receive_id_type=receive_id_type),
        experiment_dir=exp_dir,
        experiment_id=safe_experiment_id,
        experiment_title=str(exp.get("title") or exp.get("name") or safe_experiment_id),
        query_result=query_result,
        public_base_url=os.environ.get("LABSOPGUARD_PUBLIC_BASE_URL", "http://127.0.0.1:8000"),
        include_evidence_image=os.environ.get("FEISHU_REPLY_WITH_EVIDENCE_IMAGE", "1").strip().lower()
        not in {"0", "false", "no", "off"},
    )
    return {
        "status": "replied",
        "experiment_id": safe_experiment_id,
        "step_text": parsed.step_text,
        "query": query_result,
        "feishu": push.to_dict(),
    }


def _handle_feishu_inbound_message_safely(message: Any) -> None:
    try:
        result = _handle_feishu_inbound_message(message)
        logger.info("Feishu inbound event handled: %s", result.get("status"))
    except Exception as exc:
        logger.exception("Feishu inbound event handling failed: %s", exc)
        try:
            _send_feishu_text_to_message_chat(message, f"LabSOPGuard 步骤核验失败：{exc}")
        except Exception:
            logger.exception("Feishu failure notification failed")


@app.post("/api/v1/feishu/events", tags=["feishu"])
async def handle_feishu_events(
    request: Request,
    background_tasks: BackgroundTasks,
    sync: bool = False,
):
    """Receive Feishu event callbacks and answer step-material queries from chat."""
    try:
        payload = await request.json()
    except Exception as exc:
        raise HTTPException(status_code=400, detail=f"Invalid JSON body: {exc}") from exc
    from backend.feishu_event_handler import (
        FeishuEventError,
        decode_feishu_event_payload,
        feishu_url_verification_response,
        parse_feishu_inbound_message,
    )

    try:
        decoded = decode_feishu_event_payload(payload, encrypt_key=os.environ.get("FEISHU_ENCRYPT_KEY"))
        challenge = feishu_url_verification_response(
            decoded,
            expected_token=os.environ.get("FEISHU_VERIFICATION_TOKEN"),
        )
        if challenge is not None:
            return challenge
        message = parse_feishu_inbound_message(
            decoded,
            expected_token=os.environ.get("FEISHU_VERIFICATION_TOKEN"),
        )
    except FeishuEventError as exc:
        raise HTTPException(status_code=403, detail=str(exc)) from exc
    if message is None:
        return {"code": 0, "msg": "ignored"}
    if sync:
        return {"code": 0, "msg": "ok", "result": _handle_feishu_inbound_message(message)}
    background_tasks.add_task(_handle_feishu_inbound_message_safely, message)
    return {"code": 0, "msg": "ok", "event_id": message.event_id, "message_id": message.message_id}


@app.post("/api/v1/experiments/{experiment_id}/materials/step-query/feishu", tags=["feishu"])
async def query_experiment_step_materials_to_feishu(
    experiment_id: str,
    request: StepMaterialFeishuPushRequest,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Query step materials, judge the evidence, and push the result to Feishu."""
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    exp = await get_experiment_dict(safe_experiment_id)
    artifacts = _experiment_output_artifact_paths(safe_experiment_id, exp)
    _ensure_key_material_references(safe_experiment_id, exp, artifacts)
    from labsopguard.key_material_reference import query_step_materials
    from backend.feishu_step_material_bot import (
        build_step_query_feishu_message,
        select_evidence_image_path,
        send_step_query_result_to_feishu,
    )

    exp_dir = _experiment_output_dir(safe_experiment_id)
    query_result = query_step_materials(
        experiment_dir=exp_dir,
        step_text=request.step_text,
        message_sent_at=request.message_sent_at,
        window_before_sec=request.window_before_sec,
        window_after_sec=request.window_after_sec,
        limit=request.limit,
    ).to_dict()
    public_base_url = request.public_base_url or os.environ.get("LABSOPGUARD_PUBLIC_BASE_URL", "http://127.0.0.1:8000")
    experiment_title = str(exp.get("title") or exp.get("name") or safe_experiment_id)

    if request.dry_run:
        text = build_step_query_feishu_message(
            experiment_id=safe_experiment_id,
            experiment_title=experiment_title,
            query_result=query_result,
            experiment_dir=exp_dir,
            public_base_url=public_base_url,
        )
        image_path = select_evidence_image_path(experiment_dir=exp_dir, query_result=query_result)
        return {
            "experiment_id": safe_experiment_id,
            "query": query_result,
            "feishu": {
                "dry_run": True,
                "text": text,
                "image_path": str(image_path) if image_path else None,
            },
        }

    try:
        from backend.feishu_notifier import FeishuApiError, FeishuConfigError, FeishuNotifier

        push_result = send_step_query_result_to_feishu(
            notifier=FeishuNotifier.from_env(),
            experiment_dir=exp_dir,
            experiment_id=safe_experiment_id,
            experiment_title=experiment_title,
            query_result=query_result,
            public_base_url=public_base_url,
            include_evidence_image=request.include_evidence_image,
        )
    except FeishuConfigError as exc:
        raise HTTPException(status_code=503, detail=str(exc)) from exc
    except FeishuApiError as exc:
        raise HTTPException(status_code=502, detail=str(exc)) from exc
    return {
        "experiment_id": safe_experiment_id,
        "query": query_result,
        "feishu": push_result.to_dict(),
    }


@app.get("/api/v1/experiments/{experiment_id}/materials/health", tags=["experiments"])
async def get_experiment_material_index_health(
    experiment_id: str,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Return material-index health, including broken clip references."""
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    exp = await get_experiment_dict(safe_experiment_id)
    artifacts = _experiment_output_artifact_paths(safe_experiment_id, exp)
    index_path = _ensure_material_index(safe_experiment_id, artifacts)

    from labsopguard.retrieval import MaterialRetrievalIndex

    index = MaterialRetrievalIndex(index_path)
    try:
        health = index.health_check()
    finally:
        index.close()
    from labsopguard.ops_metrics import set_material_health_metrics

    set_material_health_metrics(safe_experiment_id, health)
    return {
        "experiment_id": safe_experiment_id,
        "index_path": str(index_path),
        **health,
    }


@app.post("/api/v1/experiments/{experiment_id}/materials/publish", tags=["experiments"])
async def publish_experiment_materials(
    experiment_id: str,
    force_rebuild_events: bool = False,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Publish canonical event asset packs into friendly browsable material archives.

    If materials/events/ is absent but a source video is known, EventPreprocessingEngine
    is run automatically before publishing.
    """
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    experiment_record = await get_experiment_dict(safe_experiment_id)
    exp_dir = _experiment_output_dir(safe_experiment_id)
    time_axis_health = _experiment_time_axis_health(safe_experiment_id)
    if time_axis_health.get("time_axis_unreliable"):
        return {
            "experiment_id": safe_experiment_id,
            "published_total": 0,
            "event_preprocessing_rebuilt": False,
            "published_materials": {
                "items": [],
                "total": 0,
                "returned": 0,
                "alignment_gate": {
                    "schema_version": "published_material_alignment_gate.v1",
                    "status": "blocked",
                    "reason": "time_axis_unreliable",
                },
                "time_axis_health": time_axis_health,
            },
            "taxonomy_calibration": None,
            "upload_manifest": None,
        }
    events_dir = exp_dir / "materials" / "events"

    # Auto-trigger when directory is absent OR empty (empty dir = engine ran but produced nothing)
    events_missing = force_rebuild_events or not events_dir.exists() or not any(events_dir.iterdir())
    if events_missing:
        physical_events_path = exp_dir / "physical_events.json"
        source_video = (
            (experiment_record.get("video_inputs") or [{}])[0].get("video_path", "")
            or (experiment_record.get("video_paths") or [None])[0]
        )
        if source_video and Path(source_video).exists():
            if force_rebuild_events and events_dir.exists():
                shutil.rmtree(events_dir)
            logger.info(
                "Auto-triggering EventPreprocessingEngine for %s (force_rebuild_events=%s)",
                safe_experiment_id,
                force_rebuild_events,
            )
            material_stream_raw = _load_json_if_exists(exp_dir / "material_stream.json") or []
            material_stream = material_stream_raw if isinstance(material_stream_raw, list) else []
            if force_rebuild_events:
                material_stream = [
                    item
                    for item in material_stream
                    if not (isinstance(item, dict) and item.get("schema_version") == "material_stream.event.v1")
                ]
            output_paths = {
                "source_video": str(source_video),
                "analysis_json": str(exp_dir / "analysis.json"),
                "material_index": str(exp_dir / "material_index.sqlite"),
            }
            _run_event_preprocessing_for_output(
                experiment_id=safe_experiment_id,
                experiment_record=experiment_record,
                output_dir=exp_dir,
                output_paths=output_paths,
                material_stream=material_stream,
            )
        elif not physical_events_path.exists():
            raise HTTPException(status_code=404, detail="Event assets are not ready; no source video or physical_events.json found")

    from labsopguard.material_publishing import SemanticMaterialPublisher

    try:
        result = SemanticMaterialPublisher(exp_dir, experiment_id=safe_experiment_id).publish()
    except FileNotFoundError as exc:
        raise HTTPException(status_code=404, detail=str(exc))
    taxonomy_calibration = _write_material_taxonomy_calibration_report(
        safe_experiment_id,
        _canonicalize_published_material_payload(result["published_materials"]),
    )

    # Re-run step bridge with freshly generated events
    physical_events_payload = _load_json_if_exists(exp_dir / "physical_events.json") or {}
    _run_step_bridge_for_output(
        experiment_id=safe_experiment_id,
        output_dir=exp_dir,
        physical_events_payload=physical_events_payload,
    )

    return {
        "experiment_id": safe_experiment_id,
        "published_total": result["published_materials"]["total"],
        "event_preprocessing_rebuilt": bool(force_rebuild_events),
        "published_materials": result["published_materials"],
        "taxonomy_calibration": taxonomy_calibration,
        "upload_manifest": result["upload_manifest"],
    }


@app.get("/api/v1/experiments/{experiment_id}/materials/published", tags=["experiments"])
async def get_published_experiment_materials(
    experiment_id: str,
    request: Request,
    limit: Optional[int] = None,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    exp = await get_experiment_dict(safe_experiment_id)
    exp_dir = _experiment_output_dir(safe_experiment_id)
    effective_limit = min(limit, 500) if limit is not None and limit > 0 else None
    published_json = exp_dir / "published_materials.json"
    signature_parts: Dict[str, Any] = {
        "experiment": _experiment_state_cache_token(exp),
        "published_json": _path_cache_token(published_json),
        "time_axis_health": _path_cache_token(_key_action_output_dir(safe_experiment_id) / "metadata" / "time_axis_health.json"),
        "dual_view_action_events": _path_cache_token(_key_action_output_dir(safe_experiment_id) / "metadata" / "dual_view_action_events.jsonl"),
        "material_references": _path_cache_token(exp_dir / "material_references" / "key_material_references.jsonl"),
        "limit": effective_limit,
    }
    if not published_json.exists():
        signature_parts["material_reference_roots"] = [
            _directory_tree_cache_token(root, max_entries=128)
            for root in _material_reference_root_candidates(exp_dir)
        ]
        signature_parts["materials_events"] = _directory_tree_cache_token(exp_dir / "materials" / "events", max_entries=512)
        signature_parts["physical_events"] = _path_cache_token(exp_dir / "physical_events.json")

    def build_payload() -> Dict[str, Any]:
        payload = _published_material_items(exp_dir, safe_experiment_id)
        if effective_limit is not None:
            items = payload.get("items") if isinstance(payload, dict) else None
            if isinstance(items, list):
                limited_items = items[:effective_limit]
                payload = {**payload, "items": limited_items, "returned": len(limited_items)}
        return payload

    return _cached_experiment_json_response(
        request,
        cache_key=f"experiment:{safe_experiment_id}:materials:published:{effective_limit or 'all'}",
        signature=_experiment_detail_cache_signature(signature_parts),
        build_payload=build_payload,
    )


