@app.post("/api/v1/experiments/{experiment_id}/materials/candidates/{candidate_group_id}/approve", tags=["experiments"])
async def approve_experiment_material_candidate(
    experiment_id: str,
    candidate_group_id: str,
    request: MaterialCandidateApprovalRequest,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    await get_experiment_dict(safe_experiment_id)
    candidate_ids = []
    for values in (request.candidate_ids, request.selected_keyframe_ids, request.selected_clip_ids):
        candidate_ids.extend([str(item) for item in (values or []) if str(item).strip()])
    try:
        from key_action_indexer.material_references import approve_material_candidates

        approval_kwargs = {
            "candidate_group_id": candidate_group_id,
            "candidate_ids": candidate_ids or None,
            "reviewer": request.reviewer,
            "notes": request.notes,
        }
        try:
            import inspect

            approval_params = inspect.signature(approve_material_candidates).parameters
            if "reason_code" in approval_params:
                approval_kwargs["reason_code"] = request.reason_code
            if "reason" in approval_params:
                approval_kwargs["reason"] = request.reason
        except (TypeError, ValueError):
            pass
        approval = approve_material_candidates(_key_action_output_dir(safe_experiment_id), **approval_kwargs)
        try:
            from key_action_indexer.experiment_action_ledger import apply_material_candidate_feedback

            approval["official_promotion"] = apply_material_candidate_feedback(
                _material_library_root(),
                safe_experiment_id,
                candidate_group_id=candidate_group_id,
                candidate_ids=candidate_ids or None,
                action="upgrade_to_official",
                reviewer=request.reviewer,
                notes=request.notes,
                reason_code=request.reason_code,
                reason=request.reason,
                refresh_corpus=False,
            )
        except Exception as exc:  # pragma: no cover - API should surface the legacy approval too.
            approval["official_promotion"] = {"enabled": False, "error": str(exc)}
    except FileNotFoundError as exc:
        raise HTTPException(status_code=404, detail=str(exc)) from exc
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    except Exception as exc:
        logger.exception("Material candidate approval failed for %s", safe_experiment_id)
        raise HTTPException(status_code=500, detail=str(exc)) from exc
    exp_dir = _experiment_output_dir(safe_experiment_id)
    published_materials = _sync_published_materials_from_references(exp_dir, safe_experiment_id)
    workspace_reindex = _rebuild_workspace_published_materials_index_quietly()
    return {
        "experiment_id": safe_experiment_id,
        "candidate_group_id": candidate_group_id,
        "approval": approval,
        "candidates": _material_candidates_payload(safe_experiment_id),
        "published_materials": published_materials,
        "workspace_published_materials_reindex": workspace_reindex,
    }


@app.post("/api/v1/experiments/{experiment_id}/materials/candidates/{candidate_group_id}/decision", tags=["experiments"])
async def decide_experiment_material_candidate(
    experiment_id: str,
    candidate_group_id: str,
    request: MaterialCandidateDispositionRequest,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    await get_experiment_dict(safe_experiment_id)
    decision = str(request.decision or "").strip().lower()
    try:
        if decision in {"confirm", "confirmed"}:
            from key_action_indexer.material_references import confirm_material_candidates

            disposition = confirm_material_candidates(
                _key_action_output_dir(safe_experiment_id),
                candidate_group_id=candidate_group_id,
                reviewer=request.reviewer,
                notes=request.notes,
                candidate_ids=request.candidate_ids,
            )
            try:
                from key_action_indexer.experiment_action_ledger import apply_material_candidate_feedback

                disposition["official_promotion"] = apply_material_candidate_feedback(
                    _material_library_root(),
                    safe_experiment_id,
                    candidate_group_id=candidate_group_id,
                    candidate_ids=request.candidate_ids,
                    action="confirm",
                    reviewer=request.reviewer,
                    notes=request.notes,
                    reason_code=request.reason_code,
                    reason=request.reason,
                    refresh_corpus=False,
                )
            except Exception as exc:  # pragma: no cover - keep feedback audit visible even if material DB sync fails.
                disposition["official_promotion"] = {"enabled": False, "error": str(exc)}
        else:
            from key_action_indexer.material_references import dispose_material_candidates

            disposition = dispose_material_candidates(
                _key_action_output_dir(safe_experiment_id),
                candidate_group_id=candidate_group_id,
                decision="false_positive" if decision in {"evidence_mismatch", "mark_evidence_mismatch"} else request.decision,
                reason_code=(
                    "evidence_mismatch"
                    if decision in {"evidence_mismatch", "mark_evidence_mismatch"} and not request.reason_code
                    else request.reason_code
                ),
                reason=request.reason,
                reviewer=request.reviewer,
                notes=request.notes,
                candidate_ids=request.candidate_ids,
            )
            if decision in {"reject", "rejected", "false_positive", "evidence_mismatch", "mark_evidence_mismatch"}:
                try:
                    from key_action_indexer.experiment_action_ledger import apply_material_candidate_feedback

                    disposition["official_promotion"] = apply_material_candidate_feedback(
                        _material_library_root(),
                        safe_experiment_id,
                        candidate_group_id=candidate_group_id,
                        candidate_ids=request.candidate_ids,
                        action="reject",
                        reviewer=request.reviewer,
                        notes=request.notes,
                        reason_code=request.reason_code,
                        reason=request.reason,
                        refresh_corpus=False,
                    )
                except Exception as exc:  # pragma: no cover - keep disposition result visible.
                    disposition["official_promotion"] = {"enabled": False, "error": str(exc)}
    except FileNotFoundError as exc:
        raise HTTPException(status_code=404, detail=str(exc)) from exc
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    except Exception as exc:
        logger.exception("Material candidate disposition failed for %s", safe_experiment_id)
        raise HTTPException(status_code=500, detail=str(exc)) from exc
    exp_dir = _experiment_output_dir(safe_experiment_id)
    published_materials = _sync_published_materials_from_references(exp_dir, safe_experiment_id)
    workspace_reindex = _rebuild_workspace_published_materials_index_quietly()
    return {
        "experiment_id": safe_experiment_id,
        "candidate_group_id": candidate_group_id,
        "disposition": disposition,
        "candidates": _material_candidates_payload(safe_experiment_id),
        "published_materials": published_materials,
        "workspace_published_materials_reindex": workspace_reindex,
    }


