@app.get("/api/v1/experiments/{experiment_id}/materials/candidates/batches", tags=["experiments"])
async def get_experiment_material_candidate_batches(
    experiment_id: str,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    await get_experiment_dict(safe_experiment_id)
    batches = _read_material_review_batches(safe_experiment_id)
    public_batches = []
    for row in batches:
        if not isinstance(row, dict):
            continue
        public_batches.append({key: value for key, value in row.items() if key not in {"before_rows", "after_rows"}})
    public_batches.sort(key=lambda item: str(item.get("created_at") or ""), reverse=True)
    return {
        "schema_version": "material_candidate_batch_log.v1",
        "experiment_id": safe_experiment_id,
        "total": len(public_batches),
        "items": public_batches,
        "log_path": str(_material_review_batch_log_path(safe_experiment_id)),
    }


@app.post("/api/v1/experiments/{experiment_id}/materials/candidates/batch", tags=["experiments"])
async def review_experiment_material_candidates_batch(
    experiment_id: str,
    request: MaterialCandidateBatchRequest,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    await get_experiment_dict(safe_experiment_id)
    action = str(request.action or "").strip().lower()
    if action in {"approve", "approved"}:
        action = "approve"
    elif action in {"false_positive", "reject", "rejected", "misclassified"}:
        action = "false_positive"
    else:
        raise HTTPException(status_code=400, detail="Batch action must be approve or false_positive")
    group_ids = _material_batch_group_ids(request.groups or [])
    if not group_ids:
        raise HTTPException(status_code=400, detail="At least one candidate group is required")
    if action == "false_positive" and not str(request.reason_code or "").strip():
        raise HTTPException(status_code=400, detail="reason_code is required for batch false_positive review")

    before_rows = _material_candidate_rows(safe_experiment_id)
    if not before_rows:
        raise HTTPException(status_code=404, detail="Material candidate index is not ready")
    batch_id = f"material_batch_{datetime.now(timezone.utc).strftime('%Y%m%dT%H%M%S')}_{uuid.uuid4().hex[:8]}"
    group_requests = list(request.groups or [])
    operations: List[Dict[str, Any]] = []
    try:
        if action == "approve":
            from key_action_indexer.material_references import approve_material_candidates

            for group in group_requests:
                selected_ids = [str(item).strip() for item in (group.candidate_ids or []) if str(item).strip()]
                approval = approve_material_candidates(
                    _key_action_output_dir(safe_experiment_id),
                    candidate_group_id=str(group.candidate_group_id),
                    candidate_ids=selected_ids or None,
                    reviewer=request.reviewer or auth_ctx.get("operator") or "operator",
                    notes=request.notes,
                    reason_code=request.reason_code or "batch_representative_yolo_hand_object_evidence",
                    reason=request.reason or "Batch approved as representative canonical material evidence.",
                )
                operations.append({"candidate_group_id": group.candidate_group_id, "candidate_ids": selected_ids, "result": approval})
        else:
            from key_action_indexer.material_references import dispose_material_candidates

            for group in group_requests:
                selected_ids = [str(item).strip() for item in (group.candidate_ids or []) if str(item).strip()]
                disposition = dispose_material_candidates(
                    _key_action_output_dir(safe_experiment_id),
                    candidate_group_id=str(group.candidate_group_id),
                    decision="false_positive",
                    reason_code=request.reason_code,
                    reason=request.reason,
                    reviewer=request.reviewer or auth_ctx.get("operator") or "operator",
                    notes=request.notes,
                    candidate_ids=selected_ids or None,
                )
                operations.append({"candidate_group_id": group.candidate_group_id, "candidate_ids": selected_ids, "result": disposition})
    except FileNotFoundError as exc:
        raise HTTPException(status_code=404, detail=str(exc)) from exc
    except ValueError as exc:
        raise HTTPException(status_code=400, detail=str(exc)) from exc
    except Exception as exc:
        logger.exception("Material candidate batch review failed for %s", safe_experiment_id)
        raise HTTPException(status_code=500, detail=str(exc)) from exc

    after_rows = _material_candidate_rows(safe_experiment_id)
    selected_candidate_ids = _material_batch_candidate_ids(group_requests)
    affected_after_rows = _material_batch_affected_rows(after_rows, group_ids=group_ids, candidate_ids=selected_candidate_ids)
    affected_candidate_ids = sorted({str(row.get("candidate_id") or "") for row in affected_after_rows if str(row.get("candidate_id") or "")})
    additions = _material_batch_addition_summary(before_rows, after_rows, group_ids)
    created_at = datetime.now(timezone.utc).isoformat()
    batch_record = {
        "schema_version": "material_candidate_batch.v1",
        "batch_id": batch_id,
        "experiment_id": safe_experiment_id,
        "action": action,
        "created_at": created_at,
        "created_by": request.reviewer or auth_ctx.get("operator") or "operator",
        "reason_code": request.reason_code,
        "reason": request.reason,
        "notes": request.notes,
        "candidate_group_ids": group_ids,
        "candidate_group_count": len(group_ids),
        "affected_candidate_ids": affected_candidate_ids,
        "affected_candidate_count": len(affected_candidate_ids),
        "before_status_counts": _candidate_status_counts_for_rows(before_rows),
        "after_status_counts": _candidate_status_counts_for_rows(after_rows),
        "operations": operations,
        "undone": False,
        **additions,
        "before_rows": before_rows,
        "after_rows": after_rows,
    }
    _append_material_review_batch(safe_experiment_id, batch_record)
    exp_dir = _experiment_output_dir(safe_experiment_id)
    published_materials = _sync_published_materials_from_references(exp_dir, safe_experiment_id)
    workspace_reindex = _rebuild_workspace_published_materials_index_quietly()
    public_batch = {key: value for key, value in batch_record.items() if key not in {"before_rows", "after_rows"}}
    return {
        "experiment_id": safe_experiment_id,
        "batch": public_batch,
        "candidates": _material_candidates_payload(safe_experiment_id),
        "published_materials": published_materials,
        "diagnostics": _build_material_diagnostics(safe_experiment_id, published_materials),
        "workspace_published_materials_reindex": workspace_reindex,
    }


@app.post("/api/v1/experiments/{experiment_id}/materials/candidates/batches/{batch_id}/undo", tags=["experiments"])
async def undo_experiment_material_candidate_batch(
    experiment_id: str,
    batch_id: str,
    request: MaterialCandidateRestoreRequest,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    await get_experiment_dict(safe_experiment_id)
    batches = _read_material_review_batches(safe_experiment_id)
    target_index = next((index for index, row in enumerate(batches) if str(row.get("batch_id") or "") == str(batch_id)), None)
    if target_index is None:
        raise HTTPException(status_code=404, detail="Batch log entry not found")
    target = batches[target_index]
    if target.get("undone"):
        raise HTTPException(status_code=400, detail="Batch has already been undone")
    before_rows = target.get("before_rows") if isinstance(target.get("before_rows"), list) else None
    if not before_rows:
        raise HTTPException(status_code=400, detail="Batch log does not contain an undo snapshot")
    restored_rows = [row for row in before_rows if isinstance(row, dict)]
    _write_material_candidate_rows(safe_experiment_id, restored_rows)
    _refresh_candidate_metadata_after_direct_write(safe_experiment_id, restored_rows)
    formal_reset = _reset_formal_materials_from_candidate_rows(safe_experiment_id, restored_rows)
    exp_dir = _experiment_output_dir(safe_experiment_id)
    published_materials = _sync_published_materials_from_references(exp_dir, safe_experiment_id)
    workspace_reindex = _rebuild_workspace_published_materials_index_quietly()
    undone_at = datetime.now(timezone.utc).isoformat()
    batches[target_index] = {
        **target,
        "undone": True,
        "undone_at": undone_at,
        "undone_by": request.reviewer or auth_ctx.get("operator") or "operator",
        "undo_notes": request.notes,
        "undo_formal_reset": formal_reset,
    }
    _write_material_review_batches(safe_experiment_id, batches)
    public_batch = {key: value for key, value in batches[target_index].items() if key not in {"before_rows", "after_rows"}}
    return {
        "experiment_id": safe_experiment_id,
        "batch": public_batch,
        "candidates": _material_candidates_payload(safe_experiment_id),
        "published_materials": published_materials,
        "diagnostics": _build_material_diagnostics(safe_experiment_id, published_materials),
        "workspace_published_materials_reindex": workspace_reindex,
    }


