@app.patch("/api/v1/experiments/{experiment_id}/materials/quality-review/{canonical_action_type}", tags=["experiments"])
async def update_experiment_material_quality_review(
    experiment_id: str,
    canonical_action_type: str,
    request: MaterialQualityReviewRequest,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    await get_experiment_dict(safe_experiment_id)
    action = str(canonical_action_type or "").strip()
    if action not in STANDARD_MATERIAL_ACTION_TYPES:
        raise HTTPException(status_code=400, detail="Unsupported canonical_action_type")
    status = str(request.status or "unreviewed").strip()
    if status not in MATERIAL_VISUAL_REVIEW_STATUSES:
        raise HTTPException(status_code=400, detail="Unsupported visual review status")

    payload = _published_material_items(_experiment_output_dir(safe_experiment_id), safe_experiment_id)
    items = [item for item in (payload.get("items") or []) if isinstance(item, dict)]
    action_item_ids = set()
    for item in items:
        if str(item.get("canonical_action_type") or "") == action:
            action_item_ids.update(_material_identity_values(item))
    preferred_item_id = str(request.preferred_item_id).strip() if request.preferred_item_id else None
    if preferred_item_id and preferred_item_id not in action_item_ids:
        raise HTTPException(status_code=400, detail="preferred_item_id does not match a published material in this class")

    review = _read_material_quality_review(safe_experiment_id)
    reviews = review.setdefault("reviews", {})
    reviews[action] = {
        "status": status,
        "preferred_item_id": preferred_item_id,
        "reviewed_at": datetime.now(timezone.utc).isoformat(),
        "reviewed_by": request.reviewer or auth_ctx.get("operator") or "operator",
        "note": request.note,
        "reason": request.reason,
    }
    review["updated_at"] = datetime.now(timezone.utc).isoformat()
    _write_json(_material_quality_review_path(safe_experiment_id), review)
    refreshed = _published_material_items(_experiment_output_dir(safe_experiment_id), safe_experiment_id)
    return {
        "experiment_id": safe_experiment_id,
        "canonical_action_type": action,
        "quality_review": review,
        "published_materials": refreshed,
        "diagnostics": _build_material_diagnostics(safe_experiment_id, refreshed),
    }


