@app.get("/api/v1/materials/taxonomy-regression", tags=["materials"])
async def get_material_taxonomy_regression(
    limit: int = 3,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    report = _material_taxonomy_regression(limit=limit)
    if str(auth_ctx.get("operator_role") or "").strip().lower() in {"admin", "system"}:
        return report
    allowed = {str(item).strip() for item in (auth_ctx.get("allowed_experiment_ids") or []) if str(item).strip()}
    if not allowed or "*" in allowed:
        return report
    scoped_experiments = [
        item for item in report.get("experiments", [])
        if isinstance(item, dict) and str(item.get("experiment_id") or "") in allowed
    ]
    return {**report, "experiment_count": len(scoped_experiments), "experiments": scoped_experiments}


