@app.get("/api/v1/material-library/search", tags=["materials"])
async def search_global_material_library(
    query: str = "",
    asset_type: Optional[str] = None,
    object: Optional[str] = None,
    action: Optional[str] = None,
    view: Optional[str] = None,
    session_id: Optional[str] = None,
    experiment_id: Optional[str] = None,
    package_name: Optional[str] = None,
    date: Optional[str] = None,
    start_date: Optional[str] = None,
    end_date: Optional[str] = None,
    limit: int = 20,
):
    """Search published key material references across the external material library."""
    from key_action_indexer.material_library_store import (
        global_material_library_db_path,
        query_material_library,
        sync_material_library,
    )

    library_root = _material_library_root()
    db_path = global_material_library_db_path(library_root)
    if not db_path.exists():
        sync_material_library(library_root)
    rows = query_material_library(
        library_root=library_root,
        text=query,
        asset_type=asset_type,
        primary_object=object,
        action=action,
        view=view,
        session_id=session_id,
        experiment_id=experiment_id,
        package_name=package_name,
        date=date,
        start_date=start_date,
        end_date=end_date,
        limit=min(max(int(limit), 1), 200),
    )
    items = [_compact_global_material_row(row) for row in rows]
    return {
        "schema_version": "material_library.search.v1",
        "library_root": str(library_root),
        "total": len(items),
        "items": items,
    }


