@app.post("/api/v1/video-memory/build", tags=["video-memory"])
async def build_video_memory_snapshot(request: Request):
    """Build or rebuild the rolling 30-Day Video Memory snapshot."""
    body = await request.json() if request.headers.get("content-length") not in {None, "0"} else {}
    from key_action_indexer.video_memory import (
        DEFAULT_BUNDLE_VLM_MODEL,
        DEFAULT_ITEM_VLM_MODEL,
        VLM_MODE_REAL_QWEN_ASYNC,
        build_video_memory,
        start_video_memory_rebuild_background,
    )

    vlm_mode = str(body.get("vlm_mode") or body.get("mode") or "offline_metadata")
    item_vlm_model = str(body.get("item_vlm_model") or DEFAULT_ITEM_VLM_MODEL)
    bundle_vlm_model = str(body.get("bundle_vlm_model") or DEFAULT_BUNDLE_VLM_MODEL)
    vlm_client = None
    vlm_client_config: Dict[str, Any] = {"configured": False, "reason": "not_requested"}
    if vlm_mode == VLM_MODE_REAL_QWEN_ASYNC:
        # Item-level Qwen is the first external call. Bundle-level calls pass
        # their own model override through the adapter while reusing this client.
        vlm_client, vlm_client_config = _build_key_action_vlm_assist_client(model_override=item_vlm_model)

    max_real_vlm_items = body.get("max_real_vlm_items")
    max_real_vlm_bundles = body.get("max_real_vlm_bundles")
    build_kwargs = dict(
        library_root=_material_library_root(),
        window_end_date=body.get("window_end_date"),
        window_days=int(body.get("window_days") or 30),
        job_type=str(body.get("job_type") or "incremental"),
        force_material_sync=bool(body.get("force_material_sync")),
        vlm_mode=vlm_mode,
        item_vlm_model=item_vlm_model,
        bundle_vlm_model=bundle_vlm_model,
        vlm_client=vlm_client,
        max_real_vlm_items=int(max_real_vlm_items) if max_real_vlm_items not in (None, "") else None,
        max_real_vlm_bundles=int(max_real_vlm_bundles) if max_real_vlm_bundles not in (None, "") else None,
    )
    if bool(body.get("background") or body.get("async") or body.get("run_async")):
        accepted = start_video_memory_rebuild_background(**build_kwargs)
        accepted["vlm_client_config"] = vlm_client_config
        return accepted
    result = await asyncio.to_thread(build_video_memory, **build_kwargs)
    result["vlm_client_config"] = vlm_client_config
    return result


