def _video_memory_api_value_has_content(value: Any) -> bool:
    if isinstance(value, (list, tuple, set)):
        return any(_video_memory_api_value_has_content(item) for item in value)
    if isinstance(value, dict):
        return any(_video_memory_api_value_has_content(item) for item in value.values())
    return bool(str(value or "").strip())


def _video_memory_api_int(value: Any, default: int) -> int:
    try:
        parsed = int(float(value))
    except (TypeError, ValueError):
        return default
    return parsed if parsed >= 0 else default


def _video_memory_api_claim_has_evidence(claim: Dict[str, Any]) -> bool:
    evidence_keys = (
        "evidence_item_id",
        "evidence_item_ids",
        "ledger_event_id",
        "ledger_event_ids",
        "evidence_bundle_id",
        "evidence_bundle_ids",
        "material_id",
        "material_ids",
        "keyframe",
        "keyframe_refs",
        "keyclip",
        "keyclip_refs",
        "evidence_links",
    )
    if any(_video_memory_api_value_has_content(claim.get(key)) for key in evidence_keys):
        return True
    trace = claim.get("evidence_trace")
    return isinstance(trace, dict) and any(_video_memory_api_value_has_content(trace.get(key)) for key in evidence_keys)


def _video_memory_api_window_notice_zh(payload: Dict[str, Any]) -> str:
    scope = payload.get("window_scope") if isinstance(payload.get("window_scope"), dict) else {}
    expected = _video_memory_api_int(
        scope.get("window_days_expected")
        or payload.get("window_days_expected")
        or 30,
        30,
    )
    available = _video_memory_api_int(
        scope.get("window_days_available")
        or payload.get("window_days_available")
        or 0,
        0,
    )
    if bool(payload.get("partial_window")) or not bool(payload.get("is_full_30_day_memory")):
        return f"基于 {available}/{expected} 天数据；当前不是完整 30 天态势快照。"
    return f"基于完整 {expected}/{expected} 天数据。"


def _video_memory_strip_english_window_notice(text: str) -> str:
    text = re.sub(r"^Partial window only:.*?30-day memory\.\s*", "", text).strip()
    if text == "No matching evidence-linked claim was found.":
        return ""
    return text


def _video_memory_query_answer_for_api(answer: Dict[str, Any]) -> Dict[str, Any]:
    payload = dict(answer or {})
    claims = [dict(claim) for claim in _video_memory_as_list(payload.get("claims")) if isinstance(claim, dict)]
    claims = [claim for claim in claims if _video_memory_api_claim_has_evidence(claim)]
    payload["claims"] = claims

    evidence_trace = payload.get("evidence_trace") if isinstance(payload.get("evidence_trace"), dict) else None
    trace_claims: List[Dict[str, Any]] = []
    if evidence_trace is not None:
        trace_claims = [
            dict(claim)
            for claim in _video_memory_as_list(evidence_trace.get("claims"))
            if isinstance(claim, dict) and _video_memory_api_claim_has_evidence(claim)
        ]
        evidence_trace["claims"] = trace_claims
        payload["evidence_trace"] = evidence_trace

    has_evidence = bool(claims or trace_claims)
    notice_zh = _video_memory_api_window_notice_zh(payload)
    is_partial = bool(payload.get("partial_window")) or not bool(payload.get("is_full_30_day_memory"))
    if is_partial:
        payload["partial_window"] = True
        payload["is_full_30_day_memory"] = False
        payload["partial_window_notice"] = notice_zh
        payload["partial_window_notice_zh"] = notice_zh
        scope = payload.get("window_scope") if isinstance(payload.get("window_scope"), dict) else {}
        scope["partial_window_notice"] = notice_zh
        scope["partial_window_notice_zh"] = notice_zh
        payload["window_scope"] = scope

    if not has_evidence:
        no_evidence_text = "未找到可引用动作事件或证据包，不能形成强结论。"
        payload["answer_summary"] = no_evidence_text
        payload["confidence"] = 0.0
        payload["human_confirmation_status"] = "unconfirmed"
        unresolved = [
            str(item)
            for item in _video_memory_as_list(payload.get("unresolved_questions"))
            if str(item or "").strip()
        ]
        if no_evidence_text not in unresolved:
            unresolved.insert(0, no_evidence_text)
        payload["unresolved_questions"] = unresolved
        payload["answer"] = {"status": "unsupported", "text": no_evidence_text}
        return payload

    summary = _video_memory_strip_english_window_notice(str(payload.get("answer_summary") or ""))
    if not summary:
        summary = "找到可追溯证据，已按证据链回答。"
    payload["answer_summary"] = f"{notice_zh} {summary}".strip() if is_partial else summary
    payload["answer"] = {"status": "supported", "text": payload["answer_summary"]}
    return payload


