@app.post("/api/v1/experiments/{experiment_id}/segmentation/override", tags=["experiments"])
async def override_experiment_segmentation(
    experiment_id: str,
    request: Request,
):
    """Manually override experiment segmentation boundaries."""
    body = await request.json()
    segments = body.get("segments", [])
    if not segments:
        raise HTTPException(status_code=400, detail="segments array required")

    output_dir = PROJECT_ROOT / "outputs" / "experiments" / experiment_id
    if not output_dir.exists():
        raise HTTPException(status_code=404, detail="Experiment not found")

    override_path = output_dir / "artifacts" / "segmentation_override.json"
    override_path.parent.mkdir(parents=True, exist_ok=True)
    override_path.write_text(
        json.dumps({"segments": segments, "source": "manual_override"}, ensure_ascii=False, indent=2),
        encoding="utf-8",
    )
    return {"status": "saved", "path": str(override_path), "segment_count": len(segments)}


def _candidate_experiment_window_segments(experiment_id: str, output_dir: Path) -> list[dict[str, Any]]:
    """Expose reviewable window artifacts even when formal publishing is blocked."""
    metadata_dir = output_dir / "key_action_index" / "metadata"
    payload: Any = None
    for path in (
        metadata_dir / "formal_experiment_windows.json",
        metadata_dir / "candidate_experiment_windows.json",
    ):
        payload = _load_json_if_exists(path)
        if payload:
            break
    if isinstance(payload, dict):
        raw_rows = payload.get("windows") or payload.get("candidate_windows") or payload.get("segments") or []
    elif isinstance(payload, list):
        raw_rows = payload
    else:
        raw_rows = []

    def _as_path(value: Any, fallback: Path) -> Path:
        if value:
            candidate = Path(str(value))
            return candidate if candidate.is_absolute() else output_dir / candidate
        return fallback

    def _file_url(path: Path) -> Optional[str]:
        try:
            if path.exists() and path.stat().st_size > 0:
                return _experiment_file_api_path(path, experiment_id)
        except OSError:
            return None
        return None

    segments: list[dict[str, Any]] = []
    for index, row in enumerate(raw_rows):
        if not isinstance(row, dict):
            continue
        window_id = str(
            row.get("experiment_window_id")
            or row.get("window_id")
            or row.get("segment_id")
            or f"formal_window_{index + 1:03d}"
        )
        window_dir = output_dir / "windows" / window_id
        sync_index_path = _as_path(
            row.get("source_window_sync_index") or row.get("window_sync_index"),
            window_dir / "window_sync_index.csv",
        )
        preview_path = _as_path(row.get("window_preview") or row.get("preview_video_path"), window_dir / "window_preview.mp4")
        sample_grid_path = _as_path(row.get("sample_grid") or row.get("sample_grid_path"), window_dir / "sample_grid.jpg")
        reference_audit_path = _as_path(row.get("window_reference_camera_audit"), window_dir / "window_reference_camera_audit.json")
        alignment_quality_path = _as_path(row.get("window_alignment_quality"), window_dir / "window_alignment_quality.json")
        window_report_path = _as_path(row.get("window_report"), window_dir / "window_report.json")
        window_report = _load_json_if_exists(window_report_path) or {}
        third_preview_path = _as_path(
            row.get("third_view_realtime_preview") or window_report.get("third_view_realtime_preview"),
            window_dir / "third_view_realtime_preview.mp4",
        )
        first_preview_path = _as_path(
            row.get("first_view_realtime_preview") or window_report.get("first_view_realtime_preview"),
            window_dir / "first_view_realtime_preview.mp4",
        )
        side_by_side_preview_path = _as_path(
            row.get("side_by_side_realtime_preview") or window_report.get("side_by_side_realtime_preview") or window_report.get("window_preview_browser"),
            preview_path,
        )
        fast_preview_path = _as_path(row.get("fast_preview") or window_report.get("fast_preview"), window_dir / "fast_preview.mp4")
        preview_url = _file_url(preview_path)
        side_by_side_preview_url = _file_url(side_by_side_preview_path) or preview_url
        third_preview_url = _file_url(third_preview_path)
        first_preview_url = _file_url(first_preview_path)
        fast_preview_url = _file_url(fast_preview_path)
        sample_grid_url = _file_url(sample_grid_path)
        raw_window_start_global_timestamp_us = (
            row.get("raw_window_start_global_timestamp_us")
            or window_report.get("raw_window_start_global_timestamp_us")
            or row.get("start_global_timestamp_us")
        )
        raw_window_end_global_timestamp_us = (
            row.get("raw_window_end_global_timestamp_us")
            or window_report.get("raw_window_end_global_timestamp_us")
            or row.get("end_global_timestamp_us")
        )
        experiment_window_duration_s = window_report.get("window_preview_source_duration_s") or row.get("window_preview_source_duration_s")
        try:
            if raw_window_start_global_timestamp_us is not None and raw_window_end_global_timestamp_us is not None:
                timestamp_duration_s = (float(raw_window_end_global_timestamp_us) - float(raw_window_start_global_timestamp_us)) / 1_000_000.0
                if timestamp_duration_s > 0:
                    experiment_window_duration_s = timestamp_duration_s
        except (TypeError, ValueError):
            pass
        try:
            start_sec = float(row.get("start_sec") or row.get("session_start_sec") or 0.0)
        except (TypeError, ValueError):
            start_sec = 0.0
        try:
            end_sec = float(row.get("end_sec") or row.get("session_end_sec") or start_sec)
        except (TypeError, ValueError):
            end_sec = start_sec
        duration_sec = max(0.0, float(row.get("duration_sec") or (end_sec - start_sec)))
        status = str(row.get("visual_review_status") or row.get("status") or "needs_review")
        first_has_activity = bool(row.get("first_has_experiment_activity"))
        third_has_activity = bool(row.get("third_has_experiment_activity"))
        view_support = {
            "first_person": {
                "has_physical_action": first_has_activity,
                "row_count": len(row.get("supporting_first_segments") or []),
            },
            "third_person": {
                "has_physical_action": third_has_activity,
                "row_count": len(row.get("supporting_third_segments") or []),
            },
        }
        segments.append(
            {
                "segment_id": window_id,
                "index": index,
                "display_name": f"待验收实验窗口 {index + 1}",
                "start_sec": start_sec,
                "end_sec": end_sec,
                "duration_sec": duration_sec,
                "experiment_window_duration_s": experiment_window_duration_s or duration_sec,
                "actual_experiment_duration_s": window_report.get("actual_experiment_duration_s") or row.get("actual_experiment_duration_s"),
                "preview_duration_s": window_report.get("window_preview_duration_s"),
                "preview_mode": window_report.get("window_preview_mode"),
                "playback_speed_ratio": window_report.get("window_preview_playback_speed_ratio"),
                "preview_playback_speed_ratio": window_report.get("window_preview_playback_speed_ratio"),
                "window_preview_output_fps": window_report.get("window_preview_output_fps"),
                "time_basis": "window_sync_index",
                "final_time_basis": "window_sync_index",
                "raw_window_start_global_timestamp_us": raw_window_start_global_timestamp_us,
                "raw_window_end_global_timestamp_us": raw_window_end_global_timestamp_us,
                "actual_experiment_start_global_timestamp_us": row.get("actual_experiment_start_global_timestamp_us") or window_report.get("actual_experiment_start_global_timestamp_us"),
                "actual_experiment_end_global_timestamp_us": row.get("actual_experiment_end_global_timestamp_us") or window_report.get("actual_experiment_end_global_timestamp_us"),
                "focus_preview_start_global_timestamp_us": row.get("focus_preview_start_global_timestamp_us") or window_report.get("focus_preview_start_global_timestamp_us"),
                "focus_preview_end_global_timestamp_us": row.get("focus_preview_end_global_timestamp_us") or window_report.get("focus_preview_end_global_timestamp_us"),
                "start_global_timestamp_us": row.get("start_global_timestamp_us"),
                "end_global_timestamp_us": row.get("end_global_timestamp_us"),
                "start_sync_index": row.get("start_sync_index"),
                "end_sync_index": row.get("end_sync_index"),
                "activity_segment_count": len(row.get("supporting_first_segments") or []) + len(row.get("supporting_third_segments") or []),
                "preview_ready": bool(side_by_side_preview_url),
                "preview_video_url": side_by_side_preview_url,
                "third_person_video_url": third_preview_url,
                "first_person_video_url": first_preview_url,
                "third_view_realtime_preview": third_preview_url,
                "third_view_realtime_preview_url": third_preview_url,
                "third_view_realtime_preview_path": str(third_preview_path),
                "third_view_preview_url": third_preview_url,
                "third_preview_url": third_preview_url,
                "first_view_realtime_preview": first_preview_url,
                "first_view_realtime_preview_url": first_preview_url,
                "first_view_realtime_preview_path": str(first_preview_path),
                "first_view_preview_url": first_preview_url,
                "first_preview_url": first_preview_url,
                "side_by_side_realtime_preview": side_by_side_preview_url,
                "side_by_side_realtime_preview_url": side_by_side_preview_url,
                "side_by_side_realtime_preview_path": str(side_by_side_preview_path),
                "side_by_side_preview_url": side_by_side_preview_url,
                "fast_preview": fast_preview_url,
                "fast_preview_url": fast_preview_url,
                "fast_preview_path": str(fast_preview_path),
                "preview_poster_url": sample_grid_url,
                "third_person_poster_url": sample_grid_url,
                "first_person_poster_url": sample_grid_url,
                "sample_grid_url": sample_grid_url,
                "window_preview_url": side_by_side_preview_url,
                "window_dir": str(window_dir),
                "window_sync_index": str(sync_index_path),
                "source_window_sync_index": str(sync_index_path),
                "window_reference_camera_audit": str(reference_audit_path),
                "window_alignment_quality": str(alignment_quality_path),
                "window_report": str(window_report_path),
                "window_self_validation_status": status,
                "formal_dual_view_action": False,
                "formal_action_status": "needs_review",
                "formal_action_reason": status,
                "view_alignment_status": "dual_view_candidate",
                "view_alignment_warning": "候选窗口需要人工视觉验收和双视角动作确认，不能作为 official 或 Memory 输入。",
                "view_support": view_support,
                "start_reason": row.get("start_reason"),
                "end_reason": row.get("end_reason"),
                "warnings": row.get("warnings") or [],
                "reason_code": row.get("reject_reason_if_any") or status,
            }
        )
    return segments


@app.get("/api/v1/experiments/{experiment_id}/sub-experiments", tags=["experiments"])
async def get_sub_experiments(experiment_id: str):
    """List sub-experiments if this is a segmented parent experiment."""
    output_dir = PROJECT_ROOT / "outputs" / "experiments" / experiment_id
    seg_path = output_dir / "artifacts" / "experiment_segmentation.json"
    key_action_segments_path = output_dir / "key_action_index" / "metadata" / "key_action_segments.jsonl"
    time_axis_health = _experiment_time_axis_health(experiment_id)
    formal_publish_health = _experiment_formal_publish_health(experiment_id)
    if time_axis_health.get("time_axis_unreliable"):
        return {
            "total": 0,
            "segments": [],
            "sub_experiments": [],
            "video_duration_sec": None,
            "preview_ready": False,
            "preview_video_url": None,
            "segment_preview_ready_count": 0,
            "preview_error": "time_axis_unreliable",
            "message": "时间轴健康检查未通过，不能生成正式实验片段。请修复双视角采集时间轴后重新注册/分析。",
            "source": "time_axis_health_gate",
            "time_axis_health": time_axis_health,
            "time_axis_unreliable": True,
            "formal_publish_health": formal_publish_health,
        }
    if formal_publish_health.get("status") == "blocked":
        candidate_segments = _candidate_experiment_window_segments(experiment_id, output_dir)
        if candidate_segments:
            video_duration_sec = max((float(item.get("end_sec") or 0.0) for item in candidate_segments), default=0.0)
            ready_count = sum(1 for item in candidate_segments if item.get("preview_ready"))
            return {
                "total": len(candidate_segments),
                "official_total": 0,
                "candidate_total": len(candidate_segments),
                "segments": candidate_segments,
                "sub_experiments": [
                    {
                        "sub_id": f"{experiment_id}_{item.get('segment_id')}",
                        "segment_index": int(item.get("index") or 0),
                        "path": item.get("window_dir"),
                        "has_materials": False,
                        "first_person_video_url": item.get("first_person_video_url"),
                        "third_person_video_url": item.get("third_person_video_url"),
                        "first_person_poster_url": item.get("first_person_poster_url"),
                        "third_person_poster_url": item.get("third_person_poster_url"),
                    }
                    for item in candidate_segments
                ],
                "video_duration_sec": video_duration_sec or None,
                "preview_ready": ready_count > 0,
                "preview_video_url": next((item.get("preview_video_url") for item in candidate_segments if item.get("preview_video_url")), None),
                "segment_preview_ready_count": ready_count,
                "preview_error": "no_formal_dual_view_action_episodes",
                "message": formal_publish_health.get("user_message_zh") or "双视角动作证据未对齐，当前仅展示待验收候选窗口。",
                "source": "formal_publish_health_gate_candidates",
                "time_axis_health": time_axis_health,
                "time_axis_unreliable": False,
                "formal_publish_health": formal_publish_health,
                "dual_view_action_event_count": formal_publish_health.get("dual_view_action_event_count") or 0,
                "unmatched_view_evidence_count": formal_publish_health.get("unmatched_view_evidence_count") or 0,
                "formal_action_policy": "official_segments_require_confirmed_dual_view_action_events",
            }
        return {
            "total": 0,
            "official_total": 0,
            "candidate_total": formal_publish_health.get("candidate_segment_count") or 0,
            "segments": [],
            "sub_experiments": [],
            "video_duration_sec": None,
            "preview_ready": False,
            "preview_video_url": None,
            "segment_preview_ready_count": 0,
            "preview_error": "no_formal_dual_view_action_episodes",
            "message": formal_publish_health.get("user_message_zh") or "双视角动作证据未对齐，不能生成正式实验片段。",
            "source": "formal_publish_health_gate",
            "time_axis_health": time_axis_health,
            "time_axis_unreliable": False,
            "formal_publish_health": formal_publish_health,
            "dual_view_action_event_count": formal_publish_health.get("dual_view_action_event_count") or 0,
            "unmatched_view_evidence_count": formal_publish_health.get("unmatched_view_evidence_count") or 0,
            "formal_action_policy": "official_segments_require_confirmed_dual_view_action_events",
        }
    if key_action_segments_path.exists():
            segments = []
            video_duration_sec = 0.0
            micro_yolo_rows = _read_jsonl_rows(output_dir / "key_action_index" / "cv_outputs" / "yolo_micro_frame_rows.jsonl")
            coarse_yolo_rows = _read_jsonl_rows(output_dir / "key_action_index" / "cv_outputs" / "yolo_frame_rows.jsonl")
            yolo_rows = micro_yolo_rows or coarse_yolo_rows
            key_action_manifest = _load_json_if_exists(output_dir / "key_action_index" / "manifest.json") or {}
            manifest_session_start = _parse_datetime_value(str(key_action_manifest.get("session_start_time") or ""))
            manifest_videos = key_action_manifest.get("videos") if isinstance(key_action_manifest.get("videos"), dict) else {}
            key_action_metadata_dir = output_dir / "key_action_index" / "metadata"
            formal_dual_view_context = _key_action_formal_dual_view_context(key_action_metadata_dir)
            material_reference_rows: List[Dict[str, Any]] = []
            try:
                artifacts = _experiment_output_artifact_paths(experiment_id, await get_experiment_dict(experiment_id))
                _ensure_key_material_references(experiment_id, await get_experiment_dict(experiment_id), artifacts)
                from labsopguard.key_material_reference import load_key_material_references

                material_reference_rows = load_key_material_references(output_dir)
                try:
                    from key_action_indexer.material_references import apply_formal_dual_view_material_publish_gate

                    kept_material_rows, _rejected_material_rows = apply_formal_dual_view_material_publish_gate(
                        output_dir / "key_action_index",
                        [dict(item) for item in material_reference_rows],
                    )
                    material_reference_rows = kept_material_rows
                except Exception:
                    pass
            except Exception:
                material_reference_rows = []
            key_action_segment_rows = _read_jsonl_rows(key_action_segments_path)
            formal_episode_rows = [
                {**row, "_formal_dual_view_action_episode": True}
                for row in formal_dual_view_context.get("episodes", [])
                if isinstance(row, dict)
            ]
            formal_episode_segment_ids = {
                str(row.get("segment_id") or "").strip()
                for row in formal_episode_rows
                if str(row.get("segment_id") or "").strip()
            }
            source_segment_rows: list[dict[str, Any]] = []
            candidate_source_rows: list[dict[str, Any]] = []
            if key_action_segment_rows:
                # key_action_segments.jsonl is the experiment-window source.
                # dual_view_aligned_experiment_episodes.jsonl contains action
                # confirmation snippets; it must not replace the wider episode
                # windows or short 2-5s events will masquerade as experiments.
                source_segment_rows = key_action_segment_rows
                candidate_source_rows = [
                    row
                    for row in formal_episode_rows
                    if str(row.get("segment_id") or "").strip() not in formal_episode_segment_ids
                ]
            else:
                source_segment_rows = []
                candidate_source_rows = formal_episode_rows

            def _float_or_none(value: Any) -> Optional[float]:
                try:
                    if value is None:
                        return None
                    return float(value)
                except (TypeError, ValueError):
                    return None

            def _first_float(*values: Any) -> Optional[float]:
                for value in values:
                    parsed = _float_or_none(value)
                    if parsed is not None:
                        return parsed
                return None

            def _view_source_info(view: str) -> dict[str, Any]:
                value = manifest_videos.get(view) if isinstance(manifest_videos, dict) else None
                return value if isinstance(value, dict) else {}

            def _source_start_datetime(view: str) -> Optional[datetime]:
                info = _view_source_info(view)
                for key in ("capture_start_time", "start_time"):
                    parsed = _parse_datetime_value(str(info.get(key) or ""))
                    if parsed is not None:
                        return parsed
                return None

            def _aligned_capture_range_for_view(
                view: str,
                segment_payload: dict[str, Any],
                start_sec: float,
                end_sec: float,
            ) -> tuple[Optional[float], Optional[float]]:
                """Project a segment's unified capture clock into one view's playback window.

                The pipeline already maps unified session seconds back to each video's
                local PTS using the frames.csv map. Prefer those persisted per-view
                ranges; recomputing from capture-start alone breaks videos whose capture
                timeline duration differs from playable PTS duration.
                """
                view_payload = segment_payload.get(view) if isinstance(segment_payload.get(view), dict) else {}
                stored_start = _float_or_none(view_payload.get("local_start_sec"))
                stored_end = _float_or_none(view_payload.get("local_end_sec"))
                if stored_start is not None and stored_end is not None and stored_end > stored_start:
                    return max(0.0, stored_start), max(0.0, stored_end)
                info = _view_source_info(view)
                source_start = _source_start_datetime(view)
                offset = _float_or_none(info.get("offset_sec")) or 0.0
                global_start = _parse_datetime_value(str(segment_payload.get("global_start_time") or ""))
                global_end = _parse_datetime_value(str(segment_payload.get("global_end_time") or ""))
                if source_start is not None and global_start is not None and global_end is not None:
                    local_start_value = (global_start - source_start).total_seconds() - offset
                    local_end_value = (global_end - source_start).total_seconds() - offset
                elif manifest_session_start is not None and source_start is not None:
                    source_delta = (manifest_session_start - source_start).total_seconds() - offset
                    local_start_value = start_sec + source_delta
                    local_end_value = end_sec + source_delta
                else:
                    return None, None
                if local_end_value <= local_start_value:
                    return None, None
                return max(0.0, float(local_start_value)), max(0.0, float(local_end_value))

            for index, segment in enumerate(source_segment_rows):
                if not isinstance(segment, dict):
                    continue
                first_person = segment.get("first_person") if isinstance(segment.get("first_person"), dict) else {}
                third_person = segment.get("third_person") if isinstance(segment.get("third_person"), dict) else {}
                cv_detection = segment.get("cv_detection") if isinstance(segment.get("cv_detection"), dict) else {}
                third_local_start = _float_or_none(third_person.get("local_start_sec"))
                third_local_end = _float_or_none(third_person.get("local_end_sec"))
                first_local_start = _float_or_none(first_person.get("local_start_sec"))
                first_local_end = _float_or_none(first_person.get("local_end_sec"))
                local_start = _first_float(third_local_start, first_local_start, 0.0) or 0.0
                duration_sec = _float_or_none(segment.get("duration_sec"))
                local_end = _first_float(third_local_end, first_local_end)
                if local_end is None:
                    local_end = local_start + float(duration_sec or 0.0)

                session_start = _first_float(
                    segment.get("session_start_sec"),
                    segment.get("start_sec"),
                    segment.get("start_time_sec"),
                    cv_detection.get("start_sec"),
                    local_start,
                )
                session_end = _first_float(
                    segment.get("session_end_sec"),
                    segment.get("end_sec"),
                    segment.get("end_time_sec"),
                    cv_detection.get("end_sec"),
                    local_end,
                )
                if session_start is None:
                    session_start = 0.0
                if session_end is None:
                    session_end = session_start + float(duration_sec or 0.0)
                if session_end < session_start:
                    session_end = session_start + float(duration_sec or 0.0)
                if duration_sec is None:
                    duration_sec = max(0.0, session_end - session_start)
                third_aligned_start, third_aligned_end = _aligned_capture_range_for_view(
                    "third_person",
                    segment,
                    float(session_start or 0.0),
                    float(session_end or 0.0),
                )
                first_aligned_start, first_aligned_end = _aligned_capture_range_for_view(
                    "first_person",
                    segment,
                    float(session_start or 0.0),
                    float(session_end or 0.0),
                )
                if third_aligned_start is not None and third_aligned_end is not None:
                    third_local_start = third_aligned_start
                    third_local_end = third_aligned_end
                if first_aligned_start is not None and first_aligned_end is not None:
                    first_local_start = first_aligned_start
                    first_local_end = first_aligned_end

                video_duration_sec = max(video_duration_sec, float(session_end or 0.0))
                support_start = float(session_start or 0.0)
                support_end = float(session_end or support_start)
                view_support = (
                    {
                        "third_person": _key_action_view_support(
                            yolo_rows,
                            view="third_person",
                            start_sec=support_start,
                            end_sec=support_end,
                        ),
                        "first_person": _key_action_view_support(
                            yolo_rows,
                            view="first_person",
                            start_sec=support_start,
                            end_sec=support_end,
                        ),
                    }
                    if yolo_rows
                    else {}
                )
                support_known = bool(
                    view_support
                    and view_support["third_person"].get("row_count", 0) > 0
                    and view_support["first_person"].get("row_count", 0) > 0
                )
                third_has_action = bool(view_support.get("third_person", {}).get("has_physical_action"))
                first_has_action = bool(view_support.get("first_person", {}).get("has_physical_action"))
                segment_id = str(segment.get("segment_id") or segment.get("episode_id") or f"seg_{index + 1:06d}")
                formal_action = _key_action_segment_is_formal_dual_view(
                    segment,
                    segment_id,
                    formal_dual_view_context,
                )
                try:
                    official_min_duration_sec = float(
                        os.environ.get("KEY_ACTION_OFFICIAL_EXPERIMENT_MIN_DURATION_SEC", "20") or "20"
                    )
                except ValueError:
                    official_min_duration_sec = 20.0
                has_strict_dual_view_action = bool(third_has_action and first_has_action)
                is_official_dual_view_segment = bool(
                    formal_action["confirmed"]
                    and has_strict_dual_view_action
                    and float(duration_sec or 0.0) >= official_min_duration_sec
                )
                view_alignment_status = "unverified"
                view_alignment_warning: Optional[str] = None
                if is_official_dual_view_segment:
                    view_alignment_status = "dual_view_action_confirmed"
                elif formal_action["confirmed"] and not has_strict_dual_view_action:
                    view_alignment_status = "single_view_candidate"
                    view_alignment_warning = "该时间窗只有一侧具备强动作证据，不能作为正式实验片段、正式关键素材或 30 天记忆写入。"
                elif formal_action["confirmed"] and float(duration_sec or 0.0) < official_min_duration_sec:
                    view_alignment_status = "short_action_candidate"
                    view_alignment_warning = "该时间窗更像动作证据片段，时长不足，不能作为正式实验片段。"
                elif support_known and third_has_action and first_has_action:
                    view_alignment_status = "dual_view_candidate"
                    view_alignment_warning = "双视角都检测到手物交互，但没有命中 confirmed dual_view_action_events；当前只作为候选片段展示。"
                elif support_known and third_has_action and not first_has_action:
                    view_alignment_status = "third_person_only"
                    view_alignment_warning = "第一人称视角在该时间窗内没有检测到手物交互证据；视频仍按同步采集时间窗展示，仅作为动作证据弱视角标记。"
                elif support_known and first_has_action and not third_has_action:
                    view_alignment_status = "first_person_only"
                    view_alignment_warning = "第三人称视角在该时间窗内没有检测到手物交互证据；视频仍按同步采集时间窗展示，仅作为动作证据弱视角标记。"
                elif support_known:
                    view_alignment_status = "no_physical_action_evidence"
                    view_alignment_warning = "该时间窗双视角都缺少手物交互证据，需要重新检查筛选边界。"
                view_evidence_status = view_alignment_status
                view_evidence_warning = view_alignment_warning
                micro_segments = segment.get("micro_segments") if isinstance(segment.get("micro_segments"), list) else []
                formal_event_micro_ids: set[str] = set()
                formal_event_peak_session_secs: List[float] = []
                event_micro_map = (
                    formal_dual_view_context.get("event_micro_ids")
                    if isinstance(formal_dual_view_context.get("event_micro_ids"), dict)
                    else {}
                )
                events_by_id = (
                    formal_dual_view_context.get("events_by_id")
                    if isinstance(formal_dual_view_context.get("events_by_id"), dict)
                    else {}
                )
                for event_id in formal_action.get("event_ids") or []:
                    formal_event_micro_ids.update(
                        str(value)
                        for value in event_micro_map.get(str(event_id), [])
                        if str(value).strip()
                    )
                    event_row = events_by_id.get(str(event_id))
                    if isinstance(event_row, dict):
                        for key in ("synchronized_session_sec", "sync_session_sec", "first_peak_sec", "third_peak_sec", "center_sec"):
                            try:
                                value = float(event_row.get(key))
                            except (TypeError, ValueError):
                                continue
                            if math.isfinite(value):
                                formal_event_peak_session_secs.append(value)
                                break
                yolo_label_counts = segment.get("yolo_label_counts") if isinstance(segment.get("yolo_label_counts"), dict) else {}
                clip_root = output_dir / "key_action_index" / "clips" / segment_id
                segment_asset_bindings = [
                    binding
                    for binding in (segment.get("asset_bindings") or [])
                    if isinstance(binding, dict)
                ]
                segment_bindings_by_view = {
                    str(binding.get("view") or ""): binding
                    for binding in segment_asset_bindings
                    if str(binding.get("view") or "")
                }

                def _clip_url_if_exists(path: Path) -> Optional[str]:
                    return _experiment_file_api_path(path, experiment_id) if path.exists() and path.stat().st_size > 0 else None

                def _poster_url_if_exists(*paths: Path) -> Optional[str]:
                    for path in paths:
                        if path.exists() and path.stat().st_size > 0:
                            return _experiment_file_api_path(path, experiment_id)
                    return None

                def _image_display_score(path: Path) -> float:
                    try:
                        image = cv2.imread(str(path), cv2.IMREAD_GRAYSCALE)
                        if image is None or image.size == 0:
                            return -1.0
                        mean = float(np.mean(image))
                        std = float(np.std(image))
                    except Exception:
                        return -1.0
                    if mean < 25.0 or mean > 245.0:
                        return -1.0
                    return mean + min(80.0, std * 1.5)

                def _best_micro_preview(view: str) -> dict[str, Any]:
                    scored: list[tuple[float, Path, Optional[float]]] = []

                    def _view_local_range() -> tuple[Optional[float], Optional[float]]:
                        if view == "first_person":
                            return first_local_start, first_local_end
                        return third_local_start, third_local_end

                    def _preview_time_to_view_pts(value: Optional[float]) -> Optional[float]:
                        if value is None:
                            return None
                        view_start, view_end = _view_local_range()
                        if view_start is None or view_end is None or view_end <= view_start:
                            return value
                        if view_start <= value <= view_end:
                            return value
                        session_span = max(0.0, float(support_end) - float(support_start))
                        if session_span <= 0.0:
                            return value
                        if float(support_start) <= value <= float(support_end):
                            ratio = (value - float(support_start)) / session_span
                            ratio = max(0.0, min(1.0, ratio))
                            return float(view_start) + ratio * (float(view_end) - float(view_start))
                        return value

                    def _session_time_to_view_pts(value: Optional[float]) -> Optional[float]:
                        if value is None:
                            return None
                        view_start, view_end = _view_local_range()
                        if view_start is None or view_end is None or view_end <= view_start:
                            return value
                        session_span = max(0.0, float(support_end) - float(support_start))
                        if session_span <= 0.0:
                            return value
                        ratio = (float(value) - float(support_start)) / session_span
                        ratio = max(0.0, min(1.0, ratio))
                        return float(view_start) + ratio * (float(view_end) - float(view_start))

                    for micro in micro_segments:
                        if not isinstance(micro, dict):
                            continue
                        micro_id = str(micro.get("micro_segment_id") or "").strip()
                        if formal_event_micro_ids and micro_id not in formal_event_micro_ids:
                            continue
                        bindings = micro.get("asset_bindings") if isinstance(micro.get("asset_bindings"), list) else []
                        for binding in bindings:
                            if not isinstance(binding, dict) or str(binding.get("view") or "") != view:
                                continue
                            keyframe_path = binding.get("keyframe_path")
                            if not keyframe_path:
                                continue
                            path = Path(str(keyframe_path))
                            if not path.exists() or path.stat().st_size <= 0:
                                continue
                            display_score = _image_display_score(path)
                            if display_score < 0.0:
                                continue
                            role_bonus = 120.0 if str(binding.get("evidence_role") or "") == "yolo_evidence" else 35.0
                            try:
                                interaction_bonus = float(micro.get("max_interaction_score") or 0.0) * 60.0
                            except (TypeError, ValueError):
                                interaction_bonus = 0.0
                            interaction = micro.get("interaction") if isinstance(micro.get("interaction"), dict) else {}
                            preview_time = None
                            for candidate_value in (
                                interaction.get("peak_interaction_sec"),
                                micro.get("peak_interaction_sec"),
                                *(formal_event_peak_session_secs or []),
                            ):
                                try:
                                    parsed_peak = float(candidate_value)
                                except (TypeError, ValueError):
                                    continue
                                if math.isfinite(parsed_peak):
                                    preview_time = _session_time_to_view_pts(parsed_peak)
                                    break
                            start_raw = binding.get("local_start_sec") if binding.get("local_start_sec") is not None else micro.get("start_sec")
                            end_raw = binding.get("local_end_sec") if binding.get("local_end_sec") is not None else micro.get("end_sec")
                            if preview_time is None:
                                try:
                                    start_value = float(start_raw)
                                except (TypeError, ValueError):
                                    start_value = None
                                try:
                                    end_value = float(end_raw)
                                except (TypeError, ValueError):
                                    end_value = start_value
                                if start_value is not None and end_value is not None:
                                    preview_time = start_value + max(0.0, end_value - start_value) * 0.5
                                else:
                                    preview_time = start_value
                                preview_time = _preview_time_to_view_pts(preview_time)
                            scored.append((display_score + role_bonus + interaction_bonus, path, preview_time))
                    if not scored:
                        return {"url": None, "time_sec": None}
                    _score, best_path, preview_time_sec = max(scored, key=lambda item: item[0])
                    return {
                        "url": _experiment_file_api_path(best_path, experiment_id),
                        "time_sec": preview_time_sec,
                    }

                def _ensure_poster_from_video(video_path: Path, poster_path: Path) -> Optional[str]:
                    if poster_path.exists() and poster_path.stat().st_size > 0:
                        return _experiment_file_api_path(poster_path, experiment_id)
                    if not video_path.exists() or video_path.stat().st_size <= 0:
                        return None
                    ffmpeg_bin = shutil.which("ffmpeg")
                    if not ffmpeg_bin:
                        return None
                    poster_path.parent.mkdir(parents=True, exist_ok=True)
                    tmp_path = poster_path.with_suffix(".tmp.jpg")
                    try:
                        subprocess.run(
                            [
                                ffmpeg_bin,
                                "-hide_banner",
                                "-loglevel",
                                "error",
                                "-y",
                                "-ss",
                                "0.8",
                                "-i",
                                str(video_path),
                                "-frames:v",
                                "1",
                                "-q:v",
                                "3",
                                str(tmp_path),
                            ],
                            stdout=subprocess.DEVNULL,
                            stderr=subprocess.DEVNULL,
                            timeout=8,
                            check=True,
                        )
                        if tmp_path.exists() and tmp_path.stat().st_size > 0:
                            tmp_path.replace(poster_path)
                            return _experiment_file_api_path(poster_path, experiment_id)
                    except Exception:
                        try:
                            tmp_path.unlink(missing_ok=True)
                        except Exception:
                            pass
                    return None

                def _same_file_text(left: Any, right: Any) -> bool:
                    left_text = str(left or "").strip()
                    right_text = str(right or "").strip()
                    if not left_text or not right_text:
                        return False
                    try:
                        return os.path.normcase(os.path.abspath(left_text)) == os.path.normcase(os.path.abspath(right_text))
                    except Exception:
                        return left_text == right_text

                def _is_fast_source_reference(ref: dict[str, Any]) -> bool:
                    return bool(ref.get("fast_locate_source_reference")) or _same_file_text(
                        ref.get("clip_path"),
                        ref.get("video_path"),
                    )

                def _source_range_url(view: str, ref: dict[str, Any], fallback_start: float, fallback_end: float) -> Optional[str]:
                    if _key_action_source_video_for_view(experiment_id, view) is None:
                        return None
                    try:
                        start = float(fallback_start)
                    except (TypeError, ValueError):
                        start = float(ref.get("local_start_sec") if ref.get("local_start_sec") is not None else 0.0)
                    try:
                        end = float(fallback_end)
                    except (TypeError, ValueError):
                        end = float(ref.get("local_end_sec") if ref.get("local_end_sec") is not None else start)
                    if end <= start:
                        return None
                    return (
                        f"/api/v1/experiments/{experiment_id}/key-actions/source-video/{view}"
                        f"#t={max(0.0, start):.3f},{max(0.0, end):.3f}"
                    )

                def _segment_bound_clip_url(view: str, ref: dict[str, Any]) -> Optional[str]:
                    binding = segment_bindings_by_view.get(view, {})
                    for raw_path in (ref.get("clip_path"), binding.get("clip_path")):
                        if not raw_path:
                            continue
                        clip_url = _clip_url_if_exists(Path(str(raw_path)))
                        if clip_url:
                            return clip_url
                    return None

                def _segment_bound_poster_url(view: str) -> Optional[str]:
                    binding = segment_bindings_by_view.get(view, {})
                    keyframes = binding.get("keyframes") if isinstance(binding.get("keyframes"), dict) else {}
                    candidates: list[Any] = [
                        keyframes.get("start"),
                        keyframes.get("middle"),
                        keyframes.get("end"),
                    ]
                    keyframe_paths = binding.get("keyframe_paths")
                    if isinstance(keyframe_paths, list):
                        candidates.extend(keyframe_paths)
                    candidates.append(binding.get("keyframe_path"))
                    for raw_path in candidates:
                        if not raw_path:
                            continue
                        poster_url = _clip_url_if_exists(Path(str(raw_path)))
                        if poster_url:
                            return poster_url
                    return None

                def _ensure_segment_clip_from_source(
                    view: str,
                    ref: dict[str, Any],
                    clip_name: str,
                    fallback_start: float,
                    fallback_end: float,
                ) -> Optional[str]:
                    clip_path = clip_root / clip_name
                    existing = _clip_url_if_exists(clip_path)
                    if existing:
                        return existing
                    source_path = _key_action_source_video_for_view(experiment_id, view)
                    if source_path is None or not source_path.exists():
                        return None
                    try:
                        start = float(fallback_start)
                    except (TypeError, ValueError):
                        start = float(ref.get("local_start_sec") if ref.get("local_start_sec") is not None else 0.0)
                    try:
                        end = float(fallback_end)
                    except (TypeError, ValueError):
                        end = float(ref.get("local_end_sec") if ref.get("local_end_sec") is not None else start)
                    duration = max(0.0, end - start)
                    if duration <= 0.05:
                        return None
                    ffmpeg_bin = _find_ffmpeg_exe()
                    if not ffmpeg_bin:
                        return None
                    clip_path.parent.mkdir(parents=True, exist_ok=True)
                    tmp_path = clip_path.with_name(f"{clip_path.stem}.tmp_{os.getpid()}_{int(time.time() * 1000)}{clip_path.suffix}")

                    def _run_ffmpeg(cmd: list[str], timeout_sec: int) -> bool:
                        try:
                            result = subprocess.run(
                                cmd,
                                stdout=subprocess.DEVNULL,
                                stderr=subprocess.PIPE,
                                text=True,
                                timeout=timeout_sec,
                                check=False,
                            )
                            return result.returncode == 0 and tmp_path.exists() and tmp_path.stat().st_size > 0
                        except Exception:
                            return False

                    stream_copy_first = os.environ.get(
                        "KEY_ACTION_SEGMENT_PREVIEW_STREAM_COPY",
                        "0",
                    ).strip().lower() not in {"", "0", "false", "no", "off"}

                    encoder = _preferred_segment_preview_encoder(ffmpeg_bin)
                    max_width = int(float(os.environ.get("KEY_ACTION_SEGMENT_PREVIEW_MAX_WIDTH", "1280") or 1280))
                    scale_filter = f"scale='min({max_width},iw)':-2" if max_width > 0 else None

                    def _copy_cmd() -> list[str]:
                        return [
                            ffmpeg_bin,
                            "-hide_banner",
                            "-loglevel",
                            "error",
                            "-y",
                            "-ss",
                            f"{max(0.0, start):.3f}",
                            "-i",
                            str(source_path),
                            "-t",
                            f"{duration:.3f}",
                            "-map",
                            "0:v:0",
                            "-an",
                            "-c:v",
                            "copy",
                            "-avoid_negative_ts",
                            "make_zero",
                            "-movflags",
                            "+faststart",
                            str(tmp_path),
                        ]

                    def _reencode_cmd(video_encoder: str) -> list[str]:
                        cmd = [
                            ffmpeg_bin,
                            "-hide_banner",
                            "-loglevel",
                            "error",
                            "-y",
                            "-ss",
                            f"{max(0.0, start):.3f}",
                            "-i",
                            str(source_path),
                            "-t",
                            f"{duration:.3f}",
                            "-map",
                            "0:v:0",
                            "-an",
                            "-c:v",
                            video_encoder,
                        ]
                        if scale_filter:
                            cmd += ["-vf", scale_filter]
                        if video_encoder == "h264_nvenc":
                            cmd += [
                                "-preset",
                                os.environ.get("KEY_ACTION_SEGMENT_PREVIEW_NVENC_PRESET", "p4"),
                                "-rc",
                                "vbr",
                                "-cq",
                                os.environ.get("KEY_ACTION_SEGMENT_PREVIEW_CQ", "27"),
                                "-b:v",
                                os.environ.get("KEY_ACTION_SEGMENT_PREVIEW_VIDEO_BITRATE", "4M"),
                            ]
                        else:
                            cmd += [
                                "-preset",
                                os.environ.get("KEY_ACTION_SEGMENT_PREVIEW_X264_PRESET", "veryfast"),
                                "-crf",
                                os.environ.get("KEY_ACTION_SEGMENT_PREVIEW_CRF", "26"),
                            ]
                        cmd += [
                            "-pix_fmt",
                            "yuv420p",
                            "-avoid_negative_ts",
                            "make_zero",
                            "-movflags",
                            "+faststart",
                            str(tmp_path),
                        ]
                        return cmd

                    exact_timeout = max(90, int(duration * 3.0) + 45)
                    copy_timeout = max(20, int(duration * 0.5) + 20)
                    ok = False
                    if stream_copy_first:
                        ok = _run_ffmpeg(_copy_cmd(), copy_timeout)
                    if not ok:
                        try:
                            tmp_path.unlink(missing_ok=True)
                        except Exception:
                            pass
                        ok = _run_ffmpeg(_reencode_cmd(encoder), exact_timeout)
                    if not ok and encoder != "libx264":
                        try:
                            tmp_path.unlink(missing_ok=True)
                        except Exception:
                            pass
                        ok = _run_ffmpeg(_reencode_cmd("libx264"), exact_timeout)
                    if not ok and not stream_copy_first:
                        try:
                            tmp_path.unlink(missing_ok=True)
                        except Exception:
                            pass
                        ok = _run_ffmpeg(_copy_cmd(), copy_timeout)
                    if not ok:
                        try:
                            tmp_path.unlink(missing_ok=True)
                        except Exception:
                            pass
                        return None
                    try:
                        tmp_path.replace(clip_path)
                    except Exception:
                        try:
                            tmp_path.unlink(missing_ok=True)
                        except Exception:
                            pass
                        return None
                    return _clip_url_if_exists(clip_path)

                def _view_fallback_range(view: str) -> tuple[float, float]:
                    if view == "first_person":
                        start = _first_float(first_local_start, local_start, 0.0) or 0.0
                        end = _first_float(first_local_end)
                    else:
                        start = _first_float(third_local_start, local_start, 0.0) or 0.0
                        end = _first_float(third_local_end)
                    if end is None:
                        end = start + float(duration_sec or 0.0)
                    return float(start), float(max(float(end), float(start)))

                def _segment_video_url(view: str, ref: dict[str, Any], clip_name: str, has_action: bool) -> Optional[str]:
                    if ref or has_action:
                        fallback_start, fallback_end = _view_fallback_range(view)
                        range_url = _source_range_url(view, ref, fallback_start, fallback_end)
                        generate_preview = os.environ.get(
                            "KEY_ACTION_GENERATE_SEGMENT_PREVIEW_CLIPS",
                            "0",
                        ).strip().lower() not in {"", "0", "false", "no", "off"}
                        if not generate_preview and range_url:
                            return range_url
                        segment_clip = _segment_bound_clip_url(view, ref)
                        if segment_clip:
                            return segment_clip
                        existing = _clip_url_if_exists(clip_root / clip_name)
                        if existing:
                            return existing
                        return _ensure_segment_clip_from_source(view, ref, clip_name, fallback_start, fallback_end) or range_url
                    return _clip_url_if_exists(clip_root / clip_name)

                def _ensure_poster_from_source_view(view: str, start_sec: float, poster_path: Path) -> Optional[str]:
                    source_path = _key_action_source_video_for_view(experiment_id, view)
                    if source_path is None:
                        return None
                    ffmpeg_bin = _find_ffmpeg_exe()
                    if not ffmpeg_bin:
                        return None
                    if poster_path.exists() and poster_path.stat().st_size > 0:
                        return _experiment_file_api_path(poster_path, experiment_id)
                    poster_path.parent.mkdir(parents=True, exist_ok=True)
                    tmp_path = poster_path.with_suffix(f".tmp{poster_path.suffix}")
                    try:
                        subprocess.run(
                            [
                                ffmpeg_bin,
                                "-hide_banner",
                                "-loglevel",
                                "error",
                                "-y",
                                "-ss",
                                f"{max(0.0, float(start_sec)):.3f}",
                                "-i",
                                str(source_path),
                                "-frames:v",
                                "1",
                                "-q:v",
                                "3",
                                str(tmp_path),
                            ],
                            stdout=subprocess.DEVNULL,
                            stderr=subprocess.DEVNULL,
                            timeout=8,
                            check=True,
                        )
                        if tmp_path.exists() and tmp_path.stat().st_size > 0:
                            tmp_path.replace(poster_path)
                            return _experiment_file_api_path(poster_path, experiment_id)
                    except Exception:
                        try:
                            tmp_path.unlink(missing_ok=True)
                        except Exception:
                            pass
                    return None

                first_person_video_url = _segment_video_url(
                    "first_person",
                    first_person,
                    "first_person.mp4",
                    first_has_action,
                )
                third_person_video_url = _segment_video_url(
                    "third_person",
                    third_person,
                    "third_person.mp4",
                    third_has_action,
                )
                if first_person_video_url and third_person_video_url and view_evidence_status == "dual_view_verified":
                    view_alignment_status = "dual_view_verified"
                    view_alignment_warning = None
                first_person_annotated_video_url = _clip_url_if_exists(clip_root / "first_person_yolo_annotated.mp4")
                third_person_annotated_video_url = _clip_url_if_exists(clip_root / "third_person_yolo_annotated.mp4")
                first_person_micro_preview = _best_micro_preview("first_person")
                third_person_micro_preview = _best_micro_preview("third_person")
                keyframe_root = output_dir / "key_action_index" / "keyframes" / segment_id
                first_fallback_start, _first_fallback_end = _view_fallback_range("first_person")
                third_fallback_start, _third_fallback_end = _view_fallback_range("third_person")
                generate_segment_posters = os.environ.get(
                    "KEY_ACTION_GENERATE_SEGMENT_POSTERS",
                    "0",
                ).strip().lower() not in {"", "0", "false", "no", "off"}
                source_poster_fallback = os.environ.get(
                    "KEY_ACTION_SOURCE_POSTER_FALLBACK",
                    "1",
                ).strip().lower() not in {"", "0", "false", "no", "off"}
                def _source_poster_sample_time(start_sec: float, end_sec: float) -> float:
                    duration = max(0.0, float(end_sec) - float(start_sec))
                    return float(start_sec) + min(1.2, max(0.2, duration * 0.05))
                def _source_preview_poster_time(preview: Mapping[str, Any], start_sec: float, end_sec: float) -> float:
                    try:
                        value = float(preview.get("time_sec"))
                        if math.isfinite(value):
                            return max(0.0, value)
                    except (TypeError, ValueError):
                        pass
                    return _source_poster_sample_time(start_sec, end_sec)
                def _source_preview_poster_path(view: str, preview_sec: float) -> Path:
                    millis = int(max(0.0, preview_sec) * 1000.0)
                    return keyframe_root / f"{view}_source_preview_{millis:012d}.jpg"

                def _reference_file_url(ref: Mapping[str, Any]) -> Optional[str]:
                    raw_path = ref.get("stored_file") or ref.get("file_path") or ref.get("path")
                    if not raw_path:
                        return None
                    path = Path(str(raw_path))
                    if not path.is_absolute():
                        path = output_dir / "material_references" / path
                    return _experiment_file_api_path(path, experiment_id) if path.exists() and path.stat().st_size > 0 else None

                def _reference_key_material_rows() -> list[dict[str, Any]]:
                    event_ids = {str(value) for value in (formal_action.get("event_ids") or []) if str(value).strip()}
                    micro_ids = set(formal_event_micro_ids)
                    grouped: dict[str, dict[str, Any]] = {}
                    for ref in material_reference_rows:
                        if not isinstance(ref, dict):
                            continue
                        ref_event_id = str(ref.get("dual_event_id") or ref.get("dual_view_action_event_id") or "").strip()
                        ref_micro_id = str(ref.get("micro_segment_id") or "").strip()
                        ref_segment_id = str(ref.get("segment_id") or ref.get("parent_segment_id") or "").strip()
                        try:
                            ref_start = float(ref.get("start_sec") if ref.get("start_sec") is not None else ref.get("time_start"))
                            ref_end = float(ref.get("end_sec") if ref.get("end_sec") is not None else ref.get("time_end"))
                        except (TypeError, ValueError):
                            ref_start = float(session_start or 0.0)
                            ref_end = ref_start
                        matches_segment = ref_segment_id == segment_id
                        matches_event = bool(ref_event_id and ref_event_id in event_ids)
                        matches_micro = bool(ref_micro_id and ref_micro_id in micro_ids)
                        overlaps_time = (
                            ref_end >= float(session_start or 0.0) - 0.25
                            and ref_start <= float(session_end or 0.0) + 0.25
                        )
                        if not (matches_event or matches_micro or matches_segment or overlaps_time):
                            continue
                        view_name = str(ref.get("view") or "").strip()
                        if view_name not in {"third_person", "first_person"}:
                            continue
                        file_url = _reference_file_url(ref)
                        if not file_url:
                            continue
                        group_key = ref_event_id or str(ref.get("material_group_id") or ref.get("evidence_group_id") or ref_micro_id)
                        if not group_key:
                            continue
                        group = grouped.setdefault(
                            group_key,
                            {
                                "micro_segment_id": ref_micro_id or group_key,
                                "dual_event_id": ref_event_id or None,
                                "title": ref.get("action_name") or ref.get("display_name") or "关键物理动作",
                                "primary_object": ref.get("primary_object") or ref.get("canonical_object"),
                                "interaction_type": ref.get("canonical_action_type") or ref.get("physical_action_type"),
                                "start_sec": ref_start,
                                "end_sec": ref_end,
                                "views": {},
                            },
                        )
                        group["start_sec"] = min(float(group.get("start_sec") or ref_start), ref_start)
                        group["end_sec"] = max(float(group.get("end_sec") or ref_end), ref_end)
                        group["title"] = group.get("title") or ref.get("action_name") or ref.get("display_name")
                        group["primary_object"] = group.get("primary_object") or ref.get("primary_object") or ref.get("canonical_object")
                        group["interaction_type"] = group.get("interaction_type") or ref.get("canonical_action_type") or ref.get("physical_action_type")
                        view_payload = group.setdefault("views", {}).setdefault(
                            view_name,
                            {
                                "clip_url": None,
                                "keyframe_url": None,
                                "local_start_sec": ref_start,
                                "local_end_sec": ref_end,
                                "material_type": None,
                            },
                        )
                        asset_type = str(ref.get("asset_type") or "").strip()
                        if asset_type == "video_clip":
                            view_payload["clip_url"] = file_url
                            view_payload["material_type"] = "关键片段"
                        elif asset_type == "keyframe":
                            view_payload["keyframe_url"] = file_url
                            view_payload["material_type"] = view_payload.get("material_type") or "关键帧"
                        view_payload["local_start_sec"] = min(float(view_payload.get("local_start_sec") or ref_start), ref_start)
                        view_payload["local_end_sec"] = max(float(view_payload.get("local_end_sec") or ref_end), ref_end)
                    materials = []
                    for group in grouped.values():
                        views = group.get("views") if isinstance(group.get("views"), dict) else {}
                        third = views.get("third_person") if isinstance(views.get("third_person"), dict) else {}
                        first = views.get("first_person") if isinstance(views.get("first_person"), dict) else {}
                        if not third or not first:
                            continue
                        if not (third.get("clip_url") or third.get("keyframe_url")):
                            continue
                        if not (first.get("clip_url") or first.get("keyframe_url")):
                            continue
                        materials.append(group)
                    return sorted(materials, key=lambda item: float(item.get("start_sec") or 0.0))

                reference_key_materials_for_segment = _reference_key_material_rows()

                def _reference_material_preview(view: str) -> dict[str, Any]:
                    for material in reference_key_materials_for_segment:
                        views = material.get("views") if isinstance(material.get("views"), dict) else {}
                        payload = views.get(view) if isinstance(views.get(view), dict) else {}
                        keyframe_url = payload.get("keyframe_url")
                        clip_url = payload.get("clip_url")
                        if not keyframe_url and not clip_url:
                            continue
                        return {
                            "url": keyframe_url or clip_url,
                            "time_sec": payload.get("local_start_sec") or material.get("start_sec"),
                        }
                    return {"url": None, "time_sec": None}
                first_source_preview_sec = _source_preview_poster_time(
                    first_person_micro_preview,
                    first_fallback_start,
                    _first_fallback_end,
                )
                third_source_preview_sec = _source_preview_poster_time(
                    third_person_micro_preview,
                    third_fallback_start,
                    _third_fallback_end,
                )
                first_person_poster_url = (
                    _reference_material_preview("first_person").get("url")
                    or first_person_micro_preview.get("url")
                    or _segment_bound_poster_url("first_person")
                )
                if first_person_poster_url is None:
                    first_person_poster_url = (
                        (
                            _ensure_poster_from_source_view(
                                "first_person",
                                first_source_preview_sec,
                                _source_preview_poster_path("first_person", first_source_preview_sec),
                            )
                            if source_poster_fallback
                            else None
                        )
                        or _poster_url_if_exists(
                            keyframe_root / "first_person_start.jpg",
                            keyframe_root / "first_person_middle.jpg",
                            keyframe_root / "first_person_end.jpg",
                        )
                        or (
                            _ensure_poster_from_video(clip_root / "first_person.mp4", clip_root / "first_person_process_start.jpg")
                            if generate_segment_posters
                            else None
                        )
                        or (
                            _ensure_poster_from_source_view(
                                "first_person",
                                _source_poster_sample_time(first_fallback_start, _first_fallback_end),
                                keyframe_root / "first_person_source_start.jpg",
                            )
                            if (generate_segment_posters or source_poster_fallback)
                            else None
                        )
                    )
                third_person_poster_url = (
                    _reference_material_preview("third_person").get("url")
                    or third_person_micro_preview.get("url")
                    or _segment_bound_poster_url("third_person")
                )
                if third_person_poster_url is None:
                    third_person_poster_url = (
                        (
                            _ensure_poster_from_source_view(
                                "third_person",
                                third_source_preview_sec,
                                _source_preview_poster_path("third_person", third_source_preview_sec),
                            )
                            if source_poster_fallback
                            else None
                        )
                        or _poster_url_if_exists(
                            keyframe_root / "third_person_start.jpg",
                            keyframe_root / "third_person_middle.jpg",
                            keyframe_root / "third_person_end.jpg",
                        )
                        or (
                            _ensure_poster_from_video(clip_root / "third_person.mp4", clip_root / "third_person_process_start.jpg")
                            if generate_segment_posters
                            else None
                        )
                        or (
                            _ensure_poster_from_source_view(
                                "third_person",
                                _source_poster_sample_time(third_fallback_start, _third_fallback_end),
                                keyframe_root / "third_person_source_start.jpg",
                            )
                            if (generate_segment_posters or source_poster_fallback)
                            else None
                        )
                    )

                def _micro_key_material_rows(micro_rows: list[Any]) -> list[dict[str, Any]]:
                    def _physical_action_title(interaction_type: str, primary_object: str) -> str:
                        action = f"{interaction_type} {primary_object}".lower()
                        if any(token in action for token in ("balance", "scale", "weigh")):
                            return "天平设备面板操作"
                        if any(token in action for token in ("reagent_bottle", "sample_bottle", "bottle")):
                            return "手部与试剂瓶操作"
                        if "paper" in action:
                            return "手部与称量纸操作"
                        if any(token in action for token in ("beaker", "container")):
                            return "手部与容器操作"
                        return "手部与物体操作"

                    materials: list[dict[str, Any]] = []
                    for micro in micro_rows:
                        if not isinstance(micro, dict):
                            continue
                        interaction = micro.get("interaction") if isinstance(micro.get("interaction"), dict) else {}
                        keyframes = micro.get("keyframes") if isinstance(micro.get("keyframes"), dict) else {}
                        keyframe_path = (
                            keyframes.get("peak_frame")
                            or keyframes.get("contact_frame")
                            or keyframes.get("release_frame")
                            or micro.get("peak_keyframe")
                        )
                        evidence_views = {
                            str(item.get("view") or item.get("source_view") or "")
                            for item in (micro.get("yolo_evidence") or [])
                            if isinstance(item, dict)
                        }
                        if not {"third_person", "first_person"}.issubset(evidence_views):
                            continue
                        bindings_by_view: dict[str, dict[str, Any]] = {}
                        for binding in micro.get("asset_bindings") or []:
                            if isinstance(binding, dict) and (binding.get("clip_path") or binding.get("keyframe_path")):
                                binding_view = str(binding.get("view") or "")
                                bindings_by_view[binding_view] = binding
                        views: dict[str, dict[str, Any]] = {}
                        for view_name in ("third_person", "first_person"):
                            ref = micro.get(view_name) if isinstance(micro.get(view_name), dict) else {}
                            binding = bindings_by_view.get(view_name, {})
                            if view_name not in evidence_views:
                                continue
                            clip_path = (
                                ref.get("annotated_clip_path")
                                or ref.get("clip_path")
                                or binding.get("clip_path")
                                or micro.get(f"{view_name}_clip")
                            )
                            view_keyframe_path = binding.get("keyframe_path") or keyframe_path
                            clip_url = _clip_url_if_exists(Path(str(clip_path))) if clip_path else None
                            keyframe_url = (
                                _clip_url_if_exists(Path(str(view_keyframe_path)))
                                if view_keyframe_path and (view_name in evidence_views or clip_url)
                                else None
                            )
                            if not clip_url and not keyframe_url:
                                continue
                            views[view_name] = {
                                "clip_url": clip_url,
                                "keyframe_url": keyframe_url,
                                "local_start_sec": ref.get("local_start_sec") or binding.get("local_start_sec") or micro.get("start_sec"),
                                "local_end_sec": ref.get("local_end_sec") or binding.get("local_end_sec") or micro.get("end_sec"),
                                "material_type": "关键片段" if clip_url else "关键帧",
                            }
                        if not views:
                            continue
                        primary_object = str(
                            interaction.get("primary_object")
                            or micro.get("primary_object")
                            or "object"
                        )
                        interaction_type = str(
                            interaction.get("interaction_type")
                            or micro.get("interaction_type")
                            or "physical_interaction"
                        )
                        materials.append(
                            {
                                "micro_segment_id": micro.get("micro_segment_id"),
                                "title": _physical_action_title(interaction_type, primary_object),
                                "primary_object": primary_object,
                                "interaction_type": interaction_type,
                                "start_sec": next((view.get("local_start_sec") for view in views.values() if view.get("local_start_sec") is not None), micro.get("start_sec")),
                                "end_sec": next((view.get("local_end_sec") for view in views.values() if view.get("local_end_sec") is not None), micro.get("end_sec")),
                                "views": views,
                            }
                        )
                    return materials

                preview_video_url = (
                    third_person_annotated_video_url
                    or third_person_video_url
                    or first_person_annotated_video_url
                    or first_person_video_url
                )
                preview_poster_url = third_person_poster_url or first_person_poster_url
                reference_key_materials = reference_key_materials_for_segment
                micro_key_materials = _micro_key_material_rows(micro_segments)
                segment_key_materials = reference_key_materials or micro_key_materials

                segments.append({
                    "segment_id": segment_id,
                    "index": index,
                    "display_name": f"实验片段 {index + 1}",
                    "start_sec": float(session_start or 0.0),
                    "end_sec": float(session_end or 0.0),
                    "duration_sec": float(duration_sec or 0.0),
                    "time_basis": "aligned_capture_session_sec",
                    "third_person_local_start_sec": third_local_start,
                    "third_person_local_end_sec": third_local_end,
                    "first_person_local_start_sec": first_local_start,
                    "first_person_local_end_sec": first_local_end,
                    "global_start_time": segment.get("global_start_time"),
                    "global_end_time": segment.get("global_end_time"),
                    "preview_video_url": preview_video_url,
                    "preview_poster_url": preview_poster_url,
                    "preview_ready": bool(preview_video_url),
                    "first_person_video_url": first_person_video_url,
                    "third_person_video_url": third_person_video_url,
                    "first_person_annotated_video_url": first_person_annotated_video_url,
                    "third_person_annotated_video_url": third_person_annotated_video_url,
                    "first_person_poster_url": first_person_poster_url,
                    "third_person_poster_url": third_person_poster_url,
                    "first_person_preview_time_sec": (
                        _reference_material_preview("first_person").get("time_sec")
                        or first_person_micro_preview.get("time_sec")
                    ),
                    "third_person_preview_time_sec": (
                        _reference_material_preview("third_person").get("time_sec")
                        or third_person_micro_preview.get("time_sec")
                    ),
                    "annotated_ready": bool(first_person_annotated_video_url or third_person_annotated_video_url),
                    "naming_source": "yolo:key_action_index",
                    "naming_confidence": cv_detection.get("confidence") or segment.get("final_score"),
                    "micro_segment_count": len(micro_segments),
                    "yolo_interaction_count": segment.get("yolo_interaction_count"),
                    "reason_code": segment.get("reason_code"),
                    "decision_path": segment.get("decision_path"),
                    "view_alignment_status": view_alignment_status,
                    "view_alignment_warning": view_alignment_warning,
                    "formal_action_status": formal_action["status"],
                    "formal_dual_view_action": bool(is_official_dual_view_segment),
                    "formal_action_source": formal_action["source"],
                    "formal_action_reason": formal_action["reason"],
                    "dual_view_action_event_ids": formal_action["event_ids"],
                    "view_evidence_status": view_evidence_status,
                    "view_evidence_warning": view_evidence_warning,
                    "view_support": view_support,
                    "key_materials": segment_key_materials[:6],
                    "micro_segments": [
                        {
                            "micro_segment_id": micro.get("micro_segment_id"),
                            "display_id": micro.get("display_id"),
                            "primary_object": micro.get("primary_object"),
                            "interaction_type": micro.get("interaction_type"),
                            "confidence": micro.get("confidence"),
                            "duration_sec": micro.get("duration_sec"),
                            "global_start_time": micro.get("global_start_time"),
                            "global_end_time": micro.get("global_end_time"),
                            "max_interaction_score": micro.get("max_interaction_score"),
                        }
                        for micro in micro_segments[:8]
                        if isinstance(micro, dict)
                    ],
                    "top_objects": [
                        label for label, _count in sorted(
                            yolo_label_counts.items(),
                            key=lambda item: item[1],
                            reverse=True,
                        )[:5]
                    ],
                })
            if segments:
                official_total = sum(1 for segment in segments if segment.get("formal_dual_view_action"))
                candidate_total = len(segments) - official_total
                return {
                    "total": len(segments),
                    "official_total": official_total,
                    "candidate_total": candidate_total,
                    "segments": segments,
                    "sub_experiments": [
                        {
                            "sub_id": f"{experiment_id}_seg{i + 1}",
                            "segment_index": i,
                            "path": str(output_dir / "key_action_index"),
                            "has_materials": bool(segment.get("key_materials") or segment.get("micro_segment_count", 0)),
                            "first_person_video_url": segment.get("first_person_video_url"),
                            "third_person_video_url": segment.get("third_person_video_url"),
                            "first_person_poster_url": segment.get("first_person_poster_url"),
                            "third_person_poster_url": segment.get("third_person_poster_url"),
                        }
                        for i, segment in enumerate(segments)
                    ],
                    "video_duration_sec": video_duration_sec,
                    "preview_ready": any(segment.get("preview_ready") for segment in segments),
                    "preview_video_url": next((segment.get("preview_video_url") for segment in segments if segment.get("preview_video_url")), None),
                    "segment_preview_ready_count": sum(1 for segment in segments if segment.get("preview_ready")),
                    "preview_error": None if any(segment.get("preview_ready") for segment in segments) else "segment previews are deferred; key-action segment timestamps are available",
                    "source": "key_action_index",
                    "formal_action_policy": "official_segments_require_confirmed_dual_view_action_events",
                }
            if key_action_segments_path.exists():
                return {
                    "total": 0,
                    "official_total": 0,
                    "candidate_total": len(candidate_source_rows),
                    "segments": [],
                    "sub_experiments": [],
                    "video_duration_sec": None,
                    "preview_ready": False,
                    "preview_video_url": None,
                    "segment_preview_ready_count": 0,
                    "preview_error": "no_formal_dual_view_action_episodes",
                    "message": "当前仅发现动作候选窗口，尚未形成通过双视角同动作校验的正式实验片段。",
                    "source": "key_action_index_formal_gate",
                    "formal_action_policy": "official_segments_require_confirmed_dual_view_action_events",
                    "candidate_debug_total": len(candidate_source_rows),
                    "dual_view_action_event_count": len(formal_dual_view_context.get("events") or []),
                }
    if not seg_path.exists():
        return {
            "total": 0,
            "segments": [],
            "sub_experiments": [],
            "preview_ready": False,
            "preview_video_url": None,
            "message": "No segmentation detected",
        }
    data = json.loads(seg_path.read_text(encoding="utf-8"))
    preview_path = output_dir / "artifacts" / "segmentation_preview.mp4"
    preview_url = _experiment_file_api_path(preview_path, experiment_id) if preview_path.exists() else None
    segments = []
    for segment in data.get("segments", []):
        item = dict(segment)
        raw_preview_path = item.get("preview_video_path")
        preview_candidate = Path(str(raw_preview_path)) if raw_preview_path else output_dir / "artifacts" / "segment_previews" / f"{item.get('segment_id', '')}.mp4"
        if preview_candidate.exists():
            item["preview_video_url"] = _experiment_file_api_path(preview_candidate, experiment_id)
            item["preview_ready"] = True
        else:
            item["preview_video_url"] = None
            item["preview_ready"] = False
        segments.append(item)
    sub_dirs = sorted(output_dir.glob("sub_*"))
    sub_experiments = []
    for sub_dir in sub_dirs:
        idx = sub_dir.name.replace("sub_", "")
        material_idx = sub_dir / "material_index.sqlite"
        sub_experiments.append({
            "sub_id": f"{experiment_id}_sub{idx}",
            "segment_index": int(idx) if idx.isdigit() else 0,
            "path": str(sub_dir),
            "has_materials": material_idx.exists(),
        })
    return {
        "total": data.get("total_segments", 0),
        "segments": segments,
        "sub_experiments": sub_experiments,
        "video_duration_sec": data.get("video_duration_sec"),
        "preview_ready": bool(preview_url),
        "preview_video_url": preview_url,
        "segment_preview_ready_count": sum(1 for segment in segments if segment.get("preview_ready")),
        "preview_error": data.get("preview_error"),
    }


@app.get("/api/v1/materials/global-search", tags=["materials"])
async def global_material_search(
    text: Optional[str] = None,
    event_type: Optional[str] = None,
    experiment_id: Optional[str] = None,
    objects: Optional[str] = None,
    semantic_query: Optional[str] = None,
    limit: int = 50,
):
    """Cross-experiment semantic material search for LLM tool-use integration."""
    from labsopguard.global_index import GlobalMaterialIndex
    global_db = PROJECT_ROOT / "outputs" / "global_material_index.sqlite"
    if not global_db.exists():
        # Build index on first call
        index = GlobalMaterialIndex(global_db)
        index.sync_all_experiments(PROJECT_ROOT / "outputs" / "experiments")
    else:
        index = GlobalMaterialIndex(global_db)
    try:
        results = index.search(
            text=text,
            event_type=event_type,
            experiment_id=experiment_id,
            objects=[o.strip() for o in objects.split(",") if o.strip()] if objects else None,
            semantic_query=semantic_query,
            limit=min(max(int(limit), 1), 200),
        )
        stats = index.stats()
    finally:
        index.close()
    return {
        "total": len(results),
        "items": results,
        "index_stats": stats,
        "embedding_mode": stats.get("embedding_mode"),
    }


@app.get("/api/v1/materials/global-search/sync", tags=["materials"])
async def sync_global_material_index():
    """Force re-sync all experiments into the global material index."""
    from labsopguard.global_index import GlobalMaterialIndex
    global_db = PROJECT_ROOT / "outputs" / "global_material_index.sqlite"
    index = GlobalMaterialIndex(global_db)
    try:
        results = index.sync_all_experiments(PROJECT_ROOT / "outputs" / "experiments")
        stats = index.stats()
    finally:
        index.close()
    return {
        "synced_experiments": results,
        "total_synced": sum(results.values()),
        "index_stats": stats,
    }


