def _iso_to_epoch_us(value: Any) -> Optional[int]:
    """Best-effort parse of an ISO-8601 timestamp into epoch microseconds."""
    if value is None:
        return None
    text = str(value).strip()
    if not text:
        return None
    try:
        from datetime import datetime as _dt

        normalized = text.replace("Z", "+00:00")
        parsed = _dt.fromisoformat(normalized)
        return int(parsed.timestamp() * 1_000_000)
    except (ValueError, OverflowError, OSError):
        return None


def _segment_understanding_text_from_vlm(materials: List[Dict[str, Any]]) -> List[str]:
    """Extract real Qwen narrative lines from material rows that carry vlm_semantics."""
    lines: List[str] = []
    seen: set[str] = set()
    for row in materials:
        if not isinstance(row, dict):
            continue
        vlm = row.get("vlm_semantics")
        if not isinstance(vlm, dict):
            continue
        description = str(vlm.get("description") or "").strip()
        if not description:
            continue
        action = str(vlm.get("physical_action") or "").strip()
        objects = vlm.get("confirmed_objects")
        object_text = ""
        if isinstance(objects, list) and objects:
            object_text = "、".join(str(o) for o in objects if o)
        prefix_parts = [p for p in (action, object_text) if p]
        prefix = f"【{' · '.join(prefix_parts)}】" if prefix_parts else ""
        composed = f"{prefix}{description}".strip()
        if composed and composed not in seen:
            seen.add(composed)
            lines.append(composed)
    return lines


