def _zh_lookup(table: Dict[str, str], key: Any) -> str:
    text = str(key or "").strip()
    if not text:
        return ""
    return table.get(text, text.replace("_", " "))


def _segment_understanding_line_zh(row: Dict[str, Any]) -> str:
    """Compose one readable Chinese sentence from a video_understanding.jsonl row."""
    obj = _zh_lookup(_ZH_OBJECT_LABELS, row.get("primary_object"))
    action = _zh_lookup(_ZH_ACTION_LABELS, row.get("action_type"))
    event = _zh_lookup(_ZH_EVENT_LABELS, row.get("event_type"))
    confirmed = str(row.get("conclusion_status") or "").strip() == "confirmed"
    status_text = "已确认" if confirmed else "候选"
    try:
        conf = float(row.get("confidence"))
        conf_text = f"，置信度 {conf:.0%}"
    except (TypeError, ValueError):
        conf_text = ""
    head_parts = [p for p in (action, obj) if p]
    head = " · ".join(head_parts) if head_parts else (event or "观测")
    detail = event if event and event != head else ""
    detail_text = f"（{detail}）" if detail else ""
    return f"【{status_text}】{head}{detail_text}{conf_text}".strip()


def _segment_understanding_text_zh_from_rows(
    understanding_rows: List[Dict[str, Any]],
    start_us: Optional[int],
    end_us: Optional[int],
) -> List[str]:
    """Window-scoped Chinese synthesis from structured understanding rows.

    A row is assigned to a window when its START falls inside the window range
    (not mere overlap), so each observation lands in exactly one window. Rows
    whose span covers more than 80% of the window are treated as background
    "always-on" tracks and skipped — those are what made every window look
    identical at the top. Lines are emitted in chronological order so each
    window narrates its own time slice rather than the same global top combos.
    """
    scored: List[tuple] = []
    seen: set[str] = set()
    has_window = start_us is not None and end_us is not None
    window_span = (end_us - start_us) if has_window else None
    for row in understanding_rows:
        if not isinstance(row, dict):
            continue
        row_start = _iso_to_epoch_us(row.get("global_start_time"))
        row_end = _iso_to_epoch_us(row.get("global_end_time")) or row_start
        if has_window and row_start is not None:
            # Assign by start-time containment so a row belongs to one window.
            if row_start < start_us or row_start > end_us:
                continue
            # Drop background tracks that blanket the whole window.
            if (
                window_span
                and window_span > 0
                and row_end is not None
                and (row_end - row_start) > 0.8 * window_span
            ):
                continue
        line = _segment_understanding_line_zh(row)
        if not line or line in seen:
            continue
        seen.add(line)
        scored.append((row_start if row_start is not None else 0, line))
    scored.sort(key=lambda item: item[0])
    return [line for _, line in scored]


def _segment_understanding_text_from_template(
    understanding_rows: List[Dict[str, Any]],
    start_us: Optional[int],
    end_us: Optional[int],
) -> List[str]:
    """Fallback: concatenate template understanding rows overlapping a window time range."""
    lines: List[str] = []
    seen: set[str] = set()
    for row in understanding_rows:
        if not isinstance(row, dict):
            continue
        row_start = _iso_to_epoch_us(row.get("global_start_time"))
        row_end = _iso_to_epoch_us(row.get("global_end_time")) or row_start
        # Keep the row when its time range overlaps the window, or when window
        # bounds are unavailable (avoid silently dropping everything).
        if start_us is not None and end_us is not None and row_start is not None:
            if row_end is not None and (row_end < start_us or row_start > end_us):
                continue
        text = str(row.get("text") or row.get("semantic_description") or "").strip()
        if text and text not in seen:
            seen.add(text)
            lines.append(text)
    return lines


@app.get("/api/v1/experiments/{experiment_id}/segment-understanding", tags=["experiments"])
async def get_experiment_segment_understanding(
    experiment_id: str,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    """Per-window understanding text for the frontend typewriter panel.

    Prefers real Qwen narrative (vlm_semantics from published/candidate
    materials in each window); falls back to the heuristic
    video_understanding.jsonl rows mapped by global time range. Read-only:
    serves whatever artifacts exist, never triggers generation or promotion.
    """
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    await get_experiment_dict(safe_experiment_id)
    output_dir = _experiment_output_dir(safe_experiment_id)
    metadata_dir = output_dir / "metadata"
    refs_dir = output_dir / "material_references"

    segments = _candidate_experiment_window_segments(safe_experiment_id, output_dir)

    # Material rows that may carry real Qwen vlm_semantics, keyed by window_id.
    # Published refs live under material_references/ (and a per-session subdir);
    # candidates carry the freshest vlm_semantics from enrichment.
    material_paths: List[Path] = [
        refs_dir / "key_material_references.jsonl",
        refs_dir / "material_stream.jsonl",
        refs_dir / "素材候选.jsonl",
    ]
    if refs_dir.is_dir():
        for sub in sorted(refs_dir.glob("experiments_*")):
            material_paths.append(sub / "key_material_references.jsonl")
            material_paths.append(sub / "material_stream.jsonl")
    material_rows: List[Dict[str, Any]] = []
    for path in material_paths:
        material_rows.extend(_read_jsonl_rows(path))
    materials_by_window: Dict[str, List[Dict[str, Any]]] = {}
    for row in material_rows:
        if not isinstance(row, dict):
            continue
        wid = str(row.get("window_id") or row.get("experiment_window_id") or "").strip()
        if wid:
            materials_by_window.setdefault(wid, []).append(row)

    understanding_rows = _read_jsonl_rows(metadata_dir / "video_understanding.jsonl")

    result_segments: List[Dict[str, Any]] = []
    for seg in segments:
        window_id = str(seg.get("segment_id") or "")
        start_us = seg.get("raw_window_start_global_timestamp_us") or seg.get("start_global_timestamp_us")
        end_us = seg.get("raw_window_end_global_timestamp_us") or seg.get("end_global_timestamp_us")
        try:
            start_us_int = int(start_us) if start_us is not None else None
            end_us_int = int(end_us) if end_us is not None else None
        except (TypeError, ValueError):
            start_us_int = end_us_int = None

        qwen_lines = _segment_understanding_text_from_vlm(materials_by_window.get(window_id, []))
        if qwen_lines:
            source = "qwen"
            lines = qwen_lines
        else:
            lines = _segment_understanding_text_zh_from_rows(understanding_rows, start_us_int, end_us_int)
            if lines:
                source = "heuristic_zh"
            else:
                lines = _segment_understanding_text_from_template(understanding_rows, start_us_int, end_us_int)
                source = "template"
        result_segments.append(
            {
                "segment_id": window_id,
                "index": seg.get("index"),
                "display_name": seg.get("display_name"),
                "start_sec": seg.get("start_sec"),
                "end_sec": seg.get("end_sec"),
                "understanding_text": "\n".join(lines),
                "source": source,
                "source_row_count": len(lines),
            }
        )

    return {
        "experiment_id": safe_experiment_id,
        "schema_version": "segment_understanding.v1",
        "total": len(result_segments),
        "segments": result_segments,
    }


@app.get("/api/v1/experiments/{experiment_id}/physical-events", tags=["experiments"])
async def get_experiment_physical_events(
    experiment_id: str,
    event_type: Optional[str] = None,
    actor_name: Optional[str] = None,
    start_time_sec: Optional[float] = None,
    end_time_sec: Optional[float] = None,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    await get_experiment_dict(safe_experiment_id)
    payload = _load_json_if_exists(_experiment_output_dir(safe_experiment_id) / "physical_events.json") or {}
    events = payload.get("events") if isinstance(payload, dict) else payload
    events = events or []
    filtered = []
    for event in events:
        if event_type and event.get("event_type") != event_type:
            continue
        if actor_name and event.get("actor_name") != actor_name:
            continue
        if start_time_sec is not None and float(event.get("end_time_sec") or 0.0) < float(start_time_sec):
            continue
        if end_time_sec is not None and float(event.get("start_time_sec") or 0.0) > float(end_time_sec):
            continue
        filtered.append(event)
    return {
        "experiment_id": safe_experiment_id,
        "schema_version": payload.get("schema_version", "physical_events.legacy") if isinstance(payload, dict) else "physical_events.legacy",
        "total": len(filtered),
        "events": filtered,
    }


