_VIDEO_MEMORY_CONTRACT_VERSION = "video_memory.t1_t14.contracts.v1"
_VIDEO_MEMORY_OVERVIEW_SCHEMA_VERSION = "video_memory.overview.v1"
_VIDEO_MEMORY_REQUIRED_SYMBOLS = [
    "EvidenceItem",
    "validate_evidence_item",
    "build_vlm_cache_key",
    "VLMCache",
    "score_evidence_clusters",
    "update_cluster_lifecycle",
    "build_partial_snapshot",
    "answer_video_memory_query",
    "run_feedback_update_job",
]


def _video_memory_now_dt() -> datetime:
    return datetime.now(timezone.utc)


def _video_memory_iso(value: datetime) -> str:
    if value.tzinfo is None:
        value = value.replace(tzinfo=timezone.utc)
    return value.isoformat()


def _video_memory_parse_dt(value: Any) -> Optional[datetime]:
    parsed = _parse_datetime_value(value)
    if parsed is None:
        return None
    if parsed.tzinfo is None:
        return parsed.replace(tzinfo=timezone.utc)
    return parsed.astimezone(timezone.utc)


def _video_memory_days_old(value: Any, now_dt: datetime) -> Optional[float]:
    parsed = _video_memory_parse_dt(value)
    if parsed is None:
        return None
    return (now_dt - parsed).total_seconds() / 86400.0


def _video_memory_as_list(value: Any) -> List[Any]:
    return value if isinstance(value, list) else []


def _video_memory_slug(value: Any, fallback: str = "unknown") -> str:
    text = str(value or fallback).strip().lower()
    text = re.sub(r"[^a-z0-9_+-]+", "_", text)
    text = re.sub(r"_+", "_", text).strip("_")
    return text or fallback


def _video_memory_core_status() -> Dict[str, Any]:
    try:
        import key_action_indexer.video_memory as video_memory  # type: ignore
    except ModuleNotFoundError as exc:
        if exc.name == "key_action_indexer.video_memory":
            return {
                "available": False,
                "module": "key_action_indexer.video_memory",
                "status": "module_missing",
                "missing_symbols": list(_VIDEO_MEMORY_REQUIRED_SYMBOLS),
                "error": "core module is not implemented yet",
            }
        return {
            "available": False,
            "module": "key_action_indexer.video_memory",
            "status": "import_error",
            "missing_symbols": list(_VIDEO_MEMORY_REQUIRED_SYMBOLS),
            "error": str(exc),
        }
    except Exception as exc:
        return {
            "available": False,
            "module": "key_action_indexer.video_memory",
            "status": "import_error",
            "missing_symbols": list(_VIDEO_MEMORY_REQUIRED_SYMBOLS),
            "error": str(exc),
        }
    missing = [name for name in _VIDEO_MEMORY_REQUIRED_SYMBOLS if not hasattr(video_memory, name)]
    return {
        "available": not missing,
        "module": "key_action_indexer.video_memory",
        "status": "available" if not missing else "partial",
        "missing_symbols": missing,
        "implemented_symbols": [name for name in _VIDEO_MEMORY_REQUIRED_SYMBOLS if name not in missing],
    }


def _video_memory_core_module() -> Optional[Any]:
    try:
        import key_action_indexer.video_memory as video_memory  # type: ignore
        return video_memory
    except Exception:
        return None


def _video_memory_package_uri(experiment_id: str, path_value: Any) -> Optional[str]:
    if not path_value:
        return None
    text = str(path_value).strip()
    if not text:
        return None
    try:
        path = Path(text)
    except Exception:
        return None
    if not path.is_absolute():
        rel_text = path.as_posix().lstrip("/")
        return f"package://experiments/{quote(experiment_id, safe='')}/{quote(rel_text, safe='/')}"
    try:
        rel = path.resolve().relative_to(_experiment_output_dir(experiment_id).resolve())
        return f"package://experiments/{quote(experiment_id, safe='')}/{quote(rel.as_posix(), safe='/')}"
    except Exception:
        digest = hashlib.sha1(text.encode("utf-8", errors="ignore")).hexdigest()[:12]
        return f"package://external/{quote(experiment_id, safe='')}/{digest}/{quote(path.name or 'asset', safe='')}"


def _video_memory_file_url(experiment_id: str, path_value: Any) -> Optional[str]:
    if not path_value:
        return None
    try:
        path = Path(str(path_value))
    except Exception:
        return None
    if not path.exists() or not path.is_file():
        return None
    return _experiment_file_api_path(path, experiment_id)


def _video_memory_yolo_refs_for_view(row: Dict[str, Any], view: str, *, limit: int = 6) -> List[Dict[str, Any]]:
    refs: List[Dict[str, Any]] = []
    for frame in _video_memory_as_list(row.get("yolo_evidence")):
        if not isinstance(frame, dict):
            continue
        frame_view = str(frame.get("source_view") or frame.get("view") or "").strip()
        if view and frame_view and frame_view != view:
            continue
        frame_id = str(frame.get("frame_id") or frame.get("frame_index") or "")
        for detection in _video_memory_as_list(frame.get("detections")):
            if not isinstance(detection, dict):
                continue
            label = str(detection.get("label") or detection.get("class_name") or "").strip()
            if not label:
                continue
            refs.append(
                {
                    "frame_id": frame_id,
                    "label": label,
                    "bbox": detection.get("bbox"),
                    "confidence": detection.get("confidence"),
                    "interaction_score": frame.get("interaction_score"),
                }
            )
            if len(refs) >= limit:
                return refs
    return refs


def _video_memory_view_payloads(experiment_id: str, row: Dict[str, Any]) -> List[Dict[str, Any]]:
    views: List[Dict[str, Any]] = []
    seen: set[str] = set()
    bindings = [
        item
        for item in _video_memory_as_list(row.get("asset_bindings"))
        if isinstance(item, dict) and str(item.get("view") or "").strip()
    ]
    if not bindings:
        for view_id in ("first_person", "third_person"):
            view_row = row.get(view_id)
            if isinstance(view_row, dict):
                bindings.append(
                    {
                        "view": view_id,
                        "clip_path": view_row.get("clip_path") or view_row.get("video_path"),
                        "keyframe_path": (row.get("keyframes") or {}).get("peak_frame") if isinstance(row.get("keyframes"), dict) else None,
                        "local_start_sec": view_row.get("local_start_sec"),
                        "local_end_sec": view_row.get("local_end_sec"),
                        "confidence": view_row.get("confidence"),
                    }
                )
    for binding in bindings:
        view_id = str(binding.get("view") or "").strip()
        if not view_id or view_id in seen:
            continue
        seen.add(view_id)
        clip_path = binding.get("clip_path") or binding.get("video_path")
        keyframe_path = binding.get("keyframe_path")
        if not keyframe_path and isinstance(binding.get("keyframes"), dict):
            keyframe_path = binding["keyframes"].get("peak")
        views.append(
            {
                "view_id": view_id,
                "source_video_id": binding.get("source_video_id") or binding.get("video_id") or view_id,
                "local_start_sec": binding.get("local_start_sec"),
                "local_end_sec": binding.get("local_end_sec"),
                "clip_uri": _video_memory_package_uri(experiment_id, clip_path),
                "keyframe_uri": _video_memory_package_uri(experiment_id, keyframe_path),
                "clip_url": _video_memory_file_url(experiment_id, clip_path),
                "keyframe_url": _video_memory_file_url(experiment_id, keyframe_path),
                "frame_ids": [
                    str(frame.get("frame_id") or frame.get("frame_index"))
                    for frame in _video_memory_as_list(row.get("yolo_evidence"))
                    if isinstance(frame, dict) and (not view_id or str(frame.get("source_view") or frame.get("view") or "") == view_id)
                ][:8],
                "yolo_refs": _video_memory_yolo_refs_for_view(row, view_id),
                "evidence_role": binding.get("evidence_role"),
                "confidence": binding.get("confidence"),
            }
        )
    return views


def _video_memory_cache_key(
    *,
    model: str,
    prompt_version: str,
    image_refs: List[str],
    evidence_payload: Dict[str, Any],
) -> str:
    video_memory = _video_memory_core_module()
    if video_memory is not None and hasattr(video_memory, "build_vlm_cache_key"):
        try:
            return str(
                video_memory.build_vlm_cache_key(
                    model=model,
                    prompt_version=prompt_version,
                    image_refs=image_refs,
                    evidence_item=evidence_payload,
                )
            )
        except Exception:
            logger.debug("Falling back to backend VLM cache key", exc_info=True)
    normalized = json.dumps(
        {
            "model": model,
            "prompt_version": prompt_version,
            "image_refs": image_refs,
            "evidence": evidence_payload,
        },
        ensure_ascii=False,
        sort_keys=True,
        separators=(",", ":"),
    )
    return f"backend-vm-{hashlib.sha256(normalized.encode('utf-8')).hexdigest()[:24]}"


def _video_memory_evidence_item_from_row(
    *,
    experiment_id: str,
    exp: Dict[str, Any],
    row: Dict[str, Any],
    index: int,
    now_dt: datetime,
    retention_days: int,
    source_level: str,
) -> Optional[Dict[str, Any]]:
    interaction = row.get("interaction") if isinstance(row.get("interaction"), dict) else {}
    evidence = row.get("evidence") if isinstance(row.get("evidence"), dict) else {}
    visual = evidence.get("visual_evidence") if isinstance(evidence.get("visual_evidence"), dict) else {}
    text_description = row.get("text_description") if isinstance(row.get("text_description"), dict) else {}
    item_id = str(
        row.get("micro_segment_id")
        or row.get("segment_id")
        or row.get("item_id")
        or f"video_memory_{index:06d}"
    )
    parent_segment_id = row.get("parent_segment_id") or row.get("segment_id")
    primary_object = (
        row.get("primary_object")
        or interaction.get("primary_object")
        or visual.get("primary_object")
        or "unknown_object"
    )
    interaction_type = (
        row.get("interaction_type")
        or interaction.get("interaction_type")
        or text_description.get("action_type")
        or evidence.get("inferred_action_type")
        or "unknown_interaction"
    )
    action_type = (
        row.get("inferred_action_type")
        or evidence.get("inferred_action_type")
        or text_description.get("action_type")
        or ("hand_object_interaction" if "hand_" in str(interaction_type) else str(interaction_type))
    )
    observed_at = (
        row.get("global_start_time")
        or row.get("observed_at")
        or row.get("created_at")
        or exp.get("completed_at")
        or exp.get("created_at")
        or _video_memory_iso(now_dt)
    )
    observed_dt = _video_memory_parse_dt(observed_at) or now_dt
    observed_iso = _video_memory_iso(observed_dt)
    global_end = row.get("global_end_time") or row.get("global_start_time") or observed_iso
    end_dt = _video_memory_parse_dt(global_end) or observed_dt
    start_sec = _float_value(row.get("start_sec"), 0.0)
    end_sec = _float_value(row.get("end_sec"), start_sec + _float_value(row.get("duration_sec"), 0.0))
    if end_sec < start_sec:
        end_sec = start_sec
    confidence = _float_value(
        row.get("max_interaction_score")
        or interaction.get("max_interaction_score")
        or visual.get("max_interaction_score")
        or row.get("final_score")
        or 0.0,
        0.0,
    )
    if confidence <= 0:
        quality = str((row.get("quality") or {}).get("confidence") if isinstance(row.get("quality"), dict) else "").lower()
        confidence = 0.85 if quality == "high" else 0.55 if quality == "medium" else 0.35
    views = _video_memory_view_payloads(experiment_id, row)
    package_image_refs = [
        str(view.get("keyframe_uri"))
        for view in views
        if view.get("keyframe_uri")
    ]
    evidence_id = f"{experiment_id}:{item_id}"
    cluster_id = row.get("cluster_id") or f"cluster_{_video_memory_slug(primary_object)}_{_video_memory_slug(interaction_type)}"
    trace_payload = row.get("trace") if isinstance(row.get("trace"), dict) else {}
    decision_trace = row.get("decision_trace") or trace_payload.get("decision_trace")
    if not isinstance(decision_trace, list):
        decision_trace = [
            item
            for item in (
                row.get("decision_path"),
                source_level,
                "yolo_candidate" if row.get("yolo_evidence") else None,
                "micro_segment_confirmed" if source_level == "micro_segment" else None,
            )
            if item
        ]
    compact_for_key = {
        "evidence_id": evidence_id,
        "cluster_id": cluster_id,
        "observed_at": observed_iso,
        "action": {
            "type": action_type,
            "primary_object": primary_object,
            "secondary_objects": row.get("secondary_objects") or interaction.get("secondary_objects") or [],
        },
    }
    cache_key = row.get("vlm_cache_key") or _video_memory_cache_key(
        model=str(row.get("vlm_model") or "qwen2.5-vl"),
        prompt_version=str(row.get("prompt_version") or "physical-evidence-v1"),
        image_refs=package_image_refs,
        evidence_payload=compact_for_key,
    )
    summary = (
        row.get("summary")
        or text_description.get("summary")
        or f"{interaction_type} on {primary_object}"
    )
    item = {
        "schema_version": "video_memory.evidence_item.v1",
        "evidence_id": evidence_id,
        "cluster_id": cluster_id,
        "session_id": str(row.get("session_id") or experiment_id),
        "experiment_id": experiment_id,
        "experiment_title": exp.get("title") or experiment_id,
        "created_at": observed_iso,
        "observed_at": observed_iso,
        "time_range": {
            "global_start_time": observed_iso,
            "global_end_time": _video_memory_iso(end_dt),
            "start_sec": start_sec,
            "end_sec": end_sec,
        },
        "action": {
            "type": action_type,
            "primary_object": primary_object,
            "secondary_objects": row.get("secondary_objects") or interaction.get("secondary_objects") or [],
            "description": summary,
            "interaction_type": interaction_type,
        },
        "physical_evidence": {
            "hand_object_contact": bool(
                visual.get("has_hand_object_interaction")
                or confidence >= 0.5
                or "hand_" in str(interaction_type)
            ),
            "object_state_change": str(action_type) in {"object_move", "state_change", "container_state_change"},
            "confidence": round(max(0.0, min(1.0, float(confidence))), 6),
            "uncertainty_reasons": row.get("uncertainty_reasons")
            or ((row.get("window_audit") or {}).get("uncertainty_reasons") if isinstance(row.get("window_audit"), dict) else []),
            "evidence_level": row.get("evidence_level") or evidence.get("evidence_level"),
            "evidence_reasons": row.get("evidence_reasons") or evidence.get("evidence_reasons") or [],
            "limitations": row.get("limitations") or evidence.get("limitations") or [],
        },
        "views": views,
        "vlm": {
            "cache_key": str(cache_key),
            "model": row.get("vlm_model") or "qwen2.5-vl",
            "prompt_version": row.get("prompt_version") or "physical-evidence-v1",
            "summary": row.get("vlm_summary") or summary,
            "confidence": row.get("vlm_confidence") or confidence,
            "status": row.get("vlm_status") or "not_requested",
        },
        "retrieval": {
            "index_text": " ".join(
                str(part)
                for part in [
                    action_type,
                    interaction_type,
                    primary_object,
                    " ".join(map(str, row.get("detected_objects") or interaction.get("detected_objects") or [])),
                    summary,
                ]
                if part
            ),
            "embedding_id": (row.get("index") or {}).get("embedding_id") if isinstance(row.get("index"), dict) else row.get("embedding_id"),
            "score": round(max(0.0, min(1.0, float(confidence))), 6),
            "index_level": source_level,
        },
        "trace": {
            "decision_path": row.get("decision_path") or "yolo.micro_segment.vlm",
            "decision_trace": decision_trace,
            "source_segment_ids": [str(parent_segment_id)] if parent_segment_id else [],
            "source_micro_segment_ids": [str(item_id)] if source_level == "micro_segment" else [],
            "source_row_id": item_id,
        },
        "retention": {
            "retention_days": retention_days,
            "expires_at": _video_memory_iso(observed_dt + timedelta(days=retention_days)),
            "days_old": _video_memory_days_old(observed_iso, now_dt),
        },
        "ui": {
            "title": f"{primary_object} / {interaction_type}",
            "clip_url": next((view.get("clip_url") for view in views if view.get("clip_url")), None),
            "keyframe_url": next((view.get("keyframe_url") for view in views if view.get("keyframe_url")), None),
            "view_count": len(views),
        },
    }
    video_memory = _video_memory_core_module()
    if video_memory is not None and hasattr(video_memory, "validate_evidence_item"):
        try:
            validated = video_memory.validate_evidence_item(item)
            if hasattr(validated, "to_json_dict"):
                return validated.to_json_dict()
            if hasattr(validated, "to_dict"):
                return validated.to_dict()
            if isinstance(validated, dict):
                return validated
        except Exception:
            logger.debug("Video memory core validation rejected backend item %s", evidence_id, exc_info=True)
    return item


def _video_memory_rows_for_experiment(experiment_id: str) -> tuple[str, List[Dict[str, Any]]]:
    metadata_dir = _key_action_output_dir(experiment_id) / "metadata"
    micro_rows = _read_jsonl_rows(metadata_dir / "micro_segments.jsonl")
    if micro_rows:
        return "micro_segment", micro_rows
    segment_rows = _read_jsonl_rows(metadata_dir / "key_action_segments.jsonl")
    if segment_rows:
        return "segment", segment_rows
    return "empty", []


def _video_memory_experiment_summary(
    exp: Dict[str, Any],
    *,
    now_dt: datetime,
    retention_days: int,
    max_items: int,
) -> Dict[str, Any]:
    experiment_id = _validate_experiment_id(str(exp.get("experiment_id") or ""))
    source_level, rows = _video_memory_rows_for_experiment(experiment_id)
    evidence_items: List[Dict[str, Any]] = []
    for index, row in enumerate(rows[: max(1, max_items * 3)], start=1):
        if not isinstance(row, dict):
            continue
        item = _video_memory_evidence_item_from_row(
            experiment_id=experiment_id,
            exp=exp,
            row=row,
            index=index,
            now_dt=now_dt,
            retention_days=retention_days,
            source_level=source_level,
        )
        if item:
            evidence_items.append(item)
    key_action_dir = _key_action_output_dir(experiment_id)
    metadata_dir = key_action_dir / "metadata"
    exp_dir = _experiment_output_dir(experiment_id)
    physical_change_rows = (
        _read_jsonl_rows(exp_dir / "artifacts" / "physical_change_log.jsonl")
        or _read_jsonl_rows(metadata_dir / "state_change_index.jsonl")
    )
    alignment_payload = (
        _load_json_if_exists(exp_dir / "timeline_alignment.json")
        or _load_json_if_exists(metadata_dir / "view_alignment_from_yolo.json")
        or {}
    )
    status_payload = _key_action_summary_for_experiment(experiment_id)
    latest_observed = max(
        [item.get("observed_at") for item in evidence_items if item.get("observed_at")],
        default=None,
    )
    return {
        "experiment_id": experiment_id,
        "title": exp.get("title") or experiment_id,
        "status": exp.get("status") or status_payload.get("status") or "unknown",
        "created_at": exp.get("created_at"),
        "latest_observed_at": latest_observed,
        "source_level": source_level,
        "evidence_items": evidence_items,
        "counts": {
            "source_rows": len(rows),
            "evidence_items": len(evidence_items),
            "segments": status_payload.get("segment_count") or _jsonl_row_count(metadata_dir / "key_action_segments.jsonl"),
            "micro_segments": status_payload.get("micro_segment_count") or _jsonl_row_count(metadata_dir / "micro_segments.jsonl"),
            "interactions": status_payload.get("interaction_count") or status_payload.get("raw_yolo_interaction_count") or 0,
            "vectors": status_payload.get("vector_count") or _jsonl_row_count(metadata_dir / "vector_metadata.jsonl"),
            "micro_vectors": _jsonl_row_count(metadata_dir / "micro_vector_metadata.jsonl"),
            "physical_changes": len(physical_change_rows),
        },
        "alignment": {
            "status": alignment_payload.get("alignment_status") or alignment_payload.get("status"),
            "method": alignment_payload.get("method"),
            "views": alignment_payload.get("views") or [],
        },
        "paths": {
            "key_action_index": str(key_action_dir) if key_action_dir.exists() else None,
            "micro_segments_jsonl": str(metadata_dir / "micro_segments.jsonl") if (metadata_dir / "micro_segments.jsonl").exists() else None,
            "key_action_segments_jsonl": str(metadata_dir / "key_action_segments.jsonl") if (metadata_dir / "key_action_segments.jsonl").exists() else None,
        },
    }


def _video_memory_build_clusters(
    evidence_items: List[Dict[str, Any]],
    *,
    now_dt: datetime,
    retention_days: int,
) -> List[Dict[str, Any]]:
    video_memory = _video_memory_core_module()
    if video_memory is not None and hasattr(video_memory, "score_evidence_clusters") and hasattr(video_memory, "update_cluster_lifecycle"):
        try:
            scored = video_memory.score_evidence_clusters(evidence_items=evidence_items, now=_video_memory_iso(now_dt))
            updated = video_memory.update_cluster_lifecycle(
                clusters=scored,
                feedback_events=[],
                now=_video_memory_iso(now_dt),
                policy={"promote_score": 0.75, "stale_after_days": 14, "archive_after_days": retention_days},
            )
            if isinstance(updated, dict) and isinstance(updated.get("clusters"), list):
                return updated["clusters"]
            if isinstance(updated, list):
                return updated
        except Exception:
            logger.debug("Falling back to backend video memory cluster scoring", exc_info=True)
    grouped: Dict[str, List[Dict[str, Any]]] = {}
    for item in evidence_items:
        grouped.setdefault(str(item.get("cluster_id") or "cluster_unknown"), []).append(item)
    clusters: List[Dict[str, Any]] = []
    for cluster_id, items in grouped.items():
        confidences = [
            _float_value((item.get("physical_evidence") or {}).get("confidence"), 0.0)
            for item in items
            if isinstance(item.get("physical_evidence"), dict)
        ]
        avg_conf = sum(confidences) / len(confidences) if confidences else 0.0
        view_ids = {
            str(view.get("view_id"))
            for item in items
            for view in _video_memory_as_list(item.get("views"))
            if isinstance(view, dict) and view.get("view_id")
        }
        last_observed_at = max([str(item.get("observed_at") or "") for item in items], default="")
        days_old = _video_memory_days_old(last_observed_at, now_dt)
        score = avg_conf * 0.72
        reasons = ["confidence_mean"]
        if len(view_ids) >= 2:
            score += 0.15
            reasons.append("multi_view_support")
        if len(items) >= 2:
            score += 0.08
            reasons.append("repeat_observation")
        if days_old is not None and days_old <= 7:
            score += 0.05
            reasons.append("recent_observation")
        score = round(max(0.0, min(1.0, score)), 6)
        if days_old is not None and days_old > retention_days:
            state = "archived"
        elif score >= 0.75:
            state = "promoted"
        elif score >= 0.55:
            state = "active"
        else:
            state = "candidate"
        cluster = {
            "schema_version": "video_memory.cluster.v1",
            "cluster_id": cluster_id,
            "lifecycle_state": state,
            "score": score,
            "score_reasons": reasons,
            "evidence_item_ids": [str(item.get("evidence_id")) for item in items if item.get("evidence_id")],
            "last_observed_at": last_observed_at,
            "view_ids": sorted(view_ids),
            "evidence_count": len(items),
        }
        if state == "archived":
            cluster["archive_reason"] = "older_than_retention_window"
        clusters.append(cluster)
    clusters.sort(key=lambda item: (_float_value(item.get("score"), 0.0), str(item.get("last_observed_at") or "")), reverse=True)
    return clusters


def _video_memory_build_snapshot(
    *,
    evidence_items: List[Dict[str, Any]],
    clusters: List[Dict[str, Any]],
    now_dt: datetime,
    retention_days: int,
    max_items: int,
) -> Dict[str, Any]:
    now_iso = _video_memory_iso(now_dt)
    video_memory = _video_memory_core_module()
    if video_memory is not None and hasattr(video_memory, "build_partial_snapshot"):
        try:
            snapshot = video_memory.build_partial_snapshot(
                evidence_items=evidence_items,
                clusters=clusters,
                now=now_iso,
                retention_days=retention_days,
                max_items=max_items,
            )
            if hasattr(snapshot, "to_json_dict"):
                snapshot = snapshot.to_json_dict()
            elif hasattr(snapshot, "to_dict"):
                snapshot = snapshot.to_dict()
            if isinstance(snapshot, dict):
                snapshot.setdefault("builder", "key_action_indexer.video_memory")
                return snapshot
        except Exception:
            logger.debug("Falling back to backend video memory partial snapshot", exc_info=True)
    included: List[Dict[str, Any]] = []
    skipped: List[Dict[str, Any]] = []
    for item in sorted(evidence_items, key=lambda row: str(row.get("observed_at") or ""), reverse=True):
        evidence_id = str(item.get("evidence_id") or "")
        days_old = _video_memory_days_old(item.get("observed_at"), now_dt)
        if days_old is not None and days_old > retention_days:
            skipped.append({"evidence_id": evidence_id, "reason": "outside_retention_window"})
            continue
        if len(included) >= max_items:
            skipped.append({"evidence_id": evidence_id, "reason": "max_items"})
            continue
        included.append(item)
    included_ids = {str(item.get("evidence_id")) for item in included}
    included_clusters = [
        cluster
        for cluster in clusters
        if any(str(evidence_id) in included_ids for evidence_id in _video_memory_as_list(cluster.get("evidence_item_ids")))
    ]
    truncation_reason = "max_items" if any(item.get("reason") == "max_items" for item in skipped) else None
    return {
        "schema_version": "video_memory.partial_snapshot.v1",
        "snapshot_id": f"snapshot_{hashlib.sha1(now_iso.encode('utf-8')).hexdigest()[:16]}_partial",
        "snapshot_kind": "partial",
        "generated_at": now_iso,
        "is_partial": True,
        "builder": "labsopguard.backend.thin_wrapper",
        "coverage": {
            "retention_days": retention_days,
            "start_time": _video_memory_iso(now_dt - timedelta(days=retention_days)),
            "end_time": now_iso,
            "truncation_reason": truncation_reason,
            "completeness": "partial",
        },
        "counts": {
            "source_evidence_items": len(evidence_items),
            "included_evidence_items": len(included),
            "source_clusters": len(clusters),
            "included_clusters": len(included_clusters),
            "skipped_items": len(skipped),
        },
        "evidence_items": included,
        "clusters": included_clusters,
        "skipped_items": skipped,
    }


def _video_memory_task_rows(
    *,
    core: Dict[str, Any],
    counts: Dict[str, Any],
    experiments: List[Dict[str, Any]],
    snapshot: Dict[str, Any],
) -> List[Dict[str, Any]]:
    symbols = set(core.get("implemented_symbols") or [])
    missing = set(core.get("missing_symbols") or [])
    evidence_count = int(counts.get("included_evidence_items") or 0)
    cluster_count = int(counts.get("cluster_count") or 0)
    package_safe = "D:\\" not in repr(snapshot) and "C:\\" not in repr(snapshot)
    alignment_ready = any(str((item.get("alignment") or {}).get("status") or "").lower() in {"aligned", "shared_recording", "dual_view_verified"} for item in experiments)
    task_defs = [
        ("T1", "Evidence Item normalization", {"EvidenceItem", "validate_evidence_item"}, evidence_count > 0),
        ("T2", "Stable VLM cache key and cache trace", {"build_vlm_cache_key", "VLMCache"}, int(counts.get("vlm_cache_trace_count") or 0) > 0),
        ("T3", "Evidence cluster scoring", {"score_evidence_clusters"}, cluster_count > 0),
        ("T4", "Cluster lifecycle policy", {"update_cluster_lifecycle"}, cluster_count > 0),
        ("T5", "Partial 30-day snapshot", {"build_partial_snapshot"}, bool(snapshot.get("is_partial"))),
        ("T6", "Query answer evidence trace", {"answer_video_memory_query"}, int(counts.get("query_ready_evidence_items") or 0) > 0),
        ("T7", "Feedback update dry-run", {"run_feedback_update_job"}, False),
        ("T8", "Package-relative asset URIs", set(), package_safe and evidence_count > 0),
        ("T9", "YOLO-backed candidate evidence", set(), int(counts.get("yolo_ref_count") or 0) > 0),
        ("T10", "Micro-segment memory units", set(), int(counts.get("micro_segment_count") or 0) > 0),
        ("T11", "Dual-view time alignment", set(), alignment_ready),
        ("T12", "Physical change log coverage", set(), int(counts.get("physical_change_count") or 0) > 0),
        ("T13", "Retrieval/vector metadata", set(), int(counts.get("retrieval_ready_count") or 0) > 0),
        ("T14", "Backend API and overview UI hook", set(), True),
    ]
    rows: List[Dict[str, Any]] = []
    for task_id, label, required_symbols, data_ready in task_defs:
        if required_symbols and required_symbols <= symbols:
            status = "core_ready"
        elif required_symbols and required_symbols & missing and data_ready:
            status = "thin_wrapper_partial"
        elif required_symbols and required_symbols & missing:
            status = "waiting_for_core"
        elif data_ready:
            status = "ready"
        else:
            status = "needs_source_data"
        rows.append(
            {
                "task_id": task_id,
                "label": label,
                "status": status,
                "required_symbols": sorted(required_symbols),
                "data_ready": bool(data_ready),
            }
        )
    return rows


def _build_video_memory_overview(
    experiments: List[Dict[str, Any]],
    *,
    retention_days: int = 30,
    max_items: int = 200,
) -> Dict[str, Any]:
    retention_days = max(1, min(365, int(retention_days or 30)))
    max_items = max(1, min(1000, int(max_items or 200)))
    now_dt = _video_memory_now_dt()
    core = _video_memory_core_status()
    experiment_summaries: List[Dict[str, Any]] = []
    all_evidence: List[Dict[str, Any]] = []
    excluded_time_axis_experiments: List[Dict[str, Any]] = []
    for exp in experiments:
        experiment_id = str(exp.get("experiment_id") or "")
        if not experiment_id:
            continue
        time_axis_health = _experiment_time_axis_health(experiment_id)
        if time_axis_health.get("time_axis_unreliable"):
            excluded_time_axis_experiments.append(
                {
                    "experiment_id": experiment_id,
                    "reason": "time_axis_unreliable",
                    "time_axis_health": time_axis_health,
                }
            )
            continue
        try:
            summary = _video_memory_experiment_summary(
                exp,
                now_dt=now_dt,
                retention_days=retention_days,
                max_items=max_items,
            )
        except Exception as exc:
            logger.warning("Video memory overview skipped experiment %s: %s", experiment_id, exc)
            continue
        experiment_summaries.append(summary)
        all_evidence.extend(summary.get("evidence_items") or [])
    clusters = _video_memory_build_clusters(all_evidence, now_dt=now_dt, retention_days=retention_days)
    snapshot = _video_memory_build_snapshot(
        evidence_items=all_evidence,
        clusters=clusters,
        now_dt=now_dt,
        retention_days=retention_days,
        max_items=max_items,
    )
    included_items = snapshot.get("evidence_items") if isinstance(snapshot.get("evidence_items"), list) else []
    included_clusters = snapshot.get("clusters") if isinstance(snapshot.get("clusters"), list) else []
    counts = {
        "experiment_count": len(experiment_summaries),
        "source_evidence_items": len(all_evidence),
        "included_evidence_items": len(included_items),
        "cluster_count": len(included_clusters),
        "all_cluster_count": len(clusters),
        "promoted_cluster_count": len([item for item in included_clusters if item.get("lifecycle_state") == "promoted"]),
        "active_cluster_count": len([item for item in included_clusters if item.get("lifecycle_state") == "active"]),
        "archived_cluster_count": len([item for item in clusters if item.get("lifecycle_state") == "archived"]),
        "micro_segment_count": sum(int((item.get("counts") or {}).get("micro_segments") or 0) for item in experiment_summaries),
        "segment_count": sum(int((item.get("counts") or {}).get("segments") or 0) for item in experiment_summaries),
        "physical_change_count": sum(int((item.get("counts") or {}).get("physical_changes") or 0) for item in experiment_summaries),
        "retrieval_ready_count": len([item for item in included_items if (item.get("retrieval") or {}).get("index_text")]),
        "query_ready_evidence_items": len([item for item in included_items if item.get("evidence_id") and (item.get("retrieval") or {}).get("index_text")]),
        "vlm_cache_trace_count": len([item for item in included_items if (item.get("vlm") or {}).get("cache_key")]),
        "dual_view_item_count": len([
            item
            for item in included_items
            if len([view for view in _video_memory_as_list(item.get("views")) if isinstance(view, dict) and view.get("view_id")]) >= 2
        ]),
        "yolo_ref_count": sum(
            len(_video_memory_as_list(view.get("yolo_refs")))
            for item in included_items
            for view in _video_memory_as_list(item.get("views"))
            if isinstance(view, dict)
        ),
    }
    observed_dates: set[str] = set()
    for item in included_items:
        observed_raw = str(item.get("observed_at") or item.get("created_at") or "").strip()
        if not observed_raw:
            continue
        try:
            observed_dates.add(datetime.fromisoformat(observed_raw.replace("Z", "+00:00")).date().isoformat())
        except ValueError:
            observed_dates.add(observed_raw[:10])
    window_days_available = len({value for value in observed_dates if value})
    window_days_expected = retention_days
    window_completeness = "complete" if window_days_available >= window_days_expected else "partial"
    counts.update(
        {
            "covered_day_count": window_days_available,
            "coverage_day_count": window_days_available,
            "observed_day_count": window_days_available,
            "window_days_available": window_days_available,
            "window_days_expected": window_days_expected,
        }
    )
    latest_observed = max([str(item.get("observed_at") or "") for item in included_items], default=None)
    tasks = _video_memory_task_rows(core=core, counts=counts, experiments=experiment_summaries, snapshot=snapshot)
    return {
        "schema_version": _VIDEO_MEMORY_OVERVIEW_SCHEMA_VERSION,
        "contract_version": _VIDEO_MEMORY_CONTRACT_VERSION,
        "generated_at": _video_memory_iso(now_dt),
        "scope": {
            "retention_days": retention_days,
            "max_items": max_items,
            "source": "LabSOPGuard key-action metadata",
        },
        "core": core,
        "counts": counts,
        "coverage": {
            "is_partial": window_completeness != "complete",
            "retention_days": retention_days,
            "window_days_available": window_days_available,
            "window_days_expected": window_days_expected,
            "window_completeness": window_completeness,
            "window_completeness_ratio": f"{window_days_available}/{window_days_expected}",
            "start_time": _video_memory_iso(now_dt - timedelta(days=retention_days)),
            "end_time": _video_memory_iso(now_dt),
            "latest_observed_at": latest_observed,
            "truncation_reason": (snapshot.get("coverage") or {}).get("truncation_reason") if isinstance(snapshot.get("coverage"), dict) else None,
            "skipped_items": len(snapshot.get("skipped_items") or []),
        },
        "tasks": tasks,
        "snapshot": snapshot,
        "experiments": [
            {
                "experiment_id": item.get("experiment_id"),
                "title": item.get("title"),
                "status": item.get("status"),
                "created_at": item.get("created_at"),
                "latest_observed_at": item.get("latest_observed_at"),
                "source_level": item.get("source_level"),
                "counts": item.get("counts"),
                "alignment": item.get("alignment"),
                "paths": item.get("paths"),
            }
            for item in experiment_summaries
        ],
        "evidence_items": included_items[:max_items],
        "clusters": included_clusters,
        "limitations": [
            "Overview is metadata-only and does not decode video pixels.",
            "Experiments marked time_axis_unreliable are excluded from 30-Day Memory and require re-registration after timeline repair.",
            "When key_action_indexer.video_memory is unavailable, scoring and snapshot generation use the LabSOPGuard thin wrapper.",
            "Absolute workstation paths are converted to package:// URIs for memory assets; browser URLs are emitted only for files served inside the experiment output directory.",
        ],
        "excluded_time_axis_experiments": excluded_time_axis_experiments,
        "endpoints": {
            "global_overview": "/api/v1/video-memory/overview",
            "experiment_overview": "/api/v1/experiments/{experiment_id}/video-memory/overview",
        },
    }


@app.get("/api/v1/video-memory/overview", tags=["video-memory"])
async def get_video_memory_overview(
    retention_days: int = 30,
    max_items: int = 200,
    experiment_id: Optional[str] = None,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    experiments = [_merge_experiment_with_task(exp) for exp in _load_experiments()]
    experiments = _scope_filter_experiments(auth_ctx, experiments)
    if experiment_id:
        safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
        experiments = [exp for exp in experiments if str(exp.get("experiment_id") or "") == safe_experiment_id]
        if not experiments:
            experiments = [_merge_experiment_with_task(await get_experiment_dict(safe_experiment_id))]
    experiments.sort(key=lambda item: str(item.get("created_at") or ""), reverse=True)
    return _build_video_memory_overview(experiments, retention_days=retention_days, max_items=max_items)


