@app.post("/api/v1/experiments/{experiment_id}/key-actions/run", tags=["experiments"])
async def run_registered_key_actions(
    experiment_id: str,
    request: KeyActionRunRequest,
    background_tasks: BackgroundTasks,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    exp = await get_experiment_dict(safe_experiment_id)
    current_status = _read_key_action_status(safe_experiment_id)
    if str(current_status.get("status") or "").lower() in {"queued", "running"} and not request.force:
        return current_status
    third_person_path, first_person_path = _registered_key_action_video_paths(exp)
    if not third_person_path:
        raise HTTPException(status_code=400, detail="No registered third_person/top-view video source found for key-action run")
    if not Path(third_person_path).exists():
        raise HTTPException(status_code=404, detail=f"third_person video not found: {third_person_path}")
    if first_person_path and not Path(first_person_path).exists():
        raise HTTPException(status_code=404, detail=f"first_person video not found: {first_person_path}")
    session_start_time = (
        request.session_start_time
        or ((exp.get("key_action_index") or {}).get("session_start_time") if isinstance(exp.get("key_action_index"), dict) else None)
        or exp.get("created_at")
        or _now_iso()
    )
    detection_config_payload = {
        "fast_locate_only": bool(request.fast_locate_only),
        "sample_fps": float(request.sample_fps),
        "start_threshold": float(request.start_threshold),
        "end_threshold": float(request.end_threshold),
        "start_min_duration_sec": float(request.start_min_duration_sec),
        "end_min_duration_sec": float(request.end_min_duration_sec),
        "merge_gap_sec": float(request.merge_gap_sec),
        "min_segment_duration_sec": float(request.min_segment_duration_sec),
        "buffer_sec": float(request.buffer_sec),
        "motion_normalization": "adaptive",
        "roi_mode": "manifest_or_default",
        "render_experiment_focus_yolo": bool(request.render_experiment_focus_yolo),
        "render_segment_yolo": bool(request.render_segment_yolo),
        "generate_professional_report": bool(request.generate_professional_report),
        "require_cuda": True,
    }
    for key in (
        "enable_micro_refine_rescan",
        "yolo_preferred_view",
        "yolo_scan_both_views",
        "long_video_chunk_sec",
        "long_video_stage1_sample_fps",
        "long_video_stage2_sample_fps",
        "long_video_two_stage_sampling",
        "yolo_continuity_frames",
        "expected_experiment_count",
    ):
        value = getattr(request, key, None)
        if value is not None:
            detection_config_payload[key] = value
    detection_config = _with_default_key_action_yolo_config(detection_config_payload)
    try:
        yolo_runtime = _validate_key_action_yolo_runtime(detection_config)
    except KeyActionCudaRequiredError as exc:
        raise HTTPException(
            status_code=409,
            detail=_key_action_cuda_failure_detail(exc, detection_config),
        ) from exc
    exp["status"] = "running"
    exp["processing_stage"] = "key_action_index"
    task_id = exp.get("analysis_job_id") or exp.get("run_id") or f"key_action_{safe_experiment_id}"
    exp["analysis_job_id"] = task_id
    exp.setdefault("output_paths", {})["key_action_index"] = str(_key_action_output_dir(safe_experiment_id))
    upload_context = _key_action_upload_context(exp.get("key_action_index"))
    exp["key_action_index"] = {
        **upload_context,
        "status": "queued",
        "third_person_video_path": third_person_path,
        "first_person_video_path": first_person_path,
        "session_start_time": session_start_time,
        "output_dir": str(_key_action_output_dir(safe_experiment_id)),
    }
    alignment = _write_dual_view_upload_alignment(safe_experiment_id, exp, session_start_time=str(session_start_time))
    if alignment:
        exp["key_action_index"]["timeline_alignment_path"] = str(_experiment_output_dir(safe_experiment_id) / "timeline_alignment.json")
        exp["key_action_index"]["timeline_alignment_status"] = alignment.get("alignment_status")
    _save_experiment(exp)
    analysis_request_received_at = _now_iso()
    status = _write_key_action_status(
        safe_experiment_id,
        {
            **upload_context,
            "status": "queued",
            "progress": 0.0,
            "message": "已找到双视角视频，正式 key-action 分析正在启动",
            "third_person_video_path": third_person_path,
            "first_person_video_path": first_person_path,
            "session_start_time": session_start_time,
            "detection_config": detection_config,
            "yolo_runtime": yolo_runtime,
            "output_dir": str(_key_action_output_dir(safe_experiment_id)),
            "queued_at": analysis_request_received_at,
            "analysis_request_received_at": analysis_request_received_at,
            "elapsed_sec": 0.0,
        },
    )
    _persist_experiment_task_state(
        safe_experiment_id,
        {
            "task_id": task_id,
            "experiment_id": safe_experiment_id,
            "status": "queued",
            "current_stage": "key_action_index",
            "progress": 0.0,
            "message": "已找到双视角视频，正式 key-action 分析正在启动",
            "video_path": third_person_path,
            "started_at": None,
            "completed_at": None,
            "output_paths": exp.get("output_paths", {}),
            "error_type": None,
            "error_message": None,
        },
    )
    background_tasks.add_task(
        _run_key_action_index_task,
        safe_experiment_id,
        third_person_video_path=third_person_path,
        first_person_video_path=first_person_path,
        session_start_time=str(session_start_time),
        detection_config=detection_config,
    )
    return status


