def _key_action_source_video_for_view(experiment_id: str, view: str) -> Optional[Path]:
    aliases = {
        "third": "third_person",
        "third_person": "third_person",
        "first": "first_person",
        "first_person": "first_person",
    }
    requested_view = aliases.get(str(view).strip().lower(), str(view).strip().lower())
    for row in _read_jsonl_rows(_key_action_output_dir(experiment_id) / "metadata" / "video_sources.jsonl"):
        if not isinstance(row, dict):
            continue
        row_view = str(row.get("view_id") or row.get("role") or row.get("name") or "").strip().lower()
        if aliases.get(row_view, row_view) != requested_view:
            continue
        raw_path = row.get("absolute_path") or row.get("path")
        if not raw_path:
            continue
        path = Path(str(raw_path)).resolve()
        if path.exists() and path.is_file():
            return path
    return None


