    await get_experiment_dict(safe_experiment_id)
    path = _key_action_source_video_for_view(safe_experiment_id, view)
    if path is None:
        raise HTTPException(status_code=404, detail="Key-action source video not found")
    return _serve_project_file(path, request, media_type="video/mp4")


