_key_action_results_json_cache: Dict[str, Dict[str, Any]] = {}


@app.get("/api/v1/experiments/{experiment_id}/key-actions/results", tags=["experiments"])
async def get_key_action_results(
    experiment_id: str,
    auth_ctx: Dict[str, Any] = Depends(_require_operator_context),
):
    safe_experiment_id = _enforce_experiment_scope(auth_ctx, experiment_id)
    await get_experiment_dict(safe_experiment_id)
    fingerprint = _key_action_artifact_fingerprint(safe_experiment_id)
    cached = _key_action_results_json_cache.get(safe_experiment_id)
    if cached and cached.get("fingerprint") == fingerprint and isinstance(cached.get("content"), (bytes, bytearray)):
        return Response(
            content=cached["content"],
            media_type="application/json",
        )
    payload = _key_action_results_payload(safe_experiment_id)
    encoded = json.dumps(payload, ensure_ascii=False).encode("utf-8")
    _key_action_results_json_cache[safe_experiment_id] = {
        "fingerprint": _key_action_artifact_fingerprint(safe_experiment_id),
        "content": encoded,
    }
    return Response(content=encoded, media_type="application/json")


