@app.get("/api/v1/experiments/{experiment_id}/timing", tags=["experiments"])
async def get_experiment_timing(experiment_id: str):
    """Get pipeline processing timing for each stage."""
    safe_id = experiment_id.replace("..", "").replace("/", "").replace("\\", "")
    timing_path = PROJECT_ROOT / "outputs" / "experiments" / safe_id / "artifacts" / "processing_timing.json"
    if not timing_path.exists():
        key_action_state = _read_key_action_status(safe_id)
        key_action_timing = _key_action_timing_for_overview(safe_id, key_action_state)
        stage_rows = key_action_timing.get("stages") if isinstance(key_action_timing.get("stages"), list) else []
        stages = {
            str(row.get("stage")): float(row.get("duration_sec") or 0.0)
            for row in stage_rows
            if isinstance(row, dict) and row.get("stage")
        }
        if stages or key_action_timing.get("elapsed_sec") or key_action_timing.get("core_analysis_sec"):
            response = {
                "status": key_action_state.get("status") or "completed",
                "stages": stages,
                "stage_rows": stage_rows,
                "stage_labels_zh": key_action_timing.get("stage_labels_zh") or {},
                "total_sec": key_action_timing.get("elapsed_sec") or key_action_timing.get("core_analysis_sec") or 0,
                "core_analysis_sec": key_action_timing.get("core_analysis_sec"),
                "algorithm_elapsed_sec": key_action_timing.get("algorithm_elapsed_sec"),
                "server_end_to_end_sec": key_action_timing.get("server_end_to_end_sec"),
                "upload_save_sec": key_action_timing.get("upload_save_sec"),
                "queue_wait_sec": key_action_timing.get("queue_wait_sec"),
                "video_memory_write_sec": key_action_timing.get("video_memory_write_sec"),
                "performance_benchmark": key_action_timing.get("performance_benchmark"),
                "upload_e2e_benchmark": key_action_timing.get("upload_e2e_benchmark"),
                "sampling_transparency": key_action_timing.get("sampling_transparency"),
                "coarse_sampled_frame_count": key_action_timing.get("coarse_sampled_frame_count"),
                "fine_sampled_frame_count": key_action_timing.get("fine_sampled_frame_count"),
                "coarse_wall_sec": key_action_timing.get("coarse_wall_sec"),
                "fine_wall_sec": key_action_timing.get("fine_wall_sec"),
                "gpu_device": key_action_timing.get("gpu_device"),
                "batch_size": key_action_timing.get("batch_size"),
                "source": "key_action_job_status+run_manifest",
            }
            response["display_stages"] = key_action_timing.get("display_stages")
            return _finalize_key_action_timing_payload(response)
        return _finalize_key_action_timing_payload(
            {
                "status": "processing_or_not_available",
                "stages": {},
                "stage_rows": [],
                "total_sec": 0,
                "source": "not_available",
            }
        )
    payload = json.loads(timing_path.read_text(encoding="utf-8"))
    if isinstance(payload, dict) and "sampling_transparency" not in payload:
        key_action_timing = _key_action_timing_for_overview(safe_id, _read_key_action_status(safe_id))
        for key in (
            "sampling_transparency",
            "coarse_sampled_frame_count",
            "fine_sampled_frame_count",
            "coarse_wall_sec",
            "fine_wall_sec",
            "gpu_device",
            "batch_size",
        ):
            if key_action_timing.get(key) is not None:
                payload[key] = key_action_timing.get(key)
    if isinstance(payload, dict) and "display_stages" not in payload:
        stage_rows = payload.get("stage_rows") if isinstance(payload.get("stage_rows"), list) else []
        if not stage_rows and isinstance(payload.get("stages"), dict):
            stage_rows = [
                {"stage": str(stage), "duration_sec": duration}
                for stage, duration in payload.get("stages", {}).items()
            ]
        timing_payload = {
            **payload,
            "stages": stage_rows,
            "elapsed_sec": payload.get("total_sec") or payload.get("elapsed_sec"),
        }
        payload["display_stages"] = _key_action_display_timing_stages(timing_payload)
    if isinstance(payload, dict):
        return _finalize_key_action_timing_payload(payload)
    return _finalize_key_action_timing_payload({"status": "invalid_timing_payload", "stages": {}, "total_sec": 0})


@app.get("/api/v1/experiments/{experiment_id}/export", tags=["experiments"])
async def export_experiment_materials(experiment_id: str):
    """Package experiment clips, keyframes, and reports into a downloadable zip."""
    import zipfile, tempfile
    safe_id = experiment_id.replace("..", "").replace("/", "").replace("\\", "")
    exp_dir = PROJECT_ROOT / "outputs" / "experiments" / safe_id
    if not exp_dir.exists():
        raise HTTPException(status_code=404, detail="Experiment not found")

    tmp = tempfile.NamedTemporaryFile(delete=False, suffix=".zip")
    tmp_path = tmp.name
    tmp.close()

    with zipfile.ZipFile(tmp_path, "w", zipfile.ZIP_DEFLATED) as zf:
        materials_dir = exp_dir / "materials" / "events"
        if materials_dir.exists():
            for evt_dir in materials_dir.iterdir():
                if not evt_dir.is_dir():
                    continue
                for f in evt_dir.iterdir():
                    if f.suffix in (".mp4", ".jpg", ".json"):
                        zf.write(str(f), f"materials/{evt_dir.name}/{f.name}")
        reports_dir = exp_dir / "reports"
        if reports_dir.exists():
            for f in reports_dir.iterdir():
                if f.suffix in (".pdf", ".html", ".json"):
                    zf.write(str(f), f"reports/{f.name}")
        timing_path = exp_dir / "artifacts" / "processing_timing.json"
        if timing_path.exists():
            zf.write(str(timing_path), "processing_timing.json")

    return FileResponse(tmp_path, media_type="application/zip", filename=f"{safe_id}_materials.zip")


